const MANUAL_CONTRAST_BACKGROUND = "#fff8e6";

function esc(value) {
  return String(value ?? "").replace(/[&<>"']/g, char => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#039;"
  }[char]));
}

function jsArg(value) {
  return esc(JSON.stringify(String(value ?? "")));
}

function renderNameCutFontOptions(selectedValue = NAME_CUT_DEFAULT_FONT) {
  return NAME_CUT_FONT_REGISTRY.map(font => {
    const selected = selectedValue === font.value ? "selected" : "";
    const approval = font.productionApproved ? "data-production-approved=\"true\"" : "data-production-approved=\"false\"";
    const candidate = font.productionCandidate ? "data-production-candidate=\"true\"" : "data-production-candidate=\"false\"";
    const disabled = font.enabled === false ? "disabled" : "";
    const suffix = font.enabled === false ? " (font dosyası yok)" : "";
    return `<option value="${esc(font.value)}" data-font-id="${esc(font.id)}" data-font-path="${esc(font.path || "")}" ${approval} ${candidate} ${disabled} ${selected}>${esc(font.label)}${esc(suffix)}</option>`;
  }).join("");
}

function nameCutFontMetaByValue(value = NAME_CUT_DEFAULT_FONT) {
  const token = String(value || "").toLocaleLowerCase("tr-TR");
  return NAME_CUT_FONT_REGISTRY.find(font => font.value === value || font.id === value || font.label === value)
    || NAME_CUT_FONT_REGISTRY.find(font => token && [font.value, font.id, font.label].some(part => String(part || "").toLocaleLowerCase("tr-TR") === token))
    || NAME_CUT_FONT_REGISTRY.find(font => font.default)
    || NAME_CUT_FONT_REGISTRY[0];
}

function nameCutFontMetaForItem(item = {}, cfg = nameCutLayoutConfig) {
  return nameCutFontMetaByValue(item.fontId || item.font_id || item.style || item.fontFamily || item.font_family || cfg.font_family || NAME_CUT_DEFAULT_FONT);
}

function nameCutApplyFontMetaToItem(item = {}, fontValue = NAME_CUT_DEFAULT_FONT, options = {}) {
  const font = nameCutFontMetaByValue(fontValue);
  const currentOffset = Number(item.offset_mm ?? item.offsetMm ?? "");
  const shouldAdoptOffset = options.forceOffset === true
    || (!Number.isFinite(currentOffset) && Number.isFinite(Number(font?.defaultOffsetMm)))
    || (Number.isFinite(currentOffset) && Math.abs(currentOffset - Number(nameCutLayoutConfig.offset_mm || 0.3)) < 0.001 && Number.isFinite(Number(font?.defaultOffsetMm)));
  const next = {
    ...item,
    style: font?.value || fontValue || NAME_CUT_DEFAULT_FONT,
    fontId: font?.id || "",
    font_id: font?.id || "",
    fontLabel: font?.label || fontValue || NAME_CUT_DEFAULT_FONT_LABEL,
    font_label: font?.label || fontValue || NAME_CUT_DEFAULT_FONT_LABEL,
    fontFamily: font?.value || fontValue || NAME_CUT_DEFAULT_FONT,
    font_family: font?.value || fontValue || NAME_CUT_DEFAULT_FONT,
    fontPath: font?.path || "",
    font_path: font?.path || "",
    selectedFontId: font?.id || "",
    selectedFontLabel: font?.label || ""
  };
  if (shouldAdoptOffset) {
    next.offset_mm = Number(font.defaultOffsetMm).toFixed(2).replace(/\.00$/, "");
    next.offsetMm = Number(font.defaultOffsetMm);
    next.thickening_mode = "Özel offset";
  }
  return next;
}

function nameCutFontStatusHtml(value = NAME_CUT_DEFAULT_FONT) {
  const font = nameCutFontMetaByValue(value);
  if (!font) return "";
  const status = font.productionCandidate && font.default ? "Seçili Production Candidate" : font.productionCandidate ? "Production Candidate" : font.productionApproved ? "Production Approved" : font.default ? "Güvenli Default" : "Test Fontu";
  const note = font.productionCandidate && font.default
    ? "Bu font aktif üretim adayı olarak seçildi; path-only export, Corel referans kalibrasyonu ve lisans doğrulama kontrolleri korunur."
    : font.productionCandidate
      ? "Kullanıcı onayı sonrası varsayılan yapılabilir."
    : font.productionApproved
      ? "Üretim için onaylı font kaynağı."
      : font.default
        ? "Mevcut varsayılan korunuyor; otomatik değişiklik yok."
        : "Üretim öncesi görsel ve path kontrolü gerekir.";
  const license = font.licenseReviewRequired ? `<br><b>Lisans:</b> Ticari üretim öncesi lisans doğrulaması gerekli.` : "";
  return `
    <div class="safe-note compact name-cut-font-status">
      <b>Seçili font:</b> ${esc(font.label)} · <b>Durum:</b> ${esc(status)}<br>
      ${esc(font.notes || note)}
      ${license}
    </div>
  `;
}

function nameCutOffsetModeStatusHtml() {
  const font = nameCutFontMetaByValue(nameCutLayoutConfig.font_family);
  const offset = clampNumber(Number(nameCutLayoutConfig.offset_mm ?? font?.defaultOffsetMm ?? 0.3), 0, 1.5);
  return `
    <div class="safe-note compact name-cut-offset-status">
      <b>Offset modu:</b> Export hattı FontTools path + pyclipper varsa gerçek polygon offset kullanır; proof/önizleme metrikleri ayrıca RDWorks öncesi doğrulanır.<br>
      <b>Offset:</b> ${esc(offset.toFixed(2))} mm · Aralık 0.00-1.50 mm · Sahte başarı yok.
    </div>
  `;
}

function loadNameCutCorelReferences(options = {}) {
  corelReferenceLibraryState = {
    ...corelReferenceLibraryState,
    ...options,
    loading: true,
    bridgeReady: Boolean(bridge?.listCorelReferences)
  };
  renderNameCutCorelReferencePanel();
  if (!bridge?.listCorelReferences) {
    corelReferenceLibraryState = {
      ...corelReferenceLibraryState,
      loading: false,
      bridgeReady: false,
      message: "Corel referans backend bridge bu oturumda bağlı değil."
    };
    renderNameCutCorelReferencePanel();
    return;
  }
  const payload = {
    mode: corelReferenceLibraryState.mode || "pending",
    query: corelReferenceLibraryState.query || ""
  };
  bridge.listCorelReferences(JSON.stringify(payload), raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      corelReferenceLibraryState = {
        ...corelReferenceLibraryState,
        loading: false,
        bridgeReady: true,
        references: Array.isArray(result.references) ? result.references : [],
        summary: result.summary || corelReferenceLibraryState.summary,
        dataSecurity: result.dataSecurity || corelReferenceLibraryState.dataSecurity,
        message: ""
      };
    } else {
      corelReferenceLibraryState = {
        ...corelReferenceLibraryState,
        loading: false,
        bridgeReady: true,
        dataSecurity: result.dataSecurity || corelReferenceLibraryState.dataSecurity,
        message: result.message || "Corel referansları okunamadı."
      };
    }
    renderNameCutCorelReferencePanel();
  });
}

function filterNameCutCorelReferences(mode = "pending") {
  corelReferenceLibraryState.mode = mode || "all";
  loadNameCutCorelReferences({ mode: corelReferenceLibraryState.mode });
}

function searchNameCutCorelReferences(value = "") {
  corelReferenceLibraryState.query = String(value || "");
  clearTimeout(searchNameCutCorelReferences.timer);
  searchNameCutCorelReferences.timer = setTimeout(() => {
    loadNameCutCorelReferences({ query: corelReferenceLibraryState.query });
  }, 180);
}

function applyNameCutCorelReferenceSuggestion(referenceId = "", value = "") {
  const id = String(referenceId || "");
  const input = byId(`corelRefLabel-${id}`);
  if (!input) return;
  input.value = String(value || "").trim();
  input.focus();
  const row = document.querySelector(`[data-reference-id="${CSS.escape(id)}"]`);
  if (row?.dataset?.canApproveExact === "false") {
    const checkbox = byId(`corelRefApprove-${id}`);
    if (checkbox) checkbox.checked = false;
  }
}

function saveNameCutCorelReferenceLabel(referenceId = "") {
  const id = String(referenceId || "");
  const input = byId(`corelRefLabel-${id}`);
  const approve = byId(`corelRefApprove-${id}`)?.checked === true;
  const label = String(input?.value || "").trim();
  const row = document.querySelector(`[data-reference-id="${CSS.escape(id)}"]`);
  if (!label) {
    showToast("İsim etiketi boş olamaz.", "warning");
    return;
  }
  if (approve && row?.dataset?.canApproveExact === "false") {
    showToast("Exact onay kilitli. Büyük preview ile doğru obje seçilmeli veya önce split yapılmalı.", "warning");
    return;
  }
  if (!bridge?.updateCorelReferenceLabel) {
    showToast("Corel referans kaydetme bridge'i bu oturumda bağlı değil.", "warning");
    return;
  }
  bridge.updateCorelReferenceLabel(id, label, approve, raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast(approve ? "Corel exact referans onaylandı." : "Corel referans etiketi kaydedildi.", "success");
      loadNameCutCorelReferences();
      refreshNameCutStudioViews(currentNameCutLayout());
    } else {
      showToast(result.message || "Corel referans etiketi kaydedilemedi.", "error");
    }
  });
}

function splitNameCutCorelReference(referenceId = "") {
  const id = String(referenceId || "");
  if (!bridge?.splitCorelReference) {
    showToast("Corel split bridge bu oturumda bağlı değil.", "warning");
    return;
  }
  bridge.splitCorelReference(id, raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      const count = Array.isArray(result.children) ? result.children.length : 0;
      showToast(`${count} split child reference oluşturuldu. Exact onay için child objeyi etiketleyin.`, "success");
      loadNameCutCorelReferences({ mode: "needs_split" });
    } else {
      showToast(result.message || "Otomatik split yapılamadı; manuel kontrol gerekir.", result.status === "NEEDS_MANUAL_SPLIT" ? "warning" : "error");
      loadNameCutCorelReferences();
    }
  });
}

function closeNameCutCorelReferencePreview() {
  document.querySelector(".name-cut-reference-modal")?.remove();
}

function renderNameCutCorelReferencePreviewModal(row = {}) {
  closeNameCutCorelReferencePreview();
  const id = String(row.referenceId || row.objectId || "");
  const label = row.manualNameLabel || row.displayName || "";
  const readName = row.readName || row.suggestedLabel || "";
  const target = row.targetNameHint || (Array.isArray(row.targetNameHints) ? row.targetNameHints.join(" / ") : "");
  const status = row.labelStatus || "unlabeled";
  const canApprove = row.canApproveExact === true;
  const warning = row.matchType === "mismatch" || status === "candidate_mismatch"
    ? `Bu obje ${target || label || "hedef isim"} gibi görünmüyor. Okunan isim: ${readName || "okunamadı"}. Exact onay için doğru obje seçilmeli.`
    : row.needsSplit
      ? "Bu obje birden fazla isim içeriyor; tek isim exact onayından önce split child reference oluşturulmalı."
      : row.actionNeeded || "Preview kontrolünden sonra güvenli etiketleme yapılabilir.";
  const preview = row.previewUrl
    ? `<img src="${esc(row.previewUrl)}" alt="${esc(id)}">`
    : `<div class="name-cut-reference-preview-placeholder">Path</div>`;
  const modal = document.createElement("div");
  modal.className = "name-cut-reference-modal";
  modal.innerHTML = `
    <div class="name-cut-reference-modal-card">
      <div class="panel-head compact">
        <h3>Corel Referans Büyük Preview</h3>
        <button class="icon-btn" type="button" onclick="closeNameCutCorelReferencePreview()" aria-label="Kapat">×</button>
      </div>
      <div class="name-cut-reference-zoom">${preview}</div>
      <div class="safe-note compact ${canApprove ? "ok" : "warn"}">${esc(warning)}</div>
      <div class="name-cut-reference-modal-grid">
        <span><b>Object</b><small>${esc(id)}</small></span>
        <span><b>Source</b><small>${esc(row.sourceFile || "-")}</small></span>
        <span><b>Okunan</b><small>${esc(readName || "-")}</small></span>
        <span><b>Hedef</b><small>${esc(target || "-")}</small></span>
        <span><b>Status</b><small>${esc(status)}</small></span>
        <span><b>Ölçü</b><small>${esc(formatMm(row.actualPathWidthMm))} x ${esc(formatMm(row.actualPathHeightMm))} mm</small></span>
      </div>
      <label>Manual Name
        <input id="corelRefPreviewLabel-${esc(id)}" value="${esc(label)}" placeholder="Örn. Sümeyye" />
      </label>
      <label class="check-row">
        <input id="corelRefPreviewApprove-${esc(id)}" type="checkbox" ${canApprove ? "" : "disabled"} />
        Exact isim olarak onayla
      </label>
      <div class="toolbar">
        <button class="btn small" type="button" onclick="applyNameCutCorelReferenceSuggestion(${jsArg(id)}, ${jsArg(readName)}); closeNameCutCorelReferencePreview()">Okunanı input'a yaz</button>
        ${target ? `<button class="btn small warn" type="button" onclick="applyNameCutCorelReferenceSuggestion(${jsArg(id)}, ${jsArg(target)}); closeNameCutCorelReferencePreview()">Hedef adayını input'a yaz</button>` : ""}
        <button class="btn small" type="button" onclick="splitNameCutCorelReference(${jsArg(id)})" ${bridge?.splitCorelReference ? "" : "disabled"}>Bu objeyi split et</button>
        <button class="btn small primary" type="button" onclick="saveNameCutCorelReferenceLabelFromPreview(${jsArg(id)})">Kaydet</button>
      </div>
    </div>
  `;
  document.body.appendChild(modal);
}

function openNameCutCorelReferencePreview(referenceId = "") {
  const id = String(referenceId || "");
  if (!bridge?.getCorelReference) {
    showToast("Corel referans preview bridge'i bu oturumda bağlı değil.", "warning");
    return;
  }
  bridge.getCorelReference(id, raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK" && result.reference) {
      renderNameCutCorelReferencePreviewModal(result.reference);
    } else {
      showToast(result.message || "Corel referans preview açılamadı.", "error");
    }
  });
}

function saveNameCutCorelReferenceLabelFromPreview(referenceId = "") {
  const id = String(referenceId || "");
  const modalInput = byId(`corelRefPreviewLabel-${id}`);
  const rowInput = byId(`corelRefLabel-${id}`);
  if (rowInput && modalInput) rowInput.value = modalInput.value;
  const rowApprove = byId(`corelRefApprove-${id}`);
  const modalApprove = byId(`corelRefPreviewApprove-${id}`);
  if (rowApprove && modalApprove && !modalApprove.disabled) rowApprove.checked = modalApprove.checked;
  closeNameCutCorelReferencePreview();
  saveNameCutCorelReferenceLabel(id);
}

function markNameCutCorelReferenceStyleOnly(referenceId = "") {
  const id = String(referenceId || "");
  if (!bridge?.markCorelReferenceStyleOnly) {
    showToast("Corel referans bridge bu oturumda bağlı değil.", "warning");
    return;
  }
  bridge.markCorelReferenceStyleOnly(id, raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast("Referans style-only olarak bırakıldı.", "info");
      loadNameCutCorelReferences();
    } else {
      showToast(result.message || "Referans güncellenemedi.", "error");
    }
  });
}

function rejectNameCutCorelReferenceCandidate(referenceId = "") {
  const id = String(referenceId || "");
  if (!bridge?.rejectCorelReferenceCandidate) {
    showToast("Yanlış aday işaretleme bridge'i bu oturumda bağlı değil.", "warning");
    return;
  }
  bridge.rejectCorelReferenceCandidate(id, raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast("Referans yanlış aday olarak işaretlendi; production exact override yapamaz.", "info");
      loadNameCutCorelReferences();
    } else {
      showToast(result.message || "Yanlış aday işaretlenemedi.", "error");
    }
  });
}

function rebuildNameCutCorelReferenceIndex() {
  if (!bridge?.rebuildCorelReferenceIndex) {
    showToast("Corel referans indeks bridge'i bu oturumda bağlı değil.", "warning");
    return;
  }
  if (!confirm("Corel referans indeksini yeniden inşa etmek üzeresin. Mevcut indeks dosyaları üzerine yazılır (orijinal kütüphane verisi DOKUNULMAZ, sadece türetilmiş indeks). Devam edilsin mi?")) {
    return;
  }
  bridge.rebuildCorelReferenceIndex(raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast("Corel referans indeksi yenilendi.", "success");
      loadNameCutCorelReferences();
    } else {
      showToast(result.message || "Corel referans indeksi yenilenemedi.", "error");
    }
  });
}

function createNameCutCorelReferenceBackup() {
  if (!bridge?.createCorelReferenceBackup) {
    showToast("Backup bridge bu oturumda bağlı değil.", "warning");
    return;
  }
  bridge.createCorelReferenceBackup("manual_ui", raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast("Corel referans backup oluşturuldu.", "success");
      loadNameCutCorelReferences();
    } else {
      showToast(result.message || "Backup oluşturulamadı.", "error");
    }
  });
}

function restoreNameCutCorelReferenceLatestBackup() {
  if (!bridge?.restoreCorelReferenceBackup) {
    showToast("Restore bridge bu oturumda bağlı değil.", "warning");
    return;
  }
  if (!confirm("Son Corel referans backup'ını geri yüklemek istediğine emin misin? Mevcut dosyanın ayrıca restore öncesi snapshot'ı alınacak.")) {
    return;
  }
  bridge.restoreCorelReferenceBackup("", raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast("Corel referans kütüphanesi son backup'tan geri yüklendi.", "success");
      loadNameCutCorelReferences();
      refreshNameCutStudioViews(currentNameCutLayout());
    } else {
      showToast(result.message || "Backup geri yüklenemedi.", "error");
    }
  });
}

function migrateNameCutCorelReferenceLibrary() {
  if (!bridge?.migrateCorelReferenceLibrary) {
    showToast("Migration bridge bu oturumda bağlı değil.", "warning");
    return;
  }
  if (!confirm("Corel referans kütüphanesi şema migration'ı çalıştırılacak. Yan etki: kütüphane JSON'u yerinde güncellenir. Geri alma için 'Backup Oluştur' ile snapshot al, ardından devam et. Devam edilsin mi?")) {
    return;
  }
  bridge.migrateCorelReferenceLibrary(raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      const changed = result.migration?.changedRecords ?? 0;
      showToast(`Corel referans migration tamamlandı. Güncellenen kayıt: ${changed}`, "success");
      loadNameCutCorelReferences();
    } else {
      showToast(result.message || "Migration çalışmadı.", "error");
    }
  });
}

function renderNameCutCorelReferenceRow(row = {}) {
  const id = String(row.referenceId || row.objectId || "");
  const label = row.manualNameLabel || row.displayName || "";
  const readName = row.readName || row.suggestedLabel || "";
  const suggested = readName ? ` · okunan: ${readName}` : "";
  const targetHint = row.targetNameHint ? ` · hedef aday: ${row.targetNameHint}` : "";
  const targetHints = Array.isArray(row.targetNameHints) && row.targetNameHints.length
    ? row.targetNameHints
    : (row.targetNameHint ? [row.targetNameHint] : []);
  const status = row.labelStatus || (row.approved && row.exactNameMatch && !row.styleReferenceOnly ? "exact_approved" : row.styleReferenceOnly ? "style_reference_only" : "unlabeled");
  const canApprove = row.canApproveExact === true;
  const exact = status === "exact_approved";
  const splitBadge = row.splitFromCompoundObject
    ? ` · child ${esc(row.splitIndex || "")}/${esc(row.splitClusterCount || "?")} · parent: ${esc(row.parentReferenceId || "-")}`
    : "";
  const statusText = {
    unlabeled: "Etiketsiz",
    candidate_hint: "Aday/öneri",
    candidate_mismatch: "Yanlış aday",
    needs_split: "Split gerekli",
    label_ready: "Label hazır",
    exact_approved: "Corel exact",
    style_reference_only: "Style-only",
    rejected_wrong_name: "Yanlış isim"
  }[status] || status;
  const statusTone = exact ? "ok" : (status === "candidate_mismatch" || status === "rejected_wrong_name" || status === "needs_split" ? "danger" : "warn");
  const warning = status === "candidate_mismatch" || row.matchType === "mismatch"
    ? `<div class="name-cut-reference-warning">Bu obje ${esc(row.targetNameHint || label || "hedef isim")} gibi görünmüyor. Okunan isim: ${esc(readName || "okunamadı")}.</div>`
    : row.needsSplit
      ? `<div class="name-cut-reference-warning">Bu obje çok isimli görünüyor; tek isim exact için önce split gerekir.</div>`
      : "";
  const preview = row.previewUrl
    ? `<img src="${esc(row.previewUrl)}" alt="${esc(id)}" loading="lazy">`
    : `<div class="name-cut-reference-preview-placeholder">Path</div>`;
  const bridgeReady = corelReferenceLibraryState.bridgeReady && Boolean(bridge?.updateCorelReferenceLabel);
  return `
    <article class="name-cut-reference-row" data-reference-id="${esc(id)}" data-can-approve-exact="${canApprove ? "true" : "false"}">
      <div class="name-cut-reference-preview">${preview}</div>
      <div class="name-cut-reference-info">
        <b>${esc(row.sourceFile || "Corel obje")}</b>
        <span>${esc(id)}${splitBadge}${esc(suggested)}${esc(targetHint)}</span>
        <small>${esc(formatMm(row.actualPathWidthMm))} x ${esc(formatMm(row.actualPathHeightMm))} mm · ${esc(row.matchType || "manual_needed")}</small>
        <span class="name-cut-reference-badge ${statusTone}">${esc(statusText)}</span>
      </div>
      ${warning}
      <label>Manual Name
        <input id="corelRefLabel-${esc(id)}" value="${esc(label)}" placeholder="Örn. Sümeyye" ${bridgeReady ? "" : "disabled"} />
      </label>
      <label class="check-row">
        <input id="corelRefApprove-${esc(id)}" type="checkbox" ${exact ? "checked" : ""} ${bridgeReady && canApprove ? "" : "disabled"} />
        Exact isim olarak onayla
      </label>
      <div class="name-cut-reference-actions">
        ${readName ? `<button class="btn small" type="button" ${bridgeReady ? "" : "disabled"} onclick="applyNameCutCorelReferenceSuggestion(${jsArg(id)}, ${jsArg(readName)})">Okunanı yaz</button>` : ""}
        ${targetHints.map(name => `<button class="btn small warn" type="button" ${bridgeReady ? "" : "disabled"} onclick="applyNameCutCorelReferenceSuggestion(${jsArg(id)}, ${jsArg(name)})">Aday: ${esc(name)}</button>`).join("")}
        <button class="btn small" type="button" ${bridgeReady && bridge?.getCorelReference ? "" : "disabled"} onclick="openNameCutCorelReferencePreview(${jsArg(id)})">Büyük preview</button>
        <button class="btn small warn" type="button" ${bridgeReady && bridge?.splitCorelReference ? "" : "disabled"} onclick="splitNameCutCorelReference(${jsArg(id)})">Split et</button>
        <button class="btn small primary" type="button" ${bridgeReady ? "" : "disabled"} onclick="saveNameCutCorelReferenceLabel(${jsArg(id)})">Kaydet</button>
        <button class="btn small" type="button" ${bridgeReady ? "" : "disabled"} onclick="markNameCutCorelReferenceStyleOnly(${jsArg(id)})">Style kalsın</button>
        <button class="btn small danger" type="button" ${bridgeReady && bridge?.rejectCorelReferenceCandidate ? "" : "disabled"} onclick="rejectNameCutCorelReferenceCandidate(${jsArg(id)})">Yanlış aday</button>
        ${row.actionNeeded ? `<small>${esc(row.actionNeeded)}</small>` : ""}
      </div>
    </article>
  `;
}

