  const height = parseFloat(selectedLabelModel.label_height_mm || selectedLabelModel.canvas_height_mm || "30") || 30;
  const sourceInfo = byId("cloneModelSourceInfo");
  if (sourceInfo) {
    sourceInfo.innerHTML = `
      <b>${esc(selectedLabelModel.model_name || selectedLabelModel.title || "Etiket Modeli")}</b><br>
      Ölçü: ${esc(selectedLabelModel.size_text || `${width} x ${height} mm`)} · Varyant: ${esc(selectedLabelModel.label_variant || "-")}<br>
      ${selectedLabelModel.preview_image ? "Bağlı görsel yeni varyantta da kullanılacak." : "Bu modelde görsel yok; yeni varyant da görselsiz başlayacak."}
    `;
  }
  if (byId("cloneModelName")) byId("cloneModelName").value = `${selectedLabelModel.model_name || selectedLabelModel.title || "Etiket Modeli"} Kopya`;
  if (byId("cloneModelNo")) byId("cloneModelNo").value = "";
  if (byId("cloneModelVariant")) byId("cloneModelVariant").value = selectedLabelModel.label_variant || "CUSTOM";
  if (byId("cloneModelActive")) byId("cloneModelActive").checked = true;
