function bulkItemHasLaser(item = {}) {
  return Boolean(String(item.name_cut_text || item.laser_name || item.laserName || "").trim());
}

function bulkItemQuality(item = {}) {
  if (item.status === "ERROR" || item.is_deleted) return 35;
  const nameLength = String(item.label_text || "").trim().length;
  const hasModel = item.model_status === "FOUND" || Boolean(item.model_name || item.model_path);
  let score = 70;
  if (hasModel) score += 10;
  if (nameLength >= 3 && nameLength <= 24) score += 12;
  if (nameLength > 32) score -= 12;
  if (String(item.date_text || "").trim()) score += 3;
  if ((item.warnings || []).length) score -= Math.min(18, (item.warnings || []).length * 6);
  if ((item.errors || []).length) score -= Math.min(35, (item.errors || []).length * 16);
  if (bulkItemHasLaser(item) && String(item.name_cut_text || "").length > 28) score -= 8;
  return Math.max(0, Math.min(98, Math.round(score)));
}

function bulkQualityLabel(score = 0) {
  if (score >= 85) return ["Yerleşim uygun", "ok"];
  if (score >= 68) return ["Kontrol önerilir", "warn"];
  return ["Düzeltme gerekli", "bad"];
}

function smartArrangeBulkGalleryItem(item = {}) {
  const score = bulkItemQuality(item);
  const [qualityText] = bulkQualityLabel(score);
  const next = {
    ...item,
    is_edited: true,
    layout_quality_score: Math.max(score, score < 85 ? 86 : score),
    ai_layout_status: "Sistem önerisi",
    warnings: [...(item.warnings || [])]
  };
  next.warnings = next.warnings.filter(warning => !/yazı çok küçük|boşluk fazla|otomatik düzen/i.test(String(warning || "")));
  if (!next.warnings.includes(`Yerleşim kontrolü: ${qualityText}.`)) next.warnings.push(`Yerleşim kontrolü: ${qualityText}.`);
  if (next.status !== "ERROR") next.status = next.warnings.length ? "WARNING" : "READY";
  return next;
}

function smartArrangeVisibleBulkItems(onlyProblematic = false) {
  const visibleIds = new Set(bulkGalleryFilteredItems().map(item => item.item_id));
  let changed = 0;
  bulkGalleryItems = bulkGalleryItems.map(item => {
    if (!visibleIds.has(item.item_id) || item.is_deleted) return item;
    const score = bulkItemQuality(item);
    const problematic = item.status !== "READY" || score < 85 || (item.errors || []).length || (item.warnings || []).length;
    if (onlyProblematic && !problematic) return item;
    changed += 1;
    return smartArrangeBulkGalleryItem(item);
  });
  renderBulkGallery();
  const status = byId("bulkRowPreviewStatus");
  if (status) status.textContent = changed ? `${changed} satır öğrenen yerleşim kontrolünden geçirildi.` : "Düzenlenecek satır bulunamadı.";
}

function bulkLaserQueueRowId(item = {}) {
  return String(item.item_id || item.id || item.row_id || item.row_number || item.order_no || "").trim();
}

function bulkLaserQueueDuplicates() {
  return new Set((nameCutItems || [])
    .filter(item => !item.is_deleted && item.source === "bulk_production" && item.bulk_row_id)
    .map(item => String(item.bulk_row_id)));
}

function bulkLaserQueueSafety(item = {}) {
  const laserName = bulkGalleryLaserText(item);
  const readiness = bulkGalleryQueueReadiness(item);
  const warnings = [];
  const errors = [];
  const safetyFlags = [];
  const textOnly = laserName.replace(/\s+/g, "");
  const longName = textOnly.length >= 24;
  const height = Number(item.name_cut_height_mm || nameCutLayoutConfig.target_name_height_mm || nameCutLayoutConfig.default_height_mm || 40);
  const width = Number(item.name_cut_width_mm || nameCutLayoutConfig.target_name_width_mm || 80);
  const offset = Number(item.name_cut_offset_mm ?? nameCutLayoutConfig.offset_mm);
  const font = String(item.laser_font || nameCutLayoutConfig.font_family || "").trim();
  const laserModel = String(item.laser_model || "01 A Gold Lazer Kesim").trim();

  if (!laserName) {
    errors.push("Lazer isim boş. İsim Kesim hazırlık kuyruğuna gönderilmedi.");
    safetyFlags.push("empty_laser_name");
  }
  if (readiness.state === "blocked") {
    errors.push(...readiness.reasons.map(reason => `Üretime engel: ${reason}`));
    safetyFlags.push("bulk_record_blocked");
  }
  if (!font) {
    errors.push("Lazer font/model bilgisi eksik.");
    safetyFlags.push("missing_font");
  }
  if (!laserModel) {
    errors.push("Lazer modeli eksik.");
    safetyFlags.push("missing_laser_model");
  }
  if (hasTurkishDiacriticForCutting(laserName)) {
    warnings.push("Türkçe karakter ve noktalı harfler için kopuk parça kontrolü önerilir.");
    safetyFlags.push("turkish_diacritic_risk");
  }
  if (/[iİöÖüÜğĞşŞçÇ]/.test(laserName)) {
    warnings.push("Noktalı/işaretli harfler isim içinde köprü kontrolü gerektirebilir.");
    safetyFlags.push("dotted_letter_risk");
  }
  if (longName) {
    warnings.push("Çok uzun lazer isim. Minimum boşluk ve yatay daraltma kontrolü önerilir.");
    safetyFlags.push("long_name");
  }
  if (!Number.isFinite(width) || !Number.isFinite(height) || width <= 0 || height <= 0) {
    warnings.push("Lazer ölçüsü eksik. İsim Kesim ekranında ölçü kontrolü gerekir.");
    safetyFlags.push("missing_dimensions");
  }
  if (!Number.isFinite(offset)) {
    warnings.push("Kalınlaştırma/offset ayarı eksik. İsim Kesim ekranında kontrol gerekir.");
    safetyFlags.push("missing_thickening");
  }
  if (readiness.state === "review") {
    warnings.push(...(readiness.reasons || []).map(reason => `Toplu üretim kontrolü: ${reason}`));
    safetyFlags.push("bulk_record_needs_review");
  }

  const status = errors.length ? "blocked" : (longName || readiness.state === "review" || safetyFlags.includes("missing_dimensions") || safetyFlags.includes("missing_thickening")) ? "needs_review" : "pending_preparation";
  return { laserName, warnings, errors, safetyFlags, status, width, height, offset, font, laserModel };
}

function buildNameCutItemFromBulk(item = {}, safety = {}) {
  const bulkRowId = bulkLaserQueueRowId(item) || `bulk-row-${Date.now()}`;
  const createdAt = new Date().toISOString();
  const height = Number.isFinite(Number(safety.height)) ? Number(safety.height) : Number(nameCutLayoutConfig.target_name_height_mm || nameCutLayoutConfig.default_height_mm || 40);
  const width = Number.isFinite(Number(safety.width)) ? Number(safety.width) : Number(nameCutLayoutConfig.target_name_width_mm || 80);
  const quantity = Math.max(1, Number(item.quantity || 1) || 1);
  const statusMap = {
    pending_preparation: "PENDING_PREPARATION",
    needs_review: "NEEDS_REVIEW",
    blocked: "BLOCKED"
  };
  return {
    id: `bulk-namecut-${bulkRowId}`,
    item_id: `bulk-namecut-${bulkRowId}`,
    row_number: nameCutItems.length + 1,
    source: "bulk_production",
    source_label: "Toplu Üretim",
    bulk_row_id: bulkRowId,
    duplicate_key: `bulk_production:${bulkRowId}`,
    order_no: item.order_no || "",
    customer_name: item.customer_name || "",
    laser_name: safety.laserName || "",
    name_text: safety.laserName || "",
    preview_text: safety.laserName || "",
    quantity: String(quantity),
    label_model: item.model_name || item.model_key || "",
    laser_model: safety.laserModel || "01 A Gold Lazer Kesim",
    note: item.note_text || item.note || "",
    status: statusMap[safety.status] || "NEEDS_REVIEW",
    created_at: createdAt,
    updated_at: createdAt,
    safety_flags: safety.safetyFlags || [],
    width_mm: Number(width || 0).toFixed(1),
    height_mm: Number(height || 0).toFixed(1),
    style: safety.font || nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT,
    composition: "İsimleri Bitiştir",
    composition_mode: "İsimleri Bitiştir",
    thickening_mode: "Özel offset",
    offset_mm: Number.isFinite(Number(safety.offset)) ? Number(safety.offset) : Number(nameCutLayoutConfig.offset_mm || 0.3),
    support_line: false,
    back_plate: false,
    warnings: safety.warnings || [],
    errors: safety.errors || [],
    is_deleted: false,
    is_edited: false
  };
}

function sendLaserBulkItemsToNameCutQueue() {
  const liveBulkItems = (bulkGalleryItems || []).filter(item => !item.is_deleted);
  const candidates = liveBulkItems.filter(item => bulkItemHasLaser(item));
  const status = byId("bulkRowPreviewStatus");
  if (!candidates.length) {
    const message = "Lazer isim içeren üretime uygun satır bulunamadı.";
    if (status) status.textContent = message;
    if (typeof showToast === "function") showToast(message, "warning");
    return;
  }
  const duplicates = bulkLaserQueueDuplicates();
  const prepared = [];
  const needsReview = [];
  const blocked = [];
  const duplicateRows = [];
  candidates.forEach(item => {
    const rowId = bulkLaserQueueRowId(item);
    const safety = bulkLaserQueueSafety(item);
    if (rowId && duplicates.has(rowId)) {
      duplicateRows.push(item);
      return;
    }
    if (safety.status === "blocked") {
      blocked.push({ item, safety });
      return;
    }
    const queueItem = buildNameCutItemFromBulk(item, safety);
    if (safety.status === "needs_review") needsReview.push(queueItem);
    else prepared.push(queueItem);
  });
  const additions = [...prepared, ...needsReview];
  const now = new Date().toLocaleTimeString("tr-TR", { hour: "2-digit", minute: "2-digit" });
  bulkLaserQueueTransferState = {
    found: candidates.length,
    prepared: prepared.length,
    review: needsReview.length,
    blocked: blocked.length,
    duplicate: duplicateRows.length,
    updatedAt: now
  };
  if (!additions.length) {
    const message = `${candidates.length} lazer isimli kayıt bulundu · ${blocked.length} kayıt engellendi · ${duplicateRows.length} kayıt daha önce gönderilmiş. İsim Kesim kuyruğuna yeni kayıt eklenmedi.`;
    if (status) status.textContent = message;
    setSelectedBulkRunState({ status: "error", rows: [], message });
    renderBulkProductionSummary();
    if (typeof showToast === "function") showToast(message, "warning");
    return;
  }
  if (!bridge?.save_name_cut_queue_items) {
    const message = "İsim Kesim kalıcı hazırlık kuyruğu bu oturumda backend'e bağlı değil. Kayıtlar geçici state'e alınmadı.";
    if (status) status.textContent = message;
    setSelectedBulkRunState({ status: "error", rows: [], message });
    renderBulkProductionSummary();
    if (typeof showToast === "function") showToast(message, "warning");
    return;
  }
  const payload = {
    summary: {
      total: candidates.length,
      prepared: prepared.length,
      review: needsReview.length,
      blocked: blocked.length,
      duplicate: duplicateRows.length
    },
    items: additions.map(item => ({
      ...item,
      status: String(item.status || "").toLowerCase() === "pending_preparation" ? "pending_preparation"
        : String(item.status || "").toLowerCase() === "needs_review" ? "needs_review"
          : String(item.status || "").toLowerCase() === "blocked" ? "blocked"
            : String(item.status || "").toUpperCase() === "PENDING_PREPARATION" ? "pending_preparation"
              : String(item.status || "").toUpperCase() === "NEEDS_REVIEW" ? "needs_review"
                : "needs_review"
    }))
  };
  if (status) status.textContent = `${additions.length} lazer kayıt kalıcı İsim Kesim hazırlık kuyruğuna yazılıyor. RDWorks/lazer otomatik başlamaz.`;
  bridge.save_name_cut_queue_items(JSON.stringify(payload), raw => {
    const result = parseBridgeResult(raw);
    const resultStatus = String(result.status || "").toUpperCase();
    if (resultStatus !== "OK") {
      const firstBlocked = Array.isArray(result.blockedItems) ? result.blockedItems[0] : null;
      const gateReasons = firstBlocked?.production_queue_block_reasons || firstBlocked?.production_queue_gate?.reasons || [];
      const reasonText = gateReasons.length ? ` Neden: ${gateReasons.slice(0, 3).join(" · ")}` : "";
      const message = (result.message || "İsim Kesim hazırlık kuyruğuna yazılamadı.") + reasonText;
      if (status) status.textContent = message;
      setSelectedBulkRunState({ status: "error", rows: additions.map(item => item.bulk_row_id || item.row_number), message });
      if (typeof showToast === "function") showToast(message, "warning");
      return;
    }
    const transfer = result.transfer || {};
    const addedRows = Array.isArray(result.items) ? result.items : additions;
    syncNameCutQueueFromPersistence(result.queue || addedRows, result.history || nameCutTransferHistoryRows);
    selectedNameCutItemId = (addedRows[0] || {}).item_id || selectedNameCutItemId;
    bulkLaserQueueTransferState = {
      found: Number(transfer.total ?? candidates.length) || candidates.length,
      prepared: Number(transfer.pending_preparation ?? prepared.length) || 0,
      review: Number(transfer.needs_review ?? needsReview.length) || 0,
      blocked: Number(transfer.blocked ?? blocked.length) || 0,
      duplicate: Number(transfer.duplicate ?? duplicateRows.length) || 0,
      updatedAt: now
    };
    const message = result.message || `${addedRows.length} kayıt kalıcı İsim Kesim hazırlık kuyruğuna alındı. RDWorks/lazer otomatik başlatılmadı.`;
    if (status) status.textContent = message;
    setSelectedBulkRunState({ status: addedRows.length ? "laser_prepared" : "error", rows: addedRows.map(item => item.bulk_row_id || item.row_number), message });
    renderBulkProductionSummary();
    if (typeof showToast === "function") showToast(message, transfer.needs_review || transfer.blocked || transfer.duplicate ? "info" : "success");
    showSection("nameCutStudio");
    document.getElementById("nameCutGalleryGrid")?.scrollIntoView({ block: "center" });
  });
}

function renderBulkProductionSummary() {
  const summary = bulkGallerySummary(bulkGalleryItems || []);
  const live = (bulkGalleryItems || []).filter(item => !item.is_deleted);
  const laserCount = live.filter(bulkItemHasLaser).length || nameCutLiveItems().length;
  const totalQuantity = summary.quantity || live.reduce((sum, item) => sum + Math.max(1, Number(item.quantity || 1) || 1), 0);
  const sourceNames = { excel: "Excel", trendyol: "Trendyol", manual: "Manuel" };
  const selectedExcelName = currentState.selectedExcelName || "";
  const trendyolRows = Array.isArray(currentState.trendyol?.suggestions) ? currentState.trendyol.suggestions : [];
  const trendyolReady = trendyolRows.filter(row => {
    if (typeof trendyolVerifiedReady === "function") return trendyolVerifiedReady(row);
    return ["ready", "imported"].includes(String(row.status || row.import_status || "").toLowerCase());
  }).length;
  const trendyolReview = trendyolRows.filter(row => {
    const status = String(row.status || row.import_status || "").toLowerCase();
    return !["ready", "imported"].includes(status);
  }).length;
  const trendyolMissing = trendyolRows.filter(row => {
    const productStatus = String(row.product_match_status || row.match_status || row.mapping_status || "").toLowerCase();
    return productStatus.includes("missing") || productStatus.includes("eksik") || productStatus === "unmatched";
  }).length;
  const manualRows = live.filter(item => String(item.source_type || item.source || "").toLowerCase() === "manual").length;
  const mappingFields = currentState.bulkColumnMapping?.columns ? bulkColumnRowsForOperator(currentState.bulkColumnMapping) : [];
  const mappedFieldCount = mappingFields.filter(field => field.status === "matched" || field.status === "review").length;
  const missingFieldCount = mappingFields.filter(field => field.required && field.status === "missing").length;
  const errorStats = typeof bulkErrorStats === "function" ? bulkErrorStats() : {};
  setText("bulkSummarySource", sourceNames[bulkProductionSource] || "Excel");
  setText("bulkSummaryFile", selectedExcelName || (bulkProductionSource === "manual" ? "Manuel giriş" : "-"));
  setText("bulkSummaryTotal", summary.total || currentState.summary?.total || 0);
  setText("bulkSummaryReady", summary.ready || 0);
  setText("bulkSummaryReview", summary.warning || currentState.summary?.review || 0);
  setText("bulkSummaryError", summary.error || currentState.summary?.errors || 0);
  setText("bulkSummaryModelMissing", live.filter(item => item.model_status !== "FOUND").length);
  setText("bulkSummaryBlocker", errorStats.blocker || 0);
  setText("bulkSummaryTextOverflow", errorStats.textOverflow || 0);
  setText("bulkSummarySmallText", errorStats.smallText || 0);
  setText("bulkSummaryLaserReview", errorStats.laser || 0);
  setText("bulkSummaryPreviewMissing", errorStats.previewMissing || 0);
  setText("bulkSummaryMappedFields", mappedFieldCount || 0);
  setText("bulkSummaryMissingFields", missingFieldCount || 0);
  setText("bulkSummaryLaser", laserCount);
  setText("bulkSummaryQty", totalQuantity || 0);
  setText("bulkSummaryModel", selectedLabelModel?.title || selectedLabelModel?.model_name || live.find(item => item.model_name)?.model_name || "-");
  setText("bulkSummaryLaserModel", laserCount ? "İsim Kesim Modeli 01" : "-");
  setText("bulkSummaryNameCutSent", bulkLaserQueueTransferState.prepared || 0);
  setText("bulkSummaryNameCutReview", bulkLaserQueueTransferState.review || 0);
  setText("bulkSummaryLaserBlocked", bulkLaserQueueTransferState.blocked || 0);
  setText("bulkSummaryLaserDuplicate", bulkLaserQueueTransferState.duplicate || 0);
  setText("bulkSummaryLaserTransferAt", bulkLaserQueueTransferState.updatedAt || "-");
  setText("bulkSummaryOutput", summary.ready ? "Hazırlanabilir" : "Kontrol bekliyor");
  setText("bulkSummaryQueue", (currentState.printQueue || []).length ? `${(currentState.printQueue || []).length} iş` : "Oluşturulmadı");
  setText("bulkSourceExcelFile", selectedExcelName || "Excel seçilmedi");
  setText("bulkSourceExcelRows", `${summary.total || currentState.summary?.total || currentState.summary?.valid || 0} satır`);
  setText("bulkSourceTrendyolReady", trendyolReady);
  setText("bulkSourceTrendyolReview", trendyolReview);
  setText("bulkSourceTrendyolMissing", trendyolMissing);
  setText("bulkSourceManualRows", manualRows);
  setText("bulkLastActionText", hasRunControl() ? `Son işlem: ${readinessText(currentState.readiness || "NO_CHECK")}` : "Son işlem: kontrol bekliyor");
  if (bulkProductionStep === 5) renderBulkErrorPanel();
}

function syncBulkGallery(items = []) {
  const editedById = new Map((bulkGalleryItems || []).filter(item => item.is_edited || item.is_deleted).map(item => [item.item_id, item]));
  bulkGalleryItems = (items || []).map(item => editedById.get(item.item_id) || { ...item });
  resetBulkGalleryVisibleLimit();
  if (!selectedBulkGalleryItemId || !bulkGalleryItems.some(item => item.item_id === selectedBulkGalleryItemId)) {
    selectedBulkGalleryItemId = (bulkGalleryItems.find(item => !item.is_deleted) || bulkGalleryItems[0] || {}).item_id || "";
  }
  renderBulkGallery();
  if (!bulkProductionAutoStepApplied && bulkGalleryItems.length && hasRunControl()) {
    bulkProductionAutoStepApplied = true;
    setBulkProductionStep(4);
  }
  renderBulkProductionSummary();
  if (bulkProductionStep === 5) renderBulkErrorPanel();
}

function bulkGallerySummary(items = bulkGalleryItems) {
  const live = items.filter(item => !item.is_deleted);
  const modelSet = new Set(live.filter(item => item.model_status === "FOUND").map(item => item.model_name || item.model_key).filter(Boolean));
  return {
    total: items.length,
    ready: live.filter(item => item.status === "READY").length,
    warning: live.filter(item => item.status === "WARNING").length,
    error: live.filter(item => item.status === "ERROR").length,
    deleted: items.filter(item => item.is_deleted).length,
    edited: items.filter(item => item.is_edited).length,
    quantity: live.filter(item => item.status !== "ERROR").reduce((sum, item) => sum + Math.max(1, Number(item.quantity || 1) || 1), 0),
    models: modelSet.size
  };
}

function bulkGalleryStatus(item = {}) {
  if (item.is_deleted) return ["Silindi", "muted"];
  if (item.is_edited) return ["Düzenlendi", item.status === "ERROR" ? "bad" : "ok"];
  if (item.status === "ERROR") return ["Hatalı", "bad"];
  if (item.status === "WARNING") return ["Uyarı", "warn"];
  return ["Hazır", "ok"];
}

function bulkGallerySourceLabel(item = {}) {
  const source = String(item.source_label || item.source || item.source_type || currentState.bulkProductionSource || "excel").trim().toLowerCase();
  if (/trendyol/.test(source)) return "Trendyol";
  if (/manual|manuel/.test(source)) return "Manuel";
  if (/bulk|toplu/.test(source)) return "Toplu Üretim";
  if (/laser|lazer/.test(source)) return "Lazer";
  if (/excel|xlsx|sheet/.test(source)) return "Excel";
  return item.source_label || item.source_type || "Excel";
}

function bulkGalleryStatusReason(item = {}) {
  const quality = item.layout_quality_score || bulkItemQuality(item);
  const problems = [...(item.errors || []), ...(item.warnings || [])].map(value => String(value || ""));
  const joined = problems.join(" ").toLocaleLowerCase("tr-TR");
  if (item.status === "ERROR" && /model|şablon|sablon/.test(joined)) return ["Model eksik", "bad"];
  if (item.status === "ERROR" && /isim|ad soyad/.test(joined)) return ["İsim eksik", "bad"];
  if (item.status === "ERROR") return ["Hatalı", "bad"];
  if (/taş|tas|sığ|sig/.test(joined)) return ["Yazı taşıyor", "warn"];
  if (/küçük|kucuk|font/.test(joined) || (quality > 0 && quality < 68)) return ["Yazısı küçük", "warn"];
  if (item.status === "WARNING") return ["Kontrol gerekli", "warn"];
  if (item.is_edited) return ["Operatör kontrolü", "info"];
  return ["Hazır", "ok"];
}

function bulkGalleryProblemTags(item = {}) {
  const tags = [];
  const problems = [...(item.errors || []), ...(item.warnings || [])].map(value => String(value || "").trim()).filter(Boolean);
  const joined = problems.join(" ").toLocaleLowerCase("tr-TR");
  if (item.status === "ERROR" && /model|şablon|sablon/.test(joined)) tags.push(["Model eksik", "bad"]);
  if (/isim|ad soyad/.test(joined) && item.status === "ERROR") tags.push(["İsim eksik", "bad"]);
  if (!String(item.date_text || "").trim()) tags.push(["Tarih eksik", "muted"]);
  if (/taş|tas|sığ|sig/.test(joined)) tags.push(["Yazı taşıyor", "warn"]);
  if (/küçük|kucuk|font/.test(joined) || bulkItemQuality(item) < 68) tags.push(["Yazısı küçük", "warn"]);
  if (bulkItemHasLaser(item) && String(item.name_cut_text || item.laser_name || item.laserName || "").trim().length > 28) tags.push(["Lazer kontrol", "purple"]);
  if (!tags.length && problems.length) tags.push([problems[0], item.status === "ERROR" ? "bad" : "warn"]);
  return tags.slice(0, 4);
}

function bulkGalleryProblemText(item = {}) {
  const problems = [...(item.errors || []), ...(item.warnings || [])].map(value => String(value || "").trim()).filter(Boolean);
  if (problems.length) return problems.join("\n");
  const [reason] = bulkGalleryStatusReason(item);
  return reason === "Hazır" ? "Bu satır üretime hazır görünüyor." : reason;
}

function normalizeBulkSearchText(value) {
  return String(value || "")
    .toLocaleLowerCase("tr-TR")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ı/g, "i")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function bulkGalleryFilteredItems() {
  const search = normalizeBulkSearchText(bulkGallerySearch || "");
  let items = bulkGalleryItems;
  if (bulkGalleryFilter === "ready") items = bulkGalleryItems.filter(item => !item.is_deleted && item.status === "READY");
  if (bulkGalleryFilter === "warning") items = bulkGalleryItems.filter(item => !item.is_deleted && item.status === "WARNING");
  if (bulkGalleryFilter === "error") items = bulkGalleryItems.filter(item => !item.is_deleted && item.status === "ERROR");
  if (bulkGalleryFilter === "edited") items = bulkGalleryItems.filter(item => item.is_edited && !item.is_deleted);
  if (bulkGalleryFilter === "deleted") items = bulkGalleryItems.filter(item => item.is_deleted);
  if (bulkGalleryFilter === "laser") items = bulkGalleryItems.filter(item => !item.is_deleted && bulkItemHasLaser(item));
  if (bulkGalleryFilter === "quality") items = bulkGalleryItems.filter(item => !item.is_deleted && bulkItemQuality(item) < 85);
  if (bulkGalleryFilter === "overflow") items = bulkGalleryItems.filter(item => !item.is_deleted && bulkGalleryProblemTags(item).some(([label]) => /taşıyor/i.test(label)));
  if (bulkGalleryFilter === "smallText") items = bulkGalleryItems.filter(item => !item.is_deleted && bulkGalleryProblemTags(item).some(([label]) => /küçük/i.test(label)));
  if (bulkGalleryFilter === "ai") items = bulkGalleryItems.filter(item => !item.is_deleted && String(item.ai_layout_status || "").trim());
  if (!search) return items;
  return items.filter(item => normalizeBulkSearchText([
    item.row_number,
    item.model_key,
    item.model_name,
    item.label_text,
    item.date_text,
    item.note_text,
    item.order_no,
    item.customer_name,
    item.product_name,
    item.barcode,
    item.sku,
    item.proof_text,
    item.source_label
  ].join(" ")).includes(search));
}

function setBulkGalleryFilter(filter) {
  bulkGalleryFilter = filter || "all";
  resetBulkGalleryVisibleLimit();
  document.querySelectorAll("#bulkLabel [data-bulk-gallery-filter]").forEach(button => {
    button.classList.toggle("active", button.dataset.bulkGalleryFilter === bulkGalleryFilter);
  });
  renderBulkGallery();
}

function scheduleBulkGallerySearch(value) {
  bulkGallerySearch = value || "";
  resetBulkGalleryVisibleLimit();
  debounceRender("bulkGallerySearch", renderBulkGallery);
}

function selectedBulkGalleryItem() {
  return bulkGalleryItems.find(item => item.item_id === selectedBulkGalleryItemId) || bulkGalleryItems.find(item => !item.is_deleted) || bulkGalleryItems[0] || null;
}

function bulkGalleryItemByIndexOrId(indexOrId) {
  if (typeof indexOrId === "number") return bulkGalleryItems[indexOrId] || null;
  const key = String(indexOrId || "");
  return bulkGalleryItems.find(item =>
    item.item_id === key ||
    item.id === key ||
    item.source_item_id === key ||
    item.trendyol_suggestion_id === key
  ) || null;
}

function currentBulkPreviewItem() {
  return bulkGalleryItemByIndexOrId(bulkPreviewModalItemId) || selectedBulkGalleryItem();
}

function bulkGalleryLaserText(item = {}) {
  return String(item.name_cut_text || item.laser_name || item.laser_text || item.name_cut_text || item.laserName || "").trim();
}

function bulkPreviewFieldRows(item = {}) {
  const source = bulkGallerySourceLabel(item);
  return [
    ["İsim", item.label_text, "label_text", "Dolu"],
    ["Tarih", item.date_text, "date_text", item.date_text ? "Dolu" : "Eksik"],
    ["Not", item.note_text, "note_text", item.note_text ? "Dolu" : "Opsiyonel"],
    ["Adet", item.quantity || "1", "quantity", Number(item.quantity || 1) > 0 ? "Dolu" : "Kontrol gerekli"],
    ["Lazer İsim", bulkGalleryLaserText(item), "laser_name", bulkItemHasLaser(item) ? "Dolu" : "Opsiyonel"],
    ["Etiket Modeli", item.model_name || item.model_key, "model_name", item.model_status === "FOUND" ? "Dolu" : "Kontrol gerekli"],
    ["Sipariş No", item.order_no, "order_no", item.order_no ? "Dolu" : "Opsiyonel"],
    ["Müşteri Adı", item.customer_name, "customer_name", item.customer_name ? "Dolu" : "Opsiyonel"],
    ["Ürün Adı", item.product_name, "product_name", item.product_name ? "Dolu" : "Opsiyonel"],
    ["Barkod", item.barcode, "barcode", item.barcode ? "Dolu" : "Opsiyonel"],
    ["SKU", item.sku, "sku", item.sku ? "Dolu" : "Opsiyonel"],
    ["Kaynak", source, "source", "Dolu"]
  ];
}

function bulkPreviewIssueCards(item = {}) {
  const issues = [];
  const problems = [...(item.errors || []), ...(item.warnings || [])].map(value => String(value || "").trim()).filter(Boolean);
  const [reasonLabel, reasonTone] = bulkGalleryStatusReason(item);
  if (!String(item.preview_png_path || item.preview_image || item.preview_url || "").trim()) {
    issues.push(["Önizleme henüz oluşturulmadı", "Model önizlemesi bağlanmadıysa üretimden önce gerçek çıktıyı kontrol edin.", "Model Seç", "warn"]);
  }
  if (!String(item.label_text || "").trim()) {
    issues.push(["İsim eksik", "Etikete yazılacak isim bulunamadı. Üretime almadan önce alanı düzeltin.", "Studio’da Aç", "bad"]);
  }
  if (!String(item.date_text || "").trim()) {
    issues.push(["Tarih eksik", "Tarih opsiyonel olabilir; yine de sipariş notuyla karşılaştırın.", "Sonra kontrol et", "warn"]);
  }
  if (bulkItemHasLaser(item) && bulkGalleryLaserText(item).length > 28) {
    issues.push(["Lazer isim uzun", "Minimum boşluk ve kesim güvenliği İsim Kesim ekranında kontrol edilmeli.", "Lazer Kesim’de Aç", "purple"]);
  }
  problems.forEach(text => {
    const lower = text.toLocaleLowerCase("tr-TR");
    const tone = /model|isim|hata|bulunamadı/.test(lower) ? "bad" : /taş|tas|küçük|kucuk|lazer/.test(lower) ? "warn" : "info";
    const title = /model/.test(lower) ? "Model kontrolü" : /taş|tas/.test(lower) ? "Yazı taşıyor olabilir" : /küçük|kucuk/.test(lower) ? "Yazı küçük görünebilir" : "Kontrol notu";
    issues.push([title, text, tone === "bad" ? "Model Seç" : "Akıllı Düzenle", tone]);
  });
  if (!issues.length && reasonLabel === "Hazır") {
    issues.push(["Üretime hazır", "Bu kayıt için engelleyici uyarı görünmüyor. Yine de çıktıyı kontrol ederek ilerleyin.", "Onayla", "ok"]);
  } else if (!issues.length) {
    issues.push([reasonLabel, "Bu kayıt için operatör kontrolü önerilir.", "Hata Detayı", reasonTone]);
  }
  return issues.slice(0, 6);
}

function bulkErrorIssueTone(severity = "info") {
  return {
    blocker: "bad",
    review: "warn",
    warning: "warn",
    info: "info",
    fixed: "ok"
  }[severity] || "info";
}

function bulkErrorSeverityLabel(severity = "info") {
  return {
    blocker: "Üretime engel",
    review: "Kontrol gerekli",
    warning: "Uyarı",
    info: "Bilgi",
    fixed: "Düzeldi"
  }[severity] || "Bilgi";
}

function bulkErrorCategoryLabel(category = "general") {
  return {
    model_missing: "Model Eksik",
    name_missing: "İsim Eksik",
    date_missing: "Tarih Eksik",
    text_overflow: "Yazı Taşıyor",
    small_text: "Yazısı Küçük",
    laser_check: "Lazer Kontrolü",
    preview_missing: "Önizleme / Çıktı Eksik",
    evidence_missing: "Kanıt / Trendyol Kontrolü",
    general: "Genel Kontrol"
  }[category] || "Genel Kontrol";
}

function bulkErrorCategoryHint(category = "general") {
  return {
    model_missing: "Model seçin veya model eşleştirmesini kontrol edin.",
    name_missing: "İsim alanını Excel, Trendyol mesajı veya manuel girişten tamamlayın.",
    date_missing: "Tarih opsiyonelse sonra kontrol edin; zorunluysa alanı tamamlayın.",
    text_overflow: "Akıllı düzenle veya Studio’da kontrol et.",
    small_text: "Baskıdan önce önizlemeyi kontrol edin; gerekirse yazıyı büyütün.",
    laser_check: "İsim Kesim hazırlığında minimum boşluk ve uzun isim kontrolü yapın.",
    preview_missing: "Model görseli veya gerçek mini önizleme oluşturun.",
    evidence_missing: "Müşteri mesajı/kanıt bağlantısını kontrol edin.",
    general: "Satırı üretime almadan önce operatör kontrolünden geçirin."
  }[category] || "Satırı üretime almadan önce operatör kontrolünden geçirin.";
}

function bulkErrorIssueFromText(text = "", fallbackSeverity = "review") {
  const lower = String(text || "").toLocaleLowerCase("tr-TR");
  if (/model|şablon|sablon|template/.test(lower)) {
    return { category: "model_missing", severity: "blocker", title: "Model eksik", description: text, action: "Model eşleştir" };
  }
  if (/lazer|laser|boşluk|bosluk|minimum/.test(lower)) {
    return { category: "laser_check", severity: "review", title: "Lazer kontrolü", description: text, action: "Lazer Kesim’de Aç" };
  }
  if (/isim|ad soyad|label/.test(lower) && /eksik|boş|bulunamadı|bulunamadi/.test(lower)) {
    return { category: "name_missing", severity: "blocker", title: "İsim eksik", description: text, action: "Zorunlu alanı düzelt" };
  }
  if (/tarih|date/.test(lower)) {
    return { category: "date_missing", severity: "review", title: "Tarih kontrolü", description: text, action: "Örnek satırı göster" };
  }
  if (/taş|tas|sığ|sig|overflow/.test(lower)) {
    return { category: "text_overflow", severity: "review", title: "Yazı taşıyor olabilir", description: text, action: "Akıllı düzenle" };
  }
  if (/küçük|kucuk|font|okunmayabilir/.test(lower)) {
    return { category: "small_text", severity: "warning", title: "Yazısı küçük görünebilir", description: text, action: "Studio’da kontrol et" };
  }
  if (/kanıt|kanit|mesaj|trendyol|sipariş|siparis/.test(lower)) {
    return { category: "evidence_missing", severity: "review", title: "Kanıt kontrolü", description: text, action: "Kanıtı kontrol et" };
  }
  if (/önizleme|onizleme|preview|png|pdf|görsel|gorsel/.test(lower)) {
    return { category: "preview_missing", severity: "warning", title: "Önizleme / çıktı eksik", description: text, action: "Önizleme oluştur" };
  }
  return { category: "general", severity: fallbackSeverity, title: "Kontrol notu", description: text, action: "Hata Detayı" };
}

function bulkErrorIssuesForItem(item = {}) {
  const issues = [];
  const pushIssue = issue => {
    if (!issue || !issue.category) return;
    const key = `${issue.category}|${issue.title}|${issue.description || ""}`;
    if (issues.some(existing => `${existing.category}|${existing.title}|${existing.description || ""}` === key)) return;
    issues.push(issue);
  };
  const modelText = String(item.model_name || item.model_key || item.model_path || "").trim();
  if (item.model_status !== "FOUND" || !modelText) {
    pushIssue({
      category: "model_missing",
      severity: "blocker",
      title: "Model eksik",
      description: "Etiket modeli bulunamadı veya seçilmedi. Bu kayıt model eşleşmeden üretime alınmamalı.",
      action: "Model eşleştir"
    });
  }
  if (!String(item.label_text || "").trim()) {
    pushIssue({
      category: "name_missing",
      severity: "blocker",
      title: "İsim eksik",
      description: "Etikete yazılacak isim boş. Excel kolonu veya müşteri mesajı kontrol edilmeli.",
      action: "Zorunlu alanı düzelt"
    });
  }
  if (!String(item.date_text || "").trim()) {
    pushIssue({
      category: "date_missing",
      severity: "review",
      title: "Tarih eksik",
      description: "Tarih opsiyonel olabilir; sipariş notu ve model gereksinimiyle karşılaştırın.",
      action: "Sonra kontrol et"
    });
  }
  const quality = item.layout_quality_score || bulkItemQuality(item);
  const problemText = `${[...(item.errors || []), ...(item.warnings || [])].join(" ")} ${bulkGalleryStatusReason(item)[0]}`.toLocaleLowerCase("tr-TR");
  if (/taş|tas|sığ|sig|overflow/.test(problemText)) {
    pushIssue({
      category: "text_overflow",
      severity: "review",
      title: "Yazı taşıyor",
      description: "İsim, tarih veya not alanı güvenli alana sığmayabilir.",
      action: "Akıllı düzenle"
    });
  }
  if (/küçük|kucuk|font/.test(problemText) || (quality > 0 && quality < 68)) {
    pushIssue({
      category: "small_text",
      severity: "warning",
      title: "Yazısı küçük",
      description: "Baskıda okunabilirlik düşebilir. Önizleme üzerinden kontrol edin.",
      action: "Studio’da kontrol et"
    });
  }
  const laserText = bulkGalleryLaserText(item);
  if (bulkItemHasLaser(item) && (laserText.length > 28 || /lazer|laser|minimum|boşluk|bosluk/.test(problemText))) {
    pushIssue({
      category: "laser_check",
      severity: "review",
      title: "Lazer kontrolü",
      description: "Lazer isim uzun veya minimum boşluk kontrolü öneriliyor. Lazer/RDWorks otomatik başlamaz.",
      action: "Lazer Kesim’de Aç"
    });
  }
  if (!String(item.preview_png_path || item.preview_image || item.preview_url || "").trim()) {
    pushIssue({
      category: "preview_missing",
      severity: item.status === "ERROR" ? "review" : "info",
      title: "Önizleme eksik",
      description: "Gerçek mini önizleme veya model görseli henüz bağlanmamış.",
      action: "Önizleme oluştur"
    });
  }
  if (/trendyol/.test(String(item.source_type || item.source || item.source_label || "").toLocaleLowerCase("tr-TR")) && !String(item.evidence_status || item.evidence_id || "").trim()) {
    pushIssue({
      category: "evidence_missing",
      severity: "review",
      title: "Kanıt kontrolü",
      description: "Trendyol kaydı için müşteri mesajı veya kanıt bağlantısı kontrol edilmeli.",
      action: "Kanıtı kontrol et"
    });
  }
  [...(item.errors || [])].forEach(text => pushIssue(bulkErrorIssueFromText(text, "blocker")));
  [...(item.warnings || [])].forEach(text => pushIssue(bulkErrorIssueFromText(text, "review")));
  if (item.status === "ERROR" && !issues.some(issue => issue.severity === "blocker")) {
    pushIssue({
      category: "general",
      severity: "blocker",
      title: "Üretime engel hata",
      description: "Kayıt hata durumunda. Üretime almadan önce ayrıntıyı kontrol edin.",
      action: "Hata Detayı"
    });
  }
  return issues;
}

function bulkErrorItemRows() {
  return (bulkGalleryItems || [])
    .filter(item => !item.is_deleted)
    .map((item, index) => ({ item, index, issues: bulkErrorIssuesForItem(item) }))
    .filter(row => row.issues.length);
}

function bulkErrorIssueMatchesFilter(issue = {}, filter = "all") {
  if (filter === "all") return true;
  if (filter === "blocker") return issue.severity === "blocker";
  if (filter === "review") return issue.severity === "review" || issue.severity === "warning";
  return issue.category === filter;
}

function bulkErrorFilteredRows() {
  const search = normalizeBulkSearchText(bulkErrorSearch || "");
  return bulkErrorItemRows().map(row => ({
    ...row,
    issues: row.issues.filter(issue => bulkErrorIssueMatchesFilter(issue, bulkErrorFilter))
  })).filter(row => {
    if (!row.issues.length) return false;
    if (!search) return true;
    const item = row.item;
    return normalizeBulkSearchText([
      item.row_number,
      item.order_no,
      item.label_text,
      item.date_text,
      item.note_text,
      item.model_name,
      item.model_key,
      bulkGallerySourceLabel(item),
      row.issues.map(issue => `${issue.title} ${issue.description}`).join(" ")
    ].join(" ")).includes(search);
  });
}

function bulkErrorStats() {
  const rows = bulkErrorItemRows();
  const allIssues = rows.flatMap(row => row.issues);
  const uniqueCount = key => rows.filter(row => row.issues.some(issue => issue.category === key)).length;
  return {
    total: rows.length,
    blocker: rows.filter(row => row.issues.some(issue => issue.severity === "blocker")).length,
    review: rows.filter(row => row.issues.some(issue => issue.severity === "review" || issue.severity === "warning")).length,
    textOverflow: uniqueCount("text_overflow"),
    smallText: uniqueCount("small_text"),
    modelMissing: uniqueCount("model_missing"),
    laser: uniqueCount("laser_check"),
    nameDate: rows.filter(row => row.issues.some(issue => issue.category === "name_missing" || issue.category === "date_missing")).length,
    previewMissing: uniqueCount("preview_missing"),
    evidenceMissing: uniqueCount("evidence_missing"),
    issueCount: allIssues.length
  };
}

function setBulkErrorFilter(filter = "all") {
  bulkErrorFilter = filter || "all";
  renderBulkErrorPanel();
}

function scheduleBulkErrorSearch(value = "") {
  bulkErrorSearch = value || "";
  debounceRender("bulkErrorSearch", renderBulkErrorPanel);
}

function bulkErrorActionButton(issue = {}, index = -1) {
  const action = issue.action || "Hata Detayı";
  if (/akıllı|akilli/i.test(action)) {
    return `<button class="btn small" type="button" onclick="bulkGalleryItems[${index}] = smartArrangeBulkGalleryItem(bulkGalleryItems[${index}]); renderBulkGallery(); renderBulkErrorPanel();">Akıllı Düzenle</button>`;
  }
  if (/model/i.test(action)) {
    return `<button class="btn small" type="button" onclick="showSection('labelModels')">Model Seç</button>`;
  }
  if (/lazer/i.test(action)) {
    return `<button class="btn small" type="button" onclick="openBulkItemInLaserStudio(bulkGalleryItems[${index}]?.item_id)" title="İsim Kesim Studio’ya aktar">Lazer Kesim’de Aç</button>`;
  }
  if (/önizleme|onizleme/i.test(action)) {
    return `<button class="btn small" type="button" onclick="renderBulkRealMiniPreviews()">Önizleme Oluştur</button>`;
  }
  return `<button class="btn small" type="button" onclick="showBulkFeatureNotConnected('${esc(action)}')">${esc(action)}</button>`;
}

function renderBulkErrorPanel() {
  const summaryBox = byId("bulkErrorSummary");
  const categoryBox = byId("bulkErrorCategoryGrid");
  const list = byId("bulkWarningList");
  if (!list) return;
  if (!hasRunControl() && !bulkGalleryItems.length) {
    if (summaryBox) summaryBox.innerHTML = "";
    if (categoryBox) categoryBox.innerHTML = "";
    list.innerHTML = `<div class="empty-state"><b>Önce kontrol çalıştırın.</b><p>Kritik hatalar ve kontrol gereken satırlar burada görünecek.</p></div>`;
    return;
  }
  const stats = bulkErrorStats();
  if (summaryBox) {
    const statRows = [
      ["Toplam sorunlu kayıt", stats.total, "info", "all"],
      ["Üretime engel", stats.blocker, stats.blocker ? "bad" : "ok", "blocker"],
      ["Kontrol gerekli", stats.review, stats.review ? "warn" : "ok", "review"],
      ["Yazı taşıyor", stats.textOverflow, stats.textOverflow ? "warn" : "ok", "text_overflow"],
      ["Yazısı küçük", stats.smallText, stats.smallText ? "warn" : "ok", "small_text"],
      ["Model eksik", stats.modelMissing, stats.modelMissing ? "bad" : "ok", "model_missing"],
      ["Lazer kontrolü", stats.laser, stats.laser ? "purple" : "ok", "laser_check"],
      ["İsim / tarih eksik", stats.nameDate, stats.nameDate ? "warn" : "ok", "name_missing"]
    ];
    summaryBox.innerHTML = statRows.map(([label, value, tone, filter]) => `
      <button class="bulk-error-kpi ${esc(tone)} ${bulkErrorFilter === filter ? "active" : ""}" type="button" onclick="setBulkErrorFilter('${esc(filter)}')">
        <b>${esc(value)}</b><span>${esc(label)}</span>
      </button>
    `).join("");
  }
  if (categoryBox) {
    const categories = [
      ["all", "Tümü"],
      ["blocker", "Üretime engel"],
      ["review", "Kontrol gerekli"],
      ["model_missing", "Model eksik"],
      ["name_missing", "İsim eksik"],
      ["date_missing", "Tarih eksik"],
      ["text_overflow", "Yazı taşıyor"],
      ["small_text", "Yazısı küçük"],
      ["laser_check", "Lazer kontrolü"],
      ["preview_missing", "Önizleme eksik"],
      ["evidence_missing", "Kanıt eksik"]
    ];
    categoryBox.innerHTML = categories.map(([key, label]) => `
      <button class="btn small ${bulkErrorFilter === key ? "active" : ""}" type="button" data-bulk-error-filter="${esc(key)}" onclick="setBulkErrorFilter('${esc(key)}')">${esc(label)}</button>
    `).join("");
  }
  const rows = bulkErrorFilteredRows();
  if (!rows.length) {
    list.innerHTML = `<div class="empty-state compact"><b>Bu filtrede sorunlu kayıt yok.</b><p>Başka bir hata kategorisi seçin veya aramayı temizleyin.</p></div>`;
    return;
  }
  list.innerHTML = rows.map(({ item, index, issues }) => {
    const primary = issues[0] || {};
    const tone = bulkErrorIssueTone(primary.severity);
    const source = bulkGallerySourceLabel(item);
    return `
      <article class="bulk-error-card ${esc(tone)}">
        <div class="bulk-error-card-head">
          <div>
            <span class="pill ${esc(tone)}">${esc(bulkErrorSeverityLabel(primary.severity))}</span>
            <span class="pill muted">Satır ${esc(item.row_number || index + 1)}</span>
            <span class="pill info">${esc(source)}</span>
          </div>
          <strong>${esc(bulkErrorCategoryLabel(primary.category))}</strong>
        </div>
        <div class="bulk-error-card-body">
          <div class="bulk-error-main">
            <b title="${esc(item.label_text || "")}">${esc(item.label_text || "İsim bulunamadı")}</b>
            <span>${esc(item.date_text || "Tarih bulunamadı")} · ${esc(item.note_text || "Not yok")}</span>
            <small title="${esc(item.model_name || item.model_key || "")}">Model: ${esc(item.model_name || item.model_key || "Model bulunamadı")}</small>
          </div>
          <div class="bulk-error-desc">
            <b>${esc(primary.title || bulkErrorCategoryLabel(primary.category))}</b>
            <p>${esc(primary.description || bulkErrorCategoryHint(primary.category))}</p>
            <small>Önerilen aksiyon: ${esc(primary.action || bulkErrorCategoryHint(primary.category))}</small>
          </div>
        </div>
        <div class="bulk-error-tags">
          ${issues.slice(0, 4).map(issue => `<span class="pill ${esc(bulkErrorIssueTone(issue.severity))}" title="${esc(issue.description || "")}">${esc(bulkErrorCategoryLabel(issue.category))}</span>`).join("")}
        </div>
        <div class="toolbar compact bulk-error-actions">
          <button class="btn small" type="button" onclick="openBulkPreviewModal(${index}, 'label')">Önizle</button>
          <button class="btn small danger-soft" type="button" onclick="openBulkPreviewModal(${index}, 'errors', 'errors')">Hata Detayı</button>
          ${bulkErrorActionButton(primary, index)}
          <button class="btn small" type="button" onclick="openBulkItemInLabelStudio(${index})">Studio’da Aç</button>
          <button class="btn small" type="button" onclick="setBulkItemStatus(${JSON.stringify(item.item_id || "")}, 'skipped')" title="Bu satırı atla, sonra kontrol et">Yok say / sonra</button>
          <button class="btn small" type="button" onclick="setBulkItemStatus(${JSON.stringify(item.item_id || "")}, 'fixed')" title="Düzeltildi olarak işaretle">Düzeltildi</button>
        </div>
      </article>
    `;
  }).join("");
}

function bulkPreviewTabButton(tab, label) {
  return `<button class="bulk-preview-tab ${bulkPreviewTab === tab ? "active" : ""}" type="button" onclick="setBulkPreviewTab('${esc(tab)}')">${esc(label)}</button>`;
}

function openBulkPreviewModal(indexOrId, tab = "label", mode = "detail") {
  const item = bulkGalleryItemByIndexOrId(indexOrId);
  if (!item) return;
  selectedBulkGalleryItemId = item.item_id || selectedBulkGalleryItemId;
  bulkPreviewModalItemId = item.item_id || "";
  bulkPreviewTab = tab || "label";
  bulkPreviewMode = mode || "detail";
  bulkPreviewModalOpen = true;
  renderBulkGallery();
  renderBulkPreviewModal();
  const modal = byId("bulkPreviewModal");
  if (modal) modal.hidden = false;
}

function closeBulkPreviewModal() {
  bulkPreviewModalOpen = false;
  const modal = byId("bulkPreviewModal");
  if (modal) modal.hidden = true;
}

function setBulkPreviewTab(tab = "label") {
  bulkPreviewTab = ["label", "laser", "fields", "errors"].includes(tab) ? tab : "label";
  renderBulkPreviewModal();
}

function navigateBulkPreviewModal(delta = 0) {
  const liveItems = bulkGalleryItems.filter(item => !item.is_deleted);
  if (!liveItems.length) return;
  const currentId = currentBulkPreviewItem()?.item_id || bulkPreviewModalItemId;
  const currentIndex = Math.max(0, liveItems.findIndex(item => item.item_id === currentId));
  const next = liveItems[Math.max(0, Math.min(liveItems.length - 1, currentIndex + delta))];
  if (!next) return;
  selectedBulkGalleryItemId = next.item_id || selectedBulkGalleryItemId;
  bulkPreviewModalItemId = next.item_id || "";
  renderBulkGallery();
  renderBulkPreviewModal();
}

function renderBulkPreviewModal() {
  const modal = byId("bulkPreviewModal");
  const item = currentBulkPreviewItem();
  if (!modal || !item) return;
  const index = bulkGalleryItems.findIndex(row => row.item_id === item.item_id);
  const [statusLabel, statusTone] = bulkGalleryStatus(item);
  const [reasonLabel, reasonTone] = bulkGalleryStatusReason(item);
  const quality = item.layout_quality_score || bulkItemQuality(item);
  const [qualityText, qualityTone] = bulkQualityLabel(quality);
  const sourceLabel = bulkGallerySourceLabel(item);
  const laserText = bulkGalleryLaserText(item);
  const hasLaser = bulkItemHasLaser(item);
  const title = byId("bulkPreviewModalTitle");
  const meta = byId("bulkPreviewModalMeta");
  const status = byId("bulkPreviewModalStatus");
  const tabs = byId("bulkPreviewModalTabs");
  const stage = byId("bulkPreviewModalStage");
  const side = byId("bulkPreviewModalSide");
  const actions = byId("bulkPreviewModalActions");
  if (title) title.textContent = "Toplu Önizleme Detayı";
  if (meta) meta.textContent = `Satır ${item.row_number || "-"} · ${sourceLabel} · ${item.model_name || item.model_key || "Model bulunamadı"}`;
  if (status) status.innerHTML = `<span class="pill ${statusTone}">${esc(statusLabel)}</span><span class="pill ${reasonTone}">${esc(reasonLabel)}</span><span class="pill ${qualityTone}">Kalite %${esc(quality)}</span>`;
  if (tabs) tabs.innerHTML = [
    bulkPreviewTabButton("label", "Etiket Önizleme"),
    bulkPreviewTabButton("laser", "Lazer Önizleme"),
    bulkPreviewTabButton("fields", "Alanlar"),
    bulkPreviewTabButton("errors", "Uyarılar / Hatalar")
  ].join("");
  if (stage) {
    if (bulkPreviewTab === "laser") {
      stage.innerHTML = `
        <div class="bulk-preview-laser-stage ${hasLaser ? "has-laser" : "empty"}">
          <div>
            <span class="pill purple">${hasLaser ? "Lazer var" : "Lazer isim yok"}</span>
            <h3>${esc(laserText || "Lazer yerleşimi İsim Kesim ekranında hazırlanır.")}</h3>
            <p>${hasLaser ? "Lazer otomatik başlamaz. Bu kayıt yalnızca İsim Kesim hazırlığı için kontrol edilir." : "Bu satırda lazer isim alanı bulunmuyor veya opsiyonel boş."}</p>
          </div>
          <div class="laser-safety-ruler"><span>Minimum boşluk kontrolü</span><b>${laserText.length > 28 ? "Kontrol gerekli" : hasLaser ? "Önerilir" : "Yok"}</b></div>
        </div>
      `;
    } else if (bulkPreviewTab === "fields") {
      stage.innerHTML = `<div class="bulk-preview-fields">${bulkPreviewFieldRows(item).map(([label, value, key, state]) => {
        const tone = state === "Dolu" ? "ok" : state === "Kontrol gerekli" || state === "Eksik" ? "warn" : "muted";
        return `<div><span>${esc(label)}</span><b title="${esc(value || "")}">${esc(value || "Bulunamadı")}</b><small>${esc(key)} · ${esc(state)}</small><em class="pill ${tone}">${esc(state)}</em></div>`;
      }).join("")}</div>`;
    } else if (bulkPreviewTab === "errors") {
      stage.innerHTML = `<div class="bulk-preview-issues">${bulkPreviewIssueCards(item).map(([heading, text, action, tone]) => `
        <article class="bulk-preview-issue ${esc(tone)}">
          <span class="pill ${esc(tone)}">${esc(tone === "bad" ? "Hata" : tone === "warn" ? "Uyarı" : tone === "ok" ? "Hazır" : "Bilgi")}</span>
          <h4>${esc(heading)}</h4>
          <p>${esc(text)}</p>
          <button class="btn small" type="button" onclick="showBulkFeatureNotConnected('${esc(action)}')">${esc(action)}</button>
        </article>
      `).join("")}</div>`;
    } else {
      stage.innerHTML = `
        <div class="bulk-preview-label-stage">
          ${bulkGalleryPreview(item, true)}
          <div class="bulk-preview-safe-lines" aria-hidden="true"></div>
        </div>
      `;
    }
  }
  if (side) {
    side.innerHTML = `
      <div class="bulk-preview-side-section">
        <b>Üretim Bilgisi</b>
        <div><span>Model</span><strong title="${esc(item.model_name || item.model_key || "")}">${esc(item.model_name || item.model_key || "Model bulunamadı")}</strong></div>
        <div><span>İsim</span><strong title="${esc(item.label_text || "")}">${esc(item.label_text || "Bulunamadı")}</strong></div>
        <div><span>Tarih</span><strong>${esc(item.date_text || "Bulunamadı")}</strong></div>
        <div><span>Not</span><strong title="${esc(item.note_text || "")}">${esc(item.note_text || "Not yok")}</strong></div>
        <div><span>Adet</span><strong>${esc(item.quantity || "1")}</strong></div>
        <div><span>Kaynak</span><strong>${esc(sourceLabel)}</strong></div>
      </div>
      <div class="bulk-preview-side-section">
        <b>Kalite ve Lazer</b>
        <div><span>Kalite</span><strong>%${esc(quality)} · ${esc(qualityText)}</strong></div>
        <div><span>Durum</span><strong>${esc(statusLabel)} / ${esc(reasonLabel)}</strong></div>
        <div><span>Lazer</span><strong title="${esc(laserText)}">${hasLaser ? esc(laserText || "Var") : "Yok"}</strong></div>
        <div><span>Sipariş</span><strong>${esc(item.order_no || "Bulunamadı")}</strong></div>
      </div>
      <p class="safe-note compact">Yazıcı, lazer ve RDWorks otomatik başlamaz. Bu modal yalnızca kontrol ve hazırlık içindir.</p>
    `;
  }
  if (actions) {
    actions.innerHTML = `
      <button class="btn" type="button" onclick="setBulkItemStatus(${JSON.stringify(item?.item_id || "")}, ‘approved’)" title="Bu satırı operatör onaylı olarak işaretle">Onayla</button>
      <button class="btn" type="button" onclick="openBulkItemInLabelStudio(${index})">Studio’da Aç</button>
      <button class="btn" type="button" onclick="openBulkItemInLaserStudio(${JSON.stringify(item?.item_id || "")})" title="İsim Kesim Studio’ya aktar">Lazer Kesim’de Aç</button>
      <button class="btn" type="button" onclick="bulkGalleryItems[${index}] = smartArrangeBulkGalleryItem(bulkGalleryItems[${index}]); renderBulkGallery(); renderBulkPreviewModal();">Akıllı Düzenle</button>
      <button class="btn" type="button" onclick="openBulkGalleryEditor(${index})">Düzenle</button>
      <button class="btn danger-soft" type="button" onclick="setBulkItemStatus(${JSON.stringify(item?.item_id || "")}, ‘error’)">Hatalı İşaretle</button>
    `;
  }
}

function selectBulkGalleryItem(itemId, openEditor = false) {
  const index = bulkGalleryItems.findIndex(item => item.item_id === itemId);
  if (index < 0) return;
  selectedBulkGalleryItemId = itemId;
  renderBulkGallery();
  if (openEditor) openBulkGalleryEditor(index);
}

function bulkGalleryPreview(item = {}, large = false) {
  const image = item.preview_png_path || item.preview_image || item.preview_url || "";
  const cls = large ? "bulk-gallery-preview large" : "bulk-gallery-preview";
  const nameLength = String(item.label_text || "").trim().length;
  const dense = nameLength > 48 ? " ultra-dense" : nameLength > 24 ? " dense" : "";
  return `
    <div class="${cls} ${image ? "" : "no-image"}">
      ${image ? `<img src="${esc(image)}" alt="${esc(item.model_name || "Model önizlemesi")}" />` : `<div class="bulk-gallery-placeholder"><b>Önizleme bekliyor</b><span>Model seçin veya görsel bağlayın</span></div>`}
      <div class="bulk-gallery-text${dense}">
        <b title="${esc(item.label_text || "İsim")}">${esc(item.label_text || "İsim")}</b>
        <span>${esc(item.date_text || "Tarih")}</span>
        <small>${esc(item.note_text || "Not")}</small>
      </div>
    </div>
  `;
}

function isBulkTrendyolItem(item = {}) {
  return String(item.source || item.source_type || item.source_label || "").toLocaleLowerCase("tr-TR").includes("trendyol");
}

function bulkTrendyolSuggestionId(item = {}) {
  return String(item.source_item_id || item.trendyol_suggestion_id || item.trendyol_order_id || item.item_id || item.id || "").replace(/^trendyol-/, "");
}

function findTrendyolSuggestionForBulkItem(item = {}) {
  const id = bulkTrendyolSuggestionId(item);
  const rows = Array.isArray(currentState.trendyol?.suggestions) ? currentState.trendyol.suggestions : [];
  return rows.find(row => String(row.id || "") === id)
    || rows.find(row => String(row.order_number || "") && String(row.order_number || "") === String(item.order_no || item.trendyol_order_id || ""))
    || {};
}

function bulkTrendyolProofLabel(source = "") {
  const value = String(source || "").toLocaleLowerCase("tr-TR");
  if (!value || value === "missing") return "Kanıt yok";
  if (value.includes("operator")) return "Operatör manuel";
  if (value.includes("question") || value.includes("answer")) return "Müşteri mesajı/kanıt";
  if (value.includes("template")) return "Ürün şablonu";
  if (value.includes("product") || value.includes("customer")) return "Güvenli değil";
  return source;
}

function bulkTrendyolFieldProofRows(item = {}) {
  const sources = item.field_sources || {};
  return [
    ["İsim", item.label_text || "", "label_text", sources.label_text],
    ["Tarih", item.date_text || "", "date_text", sources.date_text],
    ["Not", item.note_text || "", "note_text", sources.note_text],
    ["Lazer İsim", bulkGalleryLaserText(item), "name_cut_text", sources.name_cut_text]
  ];
}

function bulkTrendyolBadges(item = {}) {
  const badges = [["Trendyol", "info"]];
  badges.push(item.proof_text ? ["Kanıtlı", "ok"] : ["Kanıt yok", "warn"]);
  if (item.operator_corrected) badges.push(["Operatör düzeltildi", "info"]);
  badges.push(String(item.model_status || "").toUpperCase() === "FOUND" ? ["Model eşleşti", "ok"] : ["Model eksik", "bad"]);
  if (String(item.trendyol_import_status || "") === "blocked" || String(item.status || "").toUpperCase() === "ERROR") badges.push(["Üretime engel", "bad"]);
  else if (String(item.trendyol_import_status || "") === "needs_review" || String(item.status || "").toUpperCase() === "WARNING") badges.push(["Kontrol gerekli", "warn"]);
  else badges.push(["Hazır", "ok"]);
  return badges;
}

function openBulkTrendyolEvidenceDrawer(indexOrId) {
  const item = bulkGalleryItemByIndexOrId(indexOrId);
  if (!item || !isBulkTrendyolItem(item)) {
    if (typeof showToast === "function") showToast("Bu kayıt Trendyol kanıt drawer için uygun değil.", "warning");
    else alert("Bu kayıt Trendyol kanıt drawer için uygun değil.");
    return;
  }
  selectedBulkGalleryItemId = item.item_id || selectedBulkGalleryItemId;
  bulkTrendyolEvidenceDrawerState = { open: true, itemId: item.item_id || item.id || "", saving: false };
  document.body.classList.add("bulk-trendyol-drawer-open");
  renderBulkTrendyolEvidenceDrawer();
}

function closeBulkTrendyolEvidenceDrawer() {
  bulkTrendyolEvidenceDrawerState.open = false;
  document.body.classList.remove("bulk-trendyol-drawer-open");
  document.querySelector(".bulk-trendyol-evidence-backdrop")?.remove();
}

function renderBulkTrendyolEvidenceDrawer(statusMessage = "", statusType = "info") {
  if (!bulkTrendyolEvidenceDrawerState.open) return;
  const item = bulkGalleryItemByIndexOrId(bulkTrendyolEvidenceDrawerState.itemId);
  if (!item) return;
  document.querySelector(".bulk-trendyol-evidence-backdrop")?.remove();
  const suggestion = findTrendyolSuggestionForBulkItem(item);
  const proofRows = bulkTrendyolFieldProofRows(item);
  const messages = [
    item.proof_text,
    suggestion.question_text,
    suggestion.answer_text,
    ...(Array.isArray(suggestion.question_contexts) ? suggestion.question_contexts.flatMap(row => [row.question_text, row.answer_text]) : [])
  ].filter(Boolean);
  const modelOptions = currentLabelModels.map(model => {
    const value = model.path || "";
    const selected = modelPathMatches(value, item.model_path) || value === item.model_path;
    return `<option value="${esc(value)}" ${selected ? "selected" : ""}>${esc(model.title || model.model_name || value || "Model")}</option>`;
  }).join("");
  const modal = document.createElement("div");
  modal.className = "bulk-trendyol-evidence-backdrop";
  modal.onclick = event => { if (event.target === modal) closeBulkTrendyolEvidenceDrawer(); };
  modal.innerHTML = `
    <aside class="bulk-trendyol-evidence-drawer" role="dialog" aria-modal="true" aria-label="Trendyol kanıt ve operatör düzeltme paneli" onclick="event.stopPropagation()">
      <header>
        <div>
          <h3>Trendyol Kanıt / Operatör Düzeltme</h3>
          <span>${esc(item.order_no || item.trendyol_order_id || "-")} · ${esc(item.customer_name || "Müşteri yok")}</span>
        </div>
        <button class="trendyol-drawer-close" type="button" onclick="closeBulkTrendyolEvidenceDrawer()" aria-label="Paneli kapat">×</button>
      </header>
      <section class="bulk-trendyol-proof-summary">
        <div><span>Sipariş no</span><b>${esc(item.order_no || "-")}</b></div>
        <div><span>Müşteri</span><b>${esc(item.customer_name || "-")}</b></div>
        <div><span>Ürün</span><b title="${esc(item.product_name || "")}">${esc(item.product_name || "-")}</b></div>
        <div><span>Barkod / SKU</span><b>${esc(item.barcode || "-")} · ${esc(item.sku || "-")}</b></div>
        <div><span>Adet</span><b>${esc(item.quantity || "1")}</b></div>
        <div><span>Confidence</span><b>%${esc(Math.round(Number(item.confidence || 0) * 100))}</b></div>
      </section>
      <section class="bulk-trendyol-badge-row">
        ${bulkTrendyolBadges(item).map(([label, tone]) => `<span class="pill ${esc(tone)}">${esc(label)}</span>`).join("")}
      </section>
      <section class="bulk-trendyol-drawer-grid">
        <div class="bulk-trendyol-proof-panel">
          <h4>Kanıt kaynakları</h4>
          <div class="bulk-trendyol-proof-fields">
            ${proofRows.map(([label, value, key, source]) => `
              <div class="${source ? "" : "missing"}">
                <span>${esc(label)}</span>
                <b>${esc(value || "Boş")}</b>
                <small>${esc(key)} · ${esc(bulkTrendyolProofLabel(source))}</small>
              </div>
            `).join("")}
          </div>
          <div class="bulk-trendyol-message-box">
            <b>Müşteri mesajı / bağlı kanıt</b>
            ${messages.length ? messages.slice(0, 5).map(text => `<p>${esc(text)}</p>`).join("") : `<p>Kanıt yok. Bu alan ürün başlığından doldurulmadı; operatör kontrolü gerekli.</p>`}
            ${item.operator_corrected || item.proof_source === "operator_manual" ? `<p><b>Operatör manuel:</b> Bu kayıt operatör tarafından düzeltildi ve audit kaydında operator_manual kaynağıyla izlenir.</p>` : ""}
          </div>
          <p class="safe-note compact">Ürün başlığından isim, tarih, not veya lazer isim üretilmez. Kanıt yoksa alan boş veya operatör manuel kaynağıyla işaretlenir.</p>
        </div>
        <form class="bulk-trendyol-correction-panel" onsubmit="event.preventDefault(); saveBulkTrendyolOperatorCorrection();">
          <h4>Operatör düzeltme</h4>
          <label>İsim<input id="bulkTrendyolCorrectName" value="${esc(item.label_text || "")}" /></label>
          <label>Tarih<input id="bulkTrendyolCorrectDate" value="${esc(item.date_text || "")}" /></label>
          <label>Not<textarea id="bulkTrendyolCorrectNote" rows="3">${esc(item.note_text || "")}</textarea></label>
          <label>Lazer İsim<input id="bulkTrendyolCorrectLaser" value="${esc(bulkGalleryLaserText(item))}" /></label>
          <label>Etiket Modeli<select id="bulkTrendyolCorrectModel"><option value="">Model seçilmedi</option>${modelOptions}</select></label>
          <label>Adet<input id="bulkTrendyolCorrectQty" type="number" min="1" value="${esc(item.quantity || "1")}" /></label>
          <label>Ürün eşleştirme notu<textarea id="bulkTrendyolCorrectMatchNote" rows="2">${esc(item.operator_correction_note || suggestion.operator_correction_note || "")}</textarea></label>
          <div class="bulk-trendyol-correction-checks">
            <span class="${String(item.label_text || "").trim() ? "ok" : "warn"}">Boş isim kontrolü</span>
            <span class="${String(item.model_status || "").toUpperCase() === "FOUND" ? "ok" : "bad"}">Model eşleşme kontrolü</span>
            <span class="${Number(item.quantity || 0) > 0 ? "ok" : "bad"}">Adet kontrolü</span>
            <span class="${bulkGalleryLaserText(item) ? "warn" : "muted"}">Lazer isim kontrolü</span>
          </div>
          <div id="bulkTrendyolCorrectionStatus" class="bulk-trendyol-correction-status ${esc(statusType)}">${esc(statusMessage || "Düzeltme kaydedilirse alan kaynağı operator_manual olarak audit'e düşer.")}</div>
          <footer>
            <button class="btn primary" type="submit">Düzeltmeyi Kaydet</button>
            <button class="btn" type="button" onclick="openBulkPreviewModal(${jsArg(item.item_id)}, 'fields')">Önizlemede Aç</button>
            <button class="btn" type="button" onclick="closeBulkTrendyolEvidenceDrawer()">Kapat</button>
          </footer>
        </form>
      </section>
      <p class="safe-note">Bu panel yalnızca üretim öncesi doğrulama içindir. Trendyol canlı statüsü, kargo, fatura, yazıcı, lazer ve RDWorks otomatik tetiklenmez.</p>
    </aside>
  `;
  document.body.appendChild(modal);
}

function setBulkTrendyolCorrectionStatus(message, type = "info") {
  const box = byId("bulkTrendyolCorrectionStatus");
  if (box) {
    box.className = `bulk-trendyol-correction-status ${type}`;
    box.textContent = message;
  }
}

function saveBulkTrendyolOperatorCorrection() {
  const item = bulkGalleryItemByIndexOrId(bulkTrendyolEvidenceDrawerState.itemId);
  if (!item) return;
  if (!bridge?.save_trendyol_operator_correction) {
    setBulkTrendyolCorrectionStatus("Operatör düzeltme bridge'i bu oturumda bağlı değil.", "bad");
    return;
  }
  const quantity = Number(byId("bulkTrendyolCorrectQty")?.value || 0);
  if (!Number.isFinite(quantity) || quantity < 1) {
    setBulkTrendyolCorrectionStatus("Adet 1 veya daha büyük olmalı. Kayıt kaydedilmedi.", "bad");
    return;
  }
  const payload = {
    label_text: byId("bulkTrendyolCorrectName")?.value || "",
    date_text: byId("bulkTrendyolCorrectDate")?.value || "",
    note_text: byId("bulkTrendyolCorrectNote")?.value || "",
    name_cut_text: byId("bulkTrendyolCorrectLaser")?.value || "",
    model_path: byId("bulkTrendyolCorrectModel")?.value || "",
    quantity,
    product_match_note: byId("bulkTrendyolCorrectMatchNote")?.value || "",
    batch_id: item.batch_id || ""
  };
  if (!String(payload.label_text || "").trim()) {
    setBulkTrendyolCorrectionStatus("İsim boş. Kaydedilirse kayıt üretime hazır sayılmaz.", "warn");
  }
  if (!String(payload.model_path || "").trim()) {
    setBulkTrendyolCorrectionStatus("Model eksik. Kaydedilirse kayıt blocked kalır.", "warn");
  }
  bulkTrendyolEvidenceDrawerState.saving = true;
  bridge.save_trendyol_operator_correction(bulkTrendyolSuggestionId(item), JSON.stringify(payload), raw => {
    const result = parseBridgeResult(raw);
    bulkTrendyolEvidenceDrawerState.saving = false;
    if (Array.isArray(result.suggestions)) {
      currentState.trendyol = { ...(currentState.trendyol || {}), suggestions: result.suggestions };
    }
    if (result.item) {
      const index = bulkGalleryItems.findIndex(row => row.item_id === item.item_id);
      if (index >= 0) {
        bulkGalleryItems[index] = { ...bulkGalleryItems[index], ...result.item, is_selected: bulkGalleryItems[index].is_selected };
        currentState.bulkGalleryItems = bulkGalleryItems;
        selectedBulkGalleryItemId = bulkGalleryItems[index].item_id || selectedBulkGalleryItemId;
        bulkTrendyolEvidenceDrawerState.itemId = bulkGalleryItems[index].item_id || bulkTrendyolEvidenceDrawerState.itemId;
      }
    }
    renderBulkGallery();
    renderBulkTrendyolEvidenceDrawer(result.message || "Düzeltme kaydedildi.", String(result.status || "").toUpperCase() === "BLOCKED" ? "warn" : "ok");
    if (typeof showToast === "function") showToast(result.message || "Operatör düzeltmesi kaydedildi.", String(result.status || "").toUpperCase() === "OK" ? "success" : "warning");
  });
}

function renderBulkGallery() {
  const summaryBox = byId("bulkGallerySummary");
  const grid = byId("bulkGalleryGrid");
  if (!summaryBox || !grid) return;
  updateBulkProductionSummaryPanelState();
  if (!hasRunControl() && !bulkGalleryItems.length) {
    summaryBox.innerHTML = "";
    grid.innerHTML = `<div class="empty-state"><b>Önce Excel kontrolü çalıştırın.</b><p>Kontrolden sonra her satır ayrı etiket kartı olarak burada görünür.</p></div>`;
    renderBulkSelectedDetail();
    return;
  }
  if (!bulkGalleryItems.length) {
    summaryBox.innerHTML = "";
    grid.innerHTML = `<div class="empty-state"><b>Galeriye eklenecek satır yok.</b><p>Excel kolonlarını ve etiket satırlarını kontrol edin.</p></div>`;
    renderBulkSelectedDetail();
    return;
  }
  if (!selectedBulkGalleryItemId || !bulkGalleryItems.some(item => item.item_id === selectedBulkGalleryItemId)) {
    selectedBulkGalleryItemId = (bulkGalleryItems.find(item => !item.is_deleted) || bulkGalleryItems[0] || {}).item_id || "";
  }
  if (bulkGalleryItems.length && bulkProductionStep < 4) {
    setBulkProductionStep(4);
  }
  const summary = bulkGallerySummary();
  const laserCount = (bulkGalleryItems || []).filter(item => !item.is_deleted && bulkItemHasLaser(item)).length;
  const lowQualityCount = (bulkGalleryItems || []).filter(item => !item.is_deleted && bulkItemQuality(item) < 85).length;
  summaryBox.innerHTML = `
    <div><b>${esc(summary.total)}</b><span>Toplam satır</span></div>
    <div><b>${esc(summary.ready)}</b><span>Hazır</span></div>
    <div><b>${esc(summary.warning)}</b><span>Uyarılı</span></div>
    <div><b>${esc(summary.error)}</b><span>Hatalı</span></div>
    <div><b>${esc(laserCount)}</b><span>Lazer isimli</span></div>
    <div><b>${esc(lowQualityCount)}</b><span>Kalite kontrol</span></div>
    <div><b>${esc(summary.deleted)}</b><span>Silinen</span></div>
    <div><b>${esc(summary.quantity)}</b><span>Toplam adet</span></div>
    <div><b>${esc(summary.models)}</b><span>Model</span></div>
  `;
  const filteredItems = bulkGalleryFilteredItems();
  const visibleLimit = Math.max(BULK_GALLERY_RENDER_BATCH_SIZE, Number(bulkGalleryVisibleLimit) || BULK_GALLERY_RENDER_BATCH_SIZE);
  const effectiveVisibleLimit = filteredItems.length <= 100 ? filteredItems.length : visibleLimit;
  const visibleItems = filteredItems.slice(0, effectiveVisibleLimit);
  const loadStateHtml = filteredItems.length ? `
    <div class="bulk-gallery-load-state">
      <div>
        <b>${esc(Math.min(visibleItems.length, filteredItems.length))} / ${esc(filteredItems.length)} kayıt gösteriliyor</b>
        <span>Performans için galeri parça parça render edilir; önizleme üretimi manuel tetiklenir.</span>
      </div>
      ${visibleItems.length < filteredItems.length ? `<button class="btn small primary" type="button" onclick="showMoreBulkGalleryItems()">Daha fazla göster</button>` : `<span class="pill ok">Tüm sonuçlar görünür</span>`}
    </div>
  ` : "";
  grid.innerHTML = visibleItems.length ? visibleItems.map(item => {
    const originalIndex = bulkGalleryItems.findIndex(row => row.item_id === item.item_id);
    const [label, tone] = bulkGalleryStatus(item);
    const [reasonLabel, reasonTone] = bulkGalleryStatusReason(item);
    const quality = item.layout_quality_score || bulkItemQuality(item);
    const [qualityText, qualityTone] = bulkQualityLabel(quality);
    const problemTags = bulkGalleryProblemTags(item);
    const problemText = bulkGalleryProblemText(item);
    const sourceLabel = bulkGallerySourceLabel(item);
    const laserText = item.name_cut_text || item.laser_name || item.laserName || "";
    return `
      <article class="bulk-gallery-item phase3-card ${item.status === "ERROR" ? "has-error" : ""} ${item.status === "WARNING" ? "has-warning" : ""} ${bulkItemHasLaser(item) ? "has-laser" : ""} ${item.is_deleted ? "deleted" : ""} ${item.item_id === selectedBulkGalleryItemId ? "selected" : ""}" data-bulk-item-id="${esc(item.item_id || "")}" onclick="selectBulkGalleryItem('${esc(item.item_id || "")}')">
        <div class="bulk-gallery-card-head">
          <label class="bulk-card-check" onclick="event.stopPropagation()">
            <input type="checkbox" ${item.is_selected ? "checked" : ""} onchange="bulkGalleryItems[${originalIndex}].is_selected = this.checked; renderBulkGallery();" />
            <span>${esc(item.source_type === "manual" ? "Manuel" : "Satır")} ${esc(item.row_number || "-")}</span>
          </label>
          <div class="bulk-card-status-stack">
            <span class="pill ${tone}">${esc(label)}</span>
            <span class="pill ${reasonTone}">${esc(reasonLabel)}</span>
          </div>
        </div>
        ${bulkGalleryPreview(item)}
        <div class="bulk-gallery-card-body">
          <span class="bulk-gallery-model" title="${esc(item.model_name || "Model bulunamadı")}">${esc(item.model_name || "Model bulunamadı")}</span>
          <b title="${esc(item.label_text || "-")}">${esc(item.label_text || "-")}</b>
          <div class="bulk-gallery-meta-grid">
            <span><small>Tarih</small><strong>${esc(item.date_text || "Bulunamadı")}</strong></span>
            <span><small>Adet</small><strong>${esc(item.quantity || 1)}</strong></span>
            <span><small>Kaynak</small><strong>${esc(sourceLabel)}</strong></span>
          </div>
          ${String(item.source || item.source_type || "").toLowerCase() === "trendyol" ? `
            <div class="bulk-gallery-proof" title="${esc(item.proof_text || "Kanıt bekleniyor")}">
              <span>Trendyol kanıtı</span>
              <b>${esc(item.proof_text ? "Mesaj bağlı" : "Kanıt yok · kontrol gerekli")}</b>
              <small>${esc(item.order_no || item.trendyol_order_id || "-")} · ${esc(item.customer_name || "-")}</small>
            </div>
            <div class="bulk-trendyol-card-badges">
              ${bulkTrendyolBadges(item).slice(1).map(([badge, badgeTone]) => `<span class="pill ${esc(badgeTone)}">${esc(badge)}</span>`).join("")}
            </div>
          ` : ""}
          <p title="${esc(item.note_text || "")}">${esc(item.note_text || "Not yok")}</p>
          <div class="bulk-gallery-quality">
            <span class="pill ${qualityTone}">Kalite %${esc(quality)}</span>
            <span>${esc(qualityText)}</span>
            ${bulkItemHasLaser(item) ? `<span class="pill purple" title="${esc(laserText)}">Lazer var</span>` : `<span class="pill muted">Lazer yok</span>`}
            ${item.ai_layout_status ? `<span class="pill info">${esc(item.ai_layout_status)}</span>` : ""}
          </div>
          ${bulkItemHasLaser(item) ? `<div class="bulk-gallery-laser"><span>Lazer isim</span><b title="${esc(laserText)}">${esc(laserText || item.label_text || "-")}</b></div>` : ""}
          ${problemTags.length ? `<div class="bulk-gallery-problem-tags">${problemTags.map(([text, tagTone]) => `<span class="pill ${tagTone}">${esc(text)}</span>`).join("")}</div>` : ""}
          ${problemText && reasonLabel !== "Hazır" ? `<div class="bulk-gallery-problems">${esc(problemText).replace(/\n/g, "<br>")}</div>` : ""}
        </div>
        <div class="toolbar compact bulk-gallery-card-actions">
          <button class="btn small" type="button" onclick="event.stopPropagation(); openBulkPreviewModal(${originalIndex}, 'label')">Önizle</button>
          ${isBulkTrendyolItem(item) ? `<button class="btn small primary" type="button" onclick="event.stopPropagation(); openBulkTrendyolEvidenceDrawer(${originalIndex})">Kanıtı Gör</button>` : ""}
          <button class="btn small" type="button" onclick="event.stopPropagation(); openBulkGalleryEditor(${originalIndex})">Düzenle</button>
          <button class="btn small" type="button" onclick="event.stopPropagation(); openBulkItemInLabelStudio(${originalIndex})">Studio’da Aç</button>
          <button class="btn small" type="button" onclick="event.stopPropagation(); openBulkItemInLaserStudio(${JSON.stringify(item?.item_id || "")})" title="İsim Kesim Studio’ya aktar">Lazer Kesim’de Aç</button>
          <button class="btn small" type="button" onclick="event.stopPropagation(); bulkGalleryItems[${originalIndex}] = smartArrangeBulkGalleryItem(bulkGalleryItems[${originalIndex}]); renderBulkGallery();">Akıllı Düzenle</button>
          <button class="btn small" type="button" onclick="event.stopPropagation(); setBulkItemStatus(${JSON.stringify(item?.item_id || "")}, ‘approved’)">Onayla</button>
          <button class="btn small danger-soft" type="button" onclick="event.stopPropagation(); openBulkPreviewModal(${originalIndex}, 'errors', 'errors')">Hata Detayı</button>
        </div>
      </article>
    `;
  }).join("") + loadStateHtml : `<div class="empty-state"><b>Bu filtrede satır yok.</b><p>Başka bir durum filtresi seçin.</p></div>`;
  renderBulkProductionSummary();
  renderBulkSelectedDetail();
  if (bulkProductionStep === 5) renderBulkErrorPanel();
}

function renderBulkSelectedDetail() {
  const preview = byId("bulkSelectedPreview");
  const info = byId("bulkSelectedInfo");
  const actions = byId("bulkSelectedActions");
  const status = byId("bulkSelectedStatus");
  if (!preview || !info || !actions) return;
  const item = selectedBulkGalleryItem();
  if (!item) {
    preview.innerHTML = `<div class="empty-state"><b>Galeriden bir etiket seçin.</b><p>Canlı önizleme ve hızlı işlemler burada görünür.</p></div>`;
    info.innerHTML = "";
    actions.innerHTML = `<button class="btn wide" onclick="bridge.chooseExcel()">Excel Seç</button>`;
    if (status) status.textContent = "Kontrol bekleniyor.";
    return;
  }
  const index = bulkGalleryItems.findIndex(row => row.item_id === item.item_id);
  const [label, tone] = bulkGalleryStatus(item);
  const quality = item.layout_quality_score || bulkItemQuality(item);
  const [qualityText, qualityTone] = bulkQualityLabel(quality);
  const problems = [...(item.errors || []), ...(item.warnings || [])];
  preview.innerHTML = bulkGalleryPreview(item, true);
  if (status) status.innerHTML = `<span class="pill ${tone}">${esc(label)}</span>`;
  info.innerHTML = `
    <h4>${esc(item.model_name || "Model bulunamadı")}</h4>
    <div><span>Satır</span><b>${esc(item.row_number || "-")}</b></div>
    <div><span>İsim</span><b>${esc(item.label_text || "-")}</b></div>
    <div><span>Tarih</span><b>${esc(item.date_text || "-")}</b></div>
    <div><span>Not</span><b>${esc(item.note_text || "-")}</b></div>
    <div><span>Ölçü</span><b>${esc(item.size_text || `${item.width_mm || "-"} x ${item.height_mm || "-"}`)}</b></div>
    <div><span>Adet</span><b>${esc(item.quantity || "1")}</b></div>
    <div><span>Kalite</span><b class="bulk-quality-text ${qualityTone}">%${esc(quality)} · ${esc(qualityText)}</b></div>
    <div><span>Lazer</span><b>${bulkItemHasLaser(item) ? esc(item.name_cut_text || item.laser_name || item.laserName || "Var") : "Yok"}</b></div>
    ${problems.length ? `<p class="bulk-gallery-problems">${problems.map(esc).join("<br>")}</p>` : `<p class="safe-note compact">Doğrulandı. Bu satır toplu üretime alınabilir.</p>`}
  `;
  actions.innerHTML = `
    <button class="btn primary wide" type="button" onclick="openBulkGalleryEditor(${index})">Düzenle</button>
    ${isBulkTrendyolItem(item) ? `<button class="btn wide primary-soft" type="button" onclick="openBulkTrendyolEvidenceDrawer(${index})">Kanıtı Gör / Düzelt</button>` : ""}
    <button class="btn wide" type="button" onclick="openBulkPreviewModal(${index}, 'label')">Büyük Önizleme</button>
    <button class="btn wide" type="button" onclick="bulkGalleryItems[${index}] = smartArrangeBulkGalleryItem(bulkGalleryItems[${index}]); renderBulkGallery();">Akıllı Düzenle</button>
    <button class="btn wide" type="button" onclick="generateReadyBulkGalleryItems()">Hazır Olanları Üret</button>
    <button class="btn gold wide" type="button" onclick="requestBulkGallerySafePrint()">Yazdır</button>
    <button class="btn wide" type="button" onclick="generateReadyBulkGalleryItems()">Yazdırma Sırasına Ekle</button>
    <button class="btn danger-soft wide" type="button" onclick="markBulkGalleryDeleted(${index})">${item.is_deleted ? "Silindi" : "Sıradan Kaldır"}</button>
  `;
}

function requestBulkGallerySafePrint() {
  const outputs = currentState.labelOutputs || [];
  const batch = outputs.find(row => /roll_batch|batch|bulk/i.test(String(row.relative_path || row.file_name || "")) && String(row.relative_path || "").toLowerCase().endsWith(".pdf"))
    || outputs.find(row => String(row.relative_path || "").toLowerCase().endsWith(".pdf"));
  if (!batch) {
    showToast("Önce hazır etiketleri üretin. Yazdırma için doğrulanmış batch PDF gerekir.", "warning");
    return;
  }
  requestPdfPrint(batch.relative_path || batch.path || "");
}

function openBulkGalleryEditor(index) {
  if (index < 0 || index >= bulkGalleryItems.length) return;
  bulkGalleryEditIndex = index;
  bulkGalleryDraft = { ...bulkGalleryItems[index], errors: [...(bulkGalleryItems[index].errors || [])], warnings: [...(bulkGalleryItems[index].warnings || [])] };
  renderBulkGalleryEditor();
  const modal = byId("bulkGalleryEditModal");
  if (modal) modal.hidden = false;
}

function closeBulkGalleryEditor() {
  const modal = byId("bulkGalleryEditModal");
  if (modal) modal.hidden = true;
  bulkGalleryEditIndex = -1;
  bulkGalleryDraft = null;
}

function renderBulkGalleryEditor() {
  if (!bulkGalleryDraft) return;
  setText("bulkGalleryEditTitle", `Etiket Düzenle — Satır ${bulkGalleryDraft.row_number || "-"}`);
  const preview = byId("bulkGalleryEditPreview");
  if (preview) preview.innerHTML = bulkGalleryPreview(bulkGalleryDraft, true);
  const modelSelect = byId("bulkGalleryEditModel");
  if (modelSelect) {
    modelSelect.innerHTML = currentLabelModels.map(model => `<option value="${esc(model.path || "")}" ${modelPathMatches(model.path, bulkGalleryDraft.model_path) ? "selected" : ""}>${esc(model.title || model.model_name || model.path || "Model")}</option>`).join("");
  }
  const name = byId("bulkGalleryEditName");
  const date = byId("bulkGalleryEditDate");
  const note = byId("bulkGalleryEditNote");
  const qty = byId("bulkGalleryEditQty");
  if (name) name.value = bulkGalleryDraft.label_text || "";
  if (date) date.value = bulkGalleryDraft.date_text || "";
  if (note) note.value = bulkGalleryDraft.note_text || "";
  if (qty) qty.value = bulkGalleryDraft.quantity || "1";
  const status = byId("bulkGalleryEditStatus");
  if (status) {
    const [label, tone] = bulkGalleryStatus(bulkGalleryDraft);
    const problems = [...(bulkGalleryDraft.errors || []), ...(bulkGalleryDraft.warnings || [])];
    status.innerHTML = `<span class="pill ${tone}">${esc(label)}</span>${problems.length ? `<p>${problems.map(esc).join("<br>")}</p>` : `<p>Bu satır üretime hazır görünüyor.</p>`}`;
  }
}

function updateBulkGalleryDraftField(field, value) {
  if (!bulkGalleryDraft) return;
  bulkGalleryDraft[field] = value;
  if (field === "model_path") {
    const model = currentLabelModels.find(item => item.path === value);
    if (model) {
      bulkGalleryDraft.model_status = "FOUND";
      bulkGalleryDraft.model_name = model.title || model.model_name || "";
      bulkGalleryDraft.model_path = model.path || "";
      bulkGalleryDraft.model_no = model.model_no || bulkGalleryDraft.model_key || "";
      bulkGalleryDraft.template_no = model.template_no || "A";
      bulkGalleryDraft.label_variant = model.label_variant || "GOLD";
      bulkGalleryDraft.preview_png_path = model.preview_image || "";
      bulkGalleryDraft.size_text = model.size_text || "";
    }
  }
  bulkGalleryDraft.errors = [];
  bulkGalleryDraft.warnings = [];
  if (!String(bulkGalleryDraft.model_name || "").trim()) bulkGalleryDraft.errors.push("Model seçilmedi.");
  if (!String(bulkGalleryDraft.label_text || "").trim()) bulkGalleryDraft.errors.push("İsim alanı boş.");
  if (!String(bulkGalleryDraft.date_text || "").trim()) bulkGalleryDraft.warnings.push("Tarih alanı boş.");
  if (!String(bulkGalleryDraft.preview_png_path || "").trim()) bulkGalleryDraft.warnings.push("Model önizleme görseli eksik.");
  bulkGalleryDraft.status = bulkGalleryDraft.errors.length ? "ERROR" : bulkGalleryDraft.warnings.length ? "WARNING" : "READY";
  bulkGalleryDraft.is_edited = true;
  renderBulkGalleryEditor();
}

function saveBulkGalleryDraft() {
  if (bulkGalleryEditIndex < 0 || !bulkGalleryDraft) return;
  bulkGalleryItems[bulkGalleryEditIndex] = { ...bulkGalleryDraft, is_edited: true };
  closeBulkGalleryEditor();
  renderBulkGallery();
}

function cancelBulkGalleryDraft() {
  closeBulkGalleryEditor();
}

function markBulkGalleryDeleted(index = bulkGalleryEditIndex) {
  if (index < 0 || index >= bulkGalleryItems.length) return;
  bulkGalleryItems[index] = { ...bulkGalleryItems[index], is_deleted: true, is_edited: true };
  closeBulkGalleryEditor();
  renderBulkGallery();
}

function navigateBulkGallery(delta) {
  if (!bulkGalleryItems.length) return;
  const next = Math.max(0, Math.min(bulkGalleryItems.length - 1, bulkGalleryEditIndex + delta));
  openBulkGalleryEditor(next);
}

function prepareBulkGalleryItems() {
  bulkGalleryItems = bulkGalleryItems.map(item => {
    if (item.is_deleted || item.status === "ERROR") return item;
    const next = { ...item, is_edited: true, warnings: [...(item.warnings || [])] };
    const labelCharCount = String(next.label_text || "").length;
    if (labelCharCount > 28 && !next.warnings.includes("Uzun isim otomatik sığdırma gerektirir.")) {
      next.warnings.push("Uzun isim otomatik sığdırma gerektirir.");
      next.status = "WARNING";
    }
    return next;
  });
  renderBulkGallery();
  const status = byId("bulkRowPreviewStatus");
  if (status) status.textContent = "Toplu galeri üretime hazırlandı. Uzun isimler uyarı olarak işaretlendi.";
}

function fitLongBulkGalleryNames() {
  bulkGalleryItems = bulkGalleryItems.map(item => {
    if (item.is_deleted || item.status === "ERROR" || String(item.label_text || "").length <= 28) return item;
    const next = { ...item, is_edited: true, warnings: [...(item.warnings || [])] };
    if (!next.warnings.includes("Uzun isim sığdırma uygulandı.")) next.warnings.push("Uzun isim sığdırma uygulandı.");
    next.status = "WARNING";
    return next;
  });
  renderBulkGallery();
}

function bulkGalleryQueueReadiness(item = {}) {
  const status = String(item.status || "").toUpperCase();
  const modelStatus = String(item.model_status || "").toUpperCase();
  const quantity = Number(item.quantity || 0);
  const errors = Array.isArray(item.errors) ? item.errors.filter(Boolean) : [];
  const warnings = Array.isArray(item.warnings) ? item.warnings.filter(Boolean) : [];
  const reasons = [];
  if (item.is_deleted) reasons.push("silinmiş kayıt");
  if (status === "ERROR") reasons.push("hatalı kayıt");
  if (modelStatus === "MISSING" || !String(item.model_name || item.model_key || "").trim()) reasons.push("model eksik");
  if (!String(item.label_text || "").trim()) reasons.push("isim eksik");
  if (!Number.isFinite(quantity) || quantity < 1) reasons.push("adet geçersiz");
  if (errors.length) reasons.push(...errors.slice(0, 2));
  if (reasons.length) {
    return { state: "blocked", reasons };
  }
  if (status === "WARNING" || warnings.length || Number(item.layout_quality_score || item.quality_score || 100) < 70) {
    return { state: "review", reasons: warnings.length ? warnings : ["kontrol gerekli"] };
  }
  return { state: "ready", reasons: [] };
}

function bulkGalleryQueueSplit(items = bulkGalleryItems) {
  const ready = [];
  const review = [];
  const blocked = [];
  (items || []).forEach(item => {
    const check = bulkGalleryQueueReadiness(item);
    if (check.state === "ready") ready.push(item);
    else if (check.state === "review") review.push({ item, reasons: check.reasons });
    else blocked.push({ item, reasons: check.reasons });
  });
  return { ready, review, blocked };
}

function bulkQueueSkipSummary(review = [], blocked = []) {
  const parts = [];
  if (blocked.length) parts.push(`${blocked.length} kayıt hata/eksik alan nedeniyle atlandı`);
  if (review.length) parts.push(`${review.length} kayıt kontrol gerekli olduğu için bekletildi`);
  return parts.join(" · ");
}

function generateReadyBulkGalleryItems() {
  const status = byId("bulkRowPreviewStatus");
  if (!bridge?.bulk_generate_gallery_items_and_add_to_queue) {
    if (status) status.textContent = "Toplu galeri üretim köprüsü bu oturumda hazır değil.";
    return;
  }
  const { ready: readyItems, review, blocked } = bulkGalleryQueueSplit(bulkGalleryItems);
  if (!readyItems.length) {
    const skipMessage = bulkQueueSkipSummary(review, blocked);
    if (status) status.textContent = skipMessage ? `Üretime hazır galeri satırı yok. ${skipMessage}.` : "Üretime hazır galeri satırı yok.";
    setSelectedBulkRunState({ status: "error", rows: [], message: skipMessage ? `Üretime hazır kayıt yok. ${skipMessage}.` : "Üretime hazır galeri satırı yok." });
    return;
  }
  const skipMessage = bulkQueueSkipSummary(review, blocked);
  const startMessage = `${readyItems.length} hazır kayıt için PDF/PNG ve Yazdırma Sırası aktarımı başlatılıyor${skipMessage ? `. ${skipMessage}.` : "."}`;
  const laserCount = readyItems.filter(item => bulkItemHasLaser(item)).length;
  const laserMessage = laserCount ? ` ${laserCount} lazer isimli kayıt tespit edildi; İsim Kesim hazırlığı ayrı adımda yapılacak.` : "";
  if (status) status.textContent = `${startMessage}${laserMessage}`;
  setSelectedBulkRunState({ status: "starting", rows: readyItems.map(item => item.row_number), message: `${startMessage}${laserMessage}` });
  bridge.bulk_generate_gallery_items_and_add_to_queue(JSON.stringify(readyItems), raw => {
    const result = parseBridgeResult(raw);
    const resultMessage = result.message || "Toplu galeri üretim isteği gönderildi.";
    if (status) status.textContent = `${resultMessage}${skipMessage ? ` ${skipMessage}.` : ""}${laserMessage}`;
    if (result.status === "STARTED") {
      setSelectedBulkRunState({ status: "started", rows: readyItems.map(item => item.row_number), message: `${resultMessage}${skipMessage ? ` ${skipMessage}.` : ""}${laserMessage}` });
      setTimeout(refreshState, 900);
    } else {
      setSelectedBulkRunState({ status: "error", rows: readyItems.map(item => item.row_number), message: result.message || "Toplu galeri üretimi başlatılamadı." });
    }
  });
}

function nameCutLiveItems() {
  return (nameCutItems || []).filter(item => !item.is_deleted && String(item.status || "").toUpperCase() !== "ERROR");
}

function isJoinedNameMode(composition = "") {
  const token = String(composition || "").toLocaleLowerCase("tr-TR");
  return token.includes("bitiştir") || token.includes("bitistir") || token.includes("compact");
}

function isExplicitNameCutSingleLineMode(composition = "") {
  const token = String(composition || "").toLocaleLowerCase("tr-TR").replace(/ı/g, "i");
  return token.includes("single_line_text") || token.includes("tek satir yazi") || token.includes("explicit_single_line");
}

function splitNameWords(text = "") {
  return String(text || "").trim().split(/\s+/).filter(Boolean);
}

function normalizeNameCutConfig(cfg = nameCutLayoutConfig) {
  const targetWidth = clampNumber(Number(cfg.target_name_width_mm ?? 80), 20, 240);
  const targetHeight = clampNumber(Number(cfg.target_name_height_mm ?? 40), 10, 120);
  const targetGap = clampNumber(Number(cfg.target_gap_mm ?? cfg.item_gap_mm ?? 1), 1, 3);
  return {
    width_mm: Math.max(100, Number(cfg.width_mm || 800)),
    height_mm: Math.max(100, Number(cfg.height_mm || 600)),
    target_name_width_mm: targetWidth,
    target_name_height_mm: targetHeight,
    target_gap_mm: targetGap,
    margin_mm: Math.max(0, Number(cfg.margin_mm || 15)),
    item_gap_mm: clampNumber(Number(cfg.item_gap_mm ?? targetGap), 1, 3),
    row_gap_mm: Math.max(1, Number(cfg.row_gap_mm ?? cfg.item_gap_mm ?? targetGap)),
    joined_name_gap_mm: clampNumber(Number(cfg.joined_name_gap_mm ?? cfg.item_gap_mm ?? targetGap), 1, 3),
    allow_rotation: !!cfg.allow_rotation,
    mirror_cut: !!cfg.mirror_cut,
    mirror_vertical: !!cfg.mirror_vertical,
    start_corner: cfg.start_corner || "top-left",
    packing_direction: cfg.packing_direction || "left-to-right",
    row_direction: cfg.row_direction || "top-to-bottom",
    dense_nesting: cfg.dense_nesting !== false,
    font_family: cfg.font_family || NAME_CUT_DEFAULT_FONT,
    script_profile: cfg.script_profile || "ceyizhomeLabScript",
    weld_inside_name: cfg.weld_inside_name !== false,
    export_as_path: cfg.export_as_path !== false,
    capital_connection_fix: cfg.capital_connection_fix !== false,
    punctuation_fix: cfg.punctuation_fix !== false,
    letter_spacing_px: Number(cfg.letter_spacing_px ?? 0),
    word_spacing_px: Number(cfg.word_spacing_px ?? 8),
    min_height_mm: Math.max(8, Number(cfg.min_height_mm || 10)),
    max_height_mm: Math.max(10, Number(cfg.max_height_mm || targetHeight)),
    default_height_mm: Math.max(8, Number(cfg.default_height_mm || targetHeight)),
    horizontal_scale_percent: clampNumber(Number(cfg.horizontal_scale_percent || 100), 55, 140),
    vertical_scale_percent: clampNumber(Number(cfg.vertical_scale_percent || 100), 70, 140),
    optical_short_name_scale: cfg.optical_short_name_scale !== false,
    auto_condense_long_names: cfg.auto_condense_long_names !== false,
    offset_mm: clampNumber(Number(cfg.offset_mm ?? nameCutFontMetaByValue(cfg.font_family)?.defaultOffsetMm ?? 0.3), 0, 1.5),
    corner_type: cfg.corner_type || "Yuvarlak",
    offset_type: cfg.offset_type || "Dışa kalınlaştır",
    dot_bridge_mm: clampNumber(Number(cfg.dot_bridge_mm || 0.8), 0.2, 2),
    min_stroke_mm: clampNumber(Number(cfg.min_stroke_mm || 0.28), 0.12, 1.5),
    turkish_mark_bridge: cfg.turkish_mark_bridge !== false,
    dot_bridge_enabled: cfg.dot_bridge_enabled !== false
  };
}

function nameCutTextWidthEstimate(text = "", heightMm = 20, cfg = nameCutLayoutConfig) {
  const visible = String(text || "").replace(/\s+/g, "");
  const spaces = Math.max(0, String(text || "").trim().split(/\s+/).length - 1);
  const visualUnits = Math.max(1, [...visible].reduce((sum, char) => {
    const lower = char.toLocaleLowerCase("tr-TR");
    if (lower === "m" || lower === "w") return sum + 1.16;
    if (lower === "i" || lower === "ı" || lower === "l" || lower === "j") return sum + 0.78;
    return sum + 1;
  }, 0));
  const fontToken = String(cfg.font_family || "").toLocaleLowerCase("tr-TR");
  const isConnectedScript = fontToken.includes("brannboll") || fontToken.includes("mochary") || fontToken.includes("ceyizhome");
  const scriptFactor = fontToken.includes("brannboll") ? 0.28 : isConnectedScript ? 0.22 : 0.48;
  const punctuationBoost = /[&+\/.-]/.test(text) ? heightMm * 0.24 : 0;
  const base = isConnectedScript ? heightMm * 0.76 : heightMm * 0.9;
  return Math.max(heightMm * 1.05, base + (visualUnits * heightMm * scriptFactor) + (spaces * heightMm * 0.14) + punctuationBoost);
}

function nameCutActualPathMetricsEstimate(text = "", cfg = nameCutLayoutConfig, item = {}) {
  const config = normalizeNameCutConfig(cfg);
  const targetWidth = Number(config.target_name_width_mm || 80);
  const targetHeight = Number(config.target_name_height_mm || 40);
  const requestedWidth = Number(item.width_mm || 0);
  const requestedHeight = Number(item.height_mm || 0);
  const locked = !!item.operator_size_locked;
  const offsetMm = clampNumber(Number(item.offset_mm ?? config.offset_mm ?? 0), 0, 5);
  const sourceHeight = locked && requestedHeight > 0 ? requestedHeight : targetHeight;
  const rawNaturalWidth = nameCutTextWidthEstimate(text, sourceHeight, config);
  const compact = String(text || "").replace(/\s+/g, "");
  const spaces = Math.max(0, String(text || "").trim().split(/\s+/).filter(Boolean).length - 1);
  const visualUnits = Math.max(1, [...compact].reduce((sum, char) => {
    const lower = char.toLocaleLowerCase("tr-TR");
    if (lower === "m" || lower === "w") return sum + 1.16;
    if (lower === "i" || lower === "ı" || lower === "l" || lower === "j") return sum + 0.78;
    return sum + 1;
  }, 0) + (spaces * 0.72));
  const maxBoardWidth = Math.max(20, Number(config.width_mm || 800) - (Number(config.margin_mm || 15) * 2));
  const minDenseWidth = Math.max(24, Math.min(targetWidth * 0.42, 38));
  const drawHeight = Math.max(18, (locked && requestedHeight > 0 ? requestedHeight : targetHeight) * 0.86);
  const naturalDrawWidth = Math.max(
    minDenseWidth,
    Math.min(maxBoardWidth, drawHeight * clampNumber(0.78 + (visualUnits * 0.22), 1.05, 4.4))
  );
  let actualWidth;
  let actualHeight;
  let placementWidth;
  let placementHeight;
  if (locked) {
    placementWidth = clampNumber(requestedWidth || naturalDrawWidth || targetWidth, minDenseWidth, maxBoardWidth);
    placementHeight = clampNumber(requestedHeight || targetHeight, 10, Math.max(10, Number(config.height_mm || 600) - (Number(config.margin_mm || 15) * 2)));
    const lockedScale = Math.min((placementWidth * 0.94) / Math.max(1, rawNaturalWidth), (placementHeight * 0.86) / Math.max(1, sourceHeight));
    actualWidth = (rawNaturalWidth * lockedScale) + (offsetMm * 2);
    actualHeight = (sourceHeight * lockedScale) + (offsetMm * 2);
  } else if (config.dense_nesting === false) {
    placementWidth = targetWidth;
    placementHeight = targetHeight;
    const standardScale = Math.min((placementWidth * 0.94) / Math.max(1, rawNaturalWidth), (placementHeight * 0.86) / Math.max(1, sourceHeight));
    actualWidth = (rawNaturalWidth * standardScale) + (offsetMm * 2);
    actualHeight = (sourceHeight * standardScale) + (offsetMm * 2);
  } else {
    actualWidth = naturalDrawWidth + (offsetMm * 2);
    actualHeight = drawHeight + (offsetMm * 2);
    placementWidth = clampNumber(actualWidth + 2, minDenseWidth, maxBoardWidth);
    placementHeight = Math.max(targetHeight, actualHeight + 2);
  }
  actualHeight = clampNumber(actualHeight, 10, Math.max(10, config.height_mm - (config.margin_mm * 2)));
  placementHeight = clampNumber(placementHeight || actualHeight, 10, Math.max(10, config.height_mm - (config.margin_mm * 2)));
  placementWidth = clampNumber(placementWidth || actualWidth, minDenseWidth, maxBoardWidth);
  const drawScale = (actualWidth - (offsetMm * 2)) / Math.max(1, rawNaturalWidth);
  return {
    actualPathWidthMm: Number(actualWidth.toFixed(2)),
    actualPathHeightMm: Number(actualHeight.toFixed(2)),
    rawPathWidthMm: Number(rawNaturalWidth.toFixed(2)),
    rawPathHeightMm: Number(sourceHeight.toFixed(2)),
    placementWidthMm: Number(placementWidth.toFixed(2)),
    placementHeightMm: Number(placementHeight.toFixed(2)),
    pathScale: Number(drawScale.toFixed(4))
  };
}

function normalizeNameCutCompositionMode(value = "", item = {}) {
  const raw = String(value || item.composition_mode || item.composition || "").trim();
  const token = raw.toLocaleLowerCase("tr-TR");
  if (["separate_names", "single_line_text", "preserve_lines", "auto_split_and_nest"].includes(token)) return token;
  if (token.includes("otomatik") || token.includes("auto") || token.includes("böl") || token.includes("bol")) return "auto_split_and_nest";
  if (token.includes("ayrı") || token.includes("ayri") || token.includes("separate")) return "separate_names";
  if (token.includes("tek satır") || token.includes("tek satir") || token.includes("bitiştir") || token.includes("bitistir") || token.includes("single")) return "single_line_text";
  if (token.includes("koru") || token.includes("alt") || token.includes("preserve")) return "preserve_lines";
  return "single_line_text";
}

function nameCutCompositionLabel(mode = "single_line_text") {
  const labels = {
    separate_names: "Ayrı isimler",
    single_line_text: "Tek satır yazı",
    preserve_lines: "Satırları koru",
    auto_split_and_nest: "Otomatik böl ve diz"
  };
  return labels[mode] || labels.single_line_text;
}

function detectNameCutMultiNameCandidate(text = "") {
  const raw = String(text || "").trim();
  if (!raw) return false;
  const words = raw.split(/\s+/).filter(Boolean);
  const hasListSeparator = /[,;]+/.test(raw);
  const hasMultipleLines = raw.split(/\n+/).filter(line => line.trim()).length > 1;
  const hasPairJoiner = raw.includes("&");
  return (words.length >= 5 && !hasPairJoiner) || hasListSeparator || hasMultipleLines || (raw.length >= 42 && words.length >= 4 && !hasPairJoiner);
}

function splitNameCutCandidateNames(text = "") {
  const raw = String(text || "").trim();
  if (!raw) return [];
  if (/[,;\n]+/.test(raw)) {
    return raw.split(/[,;\n]+/).map(part => formatNameCutName(part)).filter(Boolean);
  }
  return raw.split(/\s+/).map(part => formatNameCutName(part)).filter(Boolean);
}

function parseNameCutInput(text = "", mode = "auto_split_and_nest") {
  const compositionMode = normalizeNameCutCompositionMode(mode);
  const raw = String(text || "").trim();
  if (!raw) return [];
  if (compositionMode === "single_line_text") return [formatNameCutName(raw)];
  if (compositionMode === "preserve_lines") return raw.split(/\n+/).map(line => formatNameCutName(line)).filter(Boolean);
  if (compositionMode === "auto_split_and_nest" || compositionMode === "separate_names") return splitNameCutCandidateNames(raw);
  return [formatNameCutName(raw)];
}

function nameCutStableSignature(payload = {}) {
  const text = JSON.stringify(payload);
  let hash = 2166136261;
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash += (hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24);
  }
  return `ncl-${(hash >>> 0).toString(16)}`;
}

function nameCutAutoRepairHeuristic(layoutResult = {}, item = {}, cfg = nameCutLayoutConfig) {
  const offsetMm = Number(layoutResult.offsetMm ?? item.offset_mm ?? cfg.offset_mm ?? 0);
  const text = String(layoutResult.formattedText || layoutResult.text || item.name_text || "");
  const hasTurkishMarks = hasTurkishDiacriticForCutting(text);
  const failed = !!(layoutResult.errors || []).length || ["too_small", "overflow"].includes(String(layoutResult.fitStatus || ""));
  const repairMessages = [];
  if (text.replace(/\s+/g, "").length > 1) repairMessages.push("kerning_fixed");
  if (offsetMm > 0) repairMessages.push("offset_applied");
  if (offsetMm > 0) repairMessages.push("weld_applied");
  if (hasTurkishMarks) repairMessages.push("marks_attached");
  if (layoutResult.widthWasAutoFixed || Number(layoutResult.widthMm || 0) || Number(layoutResult.heightMm || 0)) repairMessages.push("size_normalized");
  const autoRepaired = !failed && repairMessages.length > 0;
  const repairStatus = failed ? "failed" : autoRepaired ? "auto_repaired" : "clean";
  const componentCount = failed ? 2 : 1;
  return {
    isConnectedPath: !failed,
    componentCount,
    component_count: componentCount,
    detachedParts: failed ? [{ reason: "fit_or_geometry_not_ready" }] : [],
    detached_parts: failed ? [{ reason: "fit_or_geometry_not_ready" }] : [],
    hasDetachedDots: failed && hasTurkishMarks,
    has_detached_dots: failed && hasTurkishMarks,
    hasDisconnectedLetters: failed,
    has_disconnected_letters: failed,
    minGapMm: Number(cfg.item_gap_mm || cfg.target_gap_mm || 1),
    appliedKerningFix: repairMessages.includes("kerning_fixed"),
    applied_kerning_fix: repairMessages.includes("kerning_fixed"),
    appliedOffsetMm: offsetMm,
    applied_offset_mm: offsetMm,
    appliedWeld: repairMessages.includes("weld_applied"),
    applied_weld: repairMessages.includes("weld_applied"),
    appliedDotBridge: repairMessages.includes("marks_attached"),
    applied_dot_bridge: repairMessages.includes("marks_attached"),
    autoRepaired,
    auto_repaired: autoRepaired,
    repairStatus,
    repair_status: repairStatus,
    repairMessages,
    repair_messages: repairMessages,
    offsetMode: offsetMm > 0 ? "backend_real_path_offset_or_reported_simulation" : "none",
    offset_mode: offsetMm > 0 ? "backend_real_path_offset_or_reported_simulation" : "none",
    readyForCut: !failed,
    ready_for_cut: !failed
  };
}

function computeNameCutLayout(item = {}, options = {}) {
  const cfg = normalizeNameCutConfig(options.cfg || nameCutLayoutConfig);
  const fontMeta = nameCutFontMetaForItem(item, cfg);
  const effectiveCfg = { ...cfg, font_family: fontMeta?.value || item.style || item.fontFamily || item.font_family || cfg.font_family || NAME_CUT_DEFAULT_FONT };
  const rawText = String(item.text ?? item.name_text ?? item.laser_name ?? "").trim();
  const formattedText = formatNameCutName(rawText);
  const multiNameCandidate = detectNameCutMultiNameCandidate(rawText);
  const userSelectedComposition = item.composition_user_selected === true || options.userSelectedComposition === true;
  let compositionMode = normalizeNameCutCompositionMode(item.compositionMode || item.composition_mode || item.composition, item);
  if (multiNameCandidate && !userSelectedComposition && compositionMode === "single_line_text") {
    compositionMode = "auto_split_and_nest";
  }
  if (!multiNameCandidate && compositionMode === "auto_split_and_nest") {
    compositionMode = "single_line_text";
  }
  let lineBreakMode = item.lineBreakMode || item.line_break_mode || compositionMode;
  if (compositionMode === "single_line_text") lineBreakMode = "single_line";
  if (compositionMode === "preserve_lines") lineBreakMode = "preserve_user_lines";
  if (compositionMode === "auto_split_and_nest" || compositionMode === "separate_names") lineBreakMode = "split_to_objects";

  const rawWidthValue = Number(item.widthMm ?? item.width_mm ?? options.widthMm ?? 0);
  const rawHeightValue = Number(item.heightMm ?? item.height_mm ?? options.heightMm ?? 0);
  const operatorSizeLocked = item.operator_size_locked === true || item.size_locked === true || item.custom_size === true;
  const legacyTooSmallWidth = rawWidthValue > 0 && rawWidthValue < Number(cfg.target_name_width_mm || 80) * 0.5;
  const legacyTooSmallHeight = rawHeightValue > 0 && rawHeightValue < Number(cfg.target_name_height_mm || 40) * 0.5;
  const resolvedWidthMm = (!operatorSizeLocked && (legacyTooSmallWidth || rawWidthValue <= 0)) ? cfg.target_name_width_mm : rawWidthValue;
  const resolvedHeightMm = (!operatorSizeLocked && (legacyTooSmallHeight || rawHeightValue <= 0)) ? cfg.target_name_height_mm : rawHeightValue;
  const widthMm = clampNumber(Number(resolvedWidthMm || cfg.target_name_width_mm), 20, Math.max(20, cfg.width_mm - (cfg.margin_mm * 2)));
  const heightMm = clampNumber(Number(resolvedHeightMm || cfg.target_name_height_mm), 10, Math.max(10, cfg.height_mm - (cfg.margin_mm * 2)));
  const offsetMm = clampNumber(Number(item.offsetMm ?? item.offset_mm ?? cfg.offset_mm ?? 0), 0, 5);
  const usableWidth = Math.max(1, widthMm - (offsetMm * 2));
  const usableHeight = Math.max(1, heightMm - (offsetMm * 2));
  const baseWarnings = Array.isArray(item.warnings) ? [...item.warnings] : [];
  const warnings = new Set(baseWarnings);
  const errors = Array.isArray(item.errors) ? [...item.errors] : [];
  if (multiNameCandidate) warnings.add("Bu metin çoklu isim listesi gibi görünüyor.");
  if (legacyTooSmallWidth || legacyTooSmallHeight) {
    warnings.add(`Eski/hatalı ölçü algılandı (${rawWidthValue || "-"} x ${rawHeightValue || "-"} mm); operatör kilidi yoksa 80 x 40 mm üretim standardı uygulanır.`);
  }

  let previewLines = [];
  let previewObjects = [];
  let rawPathWidth = 0;
  let rawPathHeight = 0;
  let scale = 1;
  let fitStatus = "fits";

  if (compositionMode === "auto_split_and_nest" || compositionMode === "separate_names") {
    previewObjects = parseNameCutInput(rawText, compositionMode).map((name, index) => {
      const metrics = nameCutActualPathMetricsEstimate(name, { ...effectiveCfg, target_name_width_mm: cfg.target_name_width_mm, target_name_height_mm: cfg.target_name_height_mm }, { offset_mm: offsetMm, style: effectiveCfg.font_family });
      return {
        id: `${item.item_id || item.id || "name"}-split-${index + 1}`,
        text: name,
        formattedText: name,
        widthMm: Number((metrics.placementWidthMm || metrics.actualPathWidthMm || cfg.target_name_width_mm).toFixed(2)),
        heightMm: Number((metrics.placementHeightMm || metrics.actualPathHeightMm || cfg.target_name_height_mm).toFixed(2)),
        actualPathWidthMm: Number((metrics.actualPathWidthMm || metrics.placementWidthMm || cfg.target_name_width_mm).toFixed(2)),
        actualPathHeightMm: Number((metrics.actualPathHeightMm || metrics.placementHeightMm || cfg.target_name_height_mm).toFixed(2)),
        rawPathWidthMm: metrics.rawPathWidthMm,
        rawPathHeightMm: metrics.rawPathHeightMm,
        pathScale: metrics.pathScale,
        lineIndex: index
      };
    });
    previewLines = previewObjects.map(object => object.formattedText);
    rawPathWidth = Math.max(0, ...previewObjects.map(object => object.actualPathWidthMm));
    rawPathHeight = previewObjects.reduce((sum, object) => sum + object.actualPathHeightMm, 0);
    fitStatus = multiNameCandidate ? "line_split" : "fits";
  } else {
    const rawLines = compositionMode === "preserve_lines"
      ? String(rawText || "").split(/\n+/).map(line => formatNameCutName(line)).filter(Boolean)
      : [formattedText];
    previewLines = rawLines.length ? rawLines : [formattedText];
    const lineHeight = heightMm / Math.max(1, previewLines.length);
    const lineMetrics = previewLines.map(line => ({
      text: line,
      rawWidth: nameCutTextWidthEstimate(line, Math.max(8, lineHeight * 0.78), effectiveCfg),
      rawHeight: Math.max(8, lineHeight * 0.78)
    }));
    rawPathWidth = Math.max(1, ...lineMetrics.map(metric => metric.rawWidth));
    rawPathHeight = lineMetrics.reduce((sum, metric) => sum + metric.rawHeight, 0);
    scale = Math.min(1, usableWidth / Math.max(1, rawPathWidth), usableHeight / Math.max(1, rawPathHeight));
    if (scale < 1) fitStatus = "font_scaled";
    if (scale < 0.46) {
      fitStatus = "too_small";
      warnings.add("Metin bu ölçüde çok küçülüyor; ayrı isimlere bölme veya ölçü büyütme önerilir.");
    }
    if (rawPathWidth > usableWidth || rawPathHeight > usableHeight) {
      if (fitStatus === "fits") fitStatus = "overflow";
    }
    previewObjects = [{
      id: `${item.item_id || item.id || "name"}-layout-1`,
      text: previewLines.join("\n"),
      formattedText: previewLines.join("\n"),
      widthMm,
      heightMm,
      actualPathWidthMm: Number(((rawPathWidth * scale) + (offsetMm * 2)).toFixed(2)),
      actualPathHeightMm: Number(((rawPathHeight * scale) + (offsetMm * 2)).toFixed(2)),
      lineIndex: 0
    }];
  }

  const actualPathWidthMm = Number((Math.max(1, rawPathWidth * scale) + (offsetMm * 2)).toFixed(2));
  const actualPathHeightMm = Number((Math.max(1, rawPathHeight * scale) + (offsetMm * 2)).toFixed(2));
  if (fitStatus === "too_small" || fitStatus === "overflow") warnings.add("Metin bu ölçü için operatör kontrolü gerektiriyor.");
  const needsReview = fitStatus === "too_small" || fitStatus === "overflow" || (multiNameCandidate && compositionMode === "single_line_text");
  const readyForCut = !needsReview && !errors.length;
  const repair = nameCutAutoRepairHeuristic({
    fitStatus,
    errors,
    offsetMm,
    formattedText,
    text: rawText,
    widthMm,
    heightMm,
    widthWasAutoFixed: legacyTooSmallWidth || legacyTooSmallHeight || rawWidthValue <= 0 || rawHeightValue <= 0
  }, item, effectiveCfg);
  const layoutSignature = nameCutStableSignature({
    text: formattedText,
    compositionMode,
    lineBreakMode,
    widthMm,
    heightMm,
    actualPathWidthMm,
    actualPathHeightMm,
    offsetMm,
    scale: Number(scale.toFixed(4)),
    previewLines,
    objectCount: previewObjects.length,
    fontId: fontMeta?.id || "",
    fontFamily: effectiveCfg.font_family
  });
  const laserNameObject = {
    id: String(item.item_id || item.id || ""),
    name: formattedText,
    xMm: Number(item.xMm ?? item.x_mm ?? 0),
    yMm: Number(item.yMm ?? item.y_mm ?? 0),
    widthMm,
    heightMm,
    actualPathWidthMm,
    actualPathHeightMm,
    rotation: Number(item.rotation || 0),
    mirrored: Boolean(item.mirrored || cfg.mirror_cut),
    direction: item.direction || nameCutDirectionLabel(cfg),
    scale: Number(scale.toFixed(4)),
    selected: Boolean(item.selected),
    lockedAspectRatio: item.lockedAspectRatio ?? item.locked_aspect_ratio ?? true,
    isConnectedPath: !errors.length,
    componentCount: repair.componentCount,
    detachedParts: repair.detachedParts,
    hasDetachedDots: repair.hasDetachedDots,
    hasDisconnectedLetters: repair.hasDisconnectedLetters,
    hasCollision: Boolean(item.hasCollision || item.has_collision),
    minGapMm: repair.minGapMm,
    appliedKerningFix: repair.appliedKerningFix,
    appliedOffsetMm: repair.appliedOffsetMm,
    appliedWeld: repair.appliedWeld,
    appliedDotBridge: repair.appliedDotBridge,
    autoRepaired: repair.autoRepaired,
    repairStatus: repair.repairStatus,
    repairMessages: repair.repairMessages,
    offsetMode: repair.offsetMode,
    isInsideSafeMargin: item.isInsideSafeMargin !== false && item.is_inside_safe_margin !== false,
    readyForCut: readyForCut && repair.readyForCut,
    warnings: Array.from(warnings),
    errors
  };
  return {
    text: rawText,
    formattedText,
    compositionMode,
    lineBreakMode,
    widthMm,
    heightMm,
    actualPathWidthMm,
    actualPathHeightMm,
    offsetMm,
    scale: Number(scale.toFixed(4)),
    fitStatus,
    previewLines,
    previewObjects,
    multiNameCandidate,
    layoutSignature,
    laserNameObject,
    warnings: Array.from(warnings),
    errors,
    readyForCut: readyForCut && repair.readyForCut,
    needsReview: needsReview || repair.repairStatus === "failed",
    ...repair,
    fontId: fontMeta?.id || "",
    fontLabel: fontMeta?.label || effectiveCfg.font_family || NAME_CUT_DEFAULT_FONT_LABEL,
    fontFamily: effectiveCfg.font_family,
    fontPath: fontMeta?.path || "",
    widthWasAutoFixed: legacyTooSmallWidth || legacyTooSmallHeight || rawWidthValue <= 0 || rawHeightValue <= 0,
    validationMode: "HEURISTIC_PREVIEW_EXPORT_VALIDATED"
  };
}

function applyNameCutLayoutResultToItem(item = {}, layoutResult = computeNameCutLayout(item)) {
  const firstObject = (layoutResult.previewObjects || [])[0] || {};
  return {
    ...item,
    text: layoutResult.text,
    name: layoutResult.formattedText,
    name_text: layoutResult.formattedText,
    preview_text: layoutResult.previewLines.join("\n"),
    composition: nameCutCompositionLabel(layoutResult.compositionMode),
    composition_mode: nameCutCompositionLabel(layoutResult.compositionMode),
    compositionMode: layoutResult.compositionMode,
    lineBreakMode: layoutResult.lineBreakMode,
    line_break_mode: layoutResult.lineBreakMode,
    widthMm: layoutResult.widthMm,
    heightMm: layoutResult.heightMm,
    width_mm: layoutResult.widthMm,
    height_mm: layoutResult.heightMm,
    actualPathWidthMm: layoutResult.actualPathWidthMm,
    actualPathHeightMm: layoutResult.actualPathHeightMm,
    actual_path_width_mm: layoutResult.actualPathWidthMm,
    actual_path_height_mm: layoutResult.actualPathHeightMm,
    raw_path_width_mm: firstObject.actualPathWidthMm || layoutResult.actualPathWidthMm,
    raw_path_height_mm: firstObject.actualPathHeightMm || layoutResult.actualPathHeightMm,
    scale: layoutResult.scale,
    path_scale: layoutResult.scale,
    offsetMm: layoutResult.offsetMm,
    offset_mm: layoutResult.offsetMm,
    fitStatus: layoutResult.fitStatus,
    fit_status: layoutResult.fitStatus,
    layoutSignature: layoutResult.layoutSignature,
    layout_signature: layoutResult.layoutSignature,
    previewLines: layoutResult.previewLines,
    previewObjects: layoutResult.previewObjects,
    preview_lines: layoutResult.previewLines,
    preview_objects: layoutResult.previewObjects,
    fontId: layoutResult.fontId,
    font_id: layoutResult.fontId,
    fontLabel: layoutResult.fontLabel,
    font_label: layoutResult.fontLabel,
    fontFamily: layoutResult.fontFamily,
    font_family: layoutResult.fontFamily,
    fontPath: layoutResult.fontPath,
    font_path: layoutResult.fontPath,
    style: layoutResult.fontFamily || item.style || NAME_CUT_DEFAULT_FONT,
    selectedFontId: layoutResult.fontId,
    selectedFontLabel: layoutResult.fontLabel,
    layout_result: layoutResult,
    laserNameObject: layoutResult.laserNameObject,
    laser_name_object: layoutResult.laserNameObject,
    isConnectedPath: layoutResult.isConnectedPath,
    is_connected_path: layoutResult.isConnectedPath,
    componentCount: layoutResult.componentCount,
    component_count: layoutResult.componentCount,
    detachedParts: layoutResult.detachedParts,
    detached_parts: layoutResult.detachedParts,
    hasDetachedDots: layoutResult.hasDetachedDots,
    has_detached_dots: layoutResult.hasDetachedDots,
    hasDisconnectedLetters: layoutResult.hasDisconnectedLetters,
    has_disconnected_letters: layoutResult.hasDisconnectedLetters,
    minGapMm: layoutResult.minGapMm,
    min_gap_mm: layoutResult.minGapMm,
    appliedKerningFix: layoutResult.appliedKerningFix,
    applied_kerning_fix: layoutResult.appliedKerningFix,
    appliedOffsetMm: layoutResult.appliedOffsetMm,
    applied_offset_mm: layoutResult.appliedOffsetMm,
    appliedWeld: layoutResult.appliedWeld,
    applied_weld: layoutResult.appliedWeld,
    appliedDotBridge: layoutResult.appliedDotBridge,
    applied_dot_bridge: layoutResult.appliedDotBridge,
    autoRepaired: layoutResult.autoRepaired,
    auto_repaired: layoutResult.autoRepaired,
    repairStatus: layoutResult.repairStatus,
    repair_status: layoutResult.repairStatus,
    repairMessages: layoutResult.repairMessages,
    repair_messages: layoutResult.repairMessages,
    offsetMode: layoutResult.offsetMode,
    offset_mode: layoutResult.offsetMode,
    readyForCut: layoutResult.readyForCut,
    ready_for_cut: layoutResult.readyForCut,
    needsReview: layoutResult.needsReview,
    needs_review: layoutResult.needsReview,
    warnings: layoutResult.warnings,
    errors: layoutResult.errors
  };
}

function renderNameCutComputedPreview(layoutResult = {}, large = false) {
  const width = Math.max(1, Number(layoutResult.widthMm || nameCutLayoutConfig.target_name_width_mm || 80));
  const height = Math.max(1, Number(layoutResult.heightMm || 40));
  const lines = Array.isArray(layoutResult.previewLines) && layoutResult.previewLines.length ? layoutResult.previewLines : [layoutResult.formattedText || layoutResult.text || ""];
  const lineHeight = height / Math.max(1, lines.length);
  const fontSize = clampNumber(lineHeight * 0.58 * Number(layoutResult.scale || 1), 5, Math.max(8, height * 0.62));
  const tspans = lines.map((line, index) => {
    const y = (height / 2) - ((lines.length - 1) * lineHeight * 0.42) + (index * lineHeight * 0.84);
    return `<tspan x="${(width / 2).toFixed(3)}" y="${y.toFixed(3)}">${esc(line)}</tspan>`;
  }).join("");
  const statusText = {
    fits: "Sığıyor",
    overflow: "Taşıyor",
    font_scaled: "Font küçültüldü",
    line_split: "Satır/obje bölündü",
    too_small: "Çok küçük",
    needs_review: "Kontrol gerekli"
  }[layoutResult.fitStatus] || layoutResult.fitStatus || "Kontrol";
  const multi = layoutResult.multiNameCandidate ? `<em class="name-cut-bridge-badge">Bu metin çoklu isim listesi gibi görünüyor.</em>` : "";
  const fontFamily = layoutResult.fontFamily || nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT;
  const fixed = layoutResult.widthWasAutoFixed ? `<em class="name-cut-bridge-badge">80 x 40 üretim ölçüsü uygulanıyor.</em>` : "";
  return `
    <div class="name-cut-preview computed ${large ? "large" : ""}" data-layout-signature="${esc(layoutResult.layoutSignature || "")}" data-fit-status="${esc(layoutResult.fitStatus || "")}">
      <svg class="name-cut-computed-svg" viewBox="0 0 ${esc(width)} ${esc(height)}" role="img" aria-label="İsim kesim ortak layout önizleme">
        <rect x="0.35" y="0.35" width="${(width - 0.7).toFixed(3)}" height="${(height - 0.7).toFixed(3)}" rx="3" ry="3" fill="rgba(248,250,252,.82)" stroke="rgba(148,163,184,.38)" stroke-width=".7" />
        <text class="name-cut-computed-text" x="${(width / 2).toFixed(3)}" y="${(height / 2).toFixed(3)}" text-anchor="middle" dominant-baseline="middle" font-size="${fontSize.toFixed(2)}" font-family="${esc(fontFamily)}, Mochary TR Connect, Brannboll Connect, Segoe Script, cursive">${tspans}</text>
      </svg>
      ${multi}
      ${fixed}
      <small>${esc(layoutResult.fontLabel || fontFamily)} · ${esc(width)} x ${esc(height)} mm · actual ${esc(layoutResult.actualPathWidthMm)} x ${esc(layoutResult.actualPathHeightMm)} mm · ${esc(statusText)} · offset ${esc(layoutResult.offsetMm)} mm</small>
    </div>
  `;
}

function nameCutLayoutResultForItem(item = {}, options = {}) {
  if (item?.layout_result?.layoutSignature && !options.forceRecompute) return item.layout_result;
  return computeNameCutLayout(item, options);
}

function analyzeNameCutItemForLaser(item = {}, cfg = nameCutLayoutConfig) {
  const text = formatNameCutName(item.name_text || "");
  const compact = text.replace(/\s+/g, "");
  const warnings = [];
  const errors = [];
  const dotted = /[iİjöÖüÜ]/.test(text);
  const lowerMarks = /[çÇşŞğĞ]/.test(text);
  if (dotted) warnings.push(`${text} isminde noktalı harfler var; noktalar sadece bu ismin gövdesine bağlanacak.`);
  if (lowerMarks) warnings.push(`${text} isminde alt işaret/kuyruk var; kopuk parça kontrolü önerilir.`);
  if (compact.length >= 20) warnings.push(`${text} uzun isim; yatay daraltma veya daha düşük yükseklik gerekebilir.`);
  if (compact.length <= 3) warnings.push(`${text} kısa isim; optik büyütme uygulanabilir.`);
  const offset = Number(item.offset_mm ?? cfg.offset_mm ?? 0.3);
  if (offset > 0.75) warnings.push("Kalınlaştırma yüksek; nesting boşluğu yeniden kontrol edilmeli.");
  if (offset <= 0) warnings.push("Kalınlaştırma/offset yok; tek parça kesimde kopma riski kontrol edilmeli.");
  return { warnings, errors };
}

function nameCutDirectionLabel(cfg = nameCutLayoutConfig) {
  const horizontal = !!cfg.mirror_cut;
  const vertical = !!cfg.mirror_vertical;
  if (horizontal && vertical) return "Ters/Ayna";
  if (horizontal) return "Ayna Yatay";
  if (vertical) return "Ayna Dikey";
  return "Düz";
}

function nameCutOriginalItem(item = {}) {
  const sourceId = item.source_item_id || item.item_id || "";
  return nameCutItems.find(row => row.item_id === sourceId) || nameCutItems.find(row => row.item_id === item.item_id) || item;
}

function nameCutSourceMetrics(layout = currentNameCutLayout()) {
  if (layout?.scene_metrics) {
    return {
      source_total: Number(layout.scene_metrics.object_count || layout.summary?.total_names || 0),
      source_placed: Number(layout.scene_metrics.object_count || layout.summary?.total_names || 0),
      copies_total: Number(layout.scene_metrics.placement_count || layout.summary?.total_copies || 0),
      copies_placed: Number(layout.scene_metrics.placement_count || (layout.items || []).length || 0),
    };
  }
  const live = nameCutLiveItems();
  const sourceUnits = expandJoinedNameItems(live, normalizeNameCutConfig(nameCutLayoutConfig));
  const sourceIds = new Set(sourceUnits.map(item => item.item_id || item.id).filter(Boolean));
  const placedSourceIds = new Set((layout.items || []).map(item => item.item_id || item.id).filter(Boolean));
  const placedSourceCount = [...placedSourceIds].filter(id => sourceIds.has(id)).length;
  const totalCopies = Math.max(0, Number((layout.summary || {}).total_copies || 0));
  return {
    source_total: sourceUnits.length,
    source_placed: Math.min(sourceUnits.length, placedSourceCount),
    copies_total: totalCopies,
    copies_placed: (layout.items || []).length
  };
}

function nameCutSinglePieceQuality(item = {}, layout = null, cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  const original = nameCutOriginalItem(item);
  const merged = { ...original, ...item };
  const text = formatNameCutName(merged.name_text || "");
  const status = String(merged.status || "").toUpperCase();
  const hasErrors = (merged.errors || []).length || status === "ERROR" || status === "BLOCKED" || merged.force_blocked;
  const hasDetachedMarks = !!merged.force_detached_marks || !!merged.detached_marks || (hasTurkishDiacriticForCutting(text) && (config.punctuation_fix === false || config.turkish_mark_bridge === false || config.dot_bridge_enabled === false) && !merged.diacritic_bridge_requested);
  const needsWeld = !!merged.force_needs_weld || merged.internal_weld_ready === false || config.weld_inside_name === false;
  const offset = Number(merged.offset_mm ?? config.offset_mm ?? 0);
  const needsOffset = !!merged.force_needs_offset || offset <= 0 || offset < Math.max(0.12, Number(config.min_stroke_mm || 0.28) * 0.45);
  const collisionRisk = !!merged.force_collision_risk || (layout && (layout.summary || {}).collision_free === false);
  const productionReady = !hasErrors && !hasDetachedMarks && !needsWeld && !needsOffset && !collisionRisk;
  let qualityStatus = "ready_single_piece";
  if (hasErrors) qualityStatus = "blocked";
  else if (collisionRisk) qualityStatus = "collision_risk";
  else if (hasDetachedMarks) qualityStatus = "detached_marks";
  else if (needsWeld) qualityStatus = "needs_weld";
  else if (needsOffset) qualityStatus = "needs_offset";
  const meta = NAME_CUT_SINGLE_PIECE_STATUSES[qualityStatus] || NAME_CUT_SINGLE_PIECE_STATUSES.blocked;
  const notes = [];
  if (productionReady) notes.push("Aynı isim içindeki harfler ve işaretler tek parça kontrolünden geçti.");
  if (needsWeld) notes.push("Harf/parça birleşimi gerçek path kontrolü gerektiriyor.");
  if (hasDetachedMarks) notes.push("Nokta veya Türkçe karakter işareti ana gövdeye bağlı görünmüyor.");
  if (needsOffset) notes.push("Kalınlaştırma yetersiz; Corel benzeri offset kontrolü gerekli.");
  if (collisionRisk) notes.push("Farklı isimler arası minimum boşluk ihlali var.");
  if (hasErrors) notes.push("Üretime engel hata var.");
  return {
    status: qualityStatus,
    label: meta.label,
    tone: meta.tone,
    production_ready: productionReady,
    letters_joined: !needsWeld,
    single_piece: productionReady || (!needsWeld && !hasDetachedMarks && !hasErrors),
    weld: needsWeld ? "Kontrol" : "Hazır",
    offset: needsOffset ? "Gerekli" : "Uygulandı",
    marks: hasDetachedMarks ? "Kopuk" : "Bağlı",
    collision: collisionRisk ? "Risk" : "Yok",
    direction: nameCutDirectionLabel(config),
    notes
  };
}

function nameCutQualityBadgeHtml(quality = {}) {
  const status = quality.status || "blocked";
  const meta = NAME_CUT_SINGLE_PIECE_STATUSES[status] || NAME_CUT_SINGLE_PIECE_STATUSES.blocked;
  return `<span class="name-cut-quality-badge ${esc(status)} ${esc(meta.tone)}">${esc(meta.label)}</span>`;
}

function normalizedNameCutItemForLayout(item = {}, cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  const layoutResult = nameCutLayoutResultForItem(item, { cfg: config, context: "main" });
  const text = formatNameCutName(layoutResult.formattedText || item.name_text || "");
  const cleanLength = Math.max(1, text.replace(/\s+/g, "").length);
  const targetHeight = Number(config.target_name_height_mm || 40);
  const targetWidth = Number(config.target_name_width_mm || 80);
  const pathMetrics = nameCutActualPathMetricsEstimate(text, config, item);
  let height = item.operator_size_locked ? Number(item.height_mm || targetHeight) : Number(pathMetrics.actualPathHeightMm || targetHeight);
  height = clampNumber(height, config.min_height_mm, Math.max(config.max_height_mm, targetHeight));
  let horizontalScale = Number(item.horizontal_scale_percent || config.horizontal_scale_percent || 100);
  if (cleanLength <= 4 && config.optical_short_name_scale) horizontalScale = Math.min(125, horizontalScale + 8);
  if (cleanLength >= 18 && config.auto_condense_long_names) horizontalScale = Math.max(72, horizontalScale - Math.min(18, cleanLength - 17));
  const verticalScale = Number(item.vertical_scale_percent || config.vertical_scale_percent || 100);
  const requestedWidth = Number(layoutResult.widthMm || item.width_mm || targetWidth);
  const maxWidth = Math.max(45, config.width_mm - (config.margin_mm * 2));
  const computedWidth = Number(layoutResult.widthMm || item.width_mm || targetWidth);
  const computedHeight = Number(layoutResult.heightMm || item.height_mm || targetHeight);
  const computedActualWidth = Number(layoutResult.actualPathWidthMm || pathMetrics.actualPathWidthMm || computedWidth);
  const computedActualHeight = Number(layoutResult.actualPathHeightMm || pathMetrics.actualPathHeightMm || computedHeight);
  const placementWidth = Number(pathMetrics.placementWidthMm || computedWidth || targetWidth);
  const placementHeight = Number(pathMetrics.placementHeightMm || computedHeight || targetHeight);
  const productionWidth = item.operator_size_locked ? requestedWidth : placementWidth;
  const productionHeight = item.operator_size_locked ? computedHeight : placementHeight;
  const width = Math.max(22, Math.min(maxWidth, productionWidth));
  const risk = analyzeNameCutItemForLaser({ ...item, name_text: text }, config);
  return {
    ...item,
    name_text: text,
    preview_text: (layoutResult.previewLines || []).join("\n") || item.preview_text || text,
    width_mm: Number(width.toFixed(2)),
    height_mm: Number((productionHeight * (verticalScale / 100)).toFixed(2)),
    actual_path_width_mm: Number(computedActualWidth.toFixed(2)),
    actual_path_height_mm: Number(computedActualHeight.toFixed(2)),
    raw_path_width_mm: Number(pathMetrics.rawPathWidthMm.toFixed(2)),
    raw_path_height_mm: Number(pathMetrics.rawPathHeightMm.toFixed(2)),
    placement_width_mm: Number(width.toFixed(2)),
    placement_height_mm: Number((productionHeight * (verticalScale / 100)).toFixed(2)),
    path_scale: layoutResult.scale || pathMetrics.pathScale,
    target_name_width_mm: targetWidth,
    target_name_height_mm: targetHeight,
    target_gap_mm: config.target_gap_mm,
    horizontal_scale_percent: Number(horizontalScale.toFixed(1)),
    vertical_scale_percent: Number(verticalScale.toFixed(1)),
    offset_mm: layoutResult.offsetMm ?? item.offset_mm ?? config.offset_mm,
    compositionMode: layoutResult.compositionMode,
    composition_mode: nameCutCompositionLabel(layoutResult.compositionMode),
    lineBreakMode: layoutResult.lineBreakMode,
    line_break_mode: layoutResult.lineBreakMode,
    fitStatus: layoutResult.fitStatus,
    fit_status: layoutResult.fitStatus,
    layoutSignature: layoutResult.layoutSignature,
    layout_signature: layoutResult.layoutSignature,
    previewLines: layoutResult.previewLines,
    previewObjects: layoutResult.previewObjects,
    preview_lines: layoutResult.previewLines,
    preview_objects: layoutResult.previewObjects,
    layout_result: layoutResult,
    warnings: Array.from(new Set([...(layoutResult.warnings || []), ...(item.warnings || []), ...risk.warnings])),
    errors: Array.from(new Set([...(layoutResult.errors || []), ...(item.errors || []), ...risk.errors])),
    internal_weld_only: true,
    inter_name_connection_forbidden: true
  };
}

function nameCutLogicalItemId(item = {}) {
  return String(item.item_id || item.id || item.source_item_id || "");
}

function nameCutPathPreviewKey(item = {}) {
  const id = String(item.item_id || item.id || item.source_item_id || "");
  const page = Number(item.page || 1);
  const copy = Number(item.copy_index || 1);
  const x = Number(item.x_mm || 0).toFixed(2);
  const y = Number(item.y_mm || 0).toFixed(2);
  const width = Number(item.width_mm || 0).toFixed(2);
  const height = Number(item.height_mm || 0).toFixed(2);
  return `${id}|${copy}|${page}|${x}|${y}|${width}|${height}`;
}

function nameCutPathPreviewSignature(layout = {}) {
  const cfg = layout.config || {};
  return nameCutStableSignature({
    cfg: {
      width_mm: cfg.width_mm,
      height_mm: cfg.height_mm,
      margin_mm: cfg.margin_mm,
      mirror_cut: cfg.mirror_cut,
      mirror_vertical: cfg.mirror_vertical,
      offset_mm: cfg.offset_mm,
      font_family: nameCutLayoutConfig.font_family,
    },
    items: (layout.items || []).slice(0, 240).map(item => ({
      key: nameCutPathPreviewKey(item),
      text: item.preview_text || item.name_text || item.text || "",
      style: item.style || nameCutLayoutConfig.font_family,
      rotation: Number(item.rotation || 0),
      offset: Number(item.offset_mm ?? nameCutLayoutConfig.offset_mm ?? 0),
    })),
  });
}

function nameCutPathPreviewPayload(layout = {}) {
  const cfg = layout.config || normalizeNameCutConfig(nameCutLayoutConfig);
  return {
    config: { ...cfg, font_family: nameCutLayoutConfig.font_family },
    items: (layout.items || []).slice(0, 240).map(item => ({
      ...item,
      id: item.id || item.item_id,
      item_id: item.item_id || item.id,
      name_text: item.name_text || item.preview_text || item.text || "",
      preview_text: item.preview_text || item.name_text || item.text || "",
      style: item.style || nameCutLayoutConfig.font_family,
      x_mm: Number(item.x_mm || 0),
      y_mm: Number(item.y_mm || 0),
      width_mm: Number(item.width_mm || nameCutLayoutConfig.target_name_width_mm || 80),
      height_mm: Number(item.height_mm || nameCutLayoutConfig.target_name_height_mm || 40),
      rotation: Number(item.rotation || 0),
      offset_mm: Number(item.offset_mm ?? nameCutLayoutConfig.offset_mm ?? 0),
      quantity: "1",
      operator_position_locked: true,
      operator_size_locked: true,
    })),
  };
}

function nameCutProductionSceneSignature(items = nameCutLiveItems(), cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  return nameCutStableSignature({
    cfg: {
      width_mm: config.width_mm,
      height_mm: config.height_mm,
      margin_mm: config.margin_mm,
      item_gap_mm: config.item_gap_mm,
      row_gap_mm: config.row_gap_mm,
      target_name_width_mm: config.target_name_width_mm,
      target_name_height_mm: config.target_name_height_mm,
      dense_nesting: config.dense_nesting !== false,
      allow_rotation: config.allow_rotation !== false,
      mirror_cut: config.mirror_cut,
      mirror_vertical: config.mirror_vertical,
      offset_mm: config.offset_mm,
      font_family: config.font_family || nameCutLayoutConfig.font_family,
    },
    items: (items || []).slice(0, 260).filter(item => !item.is_deleted).map(item => {
      const layoutResult = nameCutLayoutResultForItem(item, { cfg: config, context: "scene-signature" });
      return {
        id: item.item_id || item.id || "",
        text: item.name_text || item.text || "",
        quantity: item.quantity || 1,
        compositionMode: layoutResult.compositionMode || item.compositionMode || item.composition_mode || "",
        lineBreakMode: layoutResult.lineBreakMode || item.lineBreakMode || item.line_break_mode || "",
        width: item.width_mm || item.widthMm || "",
        height: item.height_mm || item.heightMm || "",
        x: item.x_mm || "",
        y: item.y_mm || "",
        rotation: item.rotation || 0,
        positionLocked: item.operator_position_locked === true,
        sizeLocked: item.operator_size_locked === true,
        offset: item.offset_mm ?? config.offset_mm,
      };
    }),
  });
}

function nameCutProductionScenePayload(items = nameCutLiveItems(), cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  return {
    config: { ...config, font_family: config.font_family || nameCutLayoutConfig.font_family },
    items: (items || []).filter(item => !item.is_deleted).map(item => {
      const layoutResult = nameCutLayoutResultForItem(item, { cfg: config, context: "scene-payload" });
      return {
        ...item,
        id: item.id || item.item_id,
        item_id: item.item_id || item.id,
        name_text: item.name_text || item.text || "",
        text: item.text || item.name_text || "",
        preview_text: item.preview_text || item.name_text || item.text || "",
        compositionMode: layoutResult.compositionMode || item.compositionMode,
        composition_mode: layoutResult.compositionMode || item.composition_mode || item.composition,
        lineBreakMode: layoutResult.lineBreakMode || item.lineBreakMode,
        line_break_mode: layoutResult.lineBreakMode || item.line_break_mode,
        previewObjects: layoutResult.previewObjects || item.previewObjects || item.preview_objects || [],
        preview_objects: layoutResult.previewObjects || item.preview_objects || item.previewObjects || [],
        width_mm: Number(item.width_mm || layoutResult.widthMm || config.target_name_width_mm || 80),
        height_mm: Number(item.height_mm || layoutResult.heightMm || config.target_name_height_mm || 40),
        actual_path_width_mm: Number(item.actual_path_width_mm || layoutResult.actualPathWidthMm || item.width_mm || config.target_name_width_mm || 80),
        actual_path_height_mm: Number(item.actual_path_height_mm || layoutResult.actualPathHeightMm || item.height_mm || config.target_name_height_mm || 40),
        offset_mm: Number(item.offset_mm ?? layoutResult.offsetMm ?? config.offset_mm ?? 0),
        style: item.style || config.font_family || nameCutLayoutConfig.font_family,
      };
    }),
  };
}

function requestNameCutProductionScene(layout = currentNameCutLayout()) {
  const method = bridge?.build_name_cut_production_scene || bridge?.preview_name_cut_paths;
  if (typeof method !== "function") return;
  const liveItems = nameCutLiveItems();
  const signature = nameCutProductionSceneSignature(liveItems, nameCutLayoutConfig);
  if (!signature || nameCutProductionSceneCache.signature === signature || nameCutProductionSceneCache.pendingSignature === signature) return;
  nameCutProductionSceneCache = { ...nameCutProductionSceneCache, pendingSignature: signature, status: "PENDING", message: "FontTools production scene hazırlanıyor." };
  try {
    method.call(bridge, JSON.stringify(nameCutProductionScenePayload(liveItems, nameCutLayoutConfig)), raw => {
      const result = parseBridgeResult(raw);
      if (nameCutProductionSceneCache.pendingSignature !== signature) return;
      const scene = result && typeof result === "object" ? result : {};
      nameCutProductionSceneCache = {
        signature,
        pendingSignature: "",
        scene,
        status: scene.status || "UNKNOWN",
        message: scene.message || "",
      };
      renderLaserLayoutPreview(layout);
    });
  } catch (error) {
    nameCutProductionSceneCache = {
      signature,
      pendingSignature: "",
      scene: null,
      status: "ERROR",
      message: error?.message || "Production scene alınamadı.",
    };
  }
}

function currentNameCutProductionScene() {
  const signature = nameCutProductionSceneSignature(nameCutLiveItems(), nameCutLayoutConfig);
  if (nameCutProductionSceneCache.signature !== signature) return null;
  return nameCutProductionSceneCache.scene || null;
}

function nameCutProductionPathByPlacement(scene = {}, placementId = "") {
  const id = String(placementId || "");
  return ((scene && scene.paths) || []).find(path => String(path.placement_id || "") === id) || null;
}

function nameCutSceneLayout(scene = null, fallbackLayout = {}) {
  const layout = scene?.layout && typeof scene.layout === "object" ? scene.layout : fallbackLayout;
  if (!scene?.placements?.length) return layout;
  return {
    ...layout,
    scene_metrics: scene.metrics || {},
    items: scene.placements.map(placement => ({
      ...placement,
      item_id: placement.object_id || placement.item_id,
      id: placement.object_id || placement.id,
      source_item_id: placement.source_item_id || placement.item_id,
      name_text: placement.text || placement.name_text || "",
      preview_text: placement.text || placement.name_text || "",
    })),
    summary: {
      ...(layout.summary || {}),
      total_names: scene.metrics?.object_count ?? scene.placements.length,
      total_copies: scene.metrics?.placement_count ?? scene.placements.length,
      pages: scene.metrics?.pages ?? (layout.summary || {}).pages ?? 1,
      used_area_percent: scene.metrics?.used_area_percent ?? (layout.summary || {}).used_area_percent ?? 0,
      collision_free: scene.metrics?.collision_free ?? (layout.summary || {}).collision_free,
      within_work_area: scene.metrics?.within_work_area ?? (layout.summary || {}).within_work_area,
      min_safe_gap_mm: scene.metrics?.min_safe_gap_mm ?? (layout.summary || {}).min_safe_gap_mm,
      placement_strategy: scene.metrics?.placement_strategy || (layout.summary || {}).placement_strategy || "BACKEND_PRODUCTION_SCENE",
    },
  };
}

function nameCutPercent(valueMm = 0, totalMm = 1) {
  const total = Math.max(1, Number(totalMm || 1));
  return (Number(valueMm || 0) / total) * 100;
}

function nameCutFontSizeForBox(item = {}, cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  const text = String(item.name_text || "").trim();
  const cleanLength = Math.max(1, text.replace(/\s+/g, "").length);
  const height = Math.max(8, Number(item.height_mm || config.target_name_height_mm || 40));
  const width = Math.max(10, Number(item.width_mm || config.target_name_width_mm || 80));
  const heightPx = height * 0.78;
  const widthPx = (width / Math.max(4, cleanLength)) * 1.92;
  const base = Math.min(heightPx, widthPx);
  const shortBoost = cleanLength <= 5 ? 1.18 : cleanLength <= 8 ? 1.08 : 1;
  const longCut = cleanLength >= 18 ? Math.max(0.72, 1 - ((cleanLength - 17) * 0.018)) : 1;
  return clampNumber(base * shortBoost * longCut, 10, Math.max(20, height * 0.92));
}

function nameCutFindSourceItem(itemId = "") {
  const id = String(itemId || "").trim();
  if (!id) return null;
  return nameCutItems.find(item => item.item_id === id || item.id === id || item.source_item_id === id) || null;
}

function nameCutPlacedItemForSource(itemId = "", layout = currentNameCutLayout()) {
  const id = String(itemId || "").trim();
  if (!id) return null;
  const scene = currentNameCutProductionScene();
  const sceneHit = (scene?.placements || []).find(item => String(item.placement_id || "") === id || String(item.object_id || "") === id || String(item.source_item_id || "") === id);
  if (sceneHit) return {
    ...sceneHit,
    item_id: sceneHit.object_id || sceneHit.item_id,
    source_item_id: sceneHit.source_item_id || sceneHit.item_id,
    name_text: sceneHit.text || sceneHit.name_text || "",
  };
  return (layout.items || []).find(item => nameCutLogicalItemId(item) === id || item.item_id === id || item.source_item_id === id) || null;
}

function nameCutApplyManualGeometry(itemId = "", geometry = {}) {
  const item = nameCutFindSourceItem(itemId);
  if (!item) return null;
  const cfg = normalizeNameCutConfig(nameCutLayoutConfig);
  const minWidth = 20;
  const minHeight = 10;
  const maxWidth = Math.max(minWidth, cfg.width_mm - (cfg.margin_mm * 2));
  const maxHeight = Math.max(minHeight, cfg.height_mm - (cfg.margin_mm * 2));
  if (Number.isFinite(Number(geometry.x_mm))) item.x_mm = Number(Number(geometry.x_mm).toFixed(2));
  if (Number.isFinite(Number(geometry.y_mm))) item.y_mm = Number(Number(geometry.y_mm).toFixed(2));
  if (Number.isFinite(Number(geometry.width_mm))) item.width_mm = Number(clampNumber(Number(geometry.width_mm), minWidth, maxWidth).toFixed(2));
  if (Number.isFinite(Number(geometry.height_mm))) item.height_mm = Number(clampNumber(Number(geometry.height_mm), minHeight, maxHeight).toFixed(2));
  if (Number.isFinite(Number(geometry.rotation))) item.rotation = Number(geometry.rotation);
  if (geometry.operator_position_locked) item.operator_position_locked = true;
  if (geometry.operator_size_locked) item.operator_size_locked = true;
  item.locked_aspect_ratio = geometry.locked_aspect_ratio ?? item.locked_aspect_ratio ?? true;
  item.is_edited = true;
  const layoutResult = computeNameCutLayout(item, { context: "manual-geometry", userSelectedComposition: item.composition_user_selected === true, forceRecompute: true });
  Object.assign(item, applyNameCutLayoutResultToItem(item, layoutResult));
  const nextLayout = currentNameCutLayout();
  const placed = nameCutPlacedItemForSource(item.item_id, nextLayout) || { ...item };
  const safeOk = nameCutLayoutWithinWorkArea([placed], cfg);
  const collisionOk = nameCutLayoutHasNoOverlaps(nextLayout.items || [], cfg.item_gap_mm);
  const warnings = new Set(item.warnings || []);
  ["Safe margin dışına taşma var.", "Başka isimle temas riski var."].forEach(msg => warnings.delete(msg));
  if (!safeOk) warnings.add("Safe margin dışına taşma var.");
  if (!collisionOk) warnings.add("Başka isimle temas riski var.");
  item.warnings = Array.from(warnings);
  return item;
}

function expandJoinedNameItems(items = [], config = nameCutLayoutConfig) {
  const targetWidth = Number(config.target_name_width_mm || 80);
  const targetHeight = Number(config.target_name_height_mm || 40);
  const units = [];
  (items || []).forEach((item, sourceOrder) => {
    const layoutResult = nameCutLayoutResultForItem(item, { cfg: config, context: "main" });
    const compositionForSplit = item.compositionMode || item.composition_mode || item.composition || "";
    const forceSplitMultiName = layoutResult.multiNameCandidate && !isExplicitNameCutSingleLineMode(compositionForSplit) && !isJoinedNameMode(compositionForSplit);
    if ((["auto_split_and_nest", "separate_names"].includes(layoutResult.compositionMode) || forceSplitMultiName) && (layoutResult.previewObjects || []).length > 1) {
      (layoutResult.previewObjects || []).forEach((object, index) => {
        const childText = formatNameCutName(object.formattedText || object.text || "");
        const childMetrics = nameCutActualPathMetricsEstimate(childText, config, {
          ...item,
          operator_size_locked: item.operator_size_locked === true,
          width_mm: object.widthMm || item.width_mm,
          height_mm: object.heightMm || item.height_mm,
          offset_mm: item.offset_mm ?? config.offset_mm
        });
        const childWidth = Number(object.widthMm || childMetrics.placementWidthMm || childMetrics.actualPathWidthMm || targetWidth);
        const childHeight = Number(object.heightMm || childMetrics.placementHeightMm || childMetrics.actualPathHeightMm || targetHeight);
        const childBase = {
          ...item,
          item_id: object.id || `${item.item_id || "name"}-split-${index + 1}`,
          id: object.id || `${item.item_id || "name"}-split-${index + 1}`,
          text: childText,
          name: childText,
          name_text: childText,
          preview_text: childText,
          source_name_text: formatNameCutName(item.name_text || ""),
          source_item_id: item.item_id || item.id || "",
          source_order: sourceOrder,
          split_word_index: index + 1,
          split_word_count: layoutResult.previewObjects.length,
          joined_name_gap_mm: Math.max(1, Number(config.joined_name_gap_mm || config.target_gap_mm || 1)),
          composition: "Tek satır yazı",
          composition_mode: "Tek satır yazı",
          compositionMode: "single_line_text",
          lineBreakMode: "single_line",
          line_break_mode: "single_line",
          widthMm: Number(childWidth.toFixed(2)),
          heightMm: Number(childHeight.toFixed(2)),
          width_mm: Number(childWidth.toFixed(2)),
          height_mm: Number(childHeight.toFixed(2)),
          actualPathWidthMm: Number(object.actualPathWidthMm || childMetrics.actualPathWidthMm || childWidth),
          actualPathHeightMm: Number(object.actualPathHeightMm || childMetrics.actualPathHeightMm || childHeight),
          actual_path_width_mm: Number(object.actualPathWidthMm || childMetrics.actualPathWidthMm || childWidth),
          actual_path_height_mm: Number(object.actualPathHeightMm || childMetrics.actualPathHeightMm || childHeight),
          raw_path_width_mm: Number(object.rawPathWidthMm || childMetrics.rawPathWidthMm || 0),
          raw_path_height_mm: Number(object.rawPathHeightMm || childMetrics.rawPathHeightMm || 0),
          placement_width_mm: Number(childWidth.toFixed(2)),
          placement_height_mm: Number(childHeight.toFixed(2)),
          path_scale: Number(object.pathScale || childMetrics.pathScale || 1),
          quantity: "1",
          operator_size_locked: item.operator_size_locked === true,
          composition_user_selected: true,
          layout_parent_signature: layoutResult.layoutSignature,
          layout_result: null,
          previewObjects: null,
          preview_objects: null,
          previewLines: null,
          preview_lines: null
        };
        units.push({
          ...childBase,
          layout_result: computeNameCutLayout(childBase, { cfg: config, context: "main", userSelectedComposition: true })
        });
      });
      return;
    }
    const composition = item.composition_mode || item.composition || "";
    const words = splitNameWords(item.name_text);
    if (!isJoinedNameMode(composition) && (!forceSplitMultiName || words.length <= 1)) {
      units.push({ ...item, source_order: sourceOrder });
      return;
    }
    words.forEach((word, index) => {
      const wordText = formatNameCutName(word);
      const wordMetrics = nameCutActualPathMetricsEstimate(wordText, config, {
        ...item,
        operator_size_locked: false,
        offset_mm: item.offset_mm ?? config.offset_mm
      });
      const wordWidth = Number(wordMetrics.placementWidthMm || wordMetrics.actualPathWidthMm || targetWidth);
      const wordHeight = Number(wordMetrics.placementHeightMm || wordMetrics.actualPathHeightMm || targetHeight);
      units.push({
        ...item,
        item_id: `${item.item_id || "name"}-word-${index + 1}`,
        name_text: wordText,
        preview_text: wordText,
        source_name_text: formatNameCutName(item.name_text || ""),
        source_item_id: item.item_id || "",
        source_order: sourceOrder,
        split_word_index: index + 1,
        split_word_count: words.length,
        joined_name_gap_mm: Math.max(1, Number(config.joined_name_gap_mm || config.target_gap_mm || 1)),
        composition: forceSplitMultiName ? "Tek satır yazı" : "İsimleri Bitiştir",
        composition_mode: forceSplitMultiName ? "Tek satır yazı" : "İsimleri Bitiştir",
        compositionMode: "single_line_text",
        lineBreakMode: "single_line",
        line_break_mode: "single_line",
        width_mm: Number(wordWidth.toFixed(2)),
        height_mm: Number(wordHeight.toFixed(2)),
        actual_path_width_mm: Number(wordMetrics.actualPathWidthMm || wordWidth),
        actual_path_height_mm: Number(wordMetrics.actualPathHeightMm || wordHeight),
        raw_path_width_mm: Number(wordMetrics.rawPathWidthMm || 0),
        raw_path_height_mm: Number(wordMetrics.rawPathHeightMm || 0),
        placement_width_mm: Number(wordWidth.toFixed(2)),
        placement_height_mm: Number(wordHeight.toFixed(2)),
        path_scale: Number(wordMetrics.pathScale || 1),
        quantity: forceSplitMultiName ? "1" : item.quantity,
        operator_size_locked: false
      });
    });
  });
  return units;
}

function nameCutDenseOrder(units = [], config = nameCutLayoutConfig) {
  return units;
}

function nameCutMaybeRotateForDense(item = {}, cursorX = 0, cursorY = 0, rowHeight = 0, config = nameCutLayoutConfig) {
  const width = Math.max(8, Number(item.actual_path_width_mm || item.width_mm || config.target_name_width_mm || 80));
  const height = Math.max(8, Number(item.actual_path_height_mm || item.height_mm || config.target_name_height_mm || 40));
  if (!config.allow_rotation || item.operator_size_locked || item.operator_position_locked) {
    return { width, height, rotation: Number(item.rotation || 0), rotated_for_nesting: false };
  }
  const rightMargin = Number(config.width_mm || 800) - Number(config.margin_mm || 15);
  const fitsNormal = cursorX + width <= rightMargin + 0.01;
  const fitsRotated = cursorX + height <= rightMargin + 0.01;
  if (!fitsNormal && fitsRotated && height < width) {
    return { width, height, rotation: 180, rotated_for_nesting: false };
  }
  if (rowHeight > 0 && height > rowHeight * 1.24 && width <= rowHeight * 1.18 && fitsRotated) {
    return { width, height, rotation: 180, rotated_for_nesting: false };
  }
  return { width, height, rotation: Number(item.rotation || 0), rotated_for_nesting: false };
}

function buildNameCutPreviewLayout(items = nameCutLiveItems(), cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  const layoutUnits = expandJoinedNameItems(items, config).map(item => normalizedNameCutItemForLayout(item, config));
  const expanded = [];
  layoutUnits.forEach(item => {
    const quantity = Math.max(1, Number.parseInt(item.quantity || 1, 10) || 1);
    for (let copyIndex = 0; copyIndex < quantity; copyIndex += 1) {
      expanded.push({ ...item, copy_index: copyIndex + 1 });
    }
  });
  const ordered = nameCutDenseOrder(expanded, config);
  const leftMargin = config.margin_mm;
  const rightMargin = config.width_mm - config.margin_mm;
  const topMargin = config.margin_mm;
  const bottomMargin = config.height_mm - config.margin_mm;
  const usableWidth = rightMargin - leftMargin;
  const usableHeight = bottomMargin - topMargin;
  const placed = [];
  const unplaced = [];
  let pages = 1;
  let cursorX = leftMargin;
  let cursorY = topMargin;
  let rowHeight = 0;

  ordered.forEach(item => {
    const fit = nameCutMaybeRotateForDense(item, cursorX, cursorY, rowHeight, config);
    const width = Math.max(8, Number(fit.width || item.actual_path_width_mm || item.width_mm || config.target_name_width_mm || 80));
    const height = Math.max(8, Number(fit.height || item.actual_path_height_mm || item.height_mm || config.target_name_height_mm || 40));
    if (width > usableWidth || height > usableHeight) {
      unplaced.push({ ...item, not_placed_reason: "Tabla alanına sığmıyor", width_mm: width, height_mm: height });
      return;
    }
    if (item.operator_position_locked && Number.isFinite(Number(item.x_mm)) && Number.isFinite(Number(item.y_mm))) {
      placed.push({
        ...item,
        page: Number(item.page || 1),
        x_mm: Number(Number(item.x_mm).toFixed(2)),
        y_mm: Number(Number(item.y_mm).toFixed(2)),
        width_mm: Number(width.toFixed(2)),
        height_mm: Number(height.toFixed(2)),
        actual_path_width_mm: Number(item.actual_path_width_mm || width),
        actual_path_height_mm: Number(item.actual_path_height_mm || height),
        rotation: Number(item.rotation || 0),
        separate_cut_object: true,
        no_inter_name_bridge: true
      });
      return;
    }
    if (cursorX + width > rightMargin + 0.01) {
      cursorX = leftMargin;
      const rowStep = config.dense_nesting === false ? Math.max(rowHeight, config.target_name_height_mm || 40) : rowHeight;
      cursorY += Math.max(rowStep, 10) + config.row_gap_mm;
      rowHeight = 0;
    }
    if (cursorY + height > bottomMargin + 0.01) {
      pages += 1;
      cursorX = leftMargin;
      cursorY = topMargin;
      rowHeight = 0;
    }
    placed.push({
      ...item,
      page: pages,
      x_mm: Number(cursorX.toFixed(2)),
      y_mm: Number(cursorY.toFixed(2)),
      width_mm: Number(width.toFixed(2)),
      height_mm: Number(height.toFixed(2)),
      actual_path_width_mm: Number(item.actual_path_width_mm || width),
      actual_path_height_mm: Number(item.actual_path_height_mm || height),
      rotation: fit.rotation,
      rotated_for_nesting: fit.rotated_for_nesting,
      direction: nameCutDirectionLabel(config),
      mirrored: !!config.mirror_cut,
      separate_cut_object: true,
      no_inter_name_bridge: true
    });
    const itemGap = Math.max(0, Number(item.joined_name_gap_mm ?? config.item_gap_mm));
    cursorX += width + itemGap;
    rowHeight = Math.max(rowHeight, height);
  });
  pages = Math.max(pages, ...placed.map(item => Number(item.page || 1)), 1);

  const usedArea = placed.reduce((sum, item) => sum + (Number(item.width_mm || 0) * Number(item.height_mm || 0)), 0);
  const totalArea = config.width_mm * config.height_mm * Math.max(1, pages);
  const pageStats = Array.from({ length: pages }, (_, idx) => {
    const page = idx + 1;
    const pageItems = placed.filter(item => Number(item.page || 1) === page);
    const pageUsed = pageItems.reduce((sum, item) => sum + (Number(item.width_mm || 0) * Number(item.height_mm || 0)), 0);
    const pageArea = config.width_mm * config.height_mm;
    return {
      page,
      items: pageItems.length,
      used_area_percent: pageArea ? Number(((pageUsed / pageArea) * 100).toFixed(1)) : 0,
      waste_percent: pageArea ? Number((100 - ((pageUsed / pageArea) * 100)).toFixed(1)) : 0
    };
  });
  const modeledPlaced = nameCutAttachLaserObjectModel(placed, config);
  return {
    config,
    items: modeledPlaced,
    unplaced,
    summary: {
      total_source_items: items.length,
      total_names: layoutUnits.length,
      total_copies: expanded.length,
      pages,
      placement_strategy: config.dense_nesting === false ? "CLIENT_PREVIEW_LOGICAL_MM_LEFT_TO_RIGHT_ROWS" : "CLIENT_PREVIEW_ACTUAL_PATH_DENSE_SHELF",
      used_area_percent: totalArea ? Number(((usedArea / totalArea) * 100).toFixed(1)) : 0,
      waste_percent: totalArea ? Number((100 - ((usedArea / totalArea) * 100)).toFixed(1)) : 0,
      overflow: unplaced.length > 0,
      collision_free: nameCutLayoutHasNoOverlaps(placed, config.item_gap_mm),
      within_work_area: nameCutLayoutWithinWorkArea(placed, config),
      page_stats: pageStats,
      min_safe_gap_mm: config.item_gap_mm,
      target_name_width_mm: config.target_name_width_mm,
      target_name_height_mm: config.target_name_height_mm,
      target_gap_mm: config.target_gap_mm,
      dense_nesting: config.dense_nesting !== false,
      logical_coordinate_system: "800x600_MM_VIEWBOX_RENDER_ONLY",
      unplaced_count: unplaced.length,
      estimated_cut_time_seconds: Math.max(0, Math.round(placed.length * 14 + usedArea / 220)),
      inter_name_connection_forbidden: true,
      internal_weld_scope: "SINGLE_NAME_ONLY"
    }
  };
}

function nameCutLayoutHasNoOverlaps(items = [], gapMm = 0) {
  const gap = Math.max(0, Number(gapMm || 0));
  const tolerance = 0.12;
  for (let i = 0; i < items.length; i += 1) {
    for (let j = i + 1; j < items.length; j += 1) {
      const a = items[i];
      const b = items[j];
      if (Number(a.page || 1) !== Number(b.page || 1)) continue;
      const separated = (
        Number(a.x_mm) + Number(a.width_mm) + gap <= Number(b.x_mm) + tolerance ||
        Number(b.x_mm) + Number(b.width_mm) + gap <= Number(a.x_mm) + tolerance ||
        Number(a.y_mm) + Number(a.height_mm) + gap <= Number(b.y_mm) + tolerance ||
        Number(b.y_mm) + Number(b.height_mm) + gap <= Number(a.y_mm) + tolerance
      );
      if (!separated) return false;
    }
  }
  return true;
}

function nameCutItemHasCollision(target = {}, items = [], gapMm = 0) {
  const gap = Math.max(0, Number(gapMm || 0));
  const tolerance = 0.12;
  const targetId = nameCutLogicalItemId(target) || target.item_id || target.id || "";
  return (items || []).some(other => {
    if (!other || other === target) return false;
    const otherId = nameCutLogicalItemId(other) || other.item_id || other.id || "";
    if (targetId && otherId && targetId === otherId && Number(target.copy_index || 1) === Number(other.copy_index || 1)) return false;
    if (Number(target.page || 1) !== Number(other.page || 1)) return false;
    const separated = (
      Number(target.x_mm) + Number(target.width_mm) + gap <= Number(other.x_mm) + tolerance ||
      Number(other.x_mm) + Number(other.width_mm) + gap <= Number(target.x_mm) + tolerance ||
      Number(target.y_mm) + Number(target.height_mm) + gap <= Number(other.y_mm) + tolerance ||
      Number(other.y_mm) + Number(other.height_mm) + gap <= Number(target.y_mm) + tolerance
    );
    return !separated;
  });
}

function nameCutLayoutWithinWorkArea(items = [], cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  return (items || []).every(item => (
    Number(item.x_mm) >= config.margin_mm - 0.01 &&
    Number(item.y_mm) >= config.margin_mm - 0.01 &&
    Number(item.x_mm) + Number(item.width_mm) <= config.width_mm - config.margin_mm + 0.01 &&
    Number(item.y_mm) + Number(item.height_mm) <= config.height_mm - config.margin_mm + 0.01
  ));
}

function nameCutLaserObjectFromLayoutItem(item = {}, layoutItems = [], cfg = nameCutLayoutConfig) {
  const config = normalizeNameCutConfig(cfg);
  const insideSafe = nameCutLayoutWithinWorkArea([item], config);
  const hasCollision = nameCutItemHasCollision(item, layoutItems, config.item_gap_mm);
  const warnings = Array.isArray(item.warnings) ? item.warnings : [];
  const errors = Array.isArray(item.errors) ? item.errors : [];
  const repairState = nameCutRepairState(item);
  const isConnectedPath = repairState !== "failed" && !errors.length && !warnings.some(message => /üretime uygun değil|path_missing/i.test(String(message || "")));
  const hasValidSize = Number(item.width_mm || 0) > 0 && Number(item.height_mm || 0) > 0;
  return {
    id: String(nameCutLogicalItemId(item) || item.item_id || item.id || ""),
    name: String(item.name_text || item.name || ""),
    xMm: Number(item.x_mm || 0),
    yMm: Number(item.y_mm || 0),
    widthMm: Number(item.width_mm || 0),
    heightMm: Number(item.height_mm || 0),
    actualPathWidthMm: Number(item.actual_path_width_mm || item.width_mm || 0),
    actualPathHeightMm: Number(item.actual_path_height_mm || item.height_mm || 0),
    rotation: Number(item.rotation || 0),
    mirrored: !!item.mirrored,
    direction: item.direction || nameCutDirectionLabel(config),
    scale: Number(item.path_scale || item.scale || 1),
    selected: !!(nameCutCanvasSelectionVisible && selectedNameCutItemId && (nameCutLogicalItemId(item) === selectedNameCutItemId || item.item_id === selectedNameCutItemId)),
    lockedAspectRatio: item.locked_aspect_ratio !== false,
    isConnectedPath,
    componentCount: Number(item.componentCount || item.component_count || (isConnectedPath ? 1 : 2)),
    detachedParts: item.detachedParts || item.detached_parts || [],
    hasDetachedDots: !!(item.hasDetachedDots || item.has_detached_dots),
    hasDisconnectedLetters: !!(item.hasDisconnectedLetters || item.has_disconnected_letters),
    hasCollision,
    minGapMm: Number(config.item_gap_mm || config.target_gap_mm || 1),
    appliedKerningFix: !!(item.appliedKerningFix || item.applied_kerning_fix),
    appliedOffsetMm: Number(item.appliedOffsetMm || item.applied_offset_mm || item.offset_mm || 0),
    appliedWeld: !!(item.appliedWeld || item.applied_weld),
    appliedDotBridge: !!(item.appliedDotBridge || item.applied_dot_bridge),
    autoRepaired: repairState === "auto_repaired",
    repairStatus: repairState,
    repairMessages: item.repairMessages || item.repair_messages || [],
    offsetMode: item.offsetMode || item.offset_mode || "",
    isInsideSafeMargin: insideSafe,
    readyForCut: isConnectedPath && !hasCollision && insideSafe && hasValidSize,
    warnings,
    errors,
    validationMode: item.validation_mode || "HEURISTIC_PREVIEW_VALIDATION_FONTTOOLS_EXPORT_PATH"
  };
}

function nameCutAttachLaserObjectModel(items = [], cfg = nameCutLayoutConfig) {
  return (items || []).map(item => {
    const model = nameCutLaserObjectFromLayoutItem(item, items, cfg);
    return {
      ...item,
      laser_name_object: model,
      id: item.id || model.id,
      name: model.name,
      xMm: model.xMm,
      yMm: model.yMm,
      widthMm: model.widthMm,
      heightMm: model.heightMm,
      actualPathWidthMm: model.actualPathWidthMm,
      actualPathHeightMm: model.actualPathHeightMm,
      mirrored: model.mirrored,
      direction: model.direction,
      scale: model.scale,
      selected: model.selected,
      lockedAspectRatio: model.lockedAspectRatio,
      isConnectedPath: model.isConnectedPath,
      componentCount: model.componentCount,
      component_count: model.componentCount,
      detachedParts: model.detachedParts,
      detached_parts: model.detachedParts,
      hasDetachedDots: model.hasDetachedDots,
      has_detached_dots: model.hasDetachedDots,
      hasDisconnectedLetters: model.hasDisconnectedLetters,
      has_disconnected_letters: model.hasDisconnectedLetters,
      appliedKerningFix: model.appliedKerningFix,
      applied_kerning_fix: model.appliedKerningFix,
      appliedOffsetMm: model.appliedOffsetMm,
      applied_offset_mm: model.appliedOffsetMm,
      appliedWeld: model.appliedWeld,
      applied_weld: model.appliedWeld,
      appliedDotBridge: model.appliedDotBridge,
      applied_dot_bridge: model.appliedDotBridge,
      autoRepaired: model.autoRepaired,
      auto_repaired: model.autoRepaired,
      repairStatus: model.repairStatus,
      repair_status: model.repairStatus,
      repairMessages: model.repairMessages,
      repair_messages: model.repairMessages,
      offsetMode: model.offsetMode,
      offset_mode: model.offsetMode,
      hasCollision: model.hasCollision,
      isInsideSafeMargin: model.isInsideSafeMargin,
      readyForCut: model.readyForCut
    };
  });
}

function currentNameCutLayout() {
  return buildNameCutPreviewLayout(nameCutLiveItems(), nameCutLayoutConfig);
}

function nameCutPanels(ids) {
  return ids.map(id => byId(id)).filter(Boolean);
}

function setNameCutExportStatus(text = "") {
  nameCutPanels(["nameCutExportStatus", "nameCutStudioExportStatus"]).forEach(el => {
    el.textContent = text;
  });
}

function refreshNameCutStudioViews(layout = currentNameCutLayout()) {
  renderNameCutGallery();
  renderNameCutDetail();
  renderNameCutSourceList(layout);
  renderNameCutTransferHistory();
  renderNameCutExportHistory();
  renderNameCutControlStats(layout);
  renderNameCutBottomDetails(layout);
  renderLaserLayoutPreview(layout);
  renderNameCutStudioSummary(layout);
  renderNameCutExportPanel(combinedProductionState);
  renderNameCutCorelReferencePanel();
}

function nameCutSourceLabel(item = {}) {
  if (item.source_label) return String(item.source_label);
  const source = String(item.source || "").toLowerCase();
  if (source === "bulk_production") return "Toplu Üretim";
  if (source === "manual_label") return "Manuel Etiket";
  if (source === "etiket_studio") return "Etiket Studio";
  if (source === "trendyol") return "Trendyol";
  return item.bulk_row_id ? "Toplu Üretim" : "Manuel";
}

function nameCutSourceBadgeHtml(item = {}) {
  const label = nameCutSourceLabel(item);
  const key = String(item.source || label).toLowerCase();
  const cls = key.includes("bulk") || /toplu/i.test(label) ? "bulk" : key.includes("trendyol") ? "trendyol" : key.includes("studio") ? "studio" : "manual";
  return `<span class="name-cut-source-badge ${cls}">${esc(label)}</span>`;
}

function nameCutReferenceSourceHtml(item = {}) {
  const source = String(item.source || item.pathSource || item.path_source || "").toLowerCase();
  const status = String(item.corelReferenceStatus || item.corel_reference_status || item.repairStatus || item.repair_status || "").toLowerCase();
  const exact = source === "corel_exact_reference" || item.exactReferenceFound || item.exact_reference_found || item.corelReferenceOverrideApplied || item.corel_reference_override_applied;
  const review = item.requiresOperatorReview || item.requires_operator_review || item.exactReferenceRequired || item.exact_reference_required || status.includes("review") || status.includes("missing");
  const mismatch = status.includes("mismatch");
  const refId = item.referenceId || item.reference_id || item.corelReferenceSelectedObjectId || item.corel_reference_selected_object_id || item.corelReferencePath || "";
  if (exact && !mismatch) {
    return `<div class="name-cut-reference-line"><span class="name-cut-reference-badge ok">COREL EXACT REF</span><small>Corel referansından kullanıldı${refId ? ` · ${esc(fileName(refId))}` : ""}</small></div>`;
  }
  if (mismatch) {
    return `<div class="name-cut-reference-line"><span class="name-cut-reference-badge danger">REVIEW REQUIRED</span><small>Canvas/export/reference hash eşleşmedi; üretim öncesi kontrol gerekli.</small></div>`;
  }
  if (review || source === "corel_style_reproducer" || source === "corel_style_ai_generated" || source === "internal_ai_assisted_name_engine") {
    const sourceText = source === "internal_ai_assisted_name_engine"
      ? "Corel exact etiketi yok, internal vector engine ile üretildi."
      : "Corel exact etiketi yok, AI destekli stil profilinden üretildi.";
    return `<div class="name-cut-reference-line"><span class="name-cut-reference-badge warn">MISSING EXACT LABEL</span><small>${sourceText}</small></div>`;
  }
  return `<div class="name-cut-reference-line"><span class="name-cut-reference-badge warn">STYLE GENERATED</span><small>Üretim öncesi kontrol gerekli.</small></div>`;
}

function nameCutPathDataForReference(item = {}) {
  return String(item.finalCutPathData || item.final_cut_path_data || item.weldedCutPathData || item.welded_cut_path_data || item.path_data || "").trim();
}

function nameCutPathBBox(pathData = "") {
  const values = String(pathData || "").match(/[-+]?(?:\d*\.\d+|\d+)/g)?.map(Number) || [];
  if (values.length < 4) return null;
  const xs = values.filter((_, index) => index % 2 === 0);
  const ys = values.filter((_, index) => index % 2 === 1);
  if (!xs.length || !ys.length) return null;
  return {
    minX: Math.min(...xs),
    minY: Math.min(...ys),
    maxX: Math.max(...xs),
    maxY: Math.max(...ys)
  };
}

function nameCutPathPreviewSvg(pathData = "", mode = "outline") {
  const bbox = nameCutPathBBox(pathData);
  const viewBox = bbox
    ? `${bbox.minX - 8} ${bbox.minY - 8} ${Math.max(1, bbox.maxX - bbox.minX + 16)} ${Math.max(1, bbox.maxY - bbox.minY + 16)}`
    : "0 0 800 600";
  const attrs = mode === "fill"
    ? `fill="black" fill-rule="evenodd" stroke="none"`
    : `fill="none" stroke="black" stroke-width="1.2" vector-effect="non-scaling-stroke"`;
  return `<svg viewBox="${esc(viewBox)}" role="img" aria-label="İsim Kesim path proof"><path d="${esc(pathData)}" ${attrs}/></svg>`;
}

function nameCutGeneratedReferenceEligible(item = {}) {
  const source = String(item.source || item.pathSource || item.path_source || "").toLowerCase();
  const pathData = nameCutPathDataForReference(item);
  const pathOnly = item.pathOnlyExportPassed || item.path_only_export_passed || item.isPathOnly || item.is_path_only;
  const canvasExportSame = item.canvasExportConsistencyPassed || item.canvas_export_consistency_passed || (
    item.canvasPathHash && item.exportPathHash && item.canvasPathHash === item.exportPathHash
  );
  const manufacturable = String(item.manufacturabilityStatus || item.manufacturability_status || "") === "manufacturable_passed";
  return (source === "corel_style_reproducer" || source === "corel_style_ai_generated" || source === "internal_ai_assisted_name_engine") && Boolean(pathData) && Boolean(pathOnly) && Boolean(canvasExportSame) && manufacturable;
}

function nameCutGeneratedReferenceActionsHtml(item = {}, original = {}) {
  if (!nameCutGeneratedReferenceEligible(item)) return "";
  const itemId = original.item_id || item.source_item_id || item.item_id || selectedNameCutItemId || "";
  const opened = Boolean(nameCutGeneratedReferenceReviewState.openedByItemId[itemId]);
  return `
    <div class="safe-note compact name-cut-generated-reference-actions">
      <b>Style generated aday</b><br>
      Bu çıktı exact Corel referansı değildir. Büyük proof kontrolünden sonra operatör onayıyla referans kütüphanesine eklenebilir.
      <label class="check-row">
        <input id="nameCutGeneratedReferenceConfirm" type="checkbox" />
        Bu çıktıyı üretim referansı olarak onaylıyorum.
      </label>
      <div class="toolbar">
        <button class="btn small" type="button" onclick="openNameCutGeneratedReferenceReview()">Büyük proof aç</button>
        <button class="btn small primary" type="button" onclick="saveSelectedNameCutGeneratedReference()" ${opened && bridge?.saveOperatorGeneratedCorelReference ? "" : "disabled"}>Bu çıktıyı referans olarak kaydet</button>
      </div>
      ${opened ? `<small>Preview açıldı. Onay kutusu işaretlenirse exact reference olarak kaydedilebilir.</small>` : `<small>Kaydetmeden önce büyük proof açılmalı.</small>`}
    </div>
  `;
}

function selectedNameCutPlacementForGeneratedReference() {
  const item = explicitSelectedNameCutItem();
  if (!item) return { item: null, placed: null };
  const layout = currentNameCutLayout();
  const placedBase = nameCutPlacedItemForSource(item.item_id, layout) || item;
  const pathRow = (layout.paths || []).find(row => (
    row.source_item_id === item.item_id
    || row.item_id === item.item_id
    || row.object_id === placedBase.object_id
    || row.placement_id === placedBase.placement_id
  ));
  const placed = pathRow ? { ...placedBase, ...pathRow } : placedBase;
  return { item, placed };
}

function closeNameCutGeneratedReferenceReview() {
  document.querySelector(".name-cut-generated-reference-modal")?.remove();
}

function openNameCutGeneratedReferenceReview() {
  const { item, placed } = selectedNameCutPlacementForGeneratedReference();
  if (!item || !placed || !nameCutGeneratedReferenceEligible(placed)) {
    showToast("Bu isim operator exact referans kaydı için uygun bir style-generated aday değil.", "warning");
    return;
  }
  const pathData = nameCutPathDataForReference(placed);
  const modal = document.createElement("div");
  modal.className = "name-cut-reference-modal name-cut-generated-reference-modal";
  modal.innerHTML = `
    <div class="name-cut-reference-modal-card wide">
      <div class="panel-head compact">
        <h3>Style Generated Reference Proof</h3>
        <button class="icon-btn" type="button" onclick="closeNameCutGeneratedReferenceReview()" aria-label="Kapat">×</button>
      </div>
      <div class="safe-note compact warn">Bu proof onaylanırsa aynı isim sonraki girişte yeniden üretilmez; Corel exact reference olarak kullanılır.</div>
      <div class="name-cut-reference-modal-grid">
        <span><b>İsim</b><small>${esc(item.name_text || item.preview_text || "-")}</small></span>
        <span><b>Source</b><small>${esc(placed.source || "-")}</small></span>
        <span><b>Manufacturability</b><small>${esc(placed.manufacturabilityStatus || placed.manufacturability_status || "-")}</small></span>
        <span><b>Canvas/Export</b><small>${placed.canvasPathHash && placed.exportPathHash && placed.canvasPathHash === placed.exportPathHash ? "Eşleşiyor" : "Kontrol gerekli"}</small></span>
      </div>
      <div class="name-cut-generated-proof-grid">
        <section><b>Outline</b>${nameCutPathPreviewSvg(pathData, "outline")}</section>
        <section><b>Filled silhouette</b>${nameCutPathPreviewSvg(pathData, "fill")}</section>
        <section><b>Export proof</b>${nameCutPathPreviewSvg(pathData, "outline")}</section>
        <section><b>Risk / Türkçe mark özeti</b>
          <div class="safe-note compact">
            <span>Internal garbage: ${esc(String(placed.internalGarbagePath || placed.internal_garbage_path || false))}</span><br>
            <span>Mark ownership: ${esc(String(placed.markOwnershipPassed ?? placed.mark_ownership_passed ?? "-"))}</span><br>
            <span>Repair: ${esc(placed.repairStatus || placed.repair_status || "-")}</span>
          </div>
        </section>
      </div>
      <div class="toolbar">
        <button class="btn primary" type="button" onclick="nameCutGeneratedReferenceReviewState.openedByItemId[${jsArg(item.item_id || "")}] = true; closeNameCutGeneratedReferenceReview(); renderNameCutDetail();">Proofu gördüm</button>
      </div>
    </div>
  `;
  document.body.appendChild(modal);
}

function saveSelectedNameCutGeneratedReference() {
  const { item, placed } = selectedNameCutPlacementForGeneratedReference();
  if (!item || !placed || !nameCutGeneratedReferenceEligible(placed)) {
    showToast("Kaydedilecek uygun style-generated final path yok.", "warning");
    return;
  }
  const itemId = item.item_id || "";
  if (!nameCutGeneratedReferenceReviewState.openedByItemId[itemId]) {
    showToast("Önce büyük proof açılmalı.", "warning");
    return;
  }
  if (byId("nameCutGeneratedReferenceConfirm")?.checked !== true) {
    showToast("Operator onay kutusu işaretlenmeden referans kaydedilemez.", "warning");
    return;
  }
  if (!bridge?.saveOperatorGeneratedCorelReference) {
    showToast("Operator generated reference bridge bu oturumda bağlı değil.", "warning");
    return;
  }
  const pathData = nameCutPathDataForReference(placed);
  const payload = {
    name: item.name_text || item.preview_text || "",
    manualNameLabel: item.name_text || item.preview_text || "",
    source: placed.source || placed.pathSource || placed.path_source || "internal_ai_assisted_name_engine",
    finalCutPathData: pathData,
    actualPathWidthMm: placed.actual_path_width_mm || placed.actualPathWidthMm || placed.width_mm || 80,
    actualPathHeightMm: placed.actual_path_height_mm || placed.actualPathHeightMm || placed.height_mm || 40,
    componentCount: placed.componentCount || placed.component_count || 1,
    pathOnlyExportPassed: placed.pathOnlyExportPassed || placed.path_only_export_passed || true,
    canvasExportConsistencyPassed: placed.canvasExportConsistencyPassed || placed.canvas_export_consistency_passed || (placed.canvasPathHash && placed.exportPathHash && placed.canvasPathHash === placed.exportPathHash),
    manufacturabilityStatus: placed.manufacturabilityStatus || placed.manufacturability_status || "",
    canvasPathHash: placed.canvasPathHash || placed.canvas_path_hash || "",
    exportPathHash: placed.exportPathHash || placed.export_path_hash || "",
    operatorPreviewOpened: true,
    operatorConfirmation: true,
    duplicateAction: "keep_existing"
  };
  bridge.saveOperatorGeneratedCorelReference(JSON.stringify(payload), raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      showToast("Style generated çıktı yeni exact reference olarak kaydedildi.", "success");
      loadNameCutCorelReferences({ mode: "exact" });
      refreshNameCutStudioViews(currentNameCutLayout());
    } else if (result.status === "DUPLICATE_REFERENCE") {
      showToast(result.message || "Bu isim için exact reference zaten var; mevcut referans korundu.", "warning");
    } else {
      showToast(result.message || "Yeni exact reference kaydedilemedi.", "error");
    }
  });
}

function renderNameCutSourceList(layout = currentNameCutLayout()) {
  const list = byId("nameCutSourceList");
  const statsBox = byId("nameCutSourceStats");
  const live = nameCutLiveItems();
  const placedIds = new Set((layout.items || []).map(item => item.source_item_id || item.item_id));
  const warningCount = live.filter(item => (item.warnings || []).length || hasTurkishDiacriticForCutting(item.name_text || "")).length;
  const notPlaced = (layout.unplaced || []).length;
  if (statsBox) {
    statsBox.innerHTML = `
      <span>Toplam <b>${esc(nameCutItems.length)}</b></span>
      <span>Seçili <b>${selectedNameCutItemId ? 1 : 0}</b></span>
      <span>Yerleşen <b>${esc((layout.items || []).length)}</b></span>
      <span>Sığmayan <b>${esc(notPlaced)}</b></span>
    `;
  }
  if (!list) return;
  if (!live.length) {
    list.innerHTML = `<div class="empty-state compact"><b>İsim yok.</b><p>Manuel ekleyin, Excel’den alın veya Toplu Üretim’den lazer isimlerini gönderin.</p></div>`;
    return;
  }
  list.innerHTML = live.map((item, index) => {
    const selected = item.item_id === selectedNameCutItemId ? "selected" : "";
    const [label, tone] = nameCutStatus(item);
    const placed = placedIds.has(item.item_id) || [...placedIds].some(id => String(id).startsWith(`${item.item_id}-`));
    const risk = nameCutRepairMeta(item).label || (placed ? "Yerleşti" : "Hazırlanıyor");
    return `
      <button class="name-cut-source-row ${selected}" type="button" onclick="selectNameCutItem(${jsArg(item.item_id || "")})">
        <input type="checkbox" ${selected ? "checked" : ""} tabindex="-1" />
        <small>${esc(index + 1)}</small>
        <b>${esc(item.name_text || "-")}</b>
        <span class="status-dot ${tone}" title="${esc(label)}"></span>
        <em>${nameCutSourceBadgeHtml(item)} ${esc(risk)}</em>
      </button>
    `;
  }).join("");
  const status = byId("nameCutLayerStatus");
  if (status) status.textContent = `Seçili Nesne: ${selectedNameCutItemId ? 1 : 0}`;
  const placedStatus = byId("nameCutPlacedStatus");
  const metrics = nameCutSourceMetrics(layout);
  if (placedStatus) placedStatus.textContent = `Yerleşen isim: ${metrics.source_placed} / ${metrics.source_total} · Yerleşen adet: ${metrics.copies_placed} / ${metrics.copies_total}`;
  const areaStatus = byId("nameCutAreaStatus");
  if (areaStatus) areaStatus.textContent = `Kullanılan Alan: %${(layout.summary || {}).used_area_percent || 0}`;
  const timeStatus = byId("nameCutTimeStatus");
  if (timeStatus) timeStatus.textContent = `Tahmini Kesim Süresi: ${formatNameCutTime((layout.summary || {}).estimated_cut_time_seconds || 0)}`;
  renderNameCutTransferHistory();
  const sizeLabel = byId("nameCutBoardSizeLabel");
  if (sizeLabel) sizeLabel.textContent = `${Number((layout.config || {}).width_mm || 800).toFixed(2)} mm x ${Number((layout.config || {}).height_mm || 600).toFixed(2)} mm`;
  const scaleStatus = byId("nameCutScaleStatus");
  if (scaleStatus) scaleStatus.textContent = `Ölçek: %${Math.round(Number(nameCutLayoutConfig.preview_zoom || 100))}`;
  if (warningCount && !notPlaced) {
    const control = byId("nameCutControlStats");
    if (control && !control.innerHTML) control.innerHTML = `<div class="safe-note warning">${warningCount} isimde nokta/küçük parça kontrolü önerilir. Bağlantı yalnızca isim içinde yapılır.</div>`;
  }
}

function formatNameCutTime(seconds = 0) {
  const value = Math.max(0, Number(seconds || 0));
  const minutes = Math.floor(value / 60);
  const rest = Math.round(value % 60);
  return `${String(minutes).padStart(2, "0")}:${String(rest).padStart(2, "0")}`;
}

function renderNameCutControlStats(layout = currentNameCutLayout()) {
  const box = byId("nameCutControlStats");
  if (!box) return;
  const live = nameCutLiveItems();
  const summary = layout.summary || {};
  const metrics = nameCutSourceMetrics(layout);
  const qualities = live.map(item => nameCutSinglePieceQuality(item, layout));
  const countStatus = status => qualities.filter(quality => quality.status === status).length;
  const readyCount = countStatus("ready_single_piece");
  const weldCount = countStatus("needs_weld");
  const offsetCount = countStatus("needs_offset");
  const markCount = countStatus("detached_marks");
  const collisionCount = countStatus("collision_risk");
  const blockedCount = countStatus("blocked");
  const dotRisks = markCount || live.filter(item => hasTurkishDiacriticForCutting(item.name_text || "")).length;
  const longNames = live.filter(item => String(item.name_text || "").replace(/\s+/g, "").length >= 18).length;
  const issues = [
    weldCount ? `${weldCount} isimde weld/path birleşimi kontrolü` : "",
    offsetCount ? `${offsetCount} isimde kalınlaştırma gerekli` : "",
    markCount ? `${markCount} isimde nokta/işaret kopuk` : "",
    longNames ? `${longNames} uzun isimde yatay daraltma önerisi` : "",
    summary.unplaced_count ? `${summary.unplaced_count} isim tabla dışı kaldı` : "",
    collisionCount || summary.collision_free === false ? "Minimum boşluk ihlali veya temas riski var" : "",
    summary.within_work_area === false ? "Tabla dışına taşma var" : "",
    blockedCount ? `${blockedCount} isim üretime engel durumda` : ""
  ].filter(Boolean);
  const cfg = layout.config || normalizeNameCutConfig(nameCutLayoutConfig);
  const nestingMode = cfg.dense_nesting === false ? "Standart" : "Sıkı";
  box.innerHTML = `
    <div class="name-cut-control-grid">
      <span>Tabla en <b>${esc(cfg.width_mm || 800)} mm</b></span>
      <span>Tabla boy <b>${esc(cfg.height_mm || 600)} mm</b></span>
      <span>Hedef isim genişliği <b>${esc(cfg.target_name_width_mm || 80)} mm</b></span>
      <span>Hedef isim yüksekliği <b>${esc(cfg.target_name_height_mm || 40)} mm</b></span>
      <span>İsimler arası boşluk <b>${esc(summary.target_gap_mm || cfg.target_gap_mm || cfg.item_gap_mm || 1)} mm</b></span>
      <span>Safe margin <b>${esc(cfg.margin_mm || 15)} mm</b></span>
      <span>Nesting modu <b>${esc(nestingMode)}</b></span>
      <span>Yerleşen isim <b>${esc(metrics.source_placed)} / ${esc(metrics.source_total)}</b></span>
      <span>Yerleşen adet <b>${esc(metrics.copies_placed)} / ${esc(metrics.copies_total)}</b></span>
      <span>Tek parça hazır <b>${esc(readyCount)}</b></span>
      <span>Weld gerekli <b>${esc(weldCount)}</b></span>
      <span>Nokta/işaret kontrolü <b>${esc(dotRisks)}</b></span>
      <span>Kalınlaştırma gerekli <b>${esc(offsetCount)}</b></span>
      <span>Temas riski <b>${esc(collisionCount || (summary.collision_free === false ? 1 : 0))}</b></span>
      <span>Kesim yönü <b>${esc(nameCutDirectionLabel(layout.config || nameCutLayoutConfig))}</b></span>
      <span>Kullanılan alan <b>%${esc(summary.used_area_percent || 0)}</b></span>
      <span>Çıktı <b>${issues.length ? "Kontrol gerekli" : "Kontrol temiz"}</b></span>
    </div>
    ${issues.length ? `<div class="safe-note warning">${issues.map(esc).join("<br>")}</div>` : `<div class="safe-note compact">Ön kontrol temiz. Aynı isim içindeki harf/nokta/işaret tek parça; farklı isimler 1 mm boşlukla ayrı ve temas etmeden dizilir.</div>`}
  `;
}

function renderNameCutBottomDetails(layout = currentNameCutLayout()) {
  const box = byId("nameCutBottomDetails");
  if (!box) return;
  const rows = (layout.items || []).slice(0, 120);
  box.innerHTML = `
    <div class="name-cut-detail-table">
      <div class="head">No</div><div class="head">İsim</div><div class="head">Adet</div><div class="head">Kaynak</div><div class="head">Tek parça</div><div class="head">Weld</div><div class="head">Offset</div><div class="head">Nokta/İşaret</div><div class="head">Temas</div><div class="head">Yön</div><div class="head">Hazır?</div>
      ${rows.map((item, idx) => {
        const quality = nameCutSinglePieceQuality(item, layout);
        return `
        <span>${esc(idx + 1)}</span>
        <b>${esc(item.name_text || "-")}</b>
        <span>${esc(item.copy_index || 1)} / ${esc(item.quantity || 1)}</span>
        <span>${nameCutSourceBadgeHtml(nameCutOriginalItem(item))}</span>
        <span>${nameCutQualityBadgeHtml(quality)}</span>
        <span>${esc(quality.weld)}</span>
        <span>${esc(quality.offset)}</span>
        <span>${esc(quality.marks)}</span>
        <span>${esc(quality.collision)}</span>
        <span>${esc(quality.direction)}</span>
        <span>${quality.production_ready ? "Evet" : "Kontrol"}</span>
      `;
      }).join("")}
    </div>
  `;
}

function normalizeNameCutPersistentItem(item = {}) {
  const status = String(item.status || "pending_preparation").trim().toUpperCase();
  const normalizedStatus = status === "PENDING_PREPARATION" || status === "NEEDS_REVIEW" || status === "BLOCKED" || status === "PREPARED" || status === "EXPORTED"
    ? status
    : status === "ERROR" ? "BLOCKED" : status || "PENDING_PREPARATION";
  const itemId = String(item.item_id || item.id || item.bulk_row_id || `namecut-${Date.now()}`);
  return {
    ...item,
    id: String(item.id || itemId),
    item_id: itemId,
    source: item.source || "bulk_production",
    source_label: item.source_label || nameCutSourceLabel(item),
    name_text: item.name_text || item.laser_name || "",
    laser_name: item.laser_name || item.name_text || "",
    preview_text: item.preview_text || item.laser_name || item.name_text || "",
    quantity: String(item.quantity || "1"),
    status: normalizedStatus,
    warnings: Array.isArray(item.warnings) ? item.warnings : [],
    errors: Array.isArray(item.errors) ? item.errors : [],
    safety_flags: Array.isArray(item.safety_flags) ? item.safety_flags : [],
    duplicate_key: item.duplicate_key || (item.bulk_row_id ? `${item.source || "bulk_production"}:${item.bulk_row_id}` : itemId),
    persistent_queue: true
  };
}

function syncNameCutQueueFromPersistence(rows = [], history = [], exportHistory = nameCutExportHistoryRows) {
  const persistentRows = Array.isArray(rows) ? rows.map(normalizeNameCutPersistentItem) : [];
  nameCutTransferHistoryRows = Array.isArray(history) ? history : [];
  nameCutExportHistoryRows = Array.isArray(exportHistory) ? exportHistory : [];
  if (!persistentRows.length) {
    renderNameCutTransferHistory();
    renderNameCutExportHistory();
    return;
  }
  const persistentKeys = new Set(persistentRows.map(item => item.duplicate_key || item.item_id).filter(Boolean));
  const persistentIds = new Set(persistentRows.map(item => item.item_id).filter(Boolean));
  const edited = new Map((nameCutItems || [])
    .filter(item => item.is_edited || item.is_deleted)
    .map(item => [item.duplicate_key || item.item_id, item]));
  const localOnly = (nameCutItems || []).filter(item => {
    const key = item.duplicate_key || item.item_id;
    if (persistentKeys.has(key) || persistentIds.has(item.item_id)) return false;
    return item.source !== "bulk_production" || !item.bulk_row_id;
  });
  const mergedPersistent = persistentRows.map(item => {
    const editedItem = edited.get(item.duplicate_key || item.item_id);
    return editedItem ? { ...item, ...editedItem, persistent_queue: true } : item;
  });
  nameCutItems = [...localOnly, ...mergedPersistent].map((item, index) => ({ ...item, row_number: item.row_number || index + 1 }));
  if (!selectedNameCutItemId || !nameCutItems.some(item => item.item_id === selectedNameCutItemId)) {
    selectedNameCutItemId = (nameCutItems.find(item => !item.is_deleted) || nameCutItems[0] || {}).item_id || "";
  }
  refreshNameCutStudioViews(currentNameCutLayout());
}

function renderNameCutTransferHistory(history = nameCutTransferHistoryRows) {
  const box = byId("nameCutTransferHistory");
  if (!box) return;
  const rows = Array.isArray(history) ? [...history].slice(-5).reverse() : [];
  if (!rows.length) {
    box.innerHTML = `
      <div class="section-mini-head"><b>Toplu Üretim Aktarımları</b><span>Kalıcı</span></div>
      <div class="empty-state compact"><b>Aktarım geçmişi yok.</b><p>Toplu Üretim’den gönderilen lazer hazırlık batch’leri burada kalıcı olarak görünür.</p></div>
    `;
    return;
  }
  box.innerHTML = `
    <div class="section-mini-head"><b>Toplu Üretim Aktarımları</b><span>Kalıcı</span></div>
    ${rows.map(row => `
      <article class="name-cut-transfer-row">
        <div>
          <b>${esc(row.transfer_batch_id || "-")}</b>
          <span>${esc(row.created_at || "-")}</span>
        </div>
        <p>
          <span>Eklenen <b>${esc(row.added || 0)}</b></span>
          <span>Kontrol <b>${esc(row.needs_review || 0)}</b></span>
          <span>Engel <b>${esc(row.blocked || 0)}</b></span>
          <span>Duplicate <b>${esc(row.duplicate || 0)}</b></span>
        </p>
      </article>
    `).join("")}
  `;
}

function renderNameCutExportHistory(history = nameCutExportHistoryRows) {
  const boxes = [...nameCutPanels(["nameCutStudioExportHistory"]), ...document.querySelectorAll("[data-namecut-export-history]")];
  if (!boxes.length) return;
  const rows = Array.isArray(history) ? [...history].slice(-5).reverse() : [];
  const html = rows.length ? `
    <div class="section-mini-head"><b>Export Geçmişi</b><span>Kalıcı</span></div>
    ${rows.map(row => {
      const files = row.exported_files || {};
      return `
        <article class="name-cut-transfer-row name-cut-export-row">
          <div>
            <b>${esc(row.export_batch_id || "-")}</b>
            <span>${esc(row.created_at || "-")}</span>
          </div>
          <p>
            <span>Format <b>${esc((row.formats || []).join(", ") || "-")}</b></span>
            <span>Adet <b>${esc(row.quantity_total || 0)}</b></span>
            <span>Yön <b>${esc(row.cut_direction || "-")}</b></span>
            <span>Durum <b>${esc(row.status || "-")}</b></span>
          </p>
          ${files.manifest ? `<small title="${esc(files.manifest)}">Manifest: ${esc(fileName(files.manifest))}</small>` : ""}
        </article>
      `;
    }).join("")}
  ` : `
    <div class="section-mini-head"><b>Export Geçmişi</b><span>Kalıcı</span></div>
    <div class="empty-state compact"><b>Export geçmişi yok.</b><p>Güvenli export paketleri burada manifest ve dosya bilgisiyle kalıcı görünür.</p></div>
  `;
  boxes.forEach(box => { box.innerHTML = html; });
}

function updateCombinedProduction(payload = {}) {
  combinedProductionState = payload || {};
  const incoming = Array.isArray(payload.name_cut_items) ? payload.name_cut_items : [];
  const edited = new Map((nameCutItems || []).filter(item => item.is_edited || item.is_deleted).map(item => [item.item_id, item]));
  nameCutItems = incoming.map(item => edited.get(item.item_id) || { ...item });
  if (!selectedNameCutItemId || !nameCutItems.some(item => item.item_id === selectedNameCutItemId)) {
    selectedNameCutItemId = (nameCutItems.find(item => !item.is_deleted) || nameCutItems[0] || {}).item_id || "";
  }
  renderCombinedProductionSummary();
  renderCombinedOrders();
  const layout = nameCutItems.length ? currentNameCutLayout() : (payload.layout || {});
  refreshNameCutStudioViews(layout);
}

function renderCombinedProductionSummary() {
  const summary = combinedProductionState.summary || {};
  const box = byId("combinedSummaryGrid");
  if (!box) return;
  const cells = [
    ["Toplam Satır", summary.total_rows || 0, "Excel satırı"],
    ["Etiket İşleri", summary.label_jobs || 0, "Etiket üretimi"],
    ["İsim Kesim", summary.name_cut_jobs || 0, "Lazer hazırlık"],
    ["İkisi Birden", summary.both_jobs || 0, "Çift üretim"],
    ["Üretim Yok", summary.no_production || 0, "Uyarılı satır"],
    ["Toplam Adet", summary.total_quantity || 0, "Sipariş adedi"]
  ];
  box.innerHTML = cells.map(([label, value, hint]) => `
    <div class="combined-kpi">
      <span>${esc(label)}</span>
      <b>${esc(value)}</b>
      <small>${esc(hint)}</small>
    </div>
  `).join("");
}

function renderNameCutStudioSummary(layout = currentNameCutLayout()) {
  const box = byId("nameCutStudioSummaryGrid");
  if (!box) return;
  const liveItems = nameCutLiveItems();
  const warningCount = liveItems.filter(item => (item.warnings || []).length || String(item.status || "").toUpperCase() === "WARNING").length;
  const deletedCount = (nameCutItems || []).filter(item => item.is_deleted).length;
  const summary = layout.summary || {};
  const cells = [
    ["Kesime Hazır", liveItems.length, "Aktif isim işi"],
    ["Toplam Adet", summary.total_copies || 0, "Kesilecek kopya"],
    ["Plate / Sayfa", summary.pages || 0, "RDWorks çalışma alanı"],
    ["Kullanılan Alan", `${summary.used_area_percent || 0}%`, "Tahmini doluluk"],
    ["Fire", `${summary.waste_percent || 0}%`, "Boş alan"],
    ["Uyarı / Silinen", `${warningCount} / ${deletedCount}`, "Kontrol gerektiren"]
  ];
  box.innerHTML = cells.map(([label, value, hint]) => `
    <div class="combined-kpi">
      <span>${esc(label)}</span>
      <b>${esc(value)}</b>
      <small>${esc(hint)}</small>
    </div>
  `).join("");
}

function renderCombinedOrders() {
  const box = byId("combinedOrdersList");
  if (!box) return;
  const orders = combinedProductionState.orders || [];
  if (!orders.length) {
    box.innerHTML = `<div class="empty-state compact"><b>Birleşik sipariş bekleniyor.</b><p>Excel yüklendiğinde etiket ve isim kesim kararları burada görünür.</p></div>`;
    return;
  }
  box.innerHTML = orders.slice(0, 8).map(order => {
    const tags = [
      order.label_required ? `<span class="pill ok">Etiket</span>` : "",
      order.name_cut_required ? `<span class="pill purple">İsim Kesim</span>` : "",
      (!order.label_required && !order.name_cut_required) ? `<span class="pill warn">Üretim Yok</span>` : ""
    ].join("");
    const problems = [...(order.errors || []), ...(order.warnings || [])];
    return `
      <div class="combined-order-row ${problems.length ? "has-warning" : ""}">
        <b>${esc(order.customer_name || "-")}</b>
        <span>${esc(order.date_text || "-")} · Adet: ${esc(order.quantity || "1")}</span>
        <div>${tags}</div>
        ${problems.length ? `<small>${problems.map(esc).join(" · ")}</small>` : ""}
      </div>
    `;
  }).join("");
}

function nameCutRepairState(item = {}) {
  const laser = item.laser_name_object || item.laserNameObject || {};
  const status = String(item.repairStatus || item.repair_status || laser.repairStatus || item.layout_result?.repairStatus || "").trim();
  if (status && NAME_CUT_REPAIR_STATUS_META[status]) return status;
  if (item.readyForCut === false || item.ready_for_cut === false || laser.readyForCut === false) return "failed";
  if (item.autoRepaired || item.auto_repaired || laser.autoRepaired) return "auto_repaired";
  return "clean";
}

function nameCutRepairMeta(item = {}) {
  return NAME_CUT_REPAIR_STATUS_META[nameCutRepairState(item)] || NAME_CUT_REPAIR_STATUS_META.failed;
}

function nameCutRepairSummaryHtml(item = {}) {
  const meta = nameCutRepairMeta(item);
  const messages = item.repairMessages || item.repair_messages || item.laser_name_object?.repairMessages || item.layout_result?.repairMessages || [];
  const cleanMessages = (messages || []).slice(0, 4).map(message => ({
    kerning_fixed: "harf aralığı",
    offset_applied: "offset",
    weld_applied: "weld",
    marks_attached: "Türkçe işaret",
    size_normalized: "80 x 40 ölçü",
    ai_quality_candidates_scored: "AI kalite kontrol",
    ai_quality_selected: "en iyi aday seçildi",
    ai_quality_failed: "görsel kalite başarısız",
    designer_weld_plan_applied: "tasarımcı weld planı",
    manual_reference_similarity_passed: "Corel referans benzerliği",
    manufacturable_passed: "üretilebilirlik geçti",
    designer_weld_warning: "tasarımcı weld uyarılı",
    designer_weld_failed: "tasarımcı weld başarısız",
    visual_far_from_manual_reference: "referanstan uzak",
    internal_garbage_path: "kirli iç path"
  }[message] || message));
  return `<p>${esc(meta.summary)}${cleanMessages.length ? ` · ${cleanMessages.map(esc).join(", ")}` : ""}</p>`;
}

function nameCutStatus(item = {}) {
  const status = String(item.status || "").toUpperCase();
  if (item.is_deleted) return ["Silindi", "muted"];
  if (status === "BLOCKED" || status === "ERROR" || (item.errors || []).length) return ["Engelli", "bad"];
  if (status === "PENDING_PREPARATION") return ["Hazırlık bekliyor", "purple"];
  if (status === "PREPARED") return ["Hazırlandı", "ok"];
  if (status === "EXPORTED") return ["Export edildi", "ok"];
  const repairMeta = nameCutRepairMeta(item);
  if (repairMeta) return [repairMeta.label, repairMeta.tone];
  if (status === "NEEDS_REVIEW") return ["Üretime uygun değil", "bad"];
  if ((item.warnings || []).length || status === "WARNING") return ["Otomatik düzeltildi", "purple"];
  if (item.is_edited) return ["Düzenlendi", "purple"];
  return ["Hazır", "ok"];
}

function nameCutOffsetForMode(mode = "Orta") {
  const token = String(mode || "").toLocaleLowerCase("tr-TR");
  if (token.includes("yok")) return 0;
  if (token.includes("hafif")) return 0.4;
  if (token.includes("kal")) return 1.2;
  if (token.includes("özel") || token.includes("ozel")) return 0.8;
  return 0.8;
}

function formatNameCutName(value = "") {
  const corrections = {
    ayse: "Ayşe", omer: "Ömer", cagla: "Çağla", cagri: "Çağrı", cagatay: "Çağatay",
    tugce: "Tuğçe", gulsah: "Gülşah", sedef: "Sedef", sefer: "Sefer",
    mucahit: "Mücahit", mujahit: "Mücahit", leyla: "Leyla", fatma: "Fatma", ali: "Ali",
    irem: "İrem", ilker: "İlker", ibrahim: "İbrahim", oguz: "Oğuz"
  };
  return String(value || "").trim().split(/\s+/).filter(Boolean).map(word => {
    const normalized = word.toLocaleLowerCase("tr-TR");
    if (corrections[normalized]) return corrections[normalized];
    return normalized.charAt(0).toLocaleUpperCase("tr-TR") + normalized.slice(1);
  }).join(" ");
}

function hasTurkishDiacriticForCutting(value = "") {
  return /[iİıöÖüÜşŞçÇğĞ]/.test(String(value || ""));
}

function turkishDiacriticBridgeMarkup(word = "") {
  const chars = Array.from(String(word || ""));
  if (!chars.length) return "";
  return chars.map((ch, index) => {
    if (!/[iİöÖüÜğĞşŞçÇ]/.test(ch)) return "";
    const left = ((index + 0.5) / chars.length) * 100;
    const lower = /[şŞçÇ]/.test(ch) ? " lower" : "";
    const double = /[öÖüÜ]/.test(ch) ? " double" : "";
    return `<i class="diacritic-cut-bridge${lower}${double}" style="left:${left.toFixed(2)}%" aria-hidden="true"></i>`;
  }).join("");
}

function nameCutPreview(item = {}, large = false) {
  const layoutResult = nameCutLayoutResultForItem(item, { context: large ? "modal" : "card" });
  return renderNameCutComputedPreview(layoutResult, large);
}

function renderNameCutGallery() {
  const grids = nameCutPanels(["nameCutGalleryGrid", "nameCutStudioGalleryGrid"]);
  if (!grids.length) return;
  if (!nameCutItems.length) {
    const empty = `<div class="empty-state"><b>İsim kesim işi yok.</b><p>Excel’de isim_kes = evet olan satırlar veya manuel eklenen isimler burada RDWorks hazırlık işi olarak görünür.</p></div>`;
    grids.forEach(grid => { grid.innerHTML = empty; });
    return;
  }
  const layout = currentNameCutLayout();
  const html = nameCutItems.map((item, index) => {
    const [label, tone] = nameCutStatus(item);
    const quality = nameCutSinglePieceQuality(item, layout);
    const selected = item.item_id === selectedNameCutItemId ? "selected" : "";
    return `
      <article class="name-cut-card ${selected} ${item.is_deleted ? "deleted" : ""}" data-namecut-id="${esc(item.item_id || "")}" onclick="selectNameCutItem(${jsArg(item.item_id || "")})">
        <div class="name-cut-card-head">
          <span>Satır ${esc(item.row_number || index + 1)}</span>
          <span class="pill ${tone}">${esc(label)}</span>
        </div>
        ${nameCutSourceBadgeHtml(item)}
        ${nameCutQualityBadgeHtml(quality)}
        ${nameCutPreview(item)}
        <div class="name-cut-card-body">
          <b>${esc(item.name_text || "-")}</b>
          <small>${esc(item.style || "Bitişik Romantik Script")} · ${esc(item.composition_mode || item.composition || "Yan yana")} · Adet: ${esc(item.quantity || "1")}</small>
          ${item.bulk_row_id ? `<small>Toplu Üretim satırı: ${esc(item.bulk_row_id)}${item.order_no ? ` · Sipariş: ${esc(item.order_no)}` : ""}</small>` : ""}
          <small>Kesim kalınlığı: ${esc(item.thickening_mode || "Orta")} (${esc(item.offset_mm || "0.8")} mm)</small>
          ${nameCutRepairSummaryHtml(item)}
        </div>
        <div class="toolbar">
          <button class="btn small" type="button" onclick="event.stopPropagation(); openNameCutEditor(${index})">Düzenle</button>
          <button class="btn small danger-soft" type="button" onclick="event.stopPropagation(); markNameCutDeleted(${index})">Sil</button>
        </div>
      </article>
    `;
  }).join("");
  grids.forEach(grid => { grid.innerHTML = html; });
}

function selectNameCutItem(itemId) {
  selectedNameCutItemId = itemId || "";
  selectedNameCutPlacementId = "";
  nameCutCanvasSelectionVisible = true;
  renderNameCutGallery();
  renderNameCutDetail();
  renderLaserLayoutPreview(currentNameCutLayout());
}

function selectedNameCutItem() {
  return nameCutItems.find(item => item.item_id === selectedNameCutItemId) || nameCutItems.find(item => !item.is_deleted) || nameCutItems[0] || null;
}

function explicitSelectedNameCutItem() {
  return selectedNameCutItemId ? (nameCutItems.find(item => item.item_id === selectedNameCutItemId) || null) : null;
}

function renderNameCutDetail() {
  const panels = nameCutPanels(["nameCutDetailPanel", "nameCutStudioDetailPanel"]);
  if (!panels.length) return;
  const item = explicitSelectedNameCutItem();
  if (!item) {
    const cfg = normalizeNameCutConfig(nameCutLayoutConfig);
    const layout = currentNameCutLayout();
    const summary = layout.summary || {};
    const empty = `
      <div class="panel-head"><h3>Genel Nesting Ayarları</h3><span class="pill info">Seçili obje yok</span></div>
      <div class="name-cut-quality-panel compact">
        <div><span>Çalışma alanı</span><b>${esc(cfg.width_mm)} x ${esc(cfg.height_mm)} mm</b></div>
        <div><span>Safe margin</span><b>${esc(cfg.margin_mm)} mm</b></div>
        <div><span>Minimum boşluk</span><b>${esc(cfg.item_gap_mm)} mm</b></div>
        <div><span>Hedef ölçü</span><b>${esc(cfg.target_name_width_mm)} x ${esc(cfg.target_name_height_mm)} mm</b></div>
        <div><span>Dizilim modu</span><b>${cfg.dense_nesting === false ? "Standart" : "Yoğun Üretim"}</b></div>
        <div><span>Kesim yönü</span><b>${esc(nameCutDirectionLabel(cfg))}</b></div>
        <div><span>Seçili font</span><b>${esc(nameCutFontMetaByValue(cfg.font_family)?.label || cfg.font_family || "-")}</b></div>
        <div><span>Font durumu</span><b>${nameCutFontMetaByValue(cfg.font_family)?.productionCandidate ? "Production Candidate" : nameCutFontMetaByValue(cfg.font_family)?.default ? "Güvenli Default" : "Test Fontu"}</b></div>
        <div><span>Offset modu</span><b>Export path offset / proof doğrulama</b></div>
        <div><span>Yerleşen</span><b>${esc((layout.items || []).length)} iş · ${esc(summary.used_area_percent || 0)}%</b></div>
        <div><span>Path preview</span><b>${cfg.export_as_path !== false ? "FontTools export path" : "SVG outline preview"}</b></div>
      </div>
      ${nameCutFontStatusHtml(cfg.font_family)}
      ${nameCutOffsetModeStatusHtml()}
      <div class="safe-note compact">Bir ismi seçtiğinizde X/Y, genişlik/yükseklik, actual path ölçüsü, collision ve safe margin durumu burada açılır. Yardımcı çizgiler export dosyasına girmez.</div>
    `;
    panels.forEach(panel => { panel.innerHTML = empty; });
    return;
  }
  const index = nameCutItems.findIndex(row => row.item_id === item.item_id);
  const [label, tone] = nameCutStatus(item);
  const layout = currentNameCutLayout();
  const quality = nameCutSinglePieceQuality(item, layout);
  const placed = nameCutPlacedItemForSource(item.item_id, layout) || item;
  const layoutResult = nameCutLayoutResultForItem(item, { context: "inspector" });
  const repairMeta = nameCutRepairMeta({ ...item, ...placed, layout_result: layoutResult });
  const html = `
    <div class="panel-head"><h3>Seçili İsim Kesim</h3><span class="pill ${tone}">${esc(label)}</span></div>
    <div class="name-cut-detail-source">${nameCutSourceBadgeHtml(item)} ${nameCutReferenceSourceHtml(placed)}<span>Hazırlık kuyruğu · RDWorks/lazer otomatik başlamaz</span></div>
    ${nameCutGeneratedReferenceActionsHtml(placed, item)}
    ${nameCutPreview(item, true)}
    <div class="name-cut-quality-panel">
      <div><span>Otomatik pipeline</span><b>${esc(repairMeta.label)}</b></div>
      <div><span>Component</span><b>${esc(placed.componentCount || placed.component_count || layoutResult.componentCount || 1)}</b></div>
      <div><span>Kerning</span><b>${placed.appliedKerningFix || layoutResult.appliedKerningFix ? "Uygulandı" : "Gerekmedi"}</b></div>
      <div><span>Weld/union</span><b>${placed.appliedWeld || layoutResult.appliedWeld ? "Uygulandı" : "Gerekmedi"}</b></div>
      <div><span>Nokta/işaret</span><b>${placed.appliedDotBridge || layoutResult.appliedDotBridge ? "Bağlandı" : "Gerekmedi"}</b></div>
      <div><span>Kalınlaştırma</span><b>${esc(placed.appliedOffsetMm || placed.applied_offset_mm || layoutResult.appliedOffsetMm || item.offset_mm || 0)} mm</b></div>
      <div><span>Temas</span><b>${esc(quality.collision)}</b></div>
      <div><span>Kesim yönü</span><b>${esc(quality.direction)}</b></div>
    </div>
    <div class="name-cut-geometry-editor">
      <div class="section-mini-head"><b>Seçili obje ölçüleri</b><span>Hedef 80 x 40 mm</span></div>
      <div class="name-cut-geometry-grid">
        <label>X (mm)<input type="number" step="0.1" value="${esc(Number(placed.x_mm || 0).toFixed(1))}" oninput="updateSelectedNameCutGeometry('x_mm', this.value)" /></label>
        <label>Y (mm)<input type="number" step="0.1" value="${esc(Number(placed.y_mm || 0).toFixed(1))}" oninput="updateSelectedNameCutGeometry('y_mm', this.value)" /></label>
        <label>Genişlik (mm)<input type="number" min="20" step="0.1" value="${esc(Number(placed.width_mm || 80).toFixed(1))}" oninput="updateSelectedNameCutGeometry('width_mm', this.value)" /></label>
        <label>Yükseklik (mm)<input type="number" min="10" step="0.1" value="${esc(Number(placed.height_mm || 40).toFixed(1))}" oninput="updateSelectedNameCutGeometry('height_mm', this.value)" /></label>
      </div>
      <label class="check-row"><input type="checkbox" ${item.locked_aspect_ratio === false ? "" : "checked"} onchange="toggleSelectedNameCutAspectLock(this.checked)" /> Oran kilidi</label>
      <button class="btn small" type="button" onclick="resetSelectedNameCutGeometry()">Hedef ölçüye ve otomatik dizilime dön</button>
    </div>
    <div class="name-cut-info">
      <div><span>Kaynak</span><b>${esc(nameCutSourceLabel(item))}</b></div>
      <div><span>İsim</span><b>${esc(item.name_text || "-")}</b></div>
      <div><span>Bulk Satır</span><b>${esc(item.bulk_row_id || "-")}</b></div>
      <div><span>Stil</span><b>${esc(item.style || "-")}</b></div>
      <div><span>Font durumu</span><b>${nameCutFontMetaByValue(item.style || nameCutLayoutConfig.font_family)?.productionCandidate ? "Production Candidate" : nameCutFontMetaByValue(item.style || nameCutLayoutConfig.font_family)?.default ? "Güvenli Default" : "Test Fontu"}</b></div>
      <div><span>Etiket Modeli</span><b>${esc(item.label_model || "-")}</b></div>
      <div><span>Sipariş / Müşteri</span><b>${esc([item.order_no, item.customer_name].filter(Boolean).join(" · ") || "-")}</b></div>
      <div><span>Kalıcı batch</span><b>${esc(item.transfer_batch_id || "-")}</b></div>
      <div><span>Kompozisyon</span><b>${esc(nameCutCompositionLabel(layoutResult.compositionMode))}</b></div>
      <div><span>Satır modu</span><b>${esc(layoutResult.lineBreakMode || "-")}</b></div>
      <div><span>Sığma</span><b>${esc(layoutResult.fitStatus || "-")}</b></div>
      <div><span>Layout imzası</span><b>${esc(layoutResult.layoutSignature || item.layout_signature || "-")}</b></div>
      <div><span>Ölçü</span><b>${esc(Number(placed.width_mm || 0).toFixed(1))} x ${esc(Number(placed.height_mm || 0).toFixed(1))} mm</b></div>
      <div><span>Actual path</span><b>${esc(Number(layoutResult.actualPathWidthMm || placed.actual_path_width_mm || placed.width_mm || 0).toFixed(1))} x ${esc(Number(layoutResult.actualPathHeightMm || placed.actual_path_height_mm || placed.height_mm || 0).toFixed(1))} mm</b></div>
      <div><span>Path doğrulama</span><b>AutoRepairPipeline / FontTools scene</b></div>
      <div><span>Offset modu</span><b>${esc(placed.offsetMode || placed.offset_mode || layoutResult.offsetMode || "backend doğrulaması")}</b></div>
      <div><span>Safe margin</span><b>${placed.laser_name_object?.isInsideSafeMargin === false ? "Dışında" : "İçinde"}</b></div>
      <div><span>Collision</span><b>${placed.laser_name_object?.hasCollision ? "Temas riski" : "Yok"}</b></div>
      <div><span>Ready for cut</span><b>${placed.laser_name_object?.readyForCut || placed.ready_for_cut || layoutResult.readyForCut ? "Evet" : "Hayır"}</b></div>
      <div><span>Path kaynağı</span><b>${placed.source === "corel_exact_reference" ? "Corel referansından kullanıldı" : placed.source === "internal_ai_assisted_name_engine" ? "Internal Corel-like engine ile üretildi" : placed.source === "corel_style_reproducer" ? "Corel exact etiketi yok, stil profilinden üretildi" : "Üretim path"}</b></div>
      <div><span>Canvas/Export hash</span><b>${placed.canvasPathHash && placed.exportPathHash ? (placed.canvasPathHash === placed.exportPathHash && (!placed.referencePathHash || placed.referencePathHash === placed.canvasPathHash) ? "Eşleşiyor" : "Kontrol gerekli") : "-"}</b></div>
      <div><span>Kalınlaştırma</span><b>${esc(item.thickening_mode || "Orta")} · ${esc(item.offset_mm || "0.8")} mm</b></div>
      <div><span>Adet</span><b>${esc(item.quantity || "1")}</b></div>
      <div><span>Alt destek</span><b>${item.support_line ? "Açık" : "Kapalı"}</b></div>
      <div><span>Taban plaka</span><b>${item.back_plate ? "Açık" : "Kapalı"}</b></div>
    </div>
    <div class="safe-note ${repairMeta.tone === "bad" ? "warning" : "compact"}">${nameCutRepairSummaryHtml({ ...item, ...placed, layout_result: layoutResult })}</div>
    <div class="grid-actions">
      <button class="btn primary" type="button" onclick="openNameCutEditor(${index})">Düzenle</button>
      ${item.persistent_queue ? `<button class="btn" type="button" onclick="markNameCutQueueItemPrepared(${jsArg(item.item_id || item.id || "")})">Hazırlandı İşaretle</button>` : ""}
      <button class="btn" type="button" onclick="prepareNameCutFiles()">RDWorks İçin Dosya Hazırla</button>
      <button class="btn danger-soft" type="button" onclick="markNameCutDeleted(${index})">Sil</button>
    </div>
  `;
  panels.forEach(panel => { panel.innerHTML = html; });
}

function markNameCutQueueItemPrepared(itemId = "") {
  const id = String(itemId || selectedNameCutItemId || "").trim();
  if (!id) return;
  if (!bridge?.mark_name_cut_queue_item_prepared) {
    const message = "Kalıcı İsim Kesim durum güncelleme köprüsü bu oturumda hazır değil.";
    setNameCutExportStatus(message);
    if (typeof showToast === "function") showToast(message, "warning");
    return;
  }
  bridge.mark_name_cut_queue_item_prepared(id, raw => {
    const result = parseBridgeResult(raw);
    const resultStatus = String(result.status || "").toUpperCase();
    const message = result.message || "İsim Kesim hazırlık durumu güncellendi. Lazer/RDWorks başlatılmadı.";
    setNameCutExportStatus(message);
    if (resultStatus === "OK" && result.item) {
      const updated = normalizeNameCutPersistentItem(result.item);
      nameCutItems = (nameCutItems || []).map(item => (item.item_id === updated.item_id || item.id === updated.id) ? { ...item, ...updated } : item);
      refreshNameCutStudioViews(currentNameCutLayout());
      refreshState();
      if (typeof showToast === "function") showToast(message, "success");
      return;
    }
    if (typeof showToast === "function") showToast(message, "warning");
  });
}

function renderLaserLayoutPreview(layout = {}) {
  const boxes = nameCutPanels(["nameCutLayoutPreview", "nameCutStudioLayoutPreview"]);
  if (!boxes.length) return;
  const items = layout.items || [];
  const summary = layout.summary || {};
  if (!items.length) {
    const empty = `<div class="empty-state compact"><b>Lazer yerleşim bekleniyor.</b><p>İsim ekleyin veya Toplu Üretim’den lazer isimlerini gönderin. Varsayılan tabla 800 x 600 mm’dir.</p></div>`;
    boxes.forEach(box => { box.innerHTML = empty; });
    return;
  }
  requestNameCutProductionScene(layout);
  const productionScene = currentNameCutProductionScene();
  const renderLayout = nameCutSceneLayout(productionScene, layout);
  let cfg = renderLayout.config || layout.config || { width_mm: 800, height_mm: 600 };
  const renderItems = renderLayout.items || items;
  const renderSummary = renderLayout.summary || summary;
  const mirror = Boolean(cfg.mirror_cut || nameCutLayoutConfig.mirror_cut);
  const pages = Math.max(1, Number(renderSummary.pages || 1));
  nameCutPreviewPage = Math.max(1, Math.min(pages, Number(nameCutPreviewPage || 1)));
  const pageItems = renderItems.filter(item => Number(item.page || 1) === nameCutPreviewPage);
  const pageStats = (renderSummary.page_stats || []).find(stat => Number(stat.page || 1) === nameCutPreviewPage) || {};
  const boardRatio = `${Number(cfg.width_mm || 800)} / ${Number(cfg.height_mm || 600)}`;
  const xTicks = Array.from({ length: Math.floor(Number(cfg.width_mm || 800) / 50) + 1 }, (_, idx) => idx * 50);
  const yTicks = Array.from({ length: Math.floor(Number(cfg.height_mm || 600) / 50) + 1 }, (_, idx) => idx * 50);
  const safeLeft = (Number(cfg.margin_mm || 15) / Number(cfg.width_mm || 800)) * 100;
  const safeTop = (Number(cfg.margin_mm || 15) / Number(cfg.height_mm || 600)) * 100;
  const safeRight = safeLeft;
  const safeBottom = safeTop;
  const metrics = nameCutSourceMetrics(renderLayout);
  const direction = nameCutDirectionLabel(cfg);
  const collisionFree = summary.collision_free !== false;
  const qualityCounts = nameCutLiveItems().map(item => nameCutSinglePieceQuality(item, layout)).reduce((acc, quality) => {
    acc[quality.status] = (acc[quality.status] || 0) + 1;
    return acc;
  }, {});
  const targetWidth = Number(cfg.target_name_width_mm || summary.target_name_width_mm || 80);
  const targetHeight = Number(cfg.target_name_height_mm || summary.target_name_height_mm || 40);
  const minGap = Number(renderSummary.target_gap_mm || renderSummary.min_safe_gap_mm || cfg.target_gap_mm || cfg.item_gap_mm || 1);
  const hasSinglePieceIssue = !!(qualityCounts.needs_weld || qualityCounts.detached_marks || qualityCounts.needs_offset || qualityCounts.collision_risk || qualityCounts.blocked);
  const repairCounts = pageItems.reduce((acc, item) => {
    const key = nameCutRepairState(item);
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  // Real single-piece status from the production scene (targeted stroke-weld result),
  // NOT a static badge. Drives the "İsimler ayrı / Tek parça" chips honestly.
  const sceneComponentCounts = pageItems.map(item => {
    const pid = String(item.placement_id || nameCutLogicalItemId(item));
    const pp = nameCutProductionPathByPlacement(productionScene, pid);
    return Number(pp?.componentCount ?? pp?.component_count ?? item.componentCount ?? item.component_count ?? 1);
  });
  const separatePieceCount = sceneComponentCounts.filter(c => Number.isFinite(c) && c > 1).length;
  const allNamesSinglePiece = sceneComponentCounts.length > 0 && separatePieceCount === 0;
  const boardWidthMm = Number(cfg.width_mm || 800);
  const boardHeightMm = Number(cfg.height_mm || 600);
  const productionItemsHtml = pageItems.slice(0, 240).map(item => {
    const layoutResult = nameCutLayoutResultForItem(item, { cfg, context: "main" });
    const xMm = Number(item.x_mm || 0);
    const yMm = Number(item.y_mm || 0);
    const widthMm = Number(item.width_mm || 1);
    const heightMm = Number(item.height_mm || 1);
    const centerX = xMm + (widthMm / 2);
    const centerY = yMm + (heightMm / 2);
    const lines = Array.isArray(layoutResult.previewLines) && layoutResult.previewLines.length ? layoutResult.previewLines : [item.name_text || ""];
    const lineHeightMm = heightMm / Math.max(1, lines.length);
    const fontSizeMm = Math.min(nameCutFontSizeForBox(item, cfg), Math.max(7, lineHeightMm * 0.68));
    const quality = nameCutSinglePieceQuality(item, layout);
    const repairState = nameCutRepairState(item);
    const riskClass = quality.status === "detached_marks" ? " risk-dots" : quality.status === "collision_risk" ? " collision-risk" : quality.status === "needs_weld" ? " needs-weld" : "";
    const itemId = nameCutLogicalItemId(item);
    const placementId = String(item.placement_id || itemId);
    const isSelected = nameCutCanvasSelectionVisible && ((selectedNameCutPlacementId && placementId === selectedNameCutPlacementId) || (selectedNameCutItemId && (itemId === selectedNameCutItemId || item.item_id === selectedNameCutItemId || item.source_item_id === selectedNameCutItemId)));
    const pathPreview = nameCutProductionPathByPlacement(productionScene, placementId);
    const pathData = String(pathPreview?.finalCutPathData || pathPreview?.final_cut_path_data || pathPreview?.weldedCutPathData || pathPreview?.welded_cut_path_data || pathPreview?.cut_path_data || pathPreview?.path_data || "").trim();
    const pathStatus = pathPreview?.path_preview_status || item.path_preview_status || (pathData ? "OUTLINED_PATHS_WITH_FONTTOOLS" : "PATH_MISSING_NEEDS_REVIEW");
    if (!pathData) {
      const pendingPath = `M ${xMm.toFixed(3)} ${yMm.toFixed(3)} H ${(xMm + widthMm).toFixed(3)} V ${(yMm + heightMm).toFixed(3)} H ${xMm.toFixed(3)} Z`;
      return `<path class="rdworks-name-outline-svg fonttools-path-pending" data-namecut-id="${esc(itemId)}" data-namecut-placement-id="${esc(placementId)}" data-outline-export="fallback-text-needs-review" d="${pendingPath}" fill="none" stroke="none" opacity="0" pointer-events="none"></path>`;
    }
    const commonAttrs = `class="rdworks-name-outline-svg script-opentype-text fonttools-path-preview${riskClass}${isSelected ? " selected" : ""}" data-namecut-id="${esc(itemId)}" data-namecut-placement-id="${esc(placementId)}" data-namecut-object="production-final-cut-path" data-no-inter-name-bridge="true" data-single-piece-status="${esc(quality.status)}" data-repair-status="${esc(repairState)}" data-component-count="${esc(item.componentCount || item.component_count || 1)}" data-path-preview-status="${esc(pathStatus)}" data-outline-export="fonttools-final-cut-path" data-wysiwyg-cut-geometry="true" data-layout-signature="${esc(layoutResult.layoutSignature || item.layout_signature || "")}" data-actual-path-width-mm="${esc(layoutResult.actualPathWidthMm || item.actual_path_width_mm || widthMm)}" data-actual-path-height-mm="${esc(layoutResult.actualPathHeightMm || item.actual_path_height_mm || heightMm)}" data-weld-inside-name="${nameCutLayoutConfig.weld_inside_name !== false ? "true" : "false"}" data-capital-fix="${nameCutLayoutConfig.capital_connection_fix !== false ? "true" : "false"}" data-punctuation-fix="${nameCutLayoutConfig.punctuation_fix !== false ? "true" : "false"}" title="${esc((layoutResult.previewLines || [item.name_text || item.text || ""]).join(" / "))} · Final cut path · Farklı isimlerle en az ${esc(minGap)} mm boşluk" onpointerdown="beginNameCutPlacementPointer(event, ${jsArg(placementId)}, ${jsArg(item.source_item_id || itemId)}, 'move')"`;
    return `<path ${commonAttrs} d="${esc(pathData)}" fill="#020617" fill-rule="evenodd" stroke="#020617" stroke-width="0.05" stroke-linejoin="round" stroke-linecap="round" vector-effect="non-scaling-stroke"></path>`;
  }).join("");
  const selectedLayoutItem = nameCutCanvasSelectionVisible ? pageItems.find(item => {
    const itemId = nameCutLogicalItemId(item);
    const placementId = String(item.placement_id || itemId);
    return (selectedNameCutPlacementId && placementId === selectedNameCutPlacementId) || (selectedNameCutItemId && (itemId === selectedNameCutItemId || item.item_id === selectedNameCutItemId || item.source_item_id === selectedNameCutItemId));
  }) : null;
  const selectionHtml = selectedLayoutItem ? (() => {
    const itemId = nameCutLogicalItemId(selectedLayoutItem);
    const placementId = String(selectedLayoutItem.placement_id || itemId);
    const boardWidthMm = Number(cfg.width_mm || 800);
    const boardHeightMm = Number(cfg.height_mm || 600);
    const selectionPadMm = 2;
    const boxLeftMm = Number(selectedLayoutItem.x_mm || 0);
    const boxTopMm = Number(selectedLayoutItem.y_mm || 0);
    const placementWidthMm = Number(selectedLayoutItem.width_mm || 1);
    const placementHeightMm = Number(selectedLayoutItem.height_mm || 1);
    const actualWidthMm = Math.min(placementWidthMm, Math.max(1, Number(selectedLayoutItem.actual_path_width_mm || placementWidthMm)));
    const actualHeightMm = Math.min(placementHeightMm, Math.max(1, Number(selectedLayoutItem.actual_path_height_mm || placementHeightMm)));
    const actualLeftMm = boxLeftMm + Math.max(0, (placementWidthMm - actualWidthMm) / 2);
    const actualTopMm = boxTopMm + Math.max(0, (placementHeightMm - actualHeightMm) / 2);
    const boxRightMm = actualLeftMm + actualWidthMm;
    const boxBottomMm = actualTopMm + actualHeightMm;
    const frameLeftMm = clampNumber(actualLeftMm - selectionPadMm, 0, boardWidthMm);
    const frameTopMm = clampNumber(actualTopMm - selectionPadMm, 0, boardHeightMm);
    const frameRightMm = clampNumber(boxRightMm + selectionPadMm, frameLeftMm + 1, boardWidthMm);
    const frameBottomMm = clampNumber(boxBottomMm + selectionPadMm, frameTopMm + 1, boardHeightMm);
    const left = nameCutPercent(frameLeftMm, boardWidthMm);
    const top = nameCutPercent(frameTopMm, boardHeightMm);
    const width = nameCutPercent(frameRightMm - frameLeftMm, boardWidthMm);
    const height = nameCutPercent(frameBottomMm - frameTopMm, boardHeightMm);
    return `<div class="namecut-selection-frame" aria-hidden="true" data-namecut-selection="${esc(placementId)}" style="left:${left}%;top:${top}%;width:${width}%;height:${height}%">
      ${["nw", "n", "ne", "e", "se", "s", "sw", "w"].map(handle => `<b class="handle ${handle}" onpointerdown="beginNameCutPlacementPointer(event, ${jsArg(placementId)}, ${jsArg(selectedLayoutItem.source_item_id || itemId)}, '${handle}')"></b>`).join("")}
    </div>`;
  })() : "";
  const pageButtons = pages > 1 ? `
    <div class="laser-page-tabs">
      ${Array.from({ length: pages }, (_, idx) => {
        const page = idx + 1;
        return `<button class="btn small ${page === nameCutPreviewPage ? "primary" : ""}" type="button" onclick="setNameCutPreviewPage(${page})">Plate ${page}</button>`;
      }).join("")}
    </div>
  ` : "";
  const sceneSignature = nameCutProductionSceneSignature(nameCutLiveItems(), nameCutLayoutConfig);
  const pathPreviewStatus = nameCutProductionSceneCache.signature === sceneSignature ? String(nameCutProductionSceneCache.scene?.path_preview_status || nameCutProductionSceneCache.status || "") : "";
  const pathPreviewReady = pathPreviewStatus === "OUTLINED_PATHS_WITH_FONTTOOLS";
  const pathPreviewPending = nameCutProductionSceneCache.pendingSignature === sceneSignature || nameCutProductionSceneCache.status === "PENDING";
  const pathMissingCount = Number(productionScene?.metrics?.fallback_count || productionScene?.fallback_count || 0);
  const html = `
    <div class="laser-layout-meta">
      <span><b>${esc(metrics.source_placed)} / ${esc(metrics.source_total)}</b> yerleşen isim</span>
      <span><b>${esc(metrics.copies_placed)} / ${esc(metrics.copies_total)}</b> yerleşen adet</span>
      <span>Plate <b>${esc(nameCutPreviewPage)} / ${esc(pages)}</b></span>
      <span><b>${esc(pageItems.length)}</b> iş · <b>${esc(pageStats.used_area_percent || 0)}%</b> kullanım</span>
      <span>Hedef ölçü: <b>${esc(targetWidth)} x ${esc(targetHeight)} mm</b></span>
      <span>Min boşluk: <b>${esc(minGap)} mm</b></span>
      <span>Safe margin: <b>${esc(cfg.margin_mm || 15)} mm</b></span>
      <span class="${repairCounts.failed ? "warn" : "ok"}">Hazır: ${esc(repairCounts.clean || 0)}</span>
      <span class="purple">Otomatik düzeltildi: ${esc(repairCounts.auto_repaired || 0)}</span>
      <span class="${repairCounts.failed ? "warn" : "ok"}">Uygun değil: ${esc(repairCounts.failed || 0)}</span>
      ${(() => { const reviewCount = (repairCounts.reference_missing_generated_review_required || 0) + (repairCounts.corel_style_review_required || 0) + (repairCounts.designer_weld_warning || 0) + (repairCounts.manufacturable_warning || 0); return reviewCount ? `<span class="warn">İnceleme gerekli: ${esc(reviewCount)}</span>` : ""; })()}
      <span class="${allNamesSinglePiece ? "ok" : "warn"}">${allNamesSinglePiece ? "İsimler bağlı (tek parça)" : (separatePieceCount + " isim çok parçalı")}</span>
      <span class="${(hasSinglePieceIssue || separatePieceCount) ? "warn" : "ok"}">Tek parça: ${separatePieceCount ? ("⚠ " + separatePieceCount + " parça") : "✅"}</span>
      <span class="${collisionFree ? "ok" : "warn"}">${collisionFree ? "Temas yok" : "Temas riski"}</span>
      <span>Kesim yönü: <b>${esc(direction)}</b></span>
      ${(qualityCounts.needs_weld || qualityCounts.detached_marks || qualityCounts.needs_offset || qualityCounts.collision_risk || qualityCounts.blocked || pathMissingCount) ? `<span class="warn">Kalite kontrol gerekli</span>` : pathPreviewReady ? `<span class="ok">FontTools path hazır</span>` : `<span class="warn">${pathPreviewPending ? "Path hazırlanıyor" : "Path export’ta doğrulanacak"}</span>`}
    </div>
    ${pageButtons}
    <div class="rdworks-board-frame">
      <div class="rdworks-ruler top">
        ${xTicks.map(value => `<span style="left:${(value / Number(cfg.width_mm || 800)) * 100}%">${esc(value)}</span>`).join("")}
        <b>mm</b>
      </div>
      <div class="rdworks-ruler left">
        ${yTicks.map(value => `<span style="top:${(value / Number(cfg.height_mm || 600)) * 100}%">${esc(value)}</span>`).join("")}
      </div>
      <div class="laser-layout-stage rdworks-like ${mirror ? "mirror-mode" : ""}" data-namecut-board="true" onwheel="handleNameCutBoardWheel(event)" style="aspect-ratio:${esc(boardRatio)};--name-cut-zoom:${esc(nameCutLayoutConfig.preview_zoom || 100)}">
        <div class="namecut-table-layer">
          <div class="rdworks-safe-margin" style="left:${safeLeft}%;top:${safeTop}%;right:${safeRight}%;bottom:${safeBottom}%"></div>
        </div>
        <div class="namecut-production-layer">
          <svg class="namecut-production-svg" viewBox="0 0 ${esc(boardWidthMm)} ${esc(boardHeightMm)}" preserveAspectRatio="none" aria-label="Kesilecek isim path önizlemesi">
            <g class="namecut-production-paths" data-export-layer="production-only">${productionItemsHtml}</g>
          </svg>
        </div>
        <div class="namecut-helper-layer">${selectionHtml}</div>
        <div class="namecut-measurement-layer" aria-hidden="true"></div>
        <div class="namecut-debug-layer" aria-hidden="true"></div>
      </div>
    </div>
  `;
  boxes.forEach(box => { box.innerHTML = html; });
  renderNameCutSourceList(renderLayout);
  renderNameCutControlStats(renderLayout);
  renderNameCutBottomDetails(renderLayout);
}

function toggleNameCutInspector() {
  nameCutInspectorCollapsed = !nameCutInspectorCollapsed;
  const shell = document.querySelector("#nameCutStudio .name-cut-rd-shell");
  if (shell) shell.classList.toggle("inspector-collapsed", nameCutInspectorCollapsed);
  const button = document.getElementById("nameCutInspectorToggle");
  if (button) button.textContent = nameCutInspectorCollapsed ? "Inspector Aç" : "Inspector Kapat";
}

function nameCutBoardElement() {
  return document.querySelector("#nameCutStudio .laser-layout-stage[data-namecut-board='true']");
}

function beginNameCutPlacementPointer(event, placementId = "", sourceItemId = "", mode = "move") {
  selectedNameCutPlacementId = String(placementId || "");
  selectedNameCutItemId = String(sourceItemId || placementId || "");
  beginNameCutItemPointer(event, selectedNameCutItemId, mode);
}

function beginNameCutItemPointer(event, itemId = "", mode = "move") {
  if (!event || !itemId) return;
  event.preventDefault();
  event.stopPropagation();
  selectedNameCutItemId = itemId;
  nameCutCanvasSelectionVisible = true;
  const layout = currentNameCutLayout();
  const placed = selectedNameCutPlacementId ? nameCutPlacedItemForSource(selectedNameCutPlacementId, layout) : nameCutPlacedItemForSource(itemId, layout);
  const source = nameCutFindSourceItem(itemId);
  const board = nameCutBoardElement();
  if (!placed || !source || !board) {
    selectNameCutItem(itemId);
    return;
  }
  const rect = board.getBoundingClientRect();
  nameCutInteractionState = {
    itemId,
    mode: String(mode || "move"),
    startClientX: Number(event.clientX || 0),
    startClientY: Number(event.clientY || 0),
    boardWidthPx: Math.max(1, rect.width),
    boardHeightPx: Math.max(1, rect.height),
    boardWidthMm: Number((layout.config || {}).width_mm || 800),
    boardHeightMm: Number((layout.config || {}).height_mm || 600),
    startX: Number(placed.x_mm || 0),
    startY: Number(placed.y_mm || 0),
    startWidth: Number(placed.width_mm || 80),
    startHeight: Number(placed.height_mm || 40),
    aspect: Number(placed.width_mm || 80) / Math.max(1, Number(placed.height_mm || 40)),
    lockedAspectRatio: source.locked_aspect_ratio !== false
  };
  renderNameCutGallery();
  renderNameCutDetail();
  renderLaserLayoutPreview(layout);
  document.addEventListener("pointermove", moveNameCutInteraction);
  document.addEventListener("pointerup", endNameCutInteraction, { once: true });
}

function moveNameCutInteraction(event) {
  const state = nameCutInteractionState;
  if (!state || !event) return;
  event.preventDefault();
  const cfg = normalizeNameCutConfig(nameCutLayoutConfig);
  const dxMm = ((Number(event.clientX || 0) - state.startClientX) / state.boardWidthPx) * state.boardWidthMm;
  const dyMm = ((Number(event.clientY || 0) - state.startClientY) / state.boardHeightPx) * state.boardHeightMm;
  const minWidth = 20;
  const minHeight = 10;
  let x = state.startX;
  let y = state.startY;
  let width = state.startWidth;
  let height = state.startHeight;
  const mode = state.mode;
  if (mode === "move") {
    x = state.startX + dxMm;
    y = state.startY + dyMm;
  } else {
    if (mode.includes("e")) width = state.startWidth + dxMm;
    if (mode.includes("s")) height = state.startHeight + dyMm;
    if (mode.includes("w")) {
      width = state.startWidth - dxMm;
      x = state.startX + dxMm;
    }
    if (mode.includes("n")) {
      height = state.startHeight - dyMm;
      y = state.startY + dyMm;
    }
    width = Math.max(minWidth, width);
    height = Math.max(minHeight, height);
    if (state.lockedAspectRatio && /^(nw|ne|se|sw)$/.test(mode)) {
      if (Math.abs(dxMm) >= Math.abs(dyMm)) height = width / state.aspect;
      else width = height * state.aspect;
      if (mode.includes("w")) x = state.startX + state.startWidth - width;
      if (mode.includes("n")) y = state.startY + state.startHeight - height;
    }
  }
  width = clampNumber(width, minWidth, Math.max(minWidth, cfg.width_mm));
  height = clampNumber(height, minHeight, Math.max(minHeight, cfg.height_mm));
  x = clampNumber(x, 0, Math.max(0, cfg.width_mm - width));
  y = clampNumber(y, 0, Math.max(0, cfg.height_mm - height));
  nameCutApplyManualGeometry(state.itemId, {
    x_mm: x,
    y_mm: y,
    width_mm: width,
    height_mm: height,
    operator_position_locked: true,
    operator_size_locked: mode !== "move",
    locked_aspect_ratio: state.lockedAspectRatio
  });
  const layout = currentNameCutLayout();
  renderLaserLayoutPreview(layout);
  renderNameCutDetail();
  renderNameCutControlStats(layout);
}

function endNameCutInteraction() {
  document.removeEventListener("pointermove", moveNameCutInteraction);
  nameCutInteractionState = null;
  refreshNameCutStudioViews(currentNameCutLayout());
}

function handleNameCutBoardWheel(event) {
  if (!event) return;
  event.preventDefault();
  const step = event.ctrlKey ? 10 : 6;
  nameCutZoom(Number(event.deltaY || 0) < 0 ? step : -step);
}

function updateSelectedNameCutGeometry(field = "", value = "") {
  const item = selectedNameCutItem();
  if (!item) return;
  const layout = currentNameCutLayout();
  const placed = nameCutPlacedItemForSource(item.item_id, layout) || item;
  const geometry = {
    x_mm: Number(placed.x_mm || 0),
    y_mm: Number(placed.y_mm || 0),
    width_mm: Number(placed.width_mm || nameCutLayoutConfig.target_name_width_mm || 80),
    height_mm: Number(placed.height_mm || nameCutLayoutConfig.target_name_height_mm || 40),
    operator_position_locked: true,
    operator_size_locked: true,
    locked_aspect_ratio: item.locked_aspect_ratio !== false
  };
  const key = String(field || "");
  if (Object.prototype.hasOwnProperty.call(geometry, key)) geometry[key] = Number(value);
  nameCutApplyManualGeometry(item.item_id, geometry);
  refreshNameCutStudioViews(currentNameCutLayout());
}

function toggleSelectedNameCutAspectLock(checked = true) {
  const item = selectedNameCutItem();
  if (!item) return;
  item.locked_aspect_ratio = !!checked;
  item.is_edited = true;
  renderNameCutDetail();
}

function resetSelectedNameCutGeometry() {
  const item = selectedNameCutItem();
  if (!item) return;
  delete item.x_mm;
  delete item.y_mm;
  delete item.width_mm;
  delete item.height_mm;
  delete item.operator_position_locked;
  delete item.operator_size_locked;
  item.locked_aspect_ratio = true;
  item.is_edited = true;
  refreshNameCutStudioViews(currentNameCutLayout());
}

function setNameCutPreviewPage(page) {
  nameCutPreviewPage = Math.max(1, Number(page || 1));
  renderLaserLayoutPreview(currentNameCutLayout());
}

function applyNameCutConfigDefaultsToItems() {
  const config = normalizeNameCutConfig(nameCutLayoutConfig);
  nameCutItems = (nameCutItems || []).map(item => {
    if (item.is_deleted) return item;
    return nameCutApplyFontMetaToItem({
      ...item,
      style: item.style || config.font_family,
      offset_mm: item.offset_mm ?? config.offset_mm,
      thickening_mode: item.thickening_mode || "Özel offset"
    }, item.style || config.font_family);
  });
}

function showNameCutFeatureNotice(name = "Bu özellik") {
  showToast(`${name}: bu ekranda güvenli üretim modu etkin. Desteklenmeyen işlem sahte başarılı gösterilmez.`, "info");
}

function resetNameCutProject() {
  if (nameCutLiveItems().length && !confirm("İsim Kesim listesini temizleyip yeni çalışma başlatılsın mı?")) return;
  nameCutItems = [];
  selectedNameCutItemId = "";
  nameCutCanvasSelectionVisible = false;
  nameCutPreviewPage = 1;
  lastNameCutExport = null;
  refreshNameCutStudioViews(currentNameCutLayout());
  showToast("Yeni İsim Kesim çalışması açıldı.", "success");
}

function saveNameCutProject(asCopy = false) {
  const payload = {
    saved_at: new Date().toISOString(),
    config: nameCutLayoutConfig,
    items: nameCutItems,
    export: lastNameCutExport
  };
  const key = asCopy ? `cyzella_name_cut_project_${Date.now()}` : "cyzella_name_cut_project_current";
  localStorage.setItem(key, JSON.stringify(payload));
  showToast(asCopy ? "İsim Kesim çalışması farklı kayıt olarak saklandı." : "İsim Kesim çalışması kaydedildi.", "success");
}

function openNameCutPasteModal() {
  const raw = prompt("Her satıra bir isim gelecek şekilde yapıştırın:");
  if (!raw) return;
  const rows = raw.split(/\r?\n/).map(line => formatNameCutName(line)).filter(Boolean);
  rows.forEach((name, index) => {
    nameCutItems.push({
      item_id: `paste-name-${Date.now()}-${index}`,
      row_number: nameCutItems.length + 1,
      name_text: name,
      preview_text: name,
      quantity: "1",
      width_mm: nameCutLayoutConfig.target_name_width_mm || 80,
      height_mm: nameCutLayoutConfig.target_name_height_mm || 40,
      style: nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT,
      composition: "Tek Satır Yan Yana",
      composition_mode: "Tek Satır Yan Yana",
      thickening_mode: "Özel offset",
      offset_mm: nameCutLayoutConfig.offset_mm || 0.3,
      support_line: false,
      back_plate: false,
      status: "READY",
      warnings: analyzeNameCutItemForLaser({ name_text: name }, nameCutLayoutConfig).warnings,
      errors: [],
      is_deleted: false,
      is_edited: true
    });
  });
  selectedNameCutItemId = (nameCutItems.find(item => !item.is_deleted) || {}).item_id || "";
  refreshNameCutStudioViews(currentNameCutLayout());
  showToast(`${rows.length} isim eklendi. İsimler birbirine bağlanmadan ayrı objeler olarak dizilecek.`, "success");
}

function clearNameCutItems() {
  if (!nameCutItems.length) return;
  if (!confirm("Tüm isim kesim listesini temizlemek istiyor musunuz?")) return;
  nameCutItems = [];
  selectedNameCutItemId = "";
  nameCutCanvasSelectionVisible = false;
  lastNameCutExport = null;
  refreshNameCutStudioViews(currentNameCutLayout());
}

function moveSelectedNameCutItem(delta = 0) {
  const index = nameCutItems.findIndex(item => item.item_id === selectedNameCutItemId);
  const next = index + Number(delta || 0);
  if (index < 0 || next < 0 || next >= nameCutItems.length) return;
  const copy = [...nameCutItems];
  [copy[index], copy[next]] = [copy[next], copy[index]];
  nameCutItems = copy.map((item, idx) => ({ ...item, row_number: idx + 1, is_edited: true }));
  refreshNameCutStudioViews(currentNameCutLayout());
}

function deleteSelectedNameCutItem() {
  const index = nameCutItems.findIndex(item => item.item_id === selectedNameCutItemId);
  if (index < 0) return;
  markNameCutDeleted(index);
}

function nameCutZoom(delta = 0) {
  const next = clampNumber(Number(nameCutLayoutConfig.preview_zoom || 100) + Number(delta || 0), 50, 320);
  nameCutLayoutConfig.preview_zoom = next;
  renderLaserLayoutPreview(currentNameCutLayout());
  const _ro = byId('nameCutScaleReadout');
  if (_ro) _ro.textContent = '%' + Math.round(next);
  const _olcek = next / 100;
  const _ncStage = document.querySelector('#nameCutStudio .nc-stage');
  if (_ncStage) _ncStage.style.backgroundSize = (24*_olcek).toFixed(1)+'px '+(24*_olcek).toFixed(1)+'px';
}

function nameCutFitToScreen() {
  nameCutLayoutConfig.preview_zoom = 100;
  renderLaserLayoutPreview(currentNameCutLayout());
  setTimeout(() => {
    const _stage = document.querySelector('#nameCutStudio .nc-stage');
    const _board = (_stage && (_stage.querySelector('[data-namecut-board]') || byId('nameCutStudioLayoutPreview')));
    if (!_stage || !_board) return;
    const _pad = 24;
    const _avW = _stage.clientWidth  - _pad * 2;
    const _avH = _stage.clientHeight - _pad * 2;
    if (_avW <= 60 || _avH <= 60) return;

    // İçerik (yerleşen isimler) sınır kutusunu mm cinsinden hesapla — DOM ölçümünden güvenilir
    const _layout = currentNameCutLayout();
    const _items  = (_layout && _layout.items) || [];
    const _cfg    = (_layout && _layout.config) || {};
    const _cfgW   = Number(_cfg.width_mm  || nameCutLayoutConfig.width_mm  || 800);
    const _cfgH   = Number(_cfg.height_mm || nameCutLayoutConfig.height_mm || 600);
    const _boardPxW = _board.offsetWidth;   // %100 zoom'da board genişliği (px)
    const _boardPxH = _board.offsetHeight;

    let _bW, _bH, _cxMm = _cfgW / 2, _cyMm = _cfgH / 2;
    if (_items.length > 0 && _boardPxW > 0 && _boardPxH > 0) {
      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
      _items.forEach(it => {
        const x = Number(it.x_mm || 0), y = Number(it.y_mm || 0);
        const w = Number(it.width_mm || 0), h = Number(it.height_mm || 0);
        if (x < minX) minX = x;
        if (y < minY) minY = y;
        if (x + w > maxX) maxX = x + w;
        if (y + h > maxY) maxY = y + h;
      });
      const _cWmm = maxX - minX, _cHmm = maxY - minY;
      if (isFinite(_cWmm) && isFinite(_cHmm) && _cWmm > 0 && _cHmm > 0) {
        _bW = (_cWmm / _cfgW) * _boardPxW;   // içerik px @100%
        _bH = (_cHmm / _cfgH) * _boardPxH;
        _cxMm = (minX + maxX) / 2;           // içerik merkezi (mm)
        _cyMm = (minY + maxY) / 2;
      } else { _bW = _boardPxW; _bH = _boardPxH; }
    } else { _bW = _boardPxW; _bH = _boardPxH; }
    if (_bW <= 0 || _bH <= 0) return;

    const _scale = Math.min(_avW / _bW, _avH / _bH) * 0.9;
    const _newZ  = clampNumber(Math.round(100 * _scale), 10, 800);  // küçük içeriği büyütebilmek için 800'e kadar
    if (Math.abs(_newZ - 100) > 3) {
      nameCutLayoutConfig.preview_zoom = _newZ;
      renderLaserLayoutPreview(currentNameCutLayout());
    }
    const _ncOlcek = nameCutLayoutConfig.preview_zoom / 100;
    _stage.style.backgroundSize = (24*_ncOlcek).toFixed(1)+'px '+(24*_ncOlcek).toFixed(1)+'px';

    // Görünümü içerik merkezine ortala (yeni zoom'daki board px'ine göre)
    requestAnimationFrame(() => {
      const _st = document.querySelector('#nameCutStudio .nc-stage');
      const _bd = _st && (_st.querySelector('[data-namecut-board]') || byId('nameCutStudioLayoutPreview'));
      if (!_st || !_bd) return;
      const _pxW = _bd.offsetWidth, _pxH = _bd.offsetHeight;
      _st.scrollLeft = Math.max(0, (_cxMm / _cfgW) * _pxW - _st.clientWidth  / 2);
      _st.scrollTop  = Math.max(0, (_cyMm / _cfgH) * _pxH - _st.clientHeight / 2);
    });
  }, 80);
}

function nameCutSetActualSize() {
  nameCutLayoutConfig.preview_zoom = 100;
  renderLaserLayoutPreview(currentNameCutLayout());
}

function toggleNameCutMirror(axis = "horizontal") {
  if (axis === "vertical") {
    nameCutLayoutConfig.mirror_vertical = !nameCutLayoutConfig.mirror_vertical;
  } else {
    nameCutLayoutConfig.mirror_cut = !nameCutLayoutConfig.mirror_cut;
  }
  renderLaserLayoutPreview(currentNameCutLayout());
}

function rotateNameCutSelection(degrees = 180) {
  const item = selectedNameCutItem();
  if (!item) return showNameCutFeatureNotice("Döndür");
  item.rotation = ((Number(item.rotation || 0) + Number(degrees || 0)) % 360 + 360) % 360;
  item.is_edited = true;
  renderLaserLayoutPreview(currentNameCutLayout());
}

function autoNestNameCutItems() {
  nameCutLayoutConfig.dense_nesting = true;
  nameCutPreviewPage = 1;
  const layout = currentNameCutLayout();
  refreshNameCutStudioViews(layout);
  const metrics = nameCutSourceMetrics(layout);
  showToast(`Otomatik dizilim tamamlandı: ${metrics.source_placed}/${metrics.source_total} isim, ${metrics.copies_placed}/${metrics.copies_total} adet yerleşti. İsimler arası temas oluşturulmadı.`, "success");
}

function nameCutInternalWeld() {
  const targets = selectedNameCutItemId ? nameCutItems.filter(item => item.item_id === selectedNameCutItemId) : nameCutLiveItems();
  targets.forEach(item => {
    item.internal_weld_requested = true;
    item.inter_name_connection_forbidden = true;
    item.warnings = Array.from(new Set([...(item.warnings || []), "Weld kontrol modu işaretlendi; gerçek path birleşimi manifest/RDWorks kontrolünden geçmeden üretime hazır sayılmaz."]));
    item.is_edited = true;
  });
  refreshNameCutStudioViews(currentNameCutLayout());
  showToast("Weld kontrol modu isim içi parçalar için işaretlendi. Farklı isimler birbirine bağlanmaz; RDWorks/lazer başlamadı.", "info");
}

function nameCutBridgeDots() {
  const targets = selectedNameCutItemId ? nameCutItems.filter(item => item.item_id === selectedNameCutItemId) : nameCutLiveItems();
  let count = 0;
  targets.forEach(item => {
    if (hasTurkishDiacriticForCutting(item.name_text || "")) {
      count += 1;
      item.diacritic_bridge_requested = true;
      item.detached_marks = false;
      item.warnings = Array.from(new Set([...(item.warnings || []), "Nokta/işaret bağlantısı bu ismin gövdesi için kontrol işaretine alındı; isimler arası köprü yok."]));
      item.is_edited = true;
    }
  });
  refreshNameCutStudioViews(currentNameCutLayout());
  showToast(`${count} isimde nokta/işaret bağlantısı isim içinde kontrol işaretine alındı. RDWorks/lazer başlamadı.`, "info");
}

function runNameCutBreakCheck() {
  nameCutItems = (nameCutItems || []).map(item => {
    if (item.is_deleted) return item;
    const risk = analyzeNameCutItemForLaser(item, nameCutLayoutConfig);
    return {
      ...item,
      warnings: Array.from(new Set([...(item.warnings || []), ...risk.warnings])),
      errors: Array.from(new Set([...(item.errors || []), ...risk.errors])),
      status: risk.errors.length ? "ERROR" : (risk.warnings.length || (item.warnings || []).length) ? "WARNING" : "READY"
    };
  });
  refreshNameCutStudioViews(currentNameCutLayout());
  showToast("Tek parça, nokta/işaret, offset ve temas ön kontrolü tamamlandı. RDWorks/lazer başlamadı.", "info");
}

function nameCutAiSuggest() {
  const layout = currentNameCutLayout();
  const summary = layout.summary || {};
  const suggestions = [];
  if ((summary.used_area_percent || 0) < 70) suggestions.push("Boşluk oranı yüksek; minimum boşluğu 1 mm ve sağdan sola yoğun dizilimi kullanın.");
  if (nameCutLiveItems().some(item => String(item.name_text || "").replace(/\s+/g, "").length >= 18)) suggestions.push("Uzun isimlerde yatay ölçek %80-90 aralığı önerilir.");
  if (nameCutLiveItems().some(item => String(item.name_text || "").replace(/\s+/g, "").length <= 3)) suggestions.push("Kısa isimlerde optik büyütme açık kalmalı.");
  if (nameCutLiveItems().some(item => hasTurkishDiacriticForCutting(item.name_text || ""))) suggestions.push("İrem, Özge, Ümit gibi isimlerde nokta bağlantısını isim içinde uygulayın.");
  if (!suggestions.length) suggestions.push(`Yerleşim dengeli görünüyor. ${formatMm(nameCutLayoutConfig.offset_mm ?? 0.3)} mm kalınlaştırma ve minimum 1 mm boşluk güvenli.`);
  showToast(`AI önerisi: ${suggestions.join(" ")}`, "info");
}

function applyNameCutOffsetToAll() {
  const offset = clampNumber(Number(nameCutLayoutConfig.offset_mm ?? nameCutFontMetaByValue(nameCutLayoutConfig.font_family)?.defaultOffsetMm ?? 0.3), 0, 1.5);
  nameCutItems = (nameCutItems || []).map(item => item.is_deleted ? item : {
    ...item,
    offset_mm: offset,
    thickening_mode: "Özel offset",
    is_edited: true,
    warnings: Array.from(new Set([...(item.warnings || []), `Kalınlaştırma ${offset.toFixed(2)} mm üretim öncesi kontrol değerine alındı; gerçek path/offset RDWorks öncesi doğrulanmalı.`]))
  });
  refreshNameCutStudioViews(currentNameCutLayout());
  showToast("Kalınlaştırma kontrol değeri güncellendi. Gerçek lazer/RDWorks başlatılmadı.", "info");
}

function selectNameCutSettingsTab(tab = "layout") {
  document.querySelectorAll("#nameCutStudio [data-namecut-tab]").forEach(button => {
    button.classList.toggle("active", button.dataset.namecutTab === tab);
  });
  document.querySelectorAll("#nameCutStudio [data-namecut-panel]").forEach(panel => {
    panel.classList.toggle("active", panel.dataset.namecutPanel === tab);
  });
  if (tab === "reference") {
    if (!corelReferenceLibraryState.references.length && !corelReferenceLibraryState.loading) {
      loadNameCutCorelReferences();
    } else {
      renderNameCutCorelReferencePanel();
    }
  }
}

function updateNameCutLayoutConfig(field, value) {
  if (field === "mirror_cut" || field === "allow_rotation" || field === "dense_nesting" || field === "optical_short_name_scale" || field === "auto_condense_long_names" || field === "post_offset_check" || field === "script_connection_check" || field === "mirror_vertical" || field === "weld_inside_name" || field === "export_as_path" || field === "capital_connection_fix" || field === "punctuation_fix" || field === "turkish_mark_bridge" || field === "dot_bridge_enabled") {
    nameCutLayoutConfig[field] = !!value;
  } else if (["start_corner", "packing_direction", "row_direction", "font_family", "corner_type", "offset_type", "script_profile"].includes(field)) {
    nameCutLayoutConfig[field] = String(value || "");
  } else {
    const numeric = Number(value);
    if (Number.isFinite(numeric)) nameCutLayoutConfig[field] = numeric;
  }
  if (field === "item_gap_mm") {
    nameCutLayoutConfig.target_gap_mm = nameCutLayoutConfig.item_gap_mm;
    nameCutLayoutConfig.row_gap_mm = nameCutLayoutConfig.item_gap_mm;
    nameCutLayoutConfig.joined_name_gap_mm = nameCutLayoutConfig.item_gap_mm;
  }
  if (field === "target_gap_mm") {
    nameCutLayoutConfig.item_gap_mm = nameCutLayoutConfig.target_gap_mm;
    nameCutLayoutConfig.row_gap_mm = nameCutLayoutConfig.target_gap_mm;
    nameCutLayoutConfig.joined_name_gap_mm = nameCutLayoutConfig.target_gap_mm;
  }
  if (field === "font_family") {
    const fontMeta = nameCutFontMetaByValue(nameCutLayoutConfig.font_family);
    nameCutLayoutConfig.font_family = fontMeta?.value || NAME_CUT_DEFAULT_FONT;
    if (Number.isFinite(Number(fontMeta?.defaultOffsetMm))) {
      nameCutLayoutConfig.offset_mm = clampNumber(Number(fontMeta.defaultOffsetMm), 0, 1.5);
    }
    nameCutItems = (nameCutItems || []).map(item => item.is_deleted ? item : nameCutApplyFontMetaToItem({ ...item, is_edited: true }, nameCutLayoutConfig.font_family));
  }
  applyNameCutConfigDefaultsToItems();
  nameCutPreviewPage = 1;
  const layout = currentNameCutLayout();
  renderNameCutExportPanel(combinedProductionState);
  renderLaserLayoutPreview(layout);
  renderNameCutStudioSummary(layout);
  renderNameCutSourceList(layout);
  renderNameCutControlStats(layout);
  renderNameCutBottomDetails(layout);
}

function renderNameCutExportPanel(payload = combinedProductionState) {
  const boxes = nameCutPanels(["nameCutExportPanel", "nameCutStudioExportPanel"]);
  if (!boxes.length) return;
  const layout = currentNameCutLayout();
  const summary = layout.summary || payload.layout?.summary || {};
  const qa = lastNameCutExport?.rdworks_compatibility_qa || {};
  const qaChecks = qa.checks || {};
  const exportFiles = lastNameCutExport?.status === "OK" ? `
    <div class="rdworks-export-files">
      <b>Son güvenli export paketi</b>
      <span><strong>DXF</strong> ${esc(fileName(lastNameCutExport.dxf_path || lastNameCutExport.primary_export_path || ""))}</span>
      <span><strong>SVG</strong> ${esc(fileName(lastNameCutExport.svg_path || ""))}</span>
      <span><strong>PDF</strong> ${esc(fileName(lastNameCutExport.pdf_preview || ""))}</span>
      <span><strong>PNG</strong> ${esc(fileName(lastNameCutExport.png_preview || ""))}</span>
      <span><strong>Manifest</strong> ${esc(fileName(lastNameCutExport.manifest_path || ""))}</span>
      <span><strong>PLT</strong> Henüz production backend’e bağlı değil</span>
      <div class="rdworks-qa-strip">
        <span class="${qa.status === "PASSED" ? "ok" : "warn"}">RDWorks QA: ${esc(qa.status || "Kontrol bekliyor")}</span>
        <span>mm ölçek: ${qaChecks.scale_preserved === false ? "Risk" : "Korundu"}</span>
        <span>Yardımcı çizgi: ${qaChecks.no_ui_helper_geometry === false ? "Var" : "Yok"}</span>
        <span>Kesim path: ${qaChecks.cut_paths_only === false ? "Kontrol" : "Temiz"}</span>
      </div>
      <div class="toolbar">
        <button class="btn small" type="button" onclick="bridge.open_project_file(${jsArg(lastNameCutExport.manifest_path || "")})">Manifest Aç</button>
        <button class="btn small" type="button" onclick="bridge.open_project_file(${jsArg(lastNameCutExport.pdf_preview || "")})">PDF Aç</button>
        <button class="btn small" type="button" onclick="bridge.open_project_file(${jsArg(lastNameCutExport.svg_path || "")})">SVG Aç</button>
      </div>
    </div>
  ` : "";
  const html = `
    <div class="safe-note warning">
      <b>Güvenlik hatırlatması</b><br>
      SVG/DXF/PDF gerçek dosya paketidir. RDWorks ve lazer otomatik açılmaz; dosyayı RDWorks’te manuel layer/path/font/offset kontrolünden geçirin.
    </div>
    <div class="toolbar">
      <button class="btn" type="button" onclick="openManualNameCutModal()">Manuel İsim Ekle</button>
      <button class="btn primary" type="button" onclick="prepareNameCutFiles()">Güvenli Export Paketi Hazırla</button>
      <button class="btn" type="button" onclick="showSection('bulkLabel')">Excel İşlerine Git</button>
      <button class="btn" type="button" onclick="showSection('reports')">Raporlara Git</button>
    </div>
    <div class="rdworks-settings-grid">
      <label>Font
        <select onchange="updateNameCutLayoutConfig('font_family', this.value)">
          ${renderNameCutFontOptions(nameCutLayoutConfig.font_family)}
        </select>
      </label>
      <label>Alan W<input type="number" min="100" max="1800" step="10" value="${esc(nameCutLayoutConfig.width_mm)}" oninput="updateNameCutLayoutConfig('width_mm', this.value)" /></label>
      <label>Alan H<input type="number" min="100" max="1200" step="10" value="${esc(nameCutLayoutConfig.height_mm)}" oninput="updateNameCutLayoutConfig('height_mm', this.value)" /></label>
      <label>Hedef isim W<input type="number" min="20" max="240" step="1" value="${esc(nameCutLayoutConfig.target_name_width_mm || 80)}" oninput="updateNameCutLayoutConfig('target_name_width_mm', this.value)" /></label>
      <label>Hedef isim H<input type="number" min="10" max="120" step="1" value="${esc(nameCutLayoutConfig.target_name_height_mm || 40)}" oninput="updateNameCutLayoutConfig('target_name_height_mm', this.value)" /></label>
      <label>Kenar<input type="number" min="0" max="80" step="1" value="${esc(nameCutLayoutConfig.margin_mm)}" oninput="updateNameCutLayoutConfig('margin_mm', this.value)" /></label>
      <label>İsim arası<input type="number" min="1" max="3" step="0.1" value="${esc(nameCutLayoutConfig.item_gap_mm || 1)}" oninput="updateNameCutLayoutConfig('item_gap_mm', this.value)" /></label>
      <label>Satır arası<input type="number" min="1" max="3" step="0.1" value="${esc(nameCutLayoutConfig.row_gap_mm || 1)}" oninput="updateNameCutLayoutConfig('row_gap_mm', this.value)" /></label>
      <label>Bitiştir boşluğu<input type="number" min="1" max="3" step="0.1" value="${esc(nameCutLayoutConfig.joined_name_gap_mm || 1)}" oninput="updateNameCutLayoutConfig('joined_name_gap_mm', this.value)" /></label>
      <label>Harf aralığı<input type="number" min="-8" max="16" step="0.5" value="${esc(nameCutLayoutConfig.letter_spacing_px ?? 0)}" oninput="updateNameCutLayoutConfig('letter_spacing_px', this.value)" /></label>
      <label>Kelime aralığı<input type="number" min="-8" max="28" step="0.5" value="${esc(nameCutLayoutConfig.word_spacing_px ?? 8)}" oninput="updateNameCutLayoutConfig('word_spacing_px', this.value)" /></label>
      <label class="check-row"><input type="checkbox" ${nameCutLayoutConfig.mirror_cut ? "checked" : ""} onchange="updateNameCutLayoutConfig('mirror_cut', this.checked)" /> Ayna Kesim</label>
      <label class="check-row"><input type="checkbox" ${nameCutLayoutConfig.weld_inside_name !== false ? "checked" : ""} onchange="updateNameCutLayoutConfig('weld_inside_name', this.checked)" /> Weld inside name</label>
      <label class="check-row"><input type="checkbox" ${nameCutLayoutConfig.export_as_path !== false ? "checked" : ""} onchange="updateNameCutLayoutConfig('export_as_path', this.checked)" /> Export as path</label>
      <label class="check-row"><input type="checkbox" ${nameCutLayoutConfig.capital_connection_fix !== false ? "checked" : ""} onchange="updateNameCutLayoutConfig('capital_connection_fix', this.checked)" /> Büyük harf düzelt</label>
      <label class="check-row"><input type="checkbox" ${nameCutLayoutConfig.punctuation_fix !== false ? "checked" : ""} onchange="updateNameCutLayoutConfig('punctuation_fix', this.checked)" /> Noktalama düzelt</label>
    </div>
    ${nameCutFontStatusHtml(nameCutLayoutConfig.font_family)}
    ${nameCutOffsetModeStatusHtml()}
    <div class="rdworks-layer-legend">
      <span><i class="layer-red"></i>Ana kesim</span>
      <span><i class="layer-blue"></i>Alt destek</span>
      <span><i class="layer-purple"></i>Taban/plaka</span>
      <span><i class="layer-green"></i>Kalibrasyon</span>
      <span><i class="layer-gray"></i>Kılavuz</span>
    </div>
    ${exportFiles}
    <small>${esc(summary.total_copies || 0)} kopya · ${esc(summary.pages || 0)} plate · SVG/DXF/PDF + manifest hazırlanır; PLT henüz pasiftir. RDWorks/lazer otomatik başlamaz.</small>
    <div data-namecut-export-history></div>
  `;
  boxes.forEach(box => { box.innerHTML = html; });
}

function openNameCutEditor(index) {
  if (index < 0 || index >= nameCutItems.length) return;
  nameCutEditIndex = index;
  nameCutDraft = nameCutApplyFontMetaToItem({ ...nameCutItems[index], warnings: [...(nameCutItems[index].warnings || [])], errors: [...(nameCutItems[index].errors || [])] }, nameCutItems[index].style || nameCutItems[index].fontFamily || nameCutItems[index].font_family || nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT);
  renderNameCutEditor();
  const modal = byId("nameCutEditModal");
  if (modal) modal.hidden = false;
}

function openManualNameCutModal() {
  nameCutEditIndex = -1;
  const id = `manual-name-${Date.now()}`;
  nameCutDraft = {
    item_id: id,
    row_number: nameCutItems.length + 1,
    name_text: "Sedef Sefer",
    preview_text: "Sedef   Sefer",
    quantity: "1",
    width_mm: nameCutLayoutConfig.target_name_width_mm || "80",
    height_mm: nameCutLayoutConfig.target_name_height_mm || "40",
    style: nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT,
    fontFamily: nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT,
    font_family: nameCutLayoutConfig.font_family || NAME_CUT_DEFAULT_FONT,
    composition: "İsimleri Bitiştir",
    composition_mode: "İsimleri Bitiştir",
    thickening_mode: "Özel offset",
    offset_mm: nameCutLayoutConfig.offset_mm || "0.3",
    support_line: false,
    back_plate: false,
    status: "READY",
    warnings: [],
    errors: [],
    is_deleted: false,
    is_edited: true
  };
  nameCutDraft = nameCutApplyFontMetaToItem(nameCutDraft, nameCutDraft.style);
  renderNameCutEditor();
  const modal = byId("nameCutEditModal");
  if (modal) modal.hidden = false;
}

function closeNameCutEditor() {
  const modal = byId("nameCutEditModal");
  if (modal) modal.hidden = true;
  nameCutEditIndex = -1;
  nameCutDraft = null;
}

function renderNameCutEditor() {
  if (!nameCutDraft) return;
  const layoutResult = computeNameCutLayout(nameCutDraft, { context: "modal", userSelectedComposition: nameCutDraft.composition_user_selected === true, forceRecompute: true });
  nameCutDraft.layout_result = layoutResult;
  nameCutDraft.preview_text = (layoutResult.previewLines || []).join("\n");
  setText("nameCutEditTitle", `İsim Kesim Düzenle — Satır ${nameCutDraft.row_number || "-"}`);
  const preview = byId("nameCutEditPreview");
  if (preview) preview.innerHTML = renderNameCutComputedPreview(layoutResult, true);
  const styleSelect = byId("nameCutEditStyle");
  if (styleSelect) styleSelect.innerHTML = renderNameCutFontOptions(layoutResult.fontFamily || nameCutDraft.style || NAME_CUT_DEFAULT_FONT);
  const fields = {
    nameCutEditName: nameCutDraft.name_text || "",
    nameCutEditStyle: layoutResult.fontFamily || nameCutDraft.style || NAME_CUT_DEFAULT_FONT,
    nameCutEditComposition: nameCutDraft.composition_mode || nameCutDraft.composition || "Tek Satır Yan Yana",
    nameCutEditWidth: layoutResult.widthMm || nameCutLayoutConfig.target_name_width_mm || "80",
    nameCutEditHeight: layoutResult.heightMm || nameCutLayoutConfig.target_name_height_mm || "40",
    nameCutEditQty: nameCutDraft.quantity || "1",
    nameCutEditThickening: nameCutDraft.thickening_mode || "Orta",
    nameCutEditOffset: nameCutDraft.offset_mm || nameCutOffsetForMode(nameCutDraft.thickening_mode || "Orta")
  };
  Object.entries(fields).forEach(([id, value]) => {
    const el = byId(id);
    if (el) el.value = value;
  });
  const support = byId("nameCutEditSupport");
  const plate = byId("nameCutEditPlate");
  if (support) support.checked = !!nameCutDraft.support_line;
  if (plate) plate.checked = !!nameCutDraft.back_plate;
  const status = byId("nameCutEditStatus");
  if (status) {
    const [label, tone] = nameCutStatus(nameCutDraft);
    status.innerHTML = `<span class="pill ${tone}">${esc(label)}</span><p>Font: ${esc(layoutResult.fontLabel || layoutResult.fontFamily || "-")} · Hedef: ${esc(layoutResult.widthMm)} x ${esc(layoutResult.heightMm)} mm · Kompozisyon: ${esc(nameCutCompositionLabel(layoutResult.compositionMode))} · actual ${esc(layoutResult.actualPathWidthMm)} x ${esc(layoutResult.actualPathHeightMm)} mm · offset ${esc(layoutResult.offsetMm)} mm</p>${nameCutRepairSummaryHtml(layoutResult)}`;
  }
}

function updateNameCutDraftField(field, value) {
  if (!nameCutDraft) return;
  const isNameTyping = field === "name_text";
  if (field === "name_text") value = String(value || "");
  if (field === "style") {
    nameCutDraft = nameCutApplyFontMetaToItem(nameCutDraft, value);
  } else {
    nameCutDraft[field] = value;
  }
  if (field === "name_text") nameCutDraft.text = value;
  if (field === "width_mm" || field === "height_mm") {
    nameCutDraft.operator_size_locked = true;
    nameCutDraft.custom_size = true;
  }
  if (field === "support_line" || field === "back_plate") nameCutDraft[field] = !!value;
  if (field === "composition_mode") {
    nameCutDraft.composition = value;
    nameCutDraft.compositionMode = normalizeNameCutCompositionMode(value);
    nameCutDraft.lineBreakMode = nameCutDraft.compositionMode === "preserve_lines" ? "preserve_user_lines" : nameCutDraft.compositionMode === "single_line_text" ? "single_line" : "split_to_objects";
    nameCutDraft.line_break_mode = nameCutDraft.lineBreakMode;
    nameCutDraft.composition_user_selected = true;
  }
  if (field === "thickening_mode") {
    nameCutDraft.offset_mm = nameCutOffsetForMode(value);
  }
  if (field === "offset_mm") {
    const numeric = Math.max(0, Math.min(5, Number(value || 0)));
    nameCutDraft.offset_mm = Number.isFinite(numeric) ? numeric.toFixed(2).replace(/\.00$/, "") : "0";
    nameCutDraft.thickening_mode = "Özel offset";
  }
  nameCutDraft.is_edited = true;
  nameCutDraft.warnings = [];
  const layoutResult = computeNameCutLayout(nameCutDraft, { context: "modal", userSelectedComposition: nameCutDraft.composition_user_selected === true, forceRecompute: true });
  nameCutDraft = applyNameCutLayoutResultToItem(nameCutDraft, layoutResult);
  nameCutDraft.status = nameCutDraft.repairStatus === "failed" ? "NEEDS_REVIEW" : "READY";
  if (isNameTyping) {
    refreshNameCutEditorFeedback();
    return;
  }
  renderNameCutEditor();
}

function refreshNameCutEditorFeedback() {
  if (!nameCutDraft) return;
  const preview = byId("nameCutEditPreview");
  const layoutResult = computeNameCutLayout(nameCutDraft, { context: "modal", userSelectedComposition: nameCutDraft.composition_user_selected === true, forceRecompute: true });
  nameCutDraft.layout_result = layoutResult;
  nameCutDraft.preview_text = (layoutResult.previewLines || []).join("\n");
  if (preview) preview.innerHTML = renderNameCutComputedPreview(layoutResult, true);
  const status = byId("nameCutEditStatus");
  if (status) {
    const [label, tone] = nameCutStatus(nameCutDraft);
    status.innerHTML = `<span class="pill ${tone}">${esc(label)}</span><p>Font: ${esc(layoutResult.fontLabel || layoutResult.fontFamily || "-")} · Hedef: ${esc(layoutResult.widthMm)} x ${esc(layoutResult.heightMm)} mm · Kompozisyon: ${esc(nameCutCompositionLabel(layoutResult.compositionMode))} · actual ${esc(layoutResult.actualPathWidthMm)} x ${esc(layoutResult.actualPathHeightMm)} mm · offset ${esc(layoutResult.offsetMm)} mm</p>${nameCutRepairSummaryHtml(layoutResult)}`;
  }
}

function saveNameCutDraft() {
  if (!nameCutDraft) return;
  const layoutResult = computeNameCutLayout(nameCutDraft, { context: "save", userSelectedComposition: nameCutDraft.composition_user_selected === true, forceRecompute: true });
  let savedDraft = applyNameCutLayoutResultToItem({
    ...nameCutDraft,
    name_text: formatNameCutName(nameCutDraft.name_text || ""),
    is_edited: true
  }, layoutResult);
  savedDraft = {
    ...savedDraft,
    status: savedDraft.repairStatus === "failed" ? "NEEDS_REVIEW" : "READY"
  };
  if (nameCutEditIndex < 0) {
    nameCutItems.unshift(savedDraft);
  } else {
    nameCutItems[nameCutEditIndex] = savedDraft;
  }
  selectedNameCutItemId = savedDraft.item_id || selectedNameCutItemId;
  closeNameCutEditor();
  nameCutPreviewPage = 1;
  refreshNameCutStudioViews(currentNameCutLayout());
}

function markNameCutDeleted(index = nameCutEditIndex) {
  if (index < 0 || index >= nameCutItems.length) return;
  nameCutItems[index] = { ...nameCutItems[index], is_deleted: true, is_edited: true, status: "DELETED" };
  closeNameCutEditor();
  nameCutPreviewPage = 1;
  refreshNameCutStudioViews(currentNameCutLayout());
}

function navigateNameCut(delta) {
  if (!nameCutItems.length) return;
  const next = Math.max(0, Math.min(nameCutItems.length - 1, nameCutEditIndex + delta));
  openNameCutEditor(next);
}

function nameCutExportQualitySummary(items = nameCutLiveItems(), layout = currentNameCutLayout()) {
  const qualities = (items || []).map(item => nameCutSinglePieceQuality(item, layout));
  const count = status => qualities.filter(quality => quality.status === status).length;
  const repairFailed = (items || []).filter(item => [
    "failed", "ai_quality_failed", "designer_weld_failed", "unnatural_connection",
    "internal_garbage_path", "visual_far_from_manual_reference", "connected_but_ugly",
    "connected_but_not_production_ready", "manufacturable_failed",
    "glyph_identity_failed", "invalid_mark_ownership", "wrong_glyph_mark",
    "extra_mark_generated", "detached_turkish_mark", "mark_attached_to_wrong_glyph",
    "mark_blob_risk", "reference_mismatch", "corel_style_review_required"
  ].includes(nameCutRepairState(item))).length;
  const repairAuto = (items || []).filter(item => [
    "auto_repaired", "auto_repaired_ai_verified", "designer_weld_passed", "manufacturable_passed"
  ].includes(nameCutRepairState(item))).length;
  return {
    ready_single_piece: count("ready_single_piece"),
    needs_weld: count("needs_weld"),
    needs_offset: count("needs_offset"),
    detached_marks: count("detached_marks"),
    collision_risk: count("collision_risk"),
    blocked: count("blocked"),
    repair_failed: repairFailed,
    auto_repaired: repairAuto,
    total: qualities.length
  };
}

function nameCutExportPreflight() {
  const layout = currentNameCutLayout();
  const liveItems = nameCutLiveItems();
  const qualitySummary = nameCutExportQualitySummary(liveItems, layout);
  const blockers = [];
  if (!liveItems.length) blockers.push("Export edilecek isim kesim işi yok.");
  if ((layout.summary || {}).collision_free === false) blockers.push("Temas/collision riski var; farklı isimler birbirine değmemeli.");
  if ((layout.summary || {}).within_work_area === false) blockers.push("Safe margin dışına taşan isim var.");
  if (qualitySummary.needs_weld) blockers.push(`${qualitySummary.needs_weld} isimde gerçek weld/path birleşimi kontrolü gerekli.`);
  if (qualitySummary.detached_marks) blockers.push(`${qualitySummary.detached_marks} isimde nokta/işaret ana gövdeden kopuk.`);
  if (qualitySummary.collision_risk) blockers.push(`${qualitySummary.collision_risk} isimde temas riski var.`);
  if (qualitySummary.blocked) blockers.push(`${qualitySummary.blocked} isim üretime engel durumda.`);
  if (qualitySummary.repair_failed) blockers.push(`${qualitySummary.repair_failed} isim otomatik onarımdan sonra hâlâ üretime uygun değil.`);
  const offsetWarnings = qualitySummary.needs_offset ? [`${qualitySummary.needs_offset} isimde offset/kalınlaştırma eksik. Operatör onayı olmadan export edilemez.`] : [];
  const formats = Object.entries(nameCutExportFormatState).filter(([, enabled]) => enabled).map(([key]) => key);
  if (!formats.some(format => ["svg", "dxf", "pdf"].includes(format))) blockers.push("En az bir desteklenen export formatı seçilmeli: SVG, DXF veya PDF.");
  return {
    layout,
    liveItems,
    qualitySummary,
    blockers,
    offsetWarnings,
    formats,
    canExport: !blockers.length && !offsetWarnings.length && formats.some(format => ["svg", "dxf", "pdf"].includes(format)),
    requiresOffsetApproval: offsetWarnings.length > 0 && !blockers.length,
    metrics: nameCutSourceMetrics(layout)
  };
}

function updateNameCutExportFormat(format = "", checked = false) {
  const key = String(format || "").toLowerCase();
  if (!key) return;
  if (key === "plt") {
    nameCutExportFormatState.plt = false;
    showNameCutFeatureNotice("PLT export");
    renderNameCutExportConfirmModal();
    return;
  }
  nameCutExportFormatState[key] = !!checked;
  renderNameCutExportConfirmModal();
}

function updateNameCutExportOffsetApproval(checked = false) {
  nameCutExportOffsetApproval = !!checked;
  renderNameCutExportConfirmModal();
}

function openNameCutExportConfirmModal() {
  pendingNameCutExportPayload = nameCutExportPreflight();
  nameCutExportOffsetApproval = false;
  renderNameCutExportConfirmModal();
  const modal = byId("nameCutExportConfirmModal");
  if (modal) modal.hidden = false;
}

function closeNameCutExportConfirmModal() {
  const modal = byId("nameCutExportConfirmModal");
  if (modal) modal.hidden = true;
}

function renderNameCutExportConfirmModal() {
  const box = byId("nameCutExportConfirmBody");
  if (!box) return;
  const preflight = pendingNameCutExportPayload || nameCutExportPreflight();
  const layout = preflight.layout || {};
  const cfg = layout.config || normalizeNameCutConfig();
  const summary = layout.summary || {};
  const metrics = preflight.metrics || nameCutSourceMetrics(layout);
  const direction = nameCutDirectionLabel(cfg);
  const formats = [
    ["svg", "SVG", true, "Gerçek destekli"],
    ["dxf", "DXF", true, "RDWorks için dosya; otomatik açılmaz"],
    ["pdf", "PDF", true, "Kontrol önizlemesi"],
    ["plt", "PLT", false, "Henüz production backend’e bağlı değil"]
  ];
  const hasOffsetWarning = !!preflight.offsetWarnings.length;
  box.innerHTML = `
    <div class="name-cut-export-grid">
      <div><span>Çalışma alanı</span><b>${esc(cfg.width_mm || 800)} x ${esc(cfg.height_mm || 600)} mm</b></div>
      <div><span>Hedef isim ölçüsü</span><b>${esc(cfg.target_name_width_mm || 80)} x ${esc(cfg.target_name_height_mm || 40)} mm</b></div>
      <div><span>Plate</span><b>${esc(summary.pages || 1)}</b></div>
      <div><span>İsim / adet</span><b>${esc(metrics.source_placed)} / ${esc(metrics.source_total)} · ${esc(metrics.copies_placed)} / ${esc(metrics.copies_total)}</b></div>
      <div><span>Kesim yönü</span><b>${esc(direction)}</b></div>
      <div><span>Minimum boşluk</span><b>${esc(summary.target_gap_mm || summary.min_safe_gap_mm || cfg.target_gap_mm || cfg.item_gap_mm || 1)} mm</b></div>
      <div><span>Safe margin</span><b>${esc(cfg.margin_mm || 15)} mm</b></div>
      <div><span>Offset</span><b>${esc(cfg.offset_mm ?? 0.3)} mm</b></div>
      <div><span>Tahmini süre</span><b>${esc(formatNameCutTime(summary.estimated_cut_time_seconds || 0))}</b></div>
      <div><span>Tek parça</span><b>${preflight.qualitySummary.ready_single_piece}/${preflight.qualitySummary.total}</b></div>
      <div><span>Temas kontrolü</span><b>${summary.collision_free === false || preflight.qualitySummary.collision_risk ? "Temas riski" : "Temiz"}</b></div>
    </div>
    <div class="name-cut-export-formats">
      ${formats.map(([key, label, supported, note]) => `
        <label class="${supported ? "" : "disabled"}">
          <input type="checkbox" ${nameCutExportFormatState[key] ? "checked" : ""} ${supported ? "" : "disabled"} onchange="updateNameCutExportFormat('${esc(key)}', this.checked)" />
          <b>${esc(label)}</b>
          <span>${esc(note)}</span>
        </label>
      `).join("")}
    </div>
    ${preflight.blockers.length ? `<div class="safe-note danger"><b>Export engellendi</b><br>${preflight.blockers.map(esc).join("<br>")}</div>` : ""}
    ${preflight.offsetWarnings.length ? `<div class="safe-note warning"><b>Operatör onayı gerekli</b><br>${preflight.offsetWarnings.map(esc).join("<br>")}<label class="check-row"><input id="nameCutOffsetApproval" type="checkbox" ${nameCutExportOffsetApproval ? "checked" : ""} onchange="updateNameCutExportOffsetApproval(this.checked)" /> Offset eksikliğini operatör olarak gördüm; sadece kontrol paketi export edilsin.</label></div>` : ""}
    <div class="safe-note compact"><b>Güvenlik</b><br>RDWorks, lazer ve yazıcı otomatik başlamaz. Dosya paketi oluşturulduktan sonra operatör manifest, path, layer, yön ve offset kontrollerini manuel yapar.</div>
  `;
  const approved = !hasOffsetWarning || nameCutExportOffsetApproval;
  const button = byId("nameCutExportConfirmButton");
  if (button) {
    button.disabled = !!preflight.blockers.length || (hasOffsetWarning && !approved);
    button.textContent = preflight.blockers.length ? "Export Engelli" : "Dosya Paketini Hazırla";
  }
}

function prepareNameCutFiles() {
  openNameCutExportConfirmModal();
}

function confirmNameCutSafeExport() {
  if (!bridge?.prepare_name_cut_files) {
    setNameCutExportStatus("İsim kesim export köprüsü bu oturumda hazır değil.");
    return;
  }
  const preflight = nameCutExportPreflight();
  const offsetApproved = nameCutExportOffsetApproval;
  if (preflight.blockers.length || (preflight.offsetWarnings.length && !offsetApproved)) {
    setNameCutExportStatus("Export engellendi: kalite kontrol ve operatör onayı tamamlanmalı.");
    renderNameCutExportConfirmModal();
    return;
  }
  const exportBatchId = `NCE-${new Date().toISOString().replace(/[-:T.Z]/g, "").slice(0, 14)}-${Math.random().toString(16).slice(2, 8)}`;
  const config = {
    ...nameCutLayoutConfig,
    export_batch_id: exportBatchId,
    operator: "CeyizHome Lab",
    formats: preflight.formats.filter(format => ["svg", "dxf", "pdf"].includes(format)),
    cut_direction: nameCutDirectionLabel(nameCutLayoutConfig),
    quality_summary: preflight.qualitySummary,
    operator_approved_offset_warning: offsetApproved,
  };
  const exportItems = (preflight.liveItems || []).map(item => {
    const layoutResult = nameCutLayoutResultForItem(item, { context: "export", userSelectedComposition: item.composition_user_selected === true });
    return applyNameCutLayoutResultToItem(item, layoutResult);
  });
  setNameCutExportStatus("SVG/DXF/PDF/manifest hazırlanıyor. RDWorks ve lazer açılmayacak.");
  bridge.prepare_name_cut_files(JSON.stringify({ items: exportItems, config }), raw => {
    const result = parseBridgeResult(raw);
    setNameCutExportStatus(result.message || "İsim kesim dosya hazırlığı tamamlandı.");
    if (result.status === "OK") {
      lastNameCutExport = result;
      if (Array.isArray(result.export_history)) nameCutExportHistoryRows = result.export_history;
      setNameCutExportStatus(`Güvenli export paketi hazır. Manifest: ${fileName(result.manifest_path || "")} · SVG: ${fileName(result.svg_path || "")} · PDF: ${fileName(result.pdf_preview || "")}. Lazer/RDWorks başlatılmadı.`);
      closeNameCutExportConfirmModal();
      renderNameCutExportPanel(combinedProductionState);
      renderNameCutExportHistory();
    }
    refreshState();
  });
}

