const BULK_TURKISH_FIELD_STANDARD = [
  { key: "label_text", label: "İsim", required: true, group: ["label_text", "isim", "ad_soyad", "yazilacak_isim", "yazılacak_isim"] },
  { key: "quantity", label: "Adet", required: true, group: ["quantity", "adet", "miktar"] },
  { key: "model_key", label: "Etiket Modeli", required: true, group: ["model_key", "model_name", "model_no", "template_no", "label_variant", "etiket_modeli"] },
  { key: "date_text", label: "Tarih", important: true, group: ["date_text", "date", "tarih", "nikah_tarihi"] },
  { key: "note_text", label: "Not", important: true, group: ["note_text", "note", "not", "aciklama", "açıklama"] },
  { key: "laser_name", label: "Lazer İsim", important: true, group: ["laser_name", "laser_text", "name_cut_text", "lazer_isim", "lazer_yazisi", "lazer_yazısı"] },
  { key: "order_no", label: "Sipariş No", important: true, group: ["order_no", "siparis_no", "sipariş_no", "siparis_kodu"] },
  { key: "customer_name", label: "Müşteri Adı", important: true, group: ["customer_name", "musteri_adi", "müşteri_adı"] },
  { key: "product_name", label: "Ürün Adı", important: true, group: ["product_name", "urun_adi", "ürün_adı"] },
  { key: "barcode", label: "Barkod", important: true, group: ["barcode", "barkod", "barkod_no"] },
  { key: "sku", label: "SKU", important: true, group: ["sku", "urun_kodu", "ürün_kodu"] },
  { key: "extra_note", label: "Ek Açıklama", optional: true, group: ["extra_note", "ek_aciklama", "ek_açıklama", "process_type"] },
  { key: "custom_1", label: "Özel Alan 1", optional: true, group: ["custom_1", "ozel_alan_1", "özel_alan_1"] },
  { key: "custom_2", label: "Özel Alan 2", optional: true, group: ["custom_2", "ozel_alan_2", "özel_alan_2"] },
];

function normalizeBulkFieldToken(value = "") {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replaceAll("ı", "i")
    .replaceAll("İ", "i")
    .replaceAll("ş", "s")
    .replaceAll("Ş", "s")
    .replaceAll("ğ", "g")
    .replaceAll("Ğ", "g")
    .replaceAll("ü", "u")
    .replaceAll("Ü", "u")
    .replaceAll("ö", "o")
    .replaceAll("Ö", "o")
    .replaceAll("ç", "c")
    .replaceAll("Ç", "c")
    .replace(/[^\w]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function bulkFieldDefinitionFor(value = "") {
  const token = normalizeBulkFieldToken(value);
  return BULK_TURKISH_FIELD_STANDARD.find(field => field.group.some(alias => normalizeBulkFieldToken(alias) === token)) || null;
}

function bulkFieldDisplayLabel(value = "") {
  return bulkFieldDefinitionFor(value)?.label || String(value || "-");
}

function bulkColumnConfidence(row = {}, field = null) {
  const source = normalizeBulkFieldToken(row.source || "");
  const mapped = normalizeBulkFieldToken(row.mapped || "");
  if (!row.mapped) return "Yok";
  if (field && field.group.some(alias => normalizeBulkFieldToken(alias) === source || normalizeBulkFieldToken(alias) === mapped)) return "Yüksek";
  if (String(row.role || "").toLowerCase().includes("zorunlu")) return "Yüksek";
  return "Sistem önerisi";
}

function bulkColumnStatus(row = null, field = null, missingRequired = []) {
  if (!row) {
    return field?.required ? "missing" : "optional";
  }
  const mapped = String(row.mapped || "");
  const mappedIsMissing = missingRequired.some(item => normalizeBulkFieldToken(item) === normalizeBulkFieldToken(mapped));
  if (!mapped || mappedIsMissing) return field?.required ? "missing" : "optional";
  if (field?.required && (mappedIsMissing || String(row.status || "").toLowerCase() === "required")) return "review";
  if (String(row.role || "").toLowerCase().includes("yard")) return "review";
  return "matched";
}

function bulkColumnStatusText(status = "optional") {
  return {
    matched: "Eşleşti",
    review: "Kontrol gerekli",
    missing: "Eksik",
    optional: "Opsiyonel boş",
    smart: "Akıllı eşleşme",
  }[status] || "Kontrol gerekli";
}

function bulkColumnRowsForOperator(mapping = {}) {
  const rawRows = mapping.columns || [];
  const missingRequired = mapping.missing_required || [];
  return BULK_TURKISH_FIELD_STANDARD.map(field => {
    const matchedRows = rawRows.filter(row => {
      const mappedDef = bulkFieldDefinitionFor(row.mapped);
      return mappedDef?.key === field.key || field.group.some(alias => normalizeBulkFieldToken(alias) === normalizeBulkFieldToken(row.mapped));
    });
    const matched = matchedRows[0] || null;
    const status = bulkColumnStatus(matched, field, missingRequired);
    return {
      ...field,
      row: matched,
      excelColumn: matched ? matched.source : "",
      technical: matched ? matched.mapped : field.key,
      status,
      confidence: bulkColumnConfidence(matched || {}, field),
      badge: field.required ? "Zorunlu" : field.important ? "Önerilen" : "Opsiyonel",
    };
  });
}

