function updateBulkColumnMapping(mapping) {
  const box = byId("bulkColumnMappingPanel");
  if (!box) return;
  if (!mapping || mapping.status === "NO_EXCEL") {
    box.innerHTML = `<div class="empty-state compact"><b>Excel bekleniyor.</b><p>Excel seçildiğinde kolonlar Türkçe üretim alanlarıyla otomatik eşleştirilir.</p></div>`;
    return;
  }
  if (mapping.status === "ERROR") {
    box.innerHTML = `<div class="list-row bad"><b>Kolonlar okunamadı</b><br><small>${esc(mapping.message || "Excel dosyasını kontrol edin.")}</small></div>`;
    return;
  }
  const missing = mapping.missing_required || [];
  const rows = mapping.columns || [];
  const fields = bulkColumnRowsForOperator(mapping);
  const matchedFields = fields.filter(field => field.status === "matched" || field.status === "review");
  const missingRequired = fields.filter(field => field.required && field.status === "missing");
  const reviewFields = fields.filter(field => field.status === "review" || field.status === "missing");
  const totalRows = bulkGalleryItems.length || currentState.summary?.total || currentState.summary?.valid || 0;
  const missingLabels = missingRequired.map(field => field.label);
  const head = missingRequired.length
    ? `<div class="column-wizard-note warn"><b>Eksik zorunlu alan</b><span>${missingLabels.map(esc).join(", ")}</span></div>`
    : `<div class="column-wizard-note ok"><b>Kolon eşleştirme hazır</b><span>Zorunlu alanlar bulundu. Üretimden önce satır önizlemesini kontrol edin.</span></div>`;
  box.innerHTML = `
    <div class="column-wizard operator-column-wizard">
      <div class="column-wizard-head">
        <div><b>Türkçe Kolon Eşleştirme</b><span>Excel kolonları üretim alanlarıyla eşleşti. Teknik adlar yalnızca gelişmiş bölümde tutulur.</span></div>
        <span class="pill ${missingRequired.length ? "warn" : "ok"}">${esc(matchedFields.length)} alan eşleşti</span>
      </div>
      <div class="column-wizard-grid">
        <div class="column-map-card"><small>Toplam kolon</small><b>${esc(rows.length)}</b></div>
        <div class="column-map-card"><small>Eşleşen alan</small><b>${esc(matchedFields.length)}</b></div>
        <div class="column-map-card ${missingRequired.length ? "bad" : "ok"}"><small>Eksik zorunlu</small><b>${esc(missingRequired.length)}</b></div>
        <div class="column-map-card ${reviewFields.length ? "warn" : "ok"}"><small>Kontrol gerekli</small><b>${esc(reviewFields.length)}</b></div>
        <div class="column-map-card"><small>Toplam kayıt</small><b>${esc(totalRows)}</b></div>
      </div>
      ${head}
      <div class="operator-field-grid">
        ${fields.map(field => `
          <article class="operator-field-card ${esc(field.status)}">
            <div class="operator-field-head">
              <b>${esc(field.label)}</b>
              <span class="field-required-badge ${field.required ? "required" : field.important ? "important" : "optional"}">${esc(field.badge)}</span>
            </div>
            <div class="operator-field-body">
              <span>Excel kolonu</span>
              <strong title="${esc(field.excelColumn || "")}">${esc(field.excelColumn || (field.required ? "Bulunamadı" : "Opsiyonel boş"))}</strong>
              <span>Durum</span>
              <strong class="column-status ${esc(field.status)}">${esc(bulkColumnStatusText(field.status))}</strong>
              <span>Güven</span>
              <strong>${esc(field.confidence)}</strong>
            </div>
            <div class="operator-field-actions">
              <button class="btn tiny" type="button" onclick="showBulkFeatureNotConnected('Kolon değiştirme')">Kolonu değiştir</button>
              ${field.key === "model_key" ? `<button class="btn tiny" type="button" onclick="showSection('labelModels')">Model eşleştir</button>` : ""}
              ${field.status === "missing" ? `<button class="btn tiny danger" type="button" onclick="showBulkFeatureNotConnected('Zorunlu alan düzeltme')">Zorunlu alanı düzelt</button>` : ""}
            </div>
          </article>
        `).join("")}
      </div>
      <div class="bulk-sample-preview-panel">
        <div class="section-mini-head"><b>Örnek Satır Önizleme</b><span>Üretime geçmeden önce hızlı kontrol</span></div>
        <div class="bulk-sample-grid">${bulkMappingSampleHtml()}</div>
      </div>
      <details class="bulk-technical-details">
        <summary>Gelişmiş / teknik kolonları göster</summary>
        <div class="column-wizard-list">
          ${rows.map(row => `
            <div class="column-map-row">
              <b>${esc(row.source || "-")}</b>
              <span>${esc(bulkFieldDisplayLabel(row.mapped) || "Eşleşmedi")}</span>
              <small>${esc(row.mapped || "-")} · ${esc(row.role || "yardımcı")}</small>
            </div>
          `).join("")}
          ${missing.length ? `<div class="column-map-row missing"><b>Backend eksik listesi</b><span>${missing.map(item => esc(bulkFieldDisplayLabel(item))).join(", ")}</span><small>${missing.map(esc).join(", ")}</small></div>` : ""}
        </div>
      </details>
    </div>
  `;
}

function updateBulkWarnings(errors, modelRows) {
  const list = byId("bulkWarningList");
  if (!list) return;
  if (!hasRunControl()) {
    list.innerHTML = `<div class="empty-state"><b>Önce kontrol çalıştırın.</b><p>Kritik hatalar ve kontrol gereken satırlar burada görünecek.</p></div>`;
    return;
  }
  const modelWarnings = modelRows.filter(row => row.warning).map(row => ({ title: row.warning, desc: `Model ${row.model_no || "-"} / ${row.template_no || "-"} / ${row.label_variant || "-"}` }));
  const rows = [...(errors || []), ...modelWarnings];
  const categoryCounts = rows.reduce((acc, item) => {
    const category = bulkIssueCategory(item);
    acc[category] = (acc[category] || 0) + 1;
    return acc;
  }, {});
  const categoryHtml = Object.keys(categoryCounts).length
    ? `<div class="bulk-issue-breakdown">${Object.entries(categoryCounts).map(([category, count]) => `<span>${esc(category)}: <b>${esc(count)}</b></span>`).join("")}</div>`
    : `<div class="bulk-issue-breakdown ok"><span>Kontrol sonucu: <b>kritik hata yok</b></span></div>`;
  list.innerHTML = rows.length
    ? `${categoryHtml}${rows.slice(0, 8).map(item => `<div class="list-row"><b>${esc(bulkIssueCategory(item))}</b><br><small>${esc(item.title || "Uyarı")} · ${esc(item.desc || item.row || "")}</small><p class="bulk-row-fix">${esc(bulkRowIssueHint(item))}</p></div>`).join("")}`
    : `${categoryHtml}<div class="list-row">Kritik hata görünmüyor.</div>`;
}

function bulkIssueCategory(item = {}) {
  const text = `${item.title || ""} ${item.desc || ""} ${item.row || ""}`.toLowerCase();
  if (text.includes("model") || text.includes("şablon") || text.includes("template")) return "Model eşleşmesi";
  if (text.includes("isim") || text.includes("buyer") || text.includes("ad") || text.includes("label")) return "Eksik isim / etiket yazısı";
  if (text.includes("tarih") || text.includes("date")) return "Tarih kontrolü";
  if (text.includes("not") || text.includes("note")) return "Not alanı";
  if (text.includes("preview") || text.includes("görsel")) return "Görsel kontrolü";
  if (text.includes("font")) return "Font kontrolü";
  return "Genel kontrol";
}

