function updateBulkRowPreview(samples, errors = []) {
  const box = byId("bulkRowPreviewList");
  const summaryBox = byId("bulkRowPreviewSummary");
  if (!box) return;
  if (!hasRunControl()) {
    if (summaryBox) summaryBox.innerHTML = "";
    box.innerHTML = `<div class="empty-state"><b>Önce Kontrol Et.</b><p>Excel satırları kontrol sonrası burada isim, tarih, not ve durumla görünür.</p></div>`;
    return;
  }
  const displaySamples = renderedBulkPreviewSamples.length ? renderedBulkPreviewSamples : (samples || []);
  const errorCount = (errors || []).length;
  const readyCount = displaySamples.filter(sample => sample.status !== "ERROR" && sample.render_status !== "ERROR").length;
  const previewCount = displaySamples.length;
  if (summaryBox) {
    summaryBox.innerHTML = `
      <div class="bulk-row-kpi ok"><b>${esc(readyCount)}</b><span>Hazır satır</span></div>
      <div class="bulk-row-kpi ${errorCount ? "bad" : "ok"}"><b>${esc(errorCount)}</b><span>Hata / uyarı</span></div>
      <div class="bulk-row-kpi muted"><b>${esc(previewCount)}</b><span>Önizlenen</span></div>
      <p class="${errorCount ? "preview-warning" : "success-note"}">${errorCount ? "Hatalı satırlar düzeltilmeden toplu üretime geçmeyin." : "Kontrol sonrası görünen satırlar üretime hazır görünüyor."}</p>
    `;
  }
  const errorRows = (errors || []).map(item => `
    <div class="bulk-row-card bad-row">
      <div class="bulk-row-head"><b>${esc(item.title || "Satır hatası")}</b><span class="pill bad">Kontrol gerekli</span></div>
      <small>${esc(item.desc || item.row || "Excel satırını kontrol edin.")}</small>
      <p class="bulk-row-fix">${esc(bulkRowIssueHint(item))}</p>
    </div>
  `).join("");
  const sampleRows = displaySamples.slice(0, 12).map((sample, index) => `
    <div class="bulk-row-card ${sample.status === "ERROR" || sample.render_status === "ERROR" ? "bad-row" : ""}">
      <div class="bulk-row-head">
        <div>
          <label class="check bulk-row-select">
            <input class="bulk-preview-row-select" type="checkbox" value="${esc(sample.row_number || index + 1)}" ${bulkPreviewSampleReadyForQueue(sample) ? "" : "disabled"} />
            <b>Satır ${esc(sample.row_number || index + 1)} · ${esc(sample.label_text || "-")}</b>
          </label>
          <div class="bulk-row-mini-preview">${(sample.preview_url || sample.preview_image || sample.preview_uri) ? `<img src="${esc(sample.preview_url || sample.preview_image || sample.preview_uri)}" alt="${esc(sample.model_name || "Model önizlemesi")}" />` : `<span>Mini önizleme yok</span>`}</div>
          <small class="bulk-real-preview-note">${(sample.preview_url || sample.preview_uri) ? "Gerçek render mini önizlemesi" : sample.preview_image ? "Model görseli önizlemesi" : "Gerçek mini önizleme bekleniyor"}</small>
        </div>
        <span class="pill ${sample.status === "ERROR" || sample.render_status === "ERROR" ? "bad" : "ok"}">${esc(sample.render_status === "OK" ? "Gerçek render" : sample.status === "ERROR" || sample.render_status === "ERROR" ? "Kontrol gerekli" : "Üretime hazır")}</span>
      </div>
      <div class="bulk-row-meta">
        <span>Tarih: ${esc(sample.date_text || "-")}</span>
        <span>Not: ${esc(sample.note_text || "-")}</span>
        <span>Model: ${esc(sample.model_name || sample.model_no || "-")} ${esc(sample.template_no || "")} ${esc(sample.label_variant || "")}</span>
        ${sample.render_preview_path ? `<span>Mini çıktı: ${esc(fileName(sample.render_preview_path))}</span>` : ""}
      </div>
      ${sample.render_message ? `<p class="bulk-row-fix">${esc(sample.render_message)}</p>` : ""}
    </div>
  `).join("");
  box.innerHTML = errorRows || sampleRows
    ? `${errorRows}${sampleRows}`
    : `<div class="list-row">Önizlenecek satır bulunamadı.</div>`;
}

function renderBulkRealMiniPreviews() {
  const status = byId("bulkRowPreviewStatus");
  if (!hasRunControl()) {
    if (status) status.textContent = "Önce Kontrol Et çalıştırın.";
    return;
  }
  if (!bridge?.render_bulk_preview_samples) {
    if (status) status.textContent = "Gerçek mini önizleme bu oturumda hazır değil.";
    return;
  }
  if (status) status.textContent = "Gerçek mini önizlemeler oluşturuluyor...";
  bridge.render_bulk_preview_samples(raw => {
    const result = parseBridgeResult(raw);
    if (result.status !== "OK") {
      renderedBulkPreviewSamples = [];
      if (status) status.textContent = result.message || "Mini önizleme oluşturulamadı.";
      return;
    }
    renderedBulkPreviewSamples = result.samples || [];
    if (status) status.textContent = result.message || "Gerçek mini önizlemeler hazır.";
    updateBulkRowPreview(currentState.bulkPreviewSamples || [], currentState.errors || []);
  });
}

function selectedBulkPreviewRowNumbers() {
  return Array.from(document.querySelectorAll(".bulk-preview-row-select:checked"))
    .map(input => String(input.value || "").trim())
    .filter(Boolean);
}

function bulkPreviewSampleReadyForQueue(sample = {}) {
  const status = String(sample.status || "").toUpperCase();
  const renderStatus = String(sample.render_status || "").toUpperCase();
  const quantity = Number(sample.quantity || 1);
  if (status === "ERROR" || renderStatus === "ERROR") return false;
  if (!String(sample.label_text || "").trim()) return false;
  if (!String(sample.model_name || sample.model_no || "").trim()) return false;
  if (!Number.isFinite(quantity) || quantity < 1) return false;
  return true;
}

function selectedReadyBulkPreviewRowNumbers() {
  const displaySamples = renderedBulkPreviewSamples.length ? renderedBulkPreviewSamples : (currentState.bulkPreviewSamples || []);
  const sampleByRow = new Map((displaySamples || []).map((sample, index) => [String(sample.row_number || index + 1), sample]));
  const selected = selectedBulkPreviewRowNumbers();
  const ready = [];
  const blocked = [];
  selected.forEach(rowNumber => {
    const sample = sampleByRow.get(String(rowNumber));
    if (!sample || bulkPreviewSampleReadyForQueue(sample)) ready.push(rowNumber);
    else blocked.push(rowNumber);
  });
  return { ready, blocked };
}

function latestBatchPdfOutput() {
  const outputs = currentState.labelOutputs || [];
  return outputs
    .filter(item => {
      const path = item.relative_path || item.path || "";
      const name = item.name || item.file_name || path;
      const type = String(item.type || item.kind || "").toLowerCase();
      if (!String(path || name).toLowerCase().endsWith(".pdf")) return false;
      if (type.includes("teknik") || String(path).includes("reports/")) return false;
      return type.includes("batch") || type.includes("toplu") || type.includes("manuel") || String(name).toLowerCase().includes("batch");
    })
    .sort((a, b) => String(b.created_at || b.name || "").localeCompare(String(a.created_at || a.name || "")))[0] || null;
}

function updateSelectedBulkRunCard() {
  const box = byId("selectedBulkRunCard");
  if (!box) return;
  const rows = selectedBulkRunState.rows || [];
  const rowLabel = rows.length ? `${rows.length} satır` : "Satır seçilmedi";
  const statusMap = {
    idle: ["Hazır", "Seçili satırlar için üretim sonucu burada görünür.", "muted"],
    starting: ["Üretim başlatılıyor", selectedBulkRunState.message || "PDF/PNG ve queue zinciri güvenli şekilde başlatılıyor.", "pending"],
    started: ["Üretim kuyruğa alındı", selectedBulkRunState.message || "Çıktılar oluşturuluyor; durum kısa süre içinde yenilenecek.", "ok"],
    laser_prepared: ["Lazer hazırlık kuyruğu güncellendi", selectedBulkRunState.message || "İsim Kesim hazırlığı oluşturuldu; RDWorks ve lazer otomatik başlatılmaz.", "pending"],
    completed: ["Üretim tamamlandı", selectedBulkRunState.message || "Seçili satırlar üretildi ve yazdırma sırası güncellendi.", "ok"],
    cancelled: ["İşlem iptal edildi", selectedBulkRunState.message || "Devam eden toplu üretim güvenli şekilde durduruldu.", "pending"],
    error: ["İşlem başlatılamadı", selectedBulkRunState.message || "Seçili satır üretimi başlatılamadı.", "bad"]
  };
  const [title, desc, tone] = statusMap[selectedBulkRunState.status] || statusMap.idle;
  const updated = selectedBulkRunState.updatedAt ? `<span>Son işlem: ${esc(selectedBulkRunState.updatedAt)}</span>` : "";
  const latestBatch = selectedBulkRunState.status === "completed" ? latestBatchPdfOutput() : null;
  const latestBatchPath = latestBatch?.relative_path || latestBatch?.path || "";
  const outputActions = latestBatchPath ? `
    <div class="toolbar selected-bulk-run-actions">
      <button class="btn small print-primary" onclick="requestPdfPrint('${esc(latestBatchPath)}', { modelName: 'Toplu etiket', fileName: '${esc(fileName(latestBatchPath))}' })">Yazdır</button>
      <button class="btn small gold" onclick="addPdfToQueue('${esc(latestBatchPath)}')">Yazdırma Sırasına Ekle</button>
    </div>
  ` : "";
  box.innerHTML = `
    <div class="selected-bulk-run-card ${tone}">
      <div>
        <b>${esc(title)}</b>
        <p>${esc(desc)}</p>
        ${outputActions}
      </div>
      <div class="selected-bulk-run-meta">
        <span>${esc(rowLabel)}</span>
        ${selectedBulkRunState.queueCount !== undefined ? `<span>Queue: ${esc(selectedBulkRunState.queueCount)} iş</span>` : ""}
        ${updated}
      </div>
    </div>
  `;
}

function syncSelectedBulkRunFromState(run) {
  if (!run || !run.status) {
    updateSelectedBulkRunCard();
    return;
  }
  const map = {
    IDLE: "idle",
    STARTED: "started",
    COMPLETED: "completed",
    CANCELLED: "cancelled",
    ERROR: "error"
  };
  const mappedStatus = map[String(run.status || "").toUpperCase()] || "idle";
  const rows = Array.isArray(run.row_numbers) ? run.row_numbers : [];
  selectedBulkRunState = {
    status: mappedStatus,
    rows,
    message: run.message || selectedBulkRunState.message || "",
    updatedAt: selectedBulkRunState.updatedAt || "",
    queueCount: run.queue_count
  };
  updateSelectedBulkRunCard();
}

function updateBulkRunningControls(state = currentState) {
  const cancelButton = byId("bulkCancelJobButton");
  if (!cancelButton) return;
  const running = Boolean(state?.commandRunning);
  cancelButton.disabled = !running;
  cancelButton.textContent = running ? `${state.currentCommand || "İşlem"} İptal Et` : "Devam Eden İşlemi İptal Et";
}

function cancelRunningBulkJob() {
  const status = byId("bulkRowPreviewStatus");
  if (!bridge?.cancel_running_job) {
    if (status) status.textContent = "İptal için masaüstü köprüsü hazır değil.";
    return;
  }
  bridge.cancel_running_job(raw => {
    const result = parseBridgeResult(raw);
    if (status) status.textContent = result.message || "İptal isteği işlendi.";
    refreshState();
  });
}

function setSelectedBulkRunState(nextState = {}) {
  selectedBulkRunState = {
    ...selectedBulkRunState,
    ...nextState,
    updatedAt: new Date().toLocaleTimeString("tr-TR", { hour: "2-digit", minute: "2-digit" })
  };
  updateSelectedBulkRunCard();
}

function renderSelectedBulkMiniPreviews() {
  const status = byId("bulkRowPreviewStatus");
  if (!hasRunControl()) {
    if (status) status.textContent = "Önce Kontrol Et çalıştırın.";
    return;
  }
  const rowNumbers = selectedBulkPreviewRowNumbers();
  if (!rowNumbers.length) {
    if (status) status.textContent = "Önizleme almak için en az bir satır seçin.";
    return;
  }
  if (!bridge?.render_selected_bulk_preview_samples) {
    if (status) status.textContent = "Seçili satır render akışı bu oturumda hazır değil.";
    return;
  }
  if (status) status.textContent = `${rowNumbers.length} seçili satır için gerçek mini önizleme oluşturuluyor...`;
  bridge.render_selected_bulk_preview_samples(JSON.stringify(rowNumbers), raw => {
    const result = parseBridgeResult(raw);
    if (result.status !== "OK") {
      if (status) status.textContent = result.message || "Seçili satır mini önizlemesi oluşturulamadı.";
      return;
    }
    const selectedSamples = result.samples || [];
    const selectedSet = new Set(selectedSamples.map(sample => String(sample.row_number || "")));
    const previous = renderedBulkPreviewSamples.filter(sample => !selectedSet.has(String(sample.row_number || "")));
    renderedBulkPreviewSamples = [...selectedSamples, ...previous];
    if (status) status.textContent = result.message || "Seçili satır mini önizlemeleri hazır.";
    updateBulkRowPreview(currentState.bulkPreviewSamples || [], currentState.errors || []);
  });
}

function generateSelectedBulkRowsAndQueue() {
  const status = byId("bulkRowPreviewStatus");
  if (!hasRunControl()) {
    if (status) status.textContent = "Önce Kontrol Et çalıştırın.";
    setSelectedBulkRunState({ status: "error", rows: [], message: "Önce Kontrol Et çalıştırın." });
    return;
  }
  const selectedRows = selectedBulkPreviewRowNumbers();
  if (!selectedRows.length) {
    if (status) status.textContent = "Üretmek için en az bir satır seçin.";
    setSelectedBulkRunState({ status: "error", rows: [], message: "Üretmek için en az bir satır seçin." });
    return;
  }
  const { ready: rowNumbers, blocked } = selectedReadyBulkPreviewRowNumbers();
  if (!rowNumbers.length) {
    const message = `${blocked.length} seçili satır hata/eksik alan nedeniyle üretime alınmadı. Hazır satır seçin.`;
    if (status) status.textContent = message;
    setSelectedBulkRunState({ status: "error", rows: selectedRows, message });
    return;
  }
  if (!bridge?.bulk_generate_selected_and_add_to_queue) {
    if (status) status.textContent = "Seçili satır üretim akışı bu oturumda hazır değil.";
    setSelectedBulkRunState({ status: "error", rows: rowNumbers, message: "Seçili satır üretim akışı bu oturumda hazır değil." });
    return;
  }
  const skippedMessage = blocked.length ? ` ${blocked.length} sorunlu satır üretime alınmadı.` : "";
  const startMessage = `${rowNumbers.length} hazır seçili satır için PDF/PNG üretimi ve Yazdırma Sırası aktarımı başlatılıyor...${skippedMessage}`;
  if (status) status.textContent = startMessage;
  setSelectedBulkRunState({ status: "starting", rows: rowNumbers, message: startMessage });
  bridge.bulk_generate_selected_and_add_to_queue(JSON.stringify(rowNumbers), raw => {
    const result = parseBridgeResult(raw);
    if (status) status.textContent = `${result.message || "Seçili satır üretim isteği gönderildi."}${skippedMessage}`;
    if (result.status === "STARTED") {
      setSelectedBulkRunState({ status: "started", rows: rowNumbers, message: `${result.message || "Seçili satırlar için üretim başlatıldı. Yazdırma sırası yenileniyor."}${skippedMessage}` });
      setTimeout(refreshState, 900);
    } else {
      setSelectedBulkRunState({ status: "error", rows: rowNumbers, message: result.message || "Seçili satır üretimi başlatılamadı." });
    }
  });
}

function bulkRowIssueHint(item = {}) {
  const text = `${item.title || ""} ${item.desc || ""} ${item.row || ""}`.toLowerCase();
  if (text.includes("model") || text.includes("şablon") || text.includes("template")) {
    return "Model eşleşmesini kontrol edin veya Etiket Modelleri ekranında doğru modeli seçin.";
  }
  if (text.includes("isim") || text.includes("ad") || text.includes("label")) {
    return "İsim / Etiket Yazısı sütununu doldurun; boş isim üretime alınmaz.";
  }
  if (text.includes("tarih") || text.includes("date")) {
    return "Tarih formatını kontrol edin ve boş bırakılmaması gerekiyorsa Excel’de tamamlayın.";
  }
  if (text.includes("not") || text.includes("note")) {
    return "Not alanı boş kalacaksa bilinçli boş bırakın; görünmesini istiyorsanız Excel’de doldurun.";
  }
  return "Excel satırını düzeltip tekrar Kontrol Et çalıştırın.";
}

function rollLayoutVisualHtml({ width, height, gap, total, rollWidth, perRow, overflow, costPerMeter = 0, currency = "TL" }) {
  const totalCount = Math.max(1, Number(total) || perRow || 1);
  const safePerRow = Math.max(1, Number(perRow) || 1);
  const rowCount = Math.max(1, Math.ceil(totalCount / safePerRow));
  const lastRowCount = ((totalCount - 1) % safePerRow) + 1;
  const emptySlots = Math.max(0, safePerRow - lastRowCount);
  const rowsToDraw = Math.max(1, Math.min(3, rowCount));
  const labelWidthPercent = overflow ? 100 : Math.max(10, Math.min(92, (width / Math.max(rollWidth, 1)) * 100));
  const gapPercent = overflow ? 0 : Math.max(1, Math.min(8, (gap / Math.max(rollWidth, 1)) * 100));
  const usedFullRowWidth = safePerRow * width + Math.max(0, safePerRow - 1) * gap;
  const emptyFullRowWidth = Math.max(0, rollWidth - usedFullRowWidth);
  const usedLastRowWidth = lastRowCount * width + Math.max(0, lastRowCount - 1) * gap;
  const emptyLastRowWidth = Math.max(0, rollWidth - usedLastRowWidth);
  const approximateStripLength = rowCount * height + Math.max(0, rowCount - 1) * gap;
  const fullRowWastePercent = rollWidth > 0 ? Math.min(100, Math.max(0, (emptyFullRowWidth / rollWidth) * 100)) : 0;
  const lastRowWastePercent = rollWidth > 0 ? Math.min(100, Math.max(0, (emptyLastRowWidth / rollWidth) * 100)) : 0;
  const weightedWasteWidth = rowCount > 1
    ? (((rowCount - 1) * emptyFullRowWidth) + emptyLastRowWidth) / rowCount
    : emptyLastRowWidth;
  const averageWastePercent = rollWidth > 0 ? Math.min(100, Math.max(0, (weightedWasteWidth / rollWidth) * 100)) : 0;
  const stripArea = Math.max(0, rollWidth * approximateStripLength);
  const labelArea = Math.max(0, totalCount * width * height);
  const usedAreaPercent = stripArea > 0 ? Math.min(100, Math.max(0, (labelArea / stripArea) * 100)) : 0;
  const wasteAreaPercent = Math.max(0, 100 - usedAreaPercent);
  const stripLengthMeters = approximateStripLength / 1000;
  const totalRollCost = Math.max(0, Number(costPerMeter) || 0) * stripLengthMeters;
  const costPerLabel = totalCount > 0 ? totalRollCost / totalCount : 0;
  let remaining = totalCount;
  const rows = Array.from({ length: rowsToDraw }, (_, rowIndex) => {
    const count = Math.max(1, Math.min(safePerRow, remaining || safePerRow));
    remaining = Math.max(0, remaining - count);
    return `
      <div class="roll-preview-row">
        ${Array.from({ length: count }, (_, index) => `
          <span class="roll-preview-label" style="width:${labelWidthPercent}%; margin-right:${index === count - 1 ? 0 : gapPercent}%;">
            ${esc(rowIndex * perRow + index + 1)}
          </span>
        `).join("")}
      </div>
    `;
  }).join("");
  const breakdownRows = Array.from({ length: Math.min(6, rowCount) }, (_, rowIndex) => {
    const start = rowIndex * safePerRow + 1;
    const count = Math.max(0, Math.min(safePerRow, totalCount - rowIndex * safePerRow));
    const end = Math.max(start, start + count - 1);
    const rowEmpty = Math.max(0, safePerRow - count);
    return `
      <div class="roll-breakdown-row">
        <span>Satır ${rowIndex + 1}</span>
        <small>${esc(start)}-${esc(end)} arası · ${esc(count)} etiket${rowEmpty ? ` · ${esc(rowEmpty)} boş yer` : ""}</small>
      </div>
    `;
  }).join("");
  const hiddenRows = Math.max(0, rowCount - 6);
  return `
    <div class="roll-visual-card ${overflow ? "bad" : "ok"}">
      <div class="roll-visual-head">
        <b>Rulo yerleşim simülasyonu</b>
        <span>${overflow ? "Taşma var" : "Taşma görünmüyor"}</span>
      </div>
      <div class="roll-preview-strip" style="--roll-ratio:${Math.max(2, Math.min(8, rollWidth / Math.max(height, 1)))};">
        ${rows}
      </div>
      <div class="roll-visual-meta">
        <span>Rulo: ${esc(rollWidth)} mm</span>
        <span>Etiket: ${esc(width)} x ${esc(height)} mm</span>
        <span>Aralık: ${esc(gap)} mm</span>
        <span>Satır: ${esc(safePerRow)} adet</span>
        <span>Toplam satır: ${esc(rowCount)}</span>
        <span>Son satır: ${esc(lastRowCount)} etiket${emptySlots ? ` · ${esc(emptySlots)} boş yer` : ""}</span>
        <span>Yaklaşık şerit: ${esc(Number(approximateStripLength.toFixed(1)))} mm</span>
        <span>Toplam uzunluk: ${esc(Number(stripLengthMeters.toFixed(2)))} m</span>
        <span>Boş genişlik: ${esc(Number((rowCount > 1 ? emptyFullRowWidth : emptyLastRowWidth).toFixed(1)))} mm / satır</span>
        <span>Ortalama fire: %${esc(Number(averageWastePercent.toFixed(1)))}</span>
        <span>Kullanılan alan: %${esc(Number(usedAreaPercent.toFixed(1)))}</span>
        ${costPerMeter > 0 ? `<span>Yaklaşık maliyet: ${esc(Number(totalRollCost.toFixed(2)))} ${esc(currency)}</span>` : ""}
        ${costPerMeter > 0 ? `<span>Etiket başı: ${esc(Number(costPerLabel.toFixed(3)))} ${esc(currency)}</span>` : ""}
      </div>
      <div class="roll-waste-note ${overflow ? "bad" : "ok"}">
        <b>Fire özeti</b>
        <span>${overflow
          ? "Etiket genişliği rulo genişliğini aşıyor; rulo ayarını düzeltmeden üretime geçmeyin."
          : `Tam satırda yaklaşık ${esc(Number(emptyFullRowWidth.toFixed(1)))} mm (%${esc(Number(fullRowWastePercent.toFixed(1)))}), son satırda yaklaşık ${esc(Number(emptyLastRowWidth.toFixed(1)))} mm (%${esc(Number(lastRowWastePercent.toFixed(1)))}) boş genişlik kalır.`}</span>
        ${overflow ? "" : `<small>Yaklaşık alan firesi: %${esc(Number(wasteAreaPercent.toFixed(1)))}. Bu değer rulo genişliği x toplam şerit uzunluğu üzerinden hesaplanır.</small>`}
        ${costPerMeter > 0 ? `<small>Yaklaşık maliyet ${esc(Number(stripLengthMeters.toFixed(2)))} m x ${esc(Number(costPerMeter.toFixed(2)))} ${esc(currency)} üzerinden hesaplandı; fire dahil toplam rulo tüketimini gösterir.</small>` : `<small>Maliyet görmek için metre maliyetini girin; veri girilmezse mock maliyet gösterilmez.</small>`}
      </div>
      <div class="roll-row-breakdown">
        <b>Satır kırılımı</b>
        ${breakdownRows}
        ${hiddenRows ? `<small class="muted">${esc(hiddenRows)} satır daha aynı kuralla devam eder.</small>` : ""}
      </div>
    </div>
  `;
}

function updateRollLayoutPreview(state) {
  const box = byId("rollLayoutPreview");
  if (!box) return;
  if (!hasRunControl()) {
    box.innerHTML = `<div class="empty-state"><b>Önce Kontrol Et.</b><p>Rulo yerleşim bilgisi Excel analizinden sonra hesaplanır.</p></div>`;
    return;
  }
  const defaults = state.labelDefaults || {};
  const summary = state.summary || {};
  const width = Number(defaults.label_width_mm || 50);
  const height = Number(defaults.label_height_mm || 30);
  const gap = Number(defaults.roll_gap_mm || 3);
  const total = Number(summary.label || summary.valid || summary.total || 0);
  const rollWidth = Number(defaults.roll_width_mm || width);
  const perRow = Math.max(1, Math.floor((rollWidth + gap) / Math.max(width + gap, 1)));
  const overflow = width > rollWidth;
  const costPerMeter = Math.max(0, Number(byId("bulkRollCostPerMeter")?.value || 0) || 0);
  const currency = String(byId("bulkRollCostCurrency")?.value || "TL").trim() || "TL";
  box.innerHTML = `
    ${rollLayoutVisualHtml({ width, height, gap, total, rollWidth, perRow, overflow, costPerMeter, currency })}
    <div class="list-row"><b>Etiket ölçüsü</b><br><small>${esc(width)} x ${esc(height)} mm · Aralık ${esc(gap)} mm</small></div>
    <div class="list-row"><b>Rulo genişliği</b><br><small>${esc(rollWidth)} mm · Satır başına yaklaşık ${esc(perRow)} etiket</small></div>
    <div class="list-row"><b>Toplam</b><br><small>${esc(total)} etiket · ${overflow ? "Taşma var" : "Taşma görünmüyor"}</small></div>
    ${overflow ? `<div class="preview-warning">Rulo genişliği etiket genişliğinden küçük. Rulo batch oluşturmadan önce Ayarlar’ı kontrol edin.</div>` : ""}
  `;
}

function nextBulkPreview() {
  bulkPreviewIndex += 1;
  updateBulkPreview(currentState.bulkPreviewSamples || []);
}

function prevBulkPreview() {
  bulkPreviewIndex = Math.max(0, bulkPreviewIndex - 1);
  updateBulkPreview(currentState.bulkPreviewSamples || []);
}

function updateLabelOutputs(rows) {
  const list = byId("labelOutputList");
  const reports = byId("labelOutputReports");
  const summary = byId("labelOutputSummary");
  if (!list) return;
  const isReport = item => isTechnicalOutput(item) || isTestOrDemoOutput(item);
  const customerOutputs = sortCustomerOutputsForDefault(rows.filter(isCustomerOutput));
  const reportRows = rows.filter(isReport);
  const hasPng = customerOutputs.some(item => String(item.name || item.file_name || item.relative_path || "").toLowerCase().endsWith(".png"));
  const hasPdf = customerOutputs.some(item => String(item.name || item.file_name || item.relative_path || "").toLowerCase().endsWith(".pdf"));
  const searchInput = byId("labelOutputSearch");
  const typeInput = byId("labelOutputTypeFilter");
  const modelInput = byId("labelOutputModelFilter");
  const dateInput = byId("labelOutputDateFilter");
  const statusInput = byId("labelOutputStatusFilter");
  const queueInput = byId("labelOutputQueueFilter");
  labelOutputFilterState.query = String(searchInput?.value || labelOutputFilterState.query || "").trim().toLowerCase();
  labelOutputFilterState.type = String(typeInput?.value || labelOutputFilterState.type || "all");
  labelOutputFilterState.model = String(modelInput?.value || labelOutputFilterState.model || "all");
  labelOutputFilterState.date = String(dateInput?.value || labelOutputFilterState.date || "all");
  labelOutputFilterState.status = String(statusInput?.value || labelOutputFilterState.status || "all");
  labelOutputFilterState.queue = String(queueInput?.value || labelOutputFilterState.queue || "all");
  updateLabelOutputTabs();
  if (modelInput) {
    const previous = labelOutputFilterState.model;
    const models = [...new Set(customerOutputs.map(outputModelLabel).filter(Boolean))].sort((a, b) => a.localeCompare(b, "tr"));
    modelInput.innerHTML = `<option value="all">Tüm modeller</option>${models.map(model => `<option value="${esc(model)}">${esc(model)}</option>`).join("")}`;
    modelInput.value = models.includes(previous) ? previous : "all";
    labelOutputFilterState.model = modelInput.value;
  }
  const outputCreatedDate = item => {
    const raw = String(item.created_at || item.relative_path || item.path || item.name || "");
    const match = raw.match(/20\d{2}-\d{2}-\d{2}/);
    return match ? match[0] : "";
  };
  const localDateKey = date => {
    const y = date.getFullYear();
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const d = String(date.getDate()).padStart(2, "0");
    return `${y}-${m}-${d}`;
  };
  const todayKey = localDateKey(new Date());
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 6);
  const sevenDaysAgoKey = localDateKey(sevenDaysAgo);
  const matchesDateFilter = item => {
    if (labelOutputFilterState.date === "all") return true;
    const key = outputCreatedDate(item);
    if (!key) return false;
    if (labelOutputFilterState.date === "today") return key === todayKey;
    if (labelOutputFilterState.date === "last7") return key >= sevenDaysAgoKey && key <= todayKey;
    return true;
  };
  const hiddenReviewOutputs = customerOutputs.filter(item => {
    const history = historyForOutputPath(outputPath(item));
    return ["check", "missing"].includes(outputValidationState(item, history));
  });
  const filteredOutputs = customerOutputs.filter(item => {
    const kind = outputKind(item);
    const path = outputPath(item);
    const history = historyForOutputPath(path);
    const validationState = outputValidationState(item, history);
    const queueState = outputQueueState(path, history);
    const haystack = [
      item.display_name,
      item.model_name,
      item.name,
      item.file_name,
      item.relative_path,
      item.label_text,
      item.date_text,
      item.note_text
    ].map(value => String(value || "").toLowerCase()).join(" ");
    const matchesQuery = !labelOutputFilterState.query || haystack.includes(labelOutputFilterState.query);
    const matchesType = labelOutputFilterState.type === "all" || labelOutputFilterState.type === kind;
    const matchesModel = labelOutputFilterState.model === "all" || outputModelLabel(item) === labelOutputFilterState.model;
    const matchesStatus = labelOutputFilterState.status === "all" || labelOutputFilterState.status === validationState;
    const matchesQueue = labelOutputFilterState.queue === "all" || labelOutputFilterState.queue === queueState;
    if (labelOutputFilterState.status === "all" && ["check", "missing"].includes(validationState)) return false;
    return matchesQuery && matchesType && matchesModel && matchesDateFilter(item) && matchesStatus && matchesQueue;
  });
  const groupSummary = byId("labelOutputGroupSummary");
  if (groupSummary) {
    const groups = new Map();
    filteredOutputs.forEach(item => {
      const key = outputModelLabel(item) || "Model bilgisi yok";
      const group = groups.get(key) || { total: 0, pdf: 0, png: 0, batch: 0, queued: 0 };
      const kind = outputKind(item);
      const history = historyForOutputPath(outputPath(item));
      group.total += 1;
      if (kind === "pdf") group.pdf += 1;
      if (kind === "png") group.png += 1;
      if (kind === "batch") group.batch += 1;
      if (history && productionHistoryQueueState(history) === "queued") group.queued += 1;
      groups.set(key, group);
    });
    const cards = [...groups.entries()]
      .sort((a, b) => b[1].total - a[1].total || a[0].localeCompare(b[0], "tr"))
      .slice(0, 4)
      .map(([model, group]) => `
        <div class="output-group-card">
          <b>${esc(model)}</b>
          <span>${esc(group.total)} çıktı · ${esc(group.pdf)} PDF · ${esc(group.png)} PNG · ${esc(group.batch)} batch</span>
          <small>${esc(group.queued)} kayıt yazdırma sırası ile eşleşiyor.</small>
        </div>
      `).join("");
    groupSummary.innerHTML = filteredOutputs.length
      ? `<div class="output-group-head"><b>Çıktı grupları</b><span>Filtrelenen müşteri çıktıları modele göre özetlenir.</span></div>${cards}`
      : "";
  }
  const archiveAdvisor = byId("labelOutputArchiveAdvisor");
  if (archiveAdvisor) {
    const oldCustomerOutputs = customerOutputs.filter(item => {
      const key = outputCreatedDate(item);
      return key && key < sevenDaysAgoKey;
    });
    const unmatchedOutputs = customerOutputs.filter(item => !historyForOutputPath(outputPath(item)));
    const recentOutputs = customerOutputs.length - oldCustomerOutputs.length;
    if (!customerOutputs.length) {
      archiveAdvisor.innerHTML = "";
    } else {
      archiveAdvisor.innerHTML = `
        <div class="archive-advisor-card">
          <div>
            <b>Güvenli arşiv önerisi</b>
            <span>${esc(oldCustomerOutputs.length)} eski müşteri çıktısı arşiv adayı · ${esc(recentOutputs)} çıktı son 7 gün içinde.</span>
            ${unmatchedOutputs.length ? `<small>${esc(unmatchedOutputs.length)} çıktı üretim geçmişiyle eşleşmiyor; silmeden önce dosyayı manuel kontrol edin.</small>` : `<small>Üretim geçmişi eşleşen dosyalar güvenli şekilde listeleniyor.</small>`}
          </div>
          <div class="toolbar">
            <button class="btn small" type="button" onclick="setLabelOutputDateFilter('last7')">Son 7 Günü Göster</button>
            <button class="btn small" type="button" onclick="selectLabelOutputTab('technical')">Teknik/Test Arşivi Gör</button>
            <button class="btn small" type="button" onclick="archiveSelectedLabelOutputs()">Seçilileri Arşive Taşı</button>
            ${oldCustomerOutputs.length ? `<button class="btn small gold" type="button" onclick="archiveOldLabelOutputs()">Eski Çıktıları Arşive Taşı</button>` : ""}
          </div>
        </div>
      `;
    }
  }
  const archiveList = byId("labelOutputArchiveList");
  if (archiveList) {
    const archived = currentState.archivedLabelOutputs || [];
    const archiveModelLabel = item => {
      const history = historyForOutputPath(outputPath(item));
      return String(history?.model_name || item.model_name || item.display_name || item.model_no || fileName(item.name || item.file_name || outputPath(item) || "Arşiv çıktısı")).trim();
    };
    const archiveModels = [...new Set(archived.map(archiveModelLabel).filter(Boolean))].sort((a, b) => a.localeCompare(b, "tr"));
    if (labelArchiveFilterState.model !== "all" && !archiveModels.includes(labelArchiveFilterState.model)) {
      labelArchiveFilterState.model = "all";
    }
    const archiveDate = item => labelOutputCreatedDate(item);
    const filteredArchive = archived.filter(item => {
      const modelOk = labelArchiveFilterState.model === "all" || archiveModelLabel(item) === labelArchiveFilterState.model;
      const dateKey = archiveDate(item);
      const dateOk = labelArchiveFilterState.date === "all" || (labelArchiveFilterState.date === "today" && dateKey === todayKey) || (labelArchiveFilterState.date === "last7" && dateKey >= sevenDaysAgoKey && dateKey <= todayKey);
      return modelOk && dateOk;
    });
    const archiveHistory = currentState.labelOutputArchiveHistory || [];
    const archiveHistoryHtml = archiveHistory.length
      ? `
        <div class="archive-history-card">
          <b>Arşiv hareketleri</b>
          ${archiveHistory.slice(0, 5).map(row => `
            <div class="archive-history-row">
              <span>${esc(row.action === "restored" ? "Geri alındı" : "Arşivlendi")}</span>
              <small>${esc(row.created_at || "")} · ${esc(row.count || 0)} çıktı</small>
            </div>
          `).join("")}
        </div>
      `
      : "";
    archiveList.innerHTML = archived.length || archiveHistory.length
      ? `
        <details class="archive-list-card">
          <summary>Arşivdeki çıktılar (${esc(filteredArchive.length)} / ${esc(archived.length)})</summary>
          <p class="muted">Silinen dosya yoktur; arşive taşınan müşteri PDF/PNG çıktılarını gerektiğinde geri alabilirsiniz.</p>
          <div class="archive-filter-bar">
            <select id="labelArchiveModelFilter" onchange="setArchiveModelFilter(this.value)">
              <option value="all">Tüm modeller</option>
              ${archiveModels.map(model => `<option value="${esc(model)}" ${labelArchiveFilterState.model === model ? "selected" : ""}>${esc(model)}</option>`).join("")}
            </select>
            <select id="labelArchiveDateFilter" onchange="setArchiveDateFilter(this.value)">
              <option value="all" ${labelArchiveFilterState.date === "all" ? "selected" : ""}>Tüm tarihler</option>
              <option value="today" ${labelArchiveFilterState.date === "today" ? "selected" : ""}>Bugün</option>
              <option value="last7" ${labelArchiveFilterState.date === "last7" ? "selected" : ""}>Son 7 gün</option>
            </select>
            <button class="btn small" onclick="clearArchiveFilters()" type="button">Arşiv Filtrelerini Temizle</button>
          </div>
          <div class="archive-output-list">
            ${filteredArchive.slice(0, 12).map(item => {
              const path = outputPath(item);
              const isPdf = String(path || item.name || "").toLowerCase().endsWith(".pdf");
              return `
                <div class="archive-output-row">
                  <div>
                    <b>${esc(fileName(item.name || item.file_name || path || "Arşiv çıktısı"))}</b>
                    <small>${esc(archiveModelLabel(item))} · ${esc(item.created_at || "")} · ${esc(item.size_kb || "-")} KB</small>
                  </div>
                  <div class="toolbar">
                    ${isPdf ? `<button class="btn small" onclick="openPdfPreview('${esc(path)}')">PDF’i Gör</button>` : `<button class="btn small" onclick="selectManualPngPreview('${esc(path)}')">PNG Önizle</button>`}
                    <button class="btn small gold" onclick="restoreLabelOutput('${esc(path)}')">Geri Al</button>
                  </div>
                </div>
              `;
            }).join("") || `<div class="archive-output-row"><div><b>Bu filtreye uygun arşiv çıktısı yok.</b><small>Filtreleri temizleyerek tüm arşivi görebilirsiniz.</small></div></div>`}
          </div>
          ${archiveHistoryHtml}
        </details>
      `
      : "";
  }
  if (summary) {
    const summaryOutputs = labelOutputFilterState.status === "all"
      ? customerOutputs.filter(item => {
        const history = historyForOutputPath(outputPath(item));
        return !["check", "missing"].includes(outputValidationState(item, history));
      })
      : customerOutputs;
    const pdfCount = summaryOutputs.filter(item => outputKind(item) === "pdf").length;
    const pngCount = summaryOutputs.filter(item => outputKind(item) === "png").length;
    const batchCount = summaryOutputs.filter(item => outputKind(item) === "batch").length;
    const todayCount = summaryOutputs.filter(item => outputLooksLikeToday(item)).length;
    const queuedCount = summaryOutputs.filter(item => outputQueueState(outputPath(item), historyForOutputPath(outputPath(item))) === "queued").length;
    const customerSummaryTab = ["all", "pdf", "png", "batch", "roll"].includes(labelOutputFilterState.type);
    const statusSummaryLabel = !customerSummaryTab
      ? "müşteri çıktısı"
      : labelOutputFilterState.status === "check"
      ? "kontrol gereken çıktı"
      : labelOutputFilterState.status === "missing"
        ? "dosyası bulunamayan çıktı"
        : "doğrulanmış çıktı";
    const reviewSummaryNote = !customerSummaryTab
      ? "Teknik arşiv ve üretim geçmişi müşteri galerisinden ayrı tutulur."
      : labelOutputFilterState.status === "all" && hiddenReviewOutputs.length
      ? `${hiddenReviewOutputs.length} kontrol gereken çıktı filtre altında tutuluyor.`
      : labelOutputFilterState.status === "check"
        ? "Bu çıktılar yazdırılmadan önce yeniden kontrol edilmelidir."
        : "Teknik raporlar varsayılan müşteri galerisine karışmaz.";
    summary.innerHTML = `
      <button class="output-kpi" type="button" onclick="selectLabelOutputTab('all')"><span>Toplam Çıktı</span><b>${summaryOutputs.length}</b><small>${labelOutputFilterState.status === "all" ? "Doğrulanmış müşteri dosyaları" : "Tüm müşteri dosyaları"}</small></button>
      <button class="output-kpi pdf" type="button" onclick="selectLabelOutputTab('pdf')"><span>PDF</span><b>${pdfCount}</b><small>PDF dosyaları</small></button>
      <button class="output-kpi png" type="button" onclick="selectLabelOutputTab('png')"><span>PNG</span><b>${pngCount}</b><small>Görsel önizlemeler</small></button>
      <button class="output-kpi batch" type="button" onclick="selectLabelOutputTab('batch')"><span>Batch PDF</span><b>${batchCount}</b><small>Toplu çıktı</small></button>
      <button class="output-kpi today" type="button" onclick="setLabelOutputDateFilter('today')"><span>Bugünkü Çıktı</span><b>${todayCount}</b><small>Bugün oluşturulan</small></button>
      <button class="output-kpi queued" type="button" onclick="setLabelOutputQueueFilter('queued')"><span>Yazdırma Sırasında</span><b>${queuedCount}</b><small>Queue’da bekleyen</small></button>
      <p>${customerOutputs.length ? `${filteredOutputs.length} ${statusSummaryLabel} gösteriliyor. ${reviewSummaryNote}` : "Henüz müşteri çıktısı yok. Etiket Studio veya Toplu Etiket ekranından çıktı oluşturun."}</p>
    `;
  }
  if (labelOutputFilterState.type === "history") {
    const historyRows = filteredProductionHistory(currentState.productionHistory || []);
    list.innerHTML = historyRows.length
      ? historyRows.map(item => {
        const pdf = item.pdf_path || item.batch_pdf_path || "";
        const png = item.png_path || "";
        const sizeText = item.width_mm && item.height_mm ? `${item.width_mm} x ${item.height_mm} mm` : "";
        const validation = productionHistoryValidationState(item);
        return `
          <article class="output-card history-output-card" onclick="selectLabelOutput('${esc(pdf || png)}')">
            <span class="output-type-badge history">Geçmiş</span>
            <div class="output-thumb">${png ? `<img src="${esc(outputPreviewForPath(png, item) || png)}" alt="${esc(item.model_name || "Üretim geçmişi")}" onerror="this.parentElement.innerHTML='<div class=&quot;output-preview-placeholder&quot;><b>Önizleme yok</b><span>Geçmiş kaydı var.</span></div>'" />` : `<div class="output-preview-placeholder"><b>Geçmiş</b><span>PDF/PNG kaydı bulunuyor.</span></div>`}</div>
            <b>${esc(item.model_name || item.model_id || "Etiket üretimi")}</b>
            <p class="output-card-subtitle">${esc(item.label_text || "-")} · ${esc(item.created_at || "")}</p>
            <div class="output-production-meta">
              ${item.date_text ? `<span>Tarih: ${esc(item.date_text)}</span>` : ""}
              ${item.note_text ? `<span>Not: ${esc(item.note_text)}</span>` : ""}
              ${sizeText ? `<span>Ölçü: ${esc(sizeText)}</span>` : ""}
              <span>Adet: ${esc(item.quantity || 1)}</span>
            </div>
            <div class="output-pair-meta">
              <span class="${validation === "passed" ? "ok" : "warn"}">${validation === "passed" ? "Doğrulandı" : "Kontrol gerekli"}</span>
              <span class="${productionHistoryQueueState(item) === "queued" ? "ok" : ""}">${productionHistoryQueueState(item) === "queued" ? "Sırada" : "Sırada değil"}</span>
            </div>
            <div class="toolbar">
              ${pdf ? `<button class="btn small primary" onclick="event.stopPropagation(); openPdfPreview('${esc(pdf)}')">PDF’i Aç</button><button class="btn small print-primary" onclick="event.stopPropagation(); requestPdfPrint('${esc(pdf)}', { modelName: '${esc(item.model_name || "Etiket")}', labelText: '${esc(item.label_text || "")}', dateText: '${esc(item.date_text || "")}', noteText: '${esc(item.note_text || "")}', sizeText: '${esc(sizeText)}', quantity: '${esc(item.quantity || 1)}', fileName: '${esc(fileName(pdf))}' })">Yazdır</button><button class="btn small gold" onclick="event.stopPropagation(); addPdfToQueue('${esc(pdf)}')">Sıraya Ekle</button>` : ""}
              ${png ? `<button class="btn small" onclick="event.stopPropagation(); selectManualPngPreview('${esc(png)}')">PNG Önizle</button>` : ""}
              <button class="btn small" onclick="event.stopPropagation(); openHistoryInStudio(${jsArg(item.model_path || "")}, ${jsArg(item.label_text || "")}, ${jsArg(item.date_text || "")}, ${jsArg(item.note_text || "")}, ${jsArg(item.model_name || item.model_id || "")})">Studio’da Aç</button>
            </div>
          </article>
        `;
      }).join("")
      : `<div class="empty-state"><b>Üretim geçmişi bulunamadı.</b><p>PDF/PNG oluşturduğunuzda geçmiş kartları burada görünecek.</p></div>`;
    if (reports) reports.innerHTML = `<div class="list-row">Üretim geçmişi müşteri galerisi içinde kart görünümünde gösteriliyor.</div>`;
    updateSelectedOutputPanel(selectedLabelOutputPath);
    return;
  }
  const galleryOutputs = sortCustomerOutputsForDefault(filteredOutputs);
  if (labelOutputFilterState.type === "technical") {
    list.innerHTML = reportRows.length
      ? reportRows.map(item => {
        const path = item.relative_path || item.path || "";
        return `
          <article class="output-card technical-output-item">
            <div class="output-thumb"><div><b>${esc(isTestOrDemoOutput(item) ? "Test/QA" : "Teknik")}</b><small>${esc(isTestOrDemoOutput(item) ? "Kalite kapısı / test çıktısı" : "Üretim raporu / kalite dosyası")}</small></div></div>
            <b>${esc(fileName(item.name || item.file_name || path || "Teknik rapor"))}</b>
            <p class="muted">Bu dosya müşteri çıktısı değildir. Varsayılan galeriye ve normal yazdırma akışına karışmaz.</p>
            <p class="muted">Oluşturulma: ${esc(item.created_at || "-")}</p>
            <div class="toolbar">
              <button class="btn small" onclick="event.stopPropagation(); bridge.open_project_file('${esc(path)}')">Harici Aç</button>
            </div>
          </article>
        `;
      }).join("")
      : `<div class="empty-state"><b>Teknik arşiv boş.</b><p>Bu çalışma için rapor veya kalite dosyası görünmüyor.</p></div>`;
    if (reports) reports.innerHTML = `<div class="list-row">Teknik arşiv ana listede gösteriliyor.</div>`;
    updateSelectedOutputPanel("");
    return;
  }
  list.innerHTML = filteredOutputs.length
    ? galleryOutputs.map(item => {
      const name = String(item.name || item.file_name || item.relative_path || "").toLowerCase();
      const isPng = name.endsWith(".png");
      const isPdf = name.endsWith(".pdf");
      const kind = outputKind(item);
      const inferredType = outputKindLabel(kind);
      const path = item.relative_path || item.path || "";
      const history = historyForOutputPath(path);
      const modelLabel = history?.model_name || item.model_name || item.display_name || item.model_no || "";
      const labelText = history?.label_text || item.label_text || "";
      const dateText = history?.date_text || item.date_text || "";
      const noteText = history?.note_text || item.note_text || "";
      const quantity = history?.quantity || item.quantity || "";
      const sizeText = history?.width_mm && history?.height_mm ? `${history.width_mm} x ${history.height_mm} mm` : (item.size_text || "");
      const pair = outputPairForPath(path, history);
      const validationState = outputValidationState(item, history);
      const queueState = outputQueueState(path, history);
      const selectedClass = normalizeOutputRef(path) === normalizeOutputRef(selectedLabelOutputPath) ? " selected" : "";
      const pairMeta = `
        <div class="output-pair-meta">
          ${pair.pdfPath ? `<span class="ok">PDF eşleşti</span>` : ""}
          ${pair.pngPath ? `<span class="ok">PNG eşleşti</span>` : ""}
          ${history ? `<span>Üretim geçmişi bağlı</span>` : `<span class="warn">Eşleşme yok</span>`}
          <span class="${validationState === "validated" ? "ok" : "warn"}">${esc(outputValidationLabel(validationState))}</span>
          <span class="${queueState === "queued" ? "ok" : ""}">${esc(queueState === "queued" ? "Sırada" : queueState === "printed" ? "Yazdırıldı" : "Sırada değil")}</span>
        </div>`;
      return `
      <article class="output-card${selectedClass}" onclick="selectLabelOutput('${esc(path)}')">
        <label class="output-select-check" onclick="event.stopPropagation()"><input type="checkbox" ${selectedOutputArchivePaths.has(path) ? "checked" : ""} onchange="toggleOutputArchiveSelection('${esc(path)}', this.checked)" /> Seç</label>
        <div class="output-card-badges">
          <span class="output-type-badge ${esc(kind)}">${esc(inferredType)}</span>
          <span class="output-validation-badge ${esc(validationState)}">${esc(outputValidationLabel(validationState))}</span>
        </div>
        <div class="output-thumb">${outputPreviewHtml(item, history, modelLabel || item.display_name || item.name)}</div>
        <b>${esc(item.display_name || item.model_name || (item.model_no ? `Model ${item.model_no}` : fileName(item.name || item.file_name || item.relative_path || "Etiket çıktısı")))}</b>
        <p class="output-card-subtitle">${esc(labelText || fileName(item.name || item.file_name || path || "Çıktı"))}</p>
        <div class="output-production-meta">
          ${modelLabel ? `<span>Model: ${esc(modelLabel)}</span>` : ""}
          ${labelText ? `<span>İsim: ${esc(labelText)}</span>` : ""}
          ${dateText ? `<span>Tarih: ${esc(dateText)}</span>` : ""}
          ${noteText ? `<span>Not: ${esc(noteText)}</span>` : ""}
          ${sizeText ? `<span>Ölçü: ${esc(sizeText)}</span>` : ""}
          ${quantity ? `<span>Adet: ${esc(quantity)}</span>` : ""}
          <span>Oluşturma: ${esc(item.created_at || "-")}</span>
        </div>
        ${pairMeta}
        <div class="toolbar">
          ${isPdf ? `<button class="btn small primary" onclick="event.stopPropagation(); openPdfPreview('${esc(path)}')">PDF Aç</button>` : pair.pdfPath ? `<button class="btn small primary" onclick="event.stopPropagation(); openPdfPreview('${esc(pair.pdfPath)}')">PDF Aç</button>` : `<button class="btn small primary" onclick="event.stopPropagation(); selectLabelOutput('${esc(path)}')">PNG Önizle</button>`}
          ${(isPdf || pair.pdfPath) ? `<button class="btn small print-primary" onclick="event.stopPropagation(); requestPdfPrint('${esc(isPdf ? path : pair.pdfPath)}', { modelName: '${esc(modelLabel || "Etiket")}', labelText: '${esc(labelText || "")}', dateText: '${esc(dateText || "")}', noteText: '${esc(noteText || "")}', sizeText: '${esc(sizeText || "")}', quantity: '${esc(quantity || "1")}', fileName: '${esc(fileName(isPdf ? path : pair.pdfPath))}' })">Yazdır</button>` : ""}
          ${isPdf && pair.pngPath ? `<button class="btn small" onclick="event.stopPropagation(); selectManualPngPreview('${esc(pair.pngPath)}')">PNG Önizle</button>` : ""}
          ${isPdf ? `<button class="btn small gold" onclick="event.stopPropagation(); addPdfToQueue('${esc(path)}')">Sıraya Ekle</button>` : pair.pdfPath ? `<button class="btn small gold" onclick="event.stopPropagation(); addPdfToQueue('${esc(pair.pdfPath)}')">PDF’i Sıraya Ekle</button>` : `<button class="btn small" onclick="event.stopPropagation(); showLabelOutputStatus('PNG önizleme dosyasıdır. Yazdırma sırasına PDF eklenir.', 'warn')">Sıraya PDF Eklenir</button>`}
          <button class="btn small" data-history-action="${history ? "ready" : "missing"}" onclick="event.stopPropagation(); openOutputHistoryInStudio('${esc(path)}')">Studio’da Aç</button>
          <button class="btn small" data-history-action="${history ? "ready" : "missing"}" onclick="event.stopPropagation(); reproduceOutputFromHistory('${esc(path)}')">Tekrar Üret</button>
          <button class="btn small" onclick="event.stopPropagation(); bridge.open_project_file('${esc(path)}')">Harici Aç</button>
          <button class="btn small" onclick="event.stopPropagation(); bridge.open_print_folder()">Klasörde Göster</button>
          <button class="btn small" onclick="event.stopPropagation(); archiveLabelOutput('${esc(path)}')">Arşive Taşı</button>
        </div>
      </article>
    `}).join("")
    : customerOutputs.length
      ? `<div class="empty-state"><b>${hiddenReviewOutputs.length && labelOutputFilterState.status === "all" ? "Doğrulanmış müşteri çıktısı görünmüyor." : "Bu filtrelere uygun çıktı bulunamadı."}</b><p>${hiddenReviewOutputs.length && labelOutputFilterState.status === "all" ? `${hiddenReviewOutputs.length} çıktı kontrol gerekli durumunda. Müşteri galerisine almadan önce PDF/PNG doğrulamasını yenileyin veya kontrol listesinden inceleyin.` : "Aramayı temizleyin veya başka dosya tipi seçin."}</p><div class="toolbar"><button class="btn primary" onclick="clearLabelOutputFilters()">Filtreleri Temizle</button>${hiddenReviewOutputs.length && labelOutputFilterState.status === "all" ? `<button class="btn gold" onclick="setLabelOutputStatusFilter('check')">Kontrol Gerekenleri Göster</button>` : ""}</div></div>`
      : `<div class="empty-state"><b>${hasPdf && !hasPng ? "Henüz görsel önizleme yok." : "Henüz etiket çıktısı yok."}</b><p>${hasPdf && !hasPng ? "PDF’i harici açarak kontrol edebilirsiniz." : "Toplu Etiket veya Etiket Studio ekranından PDF/PNG oluşturun."}</p><div class="toolbar"><button class="btn primary" onclick="showSection('bulkLabel')">Toplu Etikete Git</button><button class="btn" onclick="showSection('label')">Etiket Studio’ya Git</button></div></div>`;
  if (filteredOutputs.length) {
    const selectedVisible = galleryOutputs.some(item => normalizeOutputRef(outputPath(item)) === normalizeOutputRef(selectedLabelOutputPath));
    if (!selectedVisible) selectedLabelOutputPath = outputPath(galleryOutputs[0]);
  } else if (labelOutputFilterState.type !== "technical") {
    selectedLabelOutputPath = "";
  }
  updateSelectedOutputPanel(selectedLabelOutputPath);
  if (reports) {
    reports.innerHTML = reportRows.length
      ? reportRows.map(item => `<div class="list-row"><b>${esc(fileName(item.name || item.file_name || item.relative_path || "Rapor"))}</b><br><small>${esc(item.created_at || "")}</small></div>`).join("")
      : `<div class="list-row">Bu üretim için ilgili rapor görünmüyor.</div>`;
  }
}

function updateLabelOutputTabs() {
  document.querySelectorAll("[data-output-tab]").forEach(button => {
    button.classList.toggle("active", button.dataset.outputTab === labelOutputFilterState.type);
  });
}

function selectLabelOutputTab(type) {
  labelOutputFilterState.type = type || "all";
  const typeInput = byId("labelOutputTypeFilter");
  if (typeInput) typeInput.value = labelOutputFilterState.type;
  updateLabelOutputs(currentState.labelOutputs || []);
}

function refreshLabelOutputFilters() {
  updateLabelOutputs(currentState.labelOutputs || []);
}

function clearLabelOutputFilters() {
  labelOutputFilterState = { query: "", type: "all", model: "all", date: "all", status: "all", queue: "all" };
  const searchInput = byId("labelOutputSearch");
  const typeInput = byId("labelOutputTypeFilter");
  const modelInput = byId("labelOutputModelFilter");
  const dateInput = byId("labelOutputDateFilter");
  const statusInput = byId("labelOutputStatusFilter");
  const queueInput = byId("labelOutputQueueFilter");
  if (searchInput) searchInput.value = "";
  if (typeInput) typeInput.value = "all";
  if (modelInput) modelInput.value = "all";
  if (dateInput) dateInput.value = "all";
  if (statusInput) statusInput.value = "all";
  if (queueInput) queueInput.value = "all";
  updateLabelOutputs(currentState.labelOutputs || []);
  showLabelOutputStatus("Çıktı filtreleri temizlendi.", "ok");
}

function openOutputHistoryInStudio(path) {
  const history = historyForOutputPath(path);
  if (!history) {
    showLabelOutputStatus("Bu çıktı için üretim geçmişi bulunamadı. Studio’da açmak için önce geçmiş kaydı gerekir.", "warn");
    return;
  }
  openHistoryInStudio(
    history.model_path || "",
    history.label_text || "",
    history.date_text || "",
    history.note_text || "",
    history.model_name || history.model_id || ""
  );
}

function reproduceOutputFromHistory(path) {
  const history = historyForOutputPath(path);
  if (!history) {
    showLabelOutputStatus("Bu çıktı için tekrar üretim bilgisi bulunamadı.", "warn");
    return;
  }
  openOutputHistoryInStudio(path);
  showLabelOutputStatus("Geçmiş bilgiler Studio'ya alındı. PDF/PNG üretmek için Studio'da 'Üret' butonuna basın (operatör onayı gerekli).", "ok");
}

function setLabelOutputDateFilter(value) {
  labelOutputFilterState.date = value || "all";
  const dateInput = byId("labelOutputDateFilter");
  if (dateInput) dateInput.value = labelOutputFilterState.date;
  updateLabelOutputs(currentState.labelOutputs || []);
}

function setLabelOutputQueueFilter(value) {
  labelOutputFilterState.queue = value || "all";
  const queueInput = byId("labelOutputQueueFilter");
  if (queueInput) queueInput.value = labelOutputFilterState.queue;
  updateLabelOutputs(currentState.labelOutputs || []);
}

function setLabelOutputStatusFilter(value) {
  labelOutputFilterState.status = value || "all";
  const statusInput = byId("labelOutputStatusFilter");
  if (statusInput) statusInput.value = labelOutputFilterState.status;
  updateLabelOutputs(currentState.labelOutputs || []);
}

function setArchiveModelFilter(value) {
  labelArchiveFilterState.model = value || "all";
  updateLabelOutputs(currentState.labelOutputs || []);
}

function setArchiveDateFilter(value) {
  labelArchiveFilterState.date = value || "all";
  updateLabelOutputs(currentState.labelOutputs || []);
}

function clearArchiveFilters() {
  labelArchiveFilterState = { model: "all", date: "all" };
  updateLabelOutputs(currentState.labelOutputs || []);
  showLabelOutputStatus("Arşiv filtreleri temizlendi.", "ok");
}

function labelOutputCreatedDate(item) {
  const raw = String(item?.created_at || item?.relative_path || item?.path || item?.name || "");
  const match = raw.match(/20\d{2}-\d{2}-\d{2}/);
  return match ? match[0] : "";
}

function toggleOutputArchiveSelection(path, checked) {
  const cleanPath = String(path || "").trim();
  if (!cleanPath) return;
  if (checked) selectedOutputArchivePaths.add(cleanPath);
  else selectedOutputArchivePaths.delete(cleanPath);
}

function archiveLabelOutput(path) {
  if (!bridge?.archive_label_outputs) {
    showLabelOutputStatus("Arşivleme için masaüstü köprüsü hazır değil.", "warn");
    return;
  }
  const cleanPath = String(path || "").trim();
  if (!cleanPath) {
    showLabelOutputStatus("Arşivlenecek çıktı seçilemedi.", "warn");
    return;
  }
  bridge.archive_label_outputs(JSON.stringify([cleanPath]), raw => {
    const result = parseBridgeResult(raw);
    showLabelOutputStatus(result.message || "Çıktı arşivleme işlemi tamamlandı.", result.status === "OK" ? "ok" : "warn");
    refreshState();
  });
}

function archiveOldLabelOutputs() {
  const today = new Date();
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(today.getDate() - 6);
  const key = `${sevenDaysAgo.getFullYear()}-${String(sevenDaysAgo.getMonth() + 1).padStart(2, "0")}-${String(sevenDaysAgo.getDate()).padStart(2, "0")}`;
  const paths = (currentState.labelOutputs || [])
    .filter(isCustomerOutput)
    .filter(item => {
      const created = labelOutputCreatedDate(item);
      return created && created < key;
    })
    .map(outputPath)
    .filter(Boolean);
  if (!paths.length) {
    showLabelOutputStatus("Arşivlenecek eski müşteri çıktısı bulunamadı.", "warn");
    return;
  }
  bridge.archive_label_outputs(JSON.stringify(paths), raw => {
    const result = parseBridgeResult(raw);
    showLabelOutputStatus(result.message || "Eski çıktılar arşivlendi.", result.status === "OK" ? "ok" : "warn");
    refreshState();
  });
}

function archiveSelectedLabelOutputs() {
  if (!bridge?.archive_label_outputs) {
    showLabelOutputStatus("Arşivleme için masaüstü köprüsü hazır değil.", "warn");
    return;
  }
  const paths = Array.from(selectedOutputArchivePaths).filter(Boolean);
  if (!paths.length) {
    showLabelOutputStatus("Önce arşivlenecek PDF/PNG çıktılarını seçin.", "warn");
    return;
  }
  const ok = confirm(`${paths.length} müşteri çıktısı güvenli arşive taşınacak. Dosyalar silinmez; arşivden geri alınabilir. Devam edilsin mi?`);
  if (!ok) return;
  bridge.archive_label_outputs(JSON.stringify(paths), raw => {
    const result = parseBridgeResult(raw);
    selectedOutputArchivePaths = new Set();
    showLabelOutputStatus(result.message || "Seçili çıktılar arşivlendi.", result.status === "OK" ? "ok" : "warn");
    refreshState();
  });
}

function restoreLabelOutput(path) {
  if (!bridge?.restore_label_outputs) {
    showLabelOutputStatus("Arşivden geri alma için masaüstü köprüsü hazır değil.", "warn");
    return;
  }
  const cleanPath = String(path || "").trim();
  if (!cleanPath) {
    showLabelOutputStatus("Geri alınacak arşiv çıktısı seçilemedi.", "warn");
    return;
  }
  bridge.restore_label_outputs(JSON.stringify([cleanPath]), raw => {
    const result = parseBridgeResult(raw);
    showLabelOutputStatus(result.message || "Arşivden geri alma işlemi tamamlandı.", result.status === "OK" ? "ok" : "warn");
    refreshState();
  });
}

function productionHistoryTopValue(rows, key, fallback = "-") {
  const counts = new Map();
  (rows || []).forEach(item => {
    const raw = String(item?.[key] || "").trim();
    if (!raw) return;
    counts.set(raw, (counts.get(raw) || 0) + Number(item.quantity || 1));
  });
  if (!counts.size) return fallback;
  return [...counts.entries()].sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0], "tr"))[0][0];
}

function updateProductionHistoryAnalytics(rows) {
  const box = byId("productionHistoryAnalytics");
  if (!box) return;
  const items = rows || [];
  if (!items.length) {
    box.innerHTML = `<div class="history-analytics-empty">Henüz üretim geçmişi yok. İlk PDF/PNG üretiminden sonra model, isim ve queue özeti burada görünür.</div>`;
    return;
  }
  const totalQuantity = items.reduce((sum, item) => sum + Number(item.quantity || 1), 0);
  const uniqueModels = new Set(items.map(item => String(item.model_name || item.model_id || "").trim()).filter(Boolean)).size;
  const queuedCount = items.filter(item => {
    const status = String(item.queue_status || item.queue_result?.status || "").toUpperCase();
    return status.includes("QUEUE") || status.includes("ADDED") || status.includes("EKL");
  }).length;
  const validatedCount = items.filter(item => {
    const status = String(item.output_validation_status || item.output_validation?.status || "").toUpperCase();
    return status.includes("PASS") || status.includes("OK") || status.includes("BAŞAR");
  }).length;
  const topModel = productionHistoryTopValue(items, "model_name", "Veri yok");
  const topLabel = productionHistoryTopValue(items, "label_text", "Veri yok");
  const byDay = new Map();
  items.forEach(item => {
    const day = productionHistoryDateKey(item) || "Tarihsiz";
    byDay.set(day, (byDay.get(day) || 0) + Number(item.quantity || 1));
  });
  const dayRows = [...byDay.entries()].sort((a, b) => a[0].localeCompare(b[0])).slice(-7);
  const maxDay = Math.max(1, ...dayRows.map(row => row[1]));
  const dayBars = dayRows.map(([day, count]) => `
    <div class="history-day-bar">
      <span>${esc(day)}</span>
      <div><i style="width:${Math.max(8, Math.round((count / maxDay) * 100))}%"></i></div>
      <b>${esc(count)}</b>
    </div>
  `).join("");
  box.innerHTML = `
    <div class="history-analytics-grid">
      <div class="history-analytics-card"><b>${esc(items.length)}</b><span>Üretim kaydı</span></div>
      <div class="history-analytics-card"><b>${esc(totalQuantity)}</b><span>Toplam adet</span></div>
      <div class="history-analytics-card"><b>${esc(uniqueModels || "-")}</b><span>Kullanılan model</span></div>
      <div class="history-analytics-card ok"><b>${esc(validatedCount)}</b><span>Doğrulanan çıktı</span></div>
    </div>
    <div class="history-analytics-chips">
      <span>Top model: ${esc(topModel)}</span>
      <span>Top isim: ${esc(topLabel)}</span>
      <span>Queue kaydı: ${esc(queuedCount)}</span>
    </div>
    ${dayBars ? `<div class="history-day-bars"><b>Son günlere göre adet</b>${dayBars}</div>` : ""}
  `;
}

function productionHistoryQueueState(item) {
  const status = String(item.queue_status || item.queue_result?.status || "").toUpperCase();
  return status.includes("QUEUE") || status.includes("ADDED") || status.includes("EKL") || status.includes("EXISTS")
    ? "queued"
    : "not_queued";
}

function productionHistoryValidationState(item) {
  const status = String(item.output_validation_status || item.output_validation?.status || "").toUpperCase();
  return status.includes("PASS") || status.includes("OK") || status.includes("BAŞAR")
    ? "passed"
    : "not_passed";
}

function productionHistoryDateKey(item) {
  const raw = String(item?.created_at || item?.pdf_path || item?.png_path || item?.batch_pdf_path || "");
  const match = raw.match(/20\d{2}-\d{2}-\d{2}/);
  return match ? match[0] : "";
}

function updateProductionHistoryFilterOptions(rows) {
  const modelInput = byId("productionHistoryModelFilter");
  if (!modelInput) return;
  const previous = productionHistoryFilterState.model || modelInput.value || "all";
  const models = [...new Set((rows || [])
    .map(item => String(item.model_name || item.model_id || "").trim())
    .filter(Boolean))]
    .sort((a, b) => a.localeCompare(b, "tr"));
  modelInput.innerHTML = `<option value="all">Tüm modeller</option>${models.map(model => `<option value="${esc(model)}">${esc(model)}</option>`).join("")}`;
  modelInput.value = models.includes(previous) ? previous : "all";
  productionHistoryFilterState.model = modelInput.value;
}

function filteredProductionHistory(rows) {
  const searchInput = byId("productionHistorySearch");
  const modelInput = byId("productionHistoryModelFilter");
  const queueInput = byId("productionHistoryQueueFilter");
  const validationInput = byId("productionHistoryValidationFilter");
  const fromInput = byId("productionHistoryFromDate");
  const toInput = byId("productionHistoryToDate");
  productionHistoryFilterState.query = String(searchInput?.value || productionHistoryFilterState.query || "").trim().toLowerCase();
  productionHistoryFilterState.model = String(modelInput?.value || productionHistoryFilterState.model || "all");
  productionHistoryFilterState.queue = String(queueInput?.value || productionHistoryFilterState.queue || "all");
  productionHistoryFilterState.validation = String(validationInput?.value || productionHistoryFilterState.validation || "all");
  productionHistoryFilterState.from = String(fromInput?.value || productionHistoryFilterState.from || "");
  productionHistoryFilterState.to = String(toInput?.value || productionHistoryFilterState.to || "");
  return (rows || []).filter(item => {
    const haystack = [
      item.model_name,
      item.model_id,
      item.label_text,
      item.date_text,
      item.note_text,
      item.pdf_path,
      item.png_path,
      item.batch_pdf_path,
    ].map(value => String(value || "").toLowerCase()).join(" ");
    const modelName = String(item.model_name || item.model_id || "").trim();
    const dateKey = productionHistoryDateKey(item);
    if (productionHistoryFilterState.query && !haystack.includes(productionHistoryFilterState.query)) return false;
    if (productionHistoryFilterState.model !== "all" && modelName !== productionHistoryFilterState.model) return false;
    if (productionHistoryFilterState.queue !== "all" && productionHistoryQueueState(item) !== productionHistoryFilterState.queue) return false;
    if (productionHistoryFilterState.validation !== "all" && productionHistoryValidationState(item) !== productionHistoryFilterState.validation) return false;
    if (productionHistoryFilterState.from && (!dateKey || dateKey < productionHistoryFilterState.from)) return false;
    if (productionHistoryFilterState.to && (!dateKey || dateKey > productionHistoryFilterState.to)) return false;
    return true;
  });
}

function updateProductionHistory(rows) {
  const box = byId("productionHistoryList");
  const customerRows = customerProductionHistoryRows(rows || []);
  updateProductionHistoryFilterOptions(customerRows);
  const filtered = filteredProductionHistory(customerRows);
  updateProductionHistoryAnalytics(filtered);
  if (!box) return;
  const recent = filtered.slice(0, 12);
  box.innerHTML = recent.length
    ? recent.map(item => {
      const pdf = item.pdf_path || item.batch_pdf_path || "";
      const png = item.png_path || "";
      const preflight = item.preflight_status || item.preflight?.status || "Kayıtlı";
      const validation = item.output_validation_status || item.output_validation?.status || "Kayıtlı";
      const queued = item.queue_status || item.queue_result?.status || "MANUEL";
      const sizeText = item.width_mm && item.height_mm ? `${item.width_mm} x ${item.height_mm} mm` : "";
      return `
        <div class="list-row production-history-row">
          <b>${esc(item.model_name || "Etiket üretimi")}</b><br>
          <small>${esc(item.created_at || "")} · ${esc(item.label_text || "-")} · ${esc(item.quantity || 1)} adet${sizeText ? ` · ${esc(sizeText)}` : ""}</small>
          <div class="history-match-meta">
            <span>Preflight: ${esc(preflight)}</span>
            <span>Çıktı doğrulama: ${esc(validation)}</span>
            <span>Queue: ${esc(queued)}</span>
          </div>
          <div class="toolbar">
            ${pdf ? `<button class="btn small primary" onclick="openPdfPreview('${esc(pdf)}')">PDF’i Gör</button>` : ""}
            ${png ? `<button class="btn small" onclick="selectManualPngPreview('${esc(png)}')">PNG Önizle</button>` : ""}
            ${pdf ? `<button class="btn small gold" onclick="addPdfToQueue('${esc(pdf)}')">Tekrar Sıraya Ekle</button>` : ""}
            <button class="btn small" onclick="openHistoryInStudio(${jsArg(item.model_path || "")}, ${jsArg(item.label_text || "")}, ${jsArg(item.date_text || "")}, ${jsArg(item.note_text || "")}, ${jsArg(item.model_name || item.model_id || "")})">Aynı Bilgilerle Studio’da Aç</button>
          </div>
        </div>
      `;
    }).join("")
    : customerRows.length
      ? `<div class="list-row">Bu filtrelere uygun müşteri üretim geçmişi bulunamadı.</div>`
      : (rows || []).length
        ? `<div class="list-row">Müşteri üretim geçmişi yok. Teknik/test kayıtları normal üretim geçmişinden ayrıldı.</div>`
      : `<div class="list-row">Henüz üretim geçmişi yok.</div>`;
}

function refreshProductionHistoryFilters() {
  updateProductionHistory(currentState.productionHistory || []);
}

function clearProductionHistoryFilters() {
  productionHistoryFilterState = { query: "", model: "all", queue: "all", validation: "all", from: "", to: "" };
  const searchInput = byId("productionHistorySearch");
  const modelInput = byId("productionHistoryModelFilter");
  const queueInput = byId("productionHistoryQueueFilter");
  const validationInput = byId("productionHistoryValidationFilter");
  const fromInput = byId("productionHistoryFromDate");
  const toInput = byId("productionHistoryToDate");
  if (searchInput) searchInput.value = "";
  if (modelInput) modelInput.value = "all";
  if (queueInput) queueInput.value = "all";
  if (validationInput) validationInput.value = "all";
  if (fromInput) fromInput.value = "";
  if (toInput) toInput.value = "";
  updateProductionHistory(currentState.productionHistory || []);
}

function openHistoryInStudio(modelPath, labelText, dateText, noteText, modelName = "") {
  const normalized = String(modelPath || "").replace(/\\/g, "/");
  const model = currentLabelModels.find(item => {
    const candidate = String(item.path || "").replace(/\\/g, "/");
    const nameMatch = modelName && [item.model_name, item.title, item.model_no].map(value => String(value || "").trim()).includes(String(modelName || "").trim());
    return candidate === normalized || candidate.endsWith(normalized) || nameMatch;
  });
  if (model) useModelForManual(model.path);
  showSection("label");
  byId("manualText").value = labelText || "";
  byId("manualDateText").value = dateText || "";
  byId("manualNoteText").value = noteText || "";
  syncManualValuesFromInputs();
  renderManualSelectedFieldPanel();
  refreshFieldOverlayOnly();
}

function auditSeverityLabel(value) {
  return {
    info: "Bilgi",
    success: "Başarılı",
    warning: "Kontrol gerekli",
    error: "Hata",
    blocked: "Engellenen"
  }[String(value || "").trim()] || "Bilgi";
}

function auditSeverityClass(value) {
  return {
    info: "audit-severity--info",
    success: "audit-severity--success",
    warning: "audit-severity--warning",
    error: "audit-severity--error",
    blocked: "audit-severity--blocked"
  }[String(value || "").trim()] || "audit-severity--info";
}

function auditSourceBadgeHtml(item) {
  const source = String(item?.source || "unknown");
  const label = item?.source_label || queueSourceLabelForKey(source) || (source === "name_cut" ? "İsim Kesim" : source === "print_queue" ? "Yazdırma Sırası" : source === "production_history" ? "Etiket Çıktıları" : "Bilinmiyor");
  const key = source === "label_studio" ? "etiket_studio" : source === "name_cut" ? "laser" : source;
  return `<span class="source-badge ${queueSourceBadgeClass(key)}" title="Kaynak: ${esc(label)}">${esc(label)}</span>`;
}

function auditSearchText(item) {
  return [
    item.customer_name,
    item.order_no,
    item.batch_id,
    item.transfer_batch_id,
    item.export_batch_id,
    item.queue_item_id,
    item.file_path,
    item.output_path,
    item.source_item_id,
    item.message,
    item.title,
    JSON.stringify(item.metadata || {})
  ].map(value => String(value || "").toLocaleLowerCase("tr-TR")).join(" ");
}

function productionAuditRows() {
  return Array.isArray(currentState.productionAudit) ? currentState.productionAudit : [];
}

function productionAuditSummary(rows = productionAuditRows()) {
  const backendSummary = currentState.productionAuditSummary || {};
  if (backendSummary && Object.keys(backendSummary).length) return backendSummary;
  return {
    today: rows.filter(row => String(row.created_at || "").startsWith(new Date().toISOString().slice(0, 10))).length,
    print_queue: rows.filter(row => ["print_queue_created", "bulk_sent_to_print_queue"].includes(row.event_type)).length,
    namecut: rows.filter(row => ["bulk_sent_to_namecut_queue", "namecut_queue_created"].includes(row.event_type)).length,
    exports: rows.filter(row => row.event_type === "namecut_export_created").length,
    review: rows.filter(row => row.severity === "warning" || row.event_type === "manual_review_required").length,
    blocked: rows.filter(row => row.severity === "blocked" || row.event_type === "blocked_detected").length,
    duplicate: rows.filter(row => row.event_type === "duplicate_detected").length,
    missing_output: rows.filter(row => row.event_type === "output_missing").length,
    total: rows.length
  };
}

function syncProductionAuditFilterInputs() {
  const pairs = [
    ["productionAuditSearch", "query"],
    ["productionAuditSourceFilter", "source"],
    ["productionAuditEventFilter", "eventType"],
    ["productionAuditStatusFilter", "status"],
    ["productionAuditSeverityFilter", "severity"],
    ["productionAuditFromDate", "from"],
    ["productionAuditToDate", "to"]
  ];
  pairs.forEach(([id, key]) => {
    const input = byId(id);
    if (input && document.activeElement !== input) input.value = productionAuditFilterState[key] || (key === "query" || key === "from" || key === "to" ? "" : "all");
  });
  const checkPairs = [
    ["productionAuditOnlyErrors", "onlyErrors"],
    ["productionAuditOnlyDuplicate", "onlyDuplicate"],
    ["productionAuditOnlyBlocked", "onlyBlocked"],
    ["productionAuditOnlyReview", "onlyReview"]
  ];
  checkPairs.forEach(([id, key]) => {
    const input = byId(id);
    if (input) input.checked = Boolean(productionAuditFilterState[key]);
  });
}

function updateProductionAuditOptions(rows) {
  const eventSelect = byId("productionAuditEventFilter");
  const statusSelect = byId("productionAuditStatusFilter");
  if (eventSelect) {
    const previous = productionAuditFilterState.eventType || eventSelect.value || "all";
    const events = [...new Map((rows || []).map(row => [row.event_type, row.event_label || row.event_type]).filter(pair => pair[0])).entries()]
      .sort((a, b) => String(a[1]).localeCompare(String(b[1]), "tr"));
    eventSelect.innerHTML = `<option value="all">Event tipi: Tümü</option>${events.map(([value, label]) => `<option value="${esc(value)}">${esc(label)}</option>`).join("")}`;
    eventSelect.value = events.some(([value]) => value === previous) ? previous : "all";
    productionAuditFilterState.eventType = eventSelect.value;
  }
  if (statusSelect) {
    const previous = productionAuditFilterState.status || statusSelect.value || "all";
    const statuses = [...new Set((rows || []).map(row => String(row.status || "").trim()).filter(Boolean))]
      .sort((a, b) => a.localeCompare(b, "tr"));
    statusSelect.innerHTML = `<option value="all">Durum: Tümü</option>${statuses.map(status => `<option value="${esc(status)}">${esc(status)}</option>`).join("")}`;
    statusSelect.value = statuses.includes(previous) ? previous : "all";
    productionAuditFilterState.status = statusSelect.value;
  }
}

function readProductionAuditFilters() {
  productionAuditFilterState.query = String(byId("productionAuditSearch")?.value || productionAuditFilterState.query || "").trim().toLocaleLowerCase("tr-TR");
  productionAuditFilterState.source = String(byId("productionAuditSourceFilter")?.value || productionAuditFilterState.source || "all");
  productionAuditFilterState.eventType = String(byId("productionAuditEventFilter")?.value || productionAuditFilterState.eventType || "all");
  productionAuditFilterState.status = String(byId("productionAuditStatusFilter")?.value || productionAuditFilterState.status || "all");
  productionAuditFilterState.severity = String(byId("productionAuditSeverityFilter")?.value || productionAuditFilterState.severity || "all");
  productionAuditFilterState.from = String(byId("productionAuditFromDate")?.value || productionAuditFilterState.from || "");
  productionAuditFilterState.to = String(byId("productionAuditToDate")?.value || productionAuditFilterState.to || "");
  productionAuditFilterState.onlyErrors = Boolean(byId("productionAuditOnlyErrors")?.checked);
  productionAuditFilterState.onlyDuplicate = Boolean(byId("productionAuditOnlyDuplicate")?.checked);
  productionAuditFilterState.onlyBlocked = Boolean(byId("productionAuditOnlyBlocked")?.checked);
  productionAuditFilterState.onlyReview = Boolean(byId("productionAuditOnlyReview")?.checked);
}

function filteredProductionAuditRows(rows) {
  readProductionAuditFilters();
  return (rows || []).filter(item => {
    const created = String(item.created_at || "");
    if (productionAuditFilterState.query && !auditSearchText(item).includes(productionAuditFilterState.query)) return false;
    if (productionAuditFilterState.source !== "all" && item.source !== productionAuditFilterState.source) return false;
    if (productionAuditFilterState.eventType !== "all" && item.event_type !== productionAuditFilterState.eventType) return false;
    if (productionAuditFilterState.status !== "all" && String(item.status || "") !== productionAuditFilterState.status) return false;
    if (productionAuditFilterState.severity !== "all" && item.severity !== productionAuditFilterState.severity) return false;
    if (productionAuditFilterState.from && (!created || created.slice(0, 10) < productionAuditFilterState.from)) return false;
    if (productionAuditFilterState.to && (!created || created.slice(0, 10) > productionAuditFilterState.to)) return false;
    if (productionAuditFilterState.onlyErrors && !["error", "blocked"].includes(item.severity)) return false;
    if (productionAuditFilterState.onlyDuplicate && item.event_type !== "duplicate_detected") return false;
    if (productionAuditFilterState.onlyBlocked && item.event_type !== "blocked_detected" && item.severity !== "blocked") return false;
    if (productionAuditFilterState.onlyReview && item.event_type !== "manual_review_required" && item.severity !== "warning") return false;
    return true;
  });
}

function renderProductionAuditKpis(rows, summary = productionAuditSummary(rows)) {
  const box = byId("productionAuditKpis");
  if (!box) return;
  const cards = [
    ["Bugünkü işlem", summary.today || 0, "Bugün oluşan audit olayı", "info"],
    ["Yazdırma kuyruğuna giden", summary.print_queue || 0, "Queue ve status eventleri", "blue"],
    ["İsim Kesim’e giden", summary.namecut || 0, "Hazırlık kuyruğu ve aktarım", "purple"],
    ["Export hazırlanan", summary.exports || 0, "Manifest/export paketleri", "green"],
    ["Kontrol gerekli", summary.review || 0, "Operatör bakmalı", "warn"],
    ["Engellenen", summary.blocked || 0, "Üretime engel", "danger"],
    ["Duplicate", summary.duplicate || 0, "Tekrar kayıt uyarısı", "muted"],
    ["Eksik çıktı", summary.missing_output || 0, "Dosya yolu/çıktı eksik", "danger"]
  ];
  box.innerHTML = cards.map(([title, value, note, tone]) => `
    <div class="audit-kpi audit-kpi--${esc(tone)}">
      <small>${esc(title)}</small>
      <b>${esc(value)}</b>
      <span>${esc(note)}</span>
    </div>
  `).join("");
}

function productionAuditMetaLine(item) {
  const parts = [
    item.customer_name ? `Müşteri: ${item.customer_name}` : "",
    item.order_no ? `Sipariş: ${item.order_no}` : "",
    item.batch_id ? `Batch: ${item.batch_id}` : "",
    item.transfer_batch_id ? `Transfer: ${item.transfer_batch_id}` : "",
    item.export_batch_id ? `Export: ${item.export_batch_id}` : "",
    item.queue_item_id ? `Queue: ${item.queue_item_id}` : ""
  ].filter(Boolean);
  return parts.join(" · ");
}

function renderProductionAuditTimeline(rows) {
  const box = byId("productionAuditTimeline");
  if (!box) return;
  if (!rows.length) {
    box.innerHTML = `<div class="empty-state"><b>Üretim geçmişi kaydı yok.</b><p>Gerçek kayıt yoksa demo veri üretilmez. Geçmişi Yeniden Tara butonu mevcut kalıcı kayıtları normalize eder.</p></div>`;
    return;
  }
  box.innerHTML = rows.slice(0, 200).map(item => `
    <article class="audit-event-card ${item.id === selectedProductionAuditEventId ? "selected" : ""}" onclick="selectProductionAuditEvent('${esc(item.id)}')">
      <div class="audit-event-icon ${auditSeverityClass(item.severity)}">${item.severity === "blocked" || item.severity === "error" ? "!" : item.severity === "success" ? "✓" : "i"}</div>
      <div class="audit-event-main">
        <div class="audit-event-title">
          <b>${esc(item.event_label || item.event_type || "Audit event")}</b>
          ${auditSourceBadgeHtml(item)}
          <span class="audit-severity ${auditSeverityClass(item.severity)}">${esc(auditSeverityLabel(item.severity))}</span>
        </div>
        <p>${esc(item.message || item.title || "-")}</p>
        <small>${esc(item.created_at || "-")}${productionAuditMetaLine(item) ? ` · ${esc(productionAuditMetaLine(item))}` : ""}</small>
      </div>
      <button class="btn small" type="button" onclick="event.stopPropagation(); selectProductionAuditEvent('${esc(item.id)}')">Detay</button>
    </article>
  `).join("");
}

function renderProductionAuditTable(rows) {
  const box = byId("productionAuditTable");
  if (!box) return;
  if (!rows.length) {
    box.innerHTML = `<div class="empty-state"><b>Tablo için kayıt yok.</b></div>`;
    return;
  }
  box.innerHTML = `
    <table class="audit-table">
      <thead><tr><th>Tarih</th><th>Kaynak</th><th>Event</th><th>Durum</th><th>Müşteri/Sipariş</th><th>Batch/Dosya</th></tr></thead>
      <tbody>${rows.slice(0, 250).map(item => `
        <tr onclick="selectProductionAuditEvent('${esc(item.id)}')" class="${item.id === selectedProductionAuditEventId ? "selected" : ""}">
          <td>${esc(item.created_at || "-")}</td>
          <td>${auditSourceBadgeHtml(item)}</td>
          <td><b>${esc(item.event_label || item.event_type)}</b><br><small>${esc(item.message || "")}</small></td>
          <td><span class="audit-severity ${auditSeverityClass(item.severity)}">${esc(auditSeverityLabel(item.severity))}</span><br><small>${esc(item.status || "-")}</small></td>
          <td>${esc(item.customer_name || "-")}<br><small>${esc(item.order_no || "-")}</small></td>
          <td>${esc(item.batch_id || item.transfer_batch_id || item.export_batch_id || "-")}<br><small title="${esc(item.output_path || item.file_path || "")}">${esc(fileName(item.output_path || item.file_path || "") || "-")}</small></td>
        </tr>
      `).join("")}</tbody>
    </table>
  `;
}

function productionAuditEventById(id) {
  return productionAuditRows().find(item => String(item.id || "") === String(id || "")) || null;
}

function auditEventMetadata(item = {}) {
  return item && typeof item.metadata === "object" && item.metadata ? item.metadata : {};
}

function auditEventPath(item = {}, preferred = "auto") {
  const metadata = auditEventMetadata(item);
  const exported = metadata.exported_files && typeof metadata.exported_files === "object" ? metadata.exported_files : {};
  const candidates = preferred === "manifest"
    ? [exported.manifest, metadata.manifest_path, metadata.manifest, item.file_path, item.output_path]
    : preferred === "output"
      ? [item.output_path, metadata.output_path, metadata.path, item.file_path, exported.pdf, exported.svg, exported.manifest]
      : [item.output_path, item.file_path, metadata.path, metadata.output_path, metadata.file_path, exported.manifest, exported.pdf, exported.svg, exported.png];
  return String(candidates.find(Boolean) || "").trim();
}

function resolveAuditEventTarget(item = {}) {
  const eventType = String(item.event_type || "");
  const source = String(item.source || "");
  const origin = String(item.origin_source || "");
  const metadata = auditEventMetadata(item);
  const sourceHint = [source, origin, eventType].join(" ");
  let page = "";
  let label = "Kaynağa Git";
  if (["bulk_import_created", "bulk_validation_completed"].includes(eventType) || /bulk_production/.test(sourceHint)) {
    page = "bulkLabel";
    label = "Toplu Üretim’de Aç";
  }
  if (["bulk_sent_to_print_queue", "print_queue_created", "print_queue_status_updated", "print_confirm_opened", "output_missing"].includes(eventType) || source === "print_queue") {
    page = "printQueue";
    label = "Yazdırma Sırası’nda Aç";
  }
  if (["bulk_sent_to_namecut_queue", "namecut_queue_created", "namecut_status_updated", "namecut_export_created"].includes(eventType) || source === "name_cut") {
    page = "nameCutStudio";
    label = eventType === "namecut_export_created" ? "İsim Kesim Export Geçmişi" : "İsim Kesim’de Aç";
  }
  if (["label_studio_session_created", "label_output_created"].includes(eventType) || source === "label_studio") {
    page = "label";
    label = "Etiket Studio’da Aç";
  }
  if (eventType === "audit_export_created" || eventType === "audit_export_failed" || source === "production_audit") {
    page = "productionAudit";
    label = "Export Özetinde Kal";
  }
  if (!page && /trendyol/.test(sourceHint)) {
    page = "trendyolOrders";
    label = "Trendyol’da Aç";
  }
  if (!page && /manual_label/.test(sourceHint)) {
    page = "label";
    label = "Manuel Etiket’te Aç";
  }
  return {
    page,
    label,
    queueId: item.queue_item_id || metadata.queue_item_id || metadata.id || "",
    sourceItemId: item.source_item_id || metadata.source_item_id || metadata.item_id || "",
    batchId: item.batch_id || metadata.batch_id || "",
    transferBatchId: item.transfer_batch_id || metadata.transfer_batch_id || "",
    exportBatchId: item.export_batch_id || metadata.export_batch_id || "",
    bulkRowId: metadata.bulk_row_id || item.bulk_row_id || "",
    outputPath: auditEventPath(item, "output"),
    manifestPath: auditEventPath(item, "manifest")
  };
}

function focusPrintQueueItemFromAudit(item = {}, target = resolveAuditEventTarget(item)) {
  const candidates = [target.queueId, item.queue_item_id, target.sourceItemId, item.source_item_id, item.output_path, item.file_path].map(value => String(value || "")).filter(Boolean);
  const row = (currentState.printQueue || []).find(queueItem => candidates.some(candidate => [
    queueItem.id,
    queueItem.queue_item_id,
    queueItem.source_item_id,
    queueItem.duplicate_key,
    queueItem.output_path,
    queueItem.relative_path
  ].map(value => String(value || "")).includes(candidate)));
  showSection("printQueue");
  printQueueDetailCollapsed = false;
  localStorage.setItem("ceyizhome_print_queue_detail_collapsed", "0");
  if (!row) {
    updatePrintQueue(currentState.printQueue || []);
    showProductionAuditStatus("İlgili Yazdırma Sırası kaydı bulunamadı veya eski kayıt hızlı geçişe bağlı değil.", "warn");
    return false;
  }
  printQueueFilterState = { query: "", status: "all", type: "all", date: "all", sort: "created", includeTestArchive: true };
  updatePrintQueue(currentState.printQueue || []);
  selectPrintQueueItem(row.id);
  document.querySelector(`[data-queue-id="${CSS.escape(row.id)}"]`)?.scrollIntoView({ block: "center" });
  showProductionAuditStatus("Yazdırma Sırası kaydı açıldı. Yazıcı otomatik başlamaz.", "ok");
  return true;
}

function focusNameCutItemFromAudit(item = {}, target = resolveAuditEventTarget(item)) {
  const candidates = [target.sourceItemId, target.queueId, item.queue_item_id, item.source_item_id, target.bulkRowId, target.transferBatchId].map(value => String(value || "")).filter(Boolean);
  const row = (nameCutItems || []).find(nameItem => candidates.some(candidate => [
    nameItem.item_id,
    nameItem.id,
    nameItem.source_item_id,
    nameItem.bulk_row_id,
    nameItem.transfer_batch_id,
    nameItem.duplicate_key
  ].map(value => String(value || "")).includes(candidate)));
  showSection("nameCutStudio");
  if (!row) {
    refreshNameCutStudioViews?.(currentNameCutLayout?.());
    showProductionAuditStatus("İlgili İsim Kesim kaydı bulunamadı veya bu eski kayıt hızlı geçişe bağlı değil.", "warn");
    return false;
  }
  selectedNameCutItemId = row.item_id || row.id || "";
  renderNameCutGallery();
  renderNameCutDetail();
  renderLaserLayoutPreview(currentNameCutLayout());
  document.querySelector(`[data-namecut-id="${CSS.escape(selectedNameCutItemId)}"]`)?.scrollIntoView({ block: "center" });
  showProductionAuditStatus("İsim Kesim hazırlık kaydı açıldı. Lazer/RDWorks otomatik başlamaz.", "ok");
  return true;
}

function focusBulkItemFromAudit(item = {}, target = resolveAuditEventTarget(item)) {
  const candidates = [target.sourceItemId, target.bulkRowId, target.batchId, target.transferBatchId].map(value => String(value || "")).filter(Boolean);
  const row = (bulkGalleryItems || []).find(bulkItem => candidates.some(candidate => [
    bulkItem.item_id,
    bulkItem.id,
    bulkItem.source_item_id,
    bulkItem.bulk_row_id,
    bulkItem.row_number,
    bulkItem.batch_id,
    bulkItem.transfer_batch_id
  ].map(value => String(value || "")).includes(candidate)));
  showSection("bulkLabel");
  if (row) {
    selectedBulkGalleryItemId = row.item_id || selectedBulkGalleryItemId;
    setBulkProductionStep(item.event_type === "bulk_sent_to_namecut_queue" ? 5 : 4);
    renderBulkGallery();
    document.querySelector(`[data-bulk-item-id="${CSS.escape(selectedBulkGalleryItemId)}"]`)?.scrollIntoView({ block: "center" });
    showProductionAuditStatus("Toplu Üretim kaydı açıldı. Üretim, yazdırma veya lazer otomatik başlamaz.", "ok");
    return true;
  }
  setBulkProductionStep(["bulk_validation_completed"].includes(item.event_type) ? 2 : 1);
  showProductionAuditStatus("Toplu Üretim ekranı açıldı; ilgili satır bu oturum state’inde bulunamadı.", "warn");
  return false;
}

function focusLabelStudioFromAudit(item = {}, target = resolveAuditEventTarget(item)) {
  showSection("label");
  const sessionMatches = labelStudioSession && [target.sourceItemId, item.source_item_id, target.queueId].filter(Boolean).some(value => String(value) === String(labelStudioSession.source_item_id || labelStudioSession.studio_session_id || ""));
  showProductionAuditStatus(sessionMatches ? "Etiket Studio session açıldı. Yazıcı otomatik başlamaz." : "Etiket Studio açıldı; bu event için kalıcı session geri yükleme henüz bağlı değil.", sessionMatches ? "ok" : "warn");
  return Boolean(sessionMatches);
}

function openAuditEventTarget(eventId = selectedProductionAuditEventId) {
  const item = productionAuditEventById(eventId);
  if (!item) {
    showProductionAuditStatus("İlgili audit event bulunamadı.", "warn");
    return false;
  }
  const target = resolveAuditEventTarget(item);
  if (!target.page) {
    showProductionAuditStatus("İlgili kayıt bulunamadı veya bu kaynak için hızlı geçiş henüz bağlı değil.", "warn");
    return false;
  }
  if (target.page === "printQueue") return focusPrintQueueItemFromAudit(item, target);
  if (target.page === "nameCutStudio") return focusNameCutItemFromAudit(item, target);
  if (target.page === "bulkLabel") return focusBulkItemFromAudit(item, target);
  if (target.page === "label") return focusLabelStudioFromAudit(item, target);
  showSection(target.page);
  showProductionAuditStatus("İlgili ekran açıldı. Bu aksiyon üretim veya cihaz başlatmaz.", "ok");
  return true;
}

function runAuditFileAction(path = "", action = "reveal") {
  const cleanPath = String(path || "").trim();
  if (!cleanPath) {
    showProductionAuditStatus("Dosya yolu bulunamadı.", "warn");
    return;
  }
  const method = action === "open" ? "open_file_safe" : "reveal_file_in_folder";
  if (!bridge?.[method]) {
    showProductionAuditStatus("Dosya/klasör aksiyonu için production backend köprüsü hazır değil. Sahte başarı gösterilmedi.", "warn");
    return;
  }
  bridge[method](cleanPath, raw => {
    const result = parseBridgeResult(raw, {});
    if (String(result.status || "").toUpperCase() === "OK") {
      showProductionAuditStatus(result.message || "Dosya aksiyonu tamamlandı.", "ok");
      return;
    }
    showProductionAuditStatus(result.message || "Dosya aksiyonu tamamlanamadı.", "error");
  });
}

function copyAuditPath(path = "") {
  const cleanPath = String(path || "").trim();
  if (!cleanPath) {
    showProductionAuditStatus("Kopyalanacak dosya yolu bulunamadı.", "warn");
    return;
  }
  if (!navigator.clipboard?.writeText) {
    showProductionAuditStatus(`Dosya yolu: ${cleanPath}`, "info");
    return;
  }
  navigator.clipboard.writeText(cleanPath)
    .then(() => showProductionAuditStatus("Dosya yolu panoya kopyalandı.", "ok"))
    .catch(() => showProductionAuditStatus(`Dosya yolu: ${cleanPath}`, "info"));
}

function renderProductionAuditDetail(item) {
  const panel = byId("productionAuditDetail");
  if (!panel) return;
  if (!item) {
    panel.innerHTML = `<div class="audit-detail-empty"><b>Event seçin.</b><span>Üretim geçmişi detayı burada görünür.</span></div>`;
    return;
  }
  const metadata = item.metadata || {};
  const raw = JSON.stringify(metadata, null, 2);
  const target = resolveAuditEventTarget(item);
  const outputPath = auditEventPath(item, "output");
  const manifestPath = auditEventPath(item, "manifest");
  const targetButton = target.page
    ? `<button class="btn small primary" onclick="openAuditEventTarget(${jsArg(item.id || "")})">${esc(target.label || "Kaynağa Git")}</button>`
    : `<button class="btn small" onclick="showProductionAuditStatus('İlgili kayıt bulunamadı veya bu kaynak için hızlı geçiş henüz bağlı değil.', 'warn')">Kaynağa Git</button>`;
  const idRows = [
    ["Source item", item.source_item_id],
    ["Queue item", item.queue_item_id],
    ["Batch", item.batch_id],
    ["Transfer batch", item.transfer_batch_id],
    ["Export batch", item.export_batch_id],
  ].filter(([, value]) => value);
  panel.innerHTML = `
    <div class="card-title">
      <h3>Event Detayı</h3>
      <span class="audit-severity ${auditSeverityClass(item.severity)}">${esc(auditSeverityLabel(item.severity))}</span>
    </div>
    <div class="audit-detail-summary">
      ${auditSourceBadgeHtml(item)}
      ${item.origin_source_label || item.origin_source ? `<span class="queue-origin-pill">Origin: ${esc(item.origin_source_label || queueSourceLabelForKey(item.origin_source) || item.origin_source)}</span>` : ""}
      <b>${esc(item.event_label || item.event_type)}</b>
      <small>${esc(item.created_at || "-")}</small>
    </div>
    <div class="audit-detail-section">
      <h4>İş Bilgisi</h4>
      <div class="audit-detail-row"><span>Başlık</span><b>${esc(item.title || "-")}</b></div>
      <div class="audit-detail-row"><span>Müşteri</span><b>${esc(item.customer_name || "-")}</b></div>
      <div class="audit-detail-row"><span>Sipariş No</span><b>${esc(item.order_no || "-")}</b></div>
      <div class="audit-detail-row"><span>Durum</span><b>${esc(item.status || "-")}</b></div>
      <div class="audit-detail-row multiline"><span>Mesaj</span><b>${esc(item.message || "-")}</b></div>
    </div>
    <div class="audit-detail-section">
      <h4>Bağlantılı ID’ler</h4>
      ${idRows.length ? idRows.map(([label, value]) => `<div class="audit-detail-row"><span>${esc(label)}</span><b>${esc(value)}</b></div>`).join("") : `<div class="audit-detail-row"><span>ID</span><b>Bağlı kayıt yok</b></div>`}
    </div>
    <div class="audit-detail-section">
      <h4>Dosya ve Manifest</h4>
      <div class="audit-detail-row multiline"><span>Output</span><b title="${esc(item.output_path || "")}">${esc(item.output_path || "-")}</b></div>
      <div class="audit-detail-row multiline"><span>Dosya</span><b title="${esc(item.file_path || "")}">${esc(item.file_path || "-")}</b></div>
    </div>
    <div class="audit-detail-section">
      <h4>Raw Metadata</h4>
      <pre class="audit-metadata-box">${esc(raw || "{}")}</pre>
    </div>
    <div class="audit-detail-actions">
      ${targetButton}
      ${target.page !== "printQueue" ? `<button class="btn small" onclick="focusPrintQueueItemFromAudit(productionAuditEventById(${jsArg(item.id || "")}) || {})">Yazdırma Sırası’nda Aç</button>` : ""}
      ${target.page !== "nameCutStudio" ? `<button class="btn small" onclick="focusNameCutItemFromAudit(productionAuditEventById(${jsArg(item.id || "")}) || {})">İsim Kesim’de Aç</button>` : ""}
      ${target.page !== "label" ? `<button class="btn small" onclick="focusLabelStudioFromAudit(productionAuditEventById(${jsArg(item.id || "")}) || {})">Etiket Studio’da Aç</button>` : ""}
      ${target.page !== "bulkLabel" ? `<button class="btn small" onclick="focusBulkItemFromAudit(productionAuditEventById(${jsArg(item.id || "")}) || {})">Toplu Üretim’de Aç</button>` : ""}
      <button class="btn small" onclick="runAuditFileAction(${jsArg(outputPath)}, 'open')">Dosyayı Aç</button>
      <button class="btn small" onclick="runAuditFileAction(${jsArg(outputPath || manifestPath)}, 'reveal')">Klasörde Göster</button>
      ${manifestPath ? `<button class="btn small" onclick="runAuditFileAction(${jsArg(manifestPath)}, 'open')">Manifest’i Göster</button>` : ""}
      <button class="btn small" onclick="copyAuditPath(${jsArg(outputPath || manifestPath)})">Dosya Yolunu Kopyala</button>
    </div>
    <p class="safe-note">Bu detay ekranı yalnızca izleme sağlar. Yazıcı, lazer ve RDWorks otomatik başlamaz.</p>
  `;
}

function updateProductionAudit(rows = [], summary = {}) {
  const page = byId("productionAudit");
  if (!page) return;
  const items = Array.isArray(rows) ? rows : [];
  updateProductionAuditOptions(items);
  syncProductionAuditFilterInputs();
  const filtered = filteredProductionAuditRows(items);
  if (!selectedProductionAuditEventId || !items.some(item => item.id === selectedProductionAuditEventId)) {
    selectedProductionAuditEventId = filtered[0]?.id || "";
  }
  const resultCount = byId("productionAuditResultCount");
  if (resultCount) resultCount.textContent = `${filtered.length} / ${items.length} kayıt`;
  renderProductionAuditKpis(items, summary);
  const timeline = byId("productionAuditTimeline");
  const table = byId("productionAuditTable");
  if (timeline) timeline.hidden = productionAuditFilterState.view !== "timeline";
  if (table) table.hidden = productionAuditFilterState.view !== "table";
  byId("productionAuditTimelineButton")?.classList.toggle("primary", productionAuditFilterState.view === "timeline");
  byId("productionAuditTableButton")?.classList.toggle("primary", productionAuditFilterState.view === "table");
  renderProductionAuditTimeline(filtered);
  renderProductionAuditTable(filtered);
  renderProductionAuditDetail(items.find(item => item.id === selectedProductionAuditEventId) || filtered[0] || null);
}

function refreshProductionAuditFilters() {
  updateProductionAudit(currentState.productionAudit || [], currentState.productionAuditSummary || {});
}

function clearProductionAuditFilters() {
  productionAuditFilterState = { query: "", source: "all", eventType: "all", status: "all", severity: "all", from: "", to: "", onlyErrors: false, onlyDuplicate: false, onlyBlocked: false, onlyReview: false, view: productionAuditFilterState.view || "timeline" };
  syncProductionAuditFilterInputs();
  updateProductionAudit(currentState.productionAudit || [], currentState.productionAuditSummary || {});
}

function setProductionAuditView(view) {
  productionAuditFilterState.view = view === "table" ? "table" : "timeline";
  updateProductionAudit(currentState.productionAudit || [], currentState.productionAuditSummary || {});
}

function selectProductionAuditEvent(id) {
  selectedProductionAuditEventId = String(id || "");
  updateProductionAudit(currentState.productionAudit || [], currentState.productionAuditSummary || {});
}

function showProductionAuditStatus(message, type = "ok") {
  const box = byId("productionAuditStatus");
  if (!box) {
    if (message) alert(message);
    return;
  }
  box.textContent = message;
  box.className = `status-line ${type}`;
  box.hidden = false;
  clearTimeout(showProductionAuditStatus.timer);
  showProductionAuditStatus.timer = setTimeout(() => { box.hidden = true; }, 5200);
}

function renderProductionAuditExportSummary(result = {}) {
  const box = byId("productionAuditStatus");
  if (!box) return;
  const path = String(result.path || "").trim();
  const format = String(result.format || "").toUpperCase() || (path.toLowerCase().endsWith(".csv") ? "CSV" : "JSON");
  lastProductionAuditExportResult = { ...result, path, format };
  box.hidden = false;
  box.className = "status-line ok audit-export-summary";
  box.innerHTML = `
    <div>
      <b>${esc(format)} export hazır</b>
      <span>${esc(result.count || 0)} kayıt · ${esc(result.created_at || result.exported_at || "")}</span>
      <small title="${esc(path)}">${esc(path || "-")}</small>
    </div>
    <div class="toolbar">
      <button class="btn small" type="button" onclick="runAuditFileAction(${jsArg(path)}, 'reveal')">Klasörde Göster</button>
      <button class="btn small" type="button" onclick="copyAuditPath(${jsArg(path)})">Dosya Yolunu Kopyala</button>
    </div>
  `;
  clearTimeout(showProductionAuditStatus.timer);
}

function rebuildProductionAudit() {
  if (!bridge?.rebuild_production_audit_from_existing_sources) {
    showProductionAuditStatus("Audit yeniden tarama için production backend köprüsü hazır değil.", "warn");
    return;
  }
  bridge.rebuild_production_audit_from_existing_sources(raw => {
    const result = parseBridgeResult(raw);
    if (result.status === "OK") {
      currentState.productionAudit = result.events || [];
      currentState.productionAuditSummary = result.summary || {};
      showProductionAuditStatus(result.message || "Üretim geçmişi yeniden tarandı.", "ok");
      updateProductionAudit(currentState.productionAudit, currentState.productionAuditSummary);
    } else {
      showProductionAuditStatus(result.message || "Üretim geçmişi yeniden taranamadı.", "warn");
    }
  });
}

function productionAuditBackendFilters() {
  readProductionAuditFilters();
  return {
    query: productionAuditFilterState.query || "",
    source: productionAuditFilterState.source || "all",
    event_type: productionAuditFilterState.eventType || "all",
    status: productionAuditFilterState.status || "all",
    severity: productionAuditFilterState.severity || "all",
    from: productionAuditFilterState.from || "",
    to: productionAuditFilterState.to || "",
    only_errors: Boolean(productionAuditFilterState.onlyErrors),
    only_duplicate: Boolean(productionAuditFilterState.onlyDuplicate),
    only_blocked: Boolean(productionAuditFilterState.onlyBlocked),
    only_review: Boolean(productionAuditFilterState.onlyReview)
  };
}

function exportProductionAudit(format) {
  const normalizedFormat = String(format || "json").toLowerCase() === "csv" ? "csv" : "json";
  if (!bridge?.export_production_audit_events) {
    showProductionAuditStatus(`${normalizedFormat.toUpperCase()} dışa aktarım için production backend köprüsü hazır değil. Sahte başarı gösterilmedi.`, "warn");
    return;
  }
  const filters = productionAuditBackendFilters();
  showProductionAuditStatus(`${normalizedFormat.toUpperCase()} dışa aktarım hazırlanıyor... Yazıcı, lazer ve RDWorks başlatılmaz.`, "info");
  bridge.export_production_audit_events(JSON.stringify({ format: normalizedFormat, filters }), raw => {
    const result = parseBridgeResult(raw, {});
    if (result.status === "OK" && result.path) {
      currentState.productionAudit = result.events || currentState.productionAudit || [];
      currentState.productionAuditSummary = result.summary || currentState.productionAuditSummary || {};
      renderProductionAuditExportSummary(result);
      updateProductionAudit(currentState.productionAudit, currentState.productionAuditSummary);
      return;
    }
    showProductionAuditStatus(result.message || `${normalizedFormat.toUpperCase()} dışa aktarım oluşturulamadı.`, "error");
  });
}

function exportProductionAuditJson() {
  exportProductionAudit("json");
}

function exportProductionAuditCsv() {
  exportProductionAudit("csv");
}

function updateSelectedOutputPanel(path) {
  const preview = byId("labelOutputPreview");
  const info = byId("selectedOutputInfo");
  const status = byId("selectedOutputStatus");
  const actions = byId("selectedOutputActions");
  const typeBadge = byId("selectedOutputTypeBadge");
  if (!preview) return;
  const item = outputItemForPath(path);
  if (!item) {
    preview.classList.add("empty");
    preview.innerHTML = `
      <div class="selected-output-empty">
        <b>Listeden bir çıktı seçin.</b>
        <span>PDF/PNG önizlemesi burada görünecek.</span>
      </div>`;
    if (info) info.innerHTML = "";
    if (status) status.innerHTML = "";
    if (actions) actions.innerHTML = "";
    if (typeBadge) {
      typeBadge.className = "status-pill muted";
      typeBadge.textContent = "Seçim yok";
    }
    return;
  }
  const cleanPath = outputPath(item);
  const history = historyForOutputPath(cleanPath);
  const pair = outputPairForPath(cleanPath, history);
  const kind = outputKind(item);
  const isPdf = kind === "pdf" || kind === "batch" || kind === "roll";
  const pdfPath = isPdf ? cleanPath : pair.pdfPath;
  const pngPath = kind === "png" ? cleanPath : pair.pngPath;
  const validationState = outputValidationState(item, history);
  const queueState = outputQueueState(cleanPath, history);
  const meta = outputMetadata(item, history);
  const modelLabel = meta.modelName || outputModelLabel(item);
  const labelText = meta.labelText;
  const dateText = meta.dateText;
  const noteText = meta.noteText;
  const quantity = meta.quantity;
  const sizeText = meta.sizeText;
  preview.classList.remove("empty");
  preview.innerHTML = outputPreviewHtml(item, history, modelLabel);
  if (typeBadge) {
    typeBadge.className = `status-pill ${validationState === "validated" ? "ok" : validationState === "missing" ? "bad" : "warn"}`;
    typeBadge.textContent = outputKindLabel(kind);
  }
  if (info) {
    info.innerHTML = `
      <h3>${esc(modelLabel || "Etiket çıktısı")}</h3>
      <div class="selected-output-file"><span class="output-type-badge ${esc(kind)}">${esc(outputKindLabel(kind))}</span><b>${esc(fileName(cleanPath || item.name || item.file_name || ""))}</b></div>
      <dl>
        <div><dt>Model</dt><dd>${esc(modelLabel || "-")}</dd></div>
        <div><dt>İsim</dt><dd>${esc(labelText || "-")}</dd></div>
        <div><dt>Tarih</dt><dd>${esc(dateText || "-")}</dd></div>
        <div><dt>Not</dt><dd>${esc(noteText || "-")}</dd></div>
        <div><dt>Ölçü</dt><dd>${esc(sizeText || "-")}</dd></div>
        <div><dt>Adet</dt><dd>${esc(quantity || "1")}</dd></div>
        <div><dt>Oluşturma</dt><dd>${esc(item.created_at || "-")}</dd></div>
        <div><dt>Dosya Boyutu</dt><dd>${esc(item.size_kb ? `${item.size_kb} KB` : "-")}</dd></div>
      </dl>
    `;
  }
  if (status) {
    status.innerHTML = `
      <div class="selected-output-status-card ${esc(validationState)}"><span>Kalite Durumu</span><b>${esc(outputValidationLabel(validationState))}</b></div>
      <div class="selected-output-status-card ${queueState === "queued" ? "queued" : ""}"><span>Queue Durumu</span><b>${esc(queueState === "queued" ? "Sırada" : queueState === "printed" ? "Yazdırıldı" : "Sırada değil")}</b></div>
    `;
  }
  if (actions) {
    actions.innerHTML = `
      ${pdfPath ? `<button class="btn primary" onclick="openPdfPreview('${esc(pdfPath)}')">PDF’i Aç</button>` : ""}
      ${pdfPath ? `<button class="btn print-primary" onclick="requestPdfPrint('${esc(pdfPath)}', { modelName: '${esc(modelLabel || "Etiket")}', labelText: '${esc(labelText)}', dateText: '${esc(dateText)}', noteText: '${esc(noteText)}', sizeText: '${esc(sizeText)}', quantity: '${esc(quantity)}', fileName: '${esc(fileName(pdfPath))}' })">Yazdır</button>` : ""}
      ${pngPath ? `<button class="btn" onclick="selectManualPngPreview('${esc(pngPath)}')">PNG Önizle</button>` : ""}
      <button class="btn" data-history-action="${history ? "ready" : "missing"}" onclick="openOutputHistoryInStudio('${esc(cleanPath)}')">Studio’da Aç</button>
      <button class="btn" data-history-action="${history ? "ready" : "missing"}" onclick="reproduceOutputFromHistory('${esc(cleanPath)}')">Tekrar Üret</button>
      ${pdfPath ? `<button class="btn gold" onclick="addPdfToQueue('${esc(pdfPath)}')">Yazdırma Sırasına Ekle</button>` : `<button class="btn" onclick="showLabelOutputStatus('PNG önizleme dosyasıdır. Yazdırma sırasına PDF eklenir.', 'warn')">Sıraya PDF Eklenir</button>`}
      <button class="btn" onclick="bridge.open_print_folder()">Klasörde Göster</button>
    `;
  }
}

function selectLabelOutput(path) {
  selectedLabelOutputPath = String(path || "");
  document.querySelectorAll("#labelOutputList .output-card").forEach(card => card.classList.remove("selected"));
  const normalized = normalizeOutputRef(path);
  document.querySelectorAll("#labelOutputList .output-card").forEach(card => {
    const click = card.getAttribute("onclick") || "";
    if (normalized && click.includes(path)) card.classList.add("selected");
  });
  updateSelectedOutputPanel(selectedLabelOutputPath);
}

function showLabelOutputStatus(message, type = "ok") {
  const box = byId("labelOutputStatus");
  if (!box) {
    if (message) alert(message);
    return;
  }
  box.textContent = message;
  box.className = `status-line ${type}`;
  box.hidden = false;
  clearTimeout(showLabelOutputStatus.timer);
  showLabelOutputStatus.timer = setTimeout(() => { box.hidden = true; }, 4600);
}

function queueItemPath(item) {
  return item?.output_path || item?.relative_path || item?.path || "";
}

function queueItemHistory(item) {
  return historyForOutputPath(queueItemPath(item));
}

function queueItemKind(item) {
  const path = queueItemPath(item);
  const text = `${item?.file_type || ""} ${item?.job_type || ""} ${path}`.toLowerCase();
  if (text.includes("roll_batch") || text.includes("rulo_batch") || text.includes("rulo-batch") || text.includes("rulo batch")) return "roll";
  if (text.includes("batch") || text.includes("toplu")) return "batch";
  if (path.toLowerCase().endsWith(".png")) return "png";
  return "pdf";
}

function queueItemSourceLabel(item) {
  if (item?.source_label) {
    const labelKey = normalizeQueueSourceKey(item.source_label);
    return queueSourceLabelForKey(labelKey) || item.source_label;
  }
  const persistent = queueSourceLabelForKey(item?.source);
  if (persistent) return persistent;
  return item?.job_type || "Eski kayıt";
}

function queueItemQuantityNumber(item, history = null) {
  const raw = String(queueItemQuantity(item, history) || "1");
  const match = raw.replace(",", ".").match(/\d+(?:\.\d+)?/);
  const value = match ? Number(match[0]) : 1;
  return Number.isFinite(value) && value > 0 ? value : 1;
}

function queueItemModelLabel(item, history = null) {
  const meta = outputMetadata({ ...item, relative_path: queueItemPath(item) }, history);
  return meta.modelName || item?.job_name || "Etiket işi";
}

function queueItemLabelText(item, history = null) {
  const meta = outputMetadata({ ...item, relative_path: queueItemPath(item) }, history);
  return meta.labelText || "";
}

function queueItemDateText(item, history = null) {
  const meta = outputMetadata({ ...item, relative_path: queueItemPath(item) }, history);
  return meta.dateText || "";
}

function queueItemNoteText(item, history = null) {
  const meta = outputMetadata({ ...item, relative_path: queueItemPath(item) }, history);
  return meta.noteText || "";
}

function queueItemQuantity(item, history = null) {
  const meta = outputMetadata({ ...item, relative_path: queueItemPath(item) }, history);
  return meta.quantity || "1";
}

function queueItemSizeText(item, history = null) {
  const meta = outputMetadata({ ...item, relative_path: queueItemPath(item) }, history);
  return meta.sizeText || "";
}

function queueItemStatusKey(item, history = null) {
  const explicit = String(item?.status_key || "").toLowerCase().trim();
  const status = String(item?.status || "").toLowerCase();
  if (status.includes("teslim")) return "delivered";
  if (["waiting_output", "output_ready", "ready_to_print", "needs_review", "blocked", "printed", "cancelled", "failed"].includes(explicit)) return explicit;
  const validation = outputValidationState({ ...item, relative_path: queueItemPath(item), status: item?.validation_status }, history);
  if (validation === "missing") return "missing";
  if (validation === "check") return "review";
  if (status.includes("yazdır") || status.includes("yazdir")) return "printed";
  if (status.includes("iptal")) return "cancelled";
  if (status.includes("hata")) return "failed";
  if (status.includes("engel")) return "blocked";
  if (status.includes("çıktı bek") || status.includes("cikti bek")) return "waiting_output";
  if (status.includes("çıktı hazır") || status.includes("cikti hazir")) return "output_ready";
  if (status.includes("hazır") || status.includes("hazir")) return "ready_to_print";
  return "pending";
}

function queueItemStatusLabel(key, item = null) {
  if (key === "delivered") return "Teslim edildi";
  if (key === "printed") return "Yazdırıldı";
  if (key === "waiting_output") return "Çıktı Bekliyor";
  if (key === "output_ready") return "Çıktı Hazır";
  if (key === "ready_to_print") return "Yazdırmaya Hazır";
  if (key === "needs_review") return "Kontrol Gerekli";
  if (key === "blocked") return "Üretime Engel";
  if (key === "cancelled") return "İptal Edildi";
  if (key === "failed") return "Hatalı";
  if (key === "missing") return "Dosya yok";
  if (key === "review") return "Kontrol gerekli";
  return item?.status || "Beklemede";
}

function queueItemStatusClass(key) {
  if (key === "delivered") return "ok";
  if (key === "printed" || key === "ready_to_print" || key === "output_ready") return "ok";
  if (key === "blocked" || key === "failed" || key === "missing") return "bad";
  if (key === "needs_review" || key === "review" || key === "waiting_output") return "warn bad-lite";
  if (key === "cancelled") return "muted";
  return "warn";
}

function queueItemSafetyFlags(item) {
  return Array.isArray(item?.safety_flags) ? item.safety_flags : [];
}

function queueSafetyFlagLabel(flag) {
  return {
    missing_output_path: "Çıktı yolu yok",
    missing_output_file: "Çıktı dosyası bulunamadı",
    unsupported_format: "Format desteklenmiyor",
    invalid_quantity: "Adet geçersiz",
    missing_model: "Model eksik",
    blocked_status: "Durum engelli"
  }[flag] || String(flag || "Kontrol gerekli");
}

function queueItemOutputFormat(item, path = queueItemPath(item)) {
  const explicit = String(item?.output_format || "").trim().toUpperCase();
  if (explicit) return explicit;
  const suffix = String(path || "").split(".").pop()?.toUpperCase() || "";
  return ["PDF", "PNG", "SVG", "DXF", "PLT"].includes(suffix) ? suffix : outputKindLabel(queueItemKind(item)).toUpperCase();
}

function queueItemCanPrint(item, history = null) {
  const statusKey = queueItemStatusKey(item, history);
  const flags = queueItemSafetyFlags(item);
  const path = queueItemPath(item);
  return Boolean(path) && ["ready_to_print", "output_ready", "pending"].includes(statusKey) && !flags.length && String(path).toLowerCase().endsWith(".pdf");
}

function queueItemCreatedDate(item, history = null) {
  const raw = String(item?.created_at || history?.created_at || queueItemPath(item) || "");
  const match = raw.match(/20\d{2}-\d{2}-\d{2}/);
  return match ? match[0] : "";
}

function queueMatchesDate(item, history = null) {
  if (printQueueFilterState.date === "all") return true;
  const created = queueItemCreatedDate(item, history);
  if (!created) return false;
  const today = new Date().toISOString().slice(0, 10);
  if (printQueueFilterState.date === "today") return created === today;
  if (printQueueFilterState.date === "last7") {
    const createdDate = new Date(`${created}T00:00:00`);
    const limit = new Date();
    limit.setDate(limit.getDate() - 7);
    return createdDate >= limit;
  }
  return true;
}

function queueItemPreviewHtml(item, history = null, label = "") {
  const path = queueItemPath(item);
  const previewUrl = outputPreviewForPath(path, history) || item?.preview_uri || "";
  const needsPdfThumb = !previewUrl && String(path).toLowerCase().endsWith(".pdf");
  const thumbAttrs = needsPdfThumb ? ` data-pdf-thumb-path="${esc(path)}"` : "";
  const fallback = `<div class=&quot;output-preview-placeholder compact&quot;><b>Önizleme yok</b><span>PDF’i açarak kontrol edin.</span></div>`;
  if (previewUrl) {
    return `<div class="queue-thumb"${thumbAttrs}><img src="${esc(previewUrl)}" alt="${esc(label || queueItemModelLabel(item, history))} önizleme" onerror="this.parentElement.innerHTML='${fallback}'" /></div>`;
  }
  return `<div class="queue-thumb placeholder"${thumbAttrs}><b>Önizleme yok</b><span>${esc(outputKindLabel(queueItemKind(item)))}</span></div>`;
}

function queueItemDisplayScore(item, history = null) {
  const statusKey = queueItemStatusKey(item, history);
  const validation = outputValidationState({ ...item, relative_path: queueItemPath(item), status: item?.validation_status }, history);
  const kind = queueItemKind(item);
  const hasPreview = Boolean(outputPreviewForPath(queueItemPath(item), history) || item?.preview_uri || kind === "png");
  let score = 0;
  if (isQueueTestArchiveItem(item)) score -= 1000;
  if (statusKey === "pending") score += 80;
  if (statusKey === "printed") score -= 20;
  if (statusKey === "review") score -= 70;
  if (statusKey === "missing") score -= 180;
  if (validation === "validated") score += 80;
  if (validation === "check") score -= 35;
  if (validation === "missing") score -= 180;
  if (history) score += 45;
  if (hasPreview) score += 45;
  if (queueItemModelLabel(item, history) && queueItemModelLabel(item, history) !== "Etiket işi") score += 20;
  if (queueItemLabelText(item, history)) score += 20;
  if (queueItemSizeText(item, history)) score += 12;
  if (kind === "batch" || kind === "roll") score += 8;
  return score;
}

function sortPrintQueueForDefault(rows) {
  return [...(rows || [])].sort((a, b) => {
    const ah = queueItemHistory(a);
    const bh = queueItemHistory(b);
    const scoreDelta = queueItemDisplayScore(b, bh) - queueItemDisplayScore(a, ah);
    if (scoreDelta) return scoreDelta;
    return outputCreatedSortValue({ relative_path: queueItemPath(b), created_at: b?.created_at }, bh) - outputCreatedSortValue({ relative_path: queueItemPath(a), created_at: a?.created_at }, ah);
  });
}

function filteredPrintQueueRows(rows) {
  const query = printQueueFilterState.query.trim().toLowerCase();
  const includeTestArchive = Boolean(printQueueFilterState.includeTestArchive) || ["qa", "test", "arşiv", "arsiv"].some(token => query.includes(token));
  const filtered = rows.filter(item => {
    if (isQueueTestArchiveItem(item) && !includeTestArchive) return false;
    const history = queueItemHistory(item);
    const statusKey = queueItemStatusKey(item, history);
    const kind = queueItemKind(item);
    const selectedStatus = printQueueFilterState.status;
    const reviewKeys = ["review", "needs_review", "missing", "blocked", "failed", "waiting_output"];
    const readyKeys = ["pending", "ready_to_print", "output_ready"];
    if (selectedStatus === "all" && !includeTestArchive && reviewKeys.includes(statusKey)) return false;
    if (selectedStatus !== "all") {
      const statusOk =
        selectedStatus === statusKey ||
        (selectedStatus === "pending" && readyKeys.includes(statusKey)) ||
        (selectedStatus === "review" && reviewKeys.includes(statusKey)) ||
        (selectedStatus === "missing" && ["missing", "blocked", "waiting_output"].includes(statusKey));
      if (!statusOk) return false;
    }
    if (printQueueFilterState.type !== "all") {
      const sourceKey = queueItemSourceKey(item);
      const type = printQueueFilterState.type;
      const typeOk =
        type === sourceKey ||
        (type === "legacy" && ["legacy", "unknown"].includes(sourceKey)) ||
        (type === "manual" && sourceKey === "manual_label") ||
        (type === "bulk" && sourceKey === "bulk_production") ||
        (type === "batch" && (kind === "batch" || kind === "roll"));
      if (!typeOk) return false;
    }
    if (!queueMatchesDate(item, history)) return false;
    if (query) {
      const haystack = [
        queueItemModelLabel(item, history),
        queueItemLabelText(item, history),
        queueItemDateText(item, history),
        queueItemNoteText(item, history),
        fileName(queueItemPath(item)),
        item.job_type || "",
        queueItemSourceLabel(item),
        item.order_no || "",
        item.customer_name || "",
        item.batch_id || "",
        item.duplicate_key || "",
        item.source_item_id || ""
      ].join(" ").toLowerCase();
      if (!haystack.includes(query)) return false;
    }
    return true;
  });
  filtered.sort((a, b) => {
    const ah = queueItemHistory(a);
    const bh = queueItemHistory(b);
    if (printQueueFilterState.sort === "model") return queueItemModelLabel(a, ah).localeCompare(queueItemModelLabel(b, bh), "tr");
    if (printQueueFilterState.sort === "quantity") return Number(queueItemQuantity(b, bh) || 0) - Number(queueItemQuantity(a, ah) || 0);
    if (printQueueFilterState.sort === "status") return queueItemStatusLabel(queueItemStatusKey(a, ah)).localeCompare(queueItemStatusLabel(queueItemStatusKey(b, bh)), "tr");
    const scoreDelta = queueItemDisplayScore(b, bh) - queueItemDisplayScore(a, ah);
    if (scoreDelta) return scoreDelta;
    return outputCreatedSortValue({ relative_path: queueItemPath(b), created_at: b?.created_at }, bh) - outputCreatedSortValue({ relative_path: queueItemPath(a), created_at: a?.created_at }, ah);
  });
  return filtered;
}

function renderQueueDetail(item) {
  const preview = byId("queueDetailPreview");
  const info = byId("queueDetailInfo");
  const statusBox = byId("queueDetailStatus");
  const actions = byId("queueDetailActions");
  const badge = byId("queueDetailBadge");
  const railBadge = byId("queueDetailRailBadge");
  if (!item) {
    if (badge) {
      badge.textContent = "Seçim yok";
      badge.className = "status-pill muted";
    }
    if (railBadge) {
      railBadge.textContent = "Seçim yok";
      railBadge.title = "Seçili iş yok";
    }
    if (preview) {
      preview.className = "queue-detail-preview empty";
      preview.innerHTML = `<div class="queue-detail-empty"><b>Listeden bir iş seçin.</b><span>PDF/PNG önizlemesi burada görünecek.</span></div>`;
    }
    if (info) info.innerHTML = "";
    if (statusBox) statusBox.innerHTML = "";
    if (actions) actions.innerHTML = "";
    return;
  }
  const history = queueItemHistory(item);
  const path = queueItemPath(item);
  const pair = outputPairForPath(path, history);
  const kind = queueItemKind(item);
  const statusKey = queueItemStatusKey(item, history);
  const modelLabel = queueItemModelLabel(item, history);
  const labelText = queueItemLabelText(item, history);
  const dateText = queueItemDateText(item, history);
  const noteText = queueItemNoteText(item, history);
  const quantity = queueItemQuantity(item, history);
  const sizeText = queueItemSizeText(item, history);
  const validation = outputValidationState({ ...item, relative_path: path, status: item.validation_status }, history);
  const createdText = item.created_at || queueItemCreatedDate(item, history) || "-";
  const pdfPath = String(path || "").toLowerCase().endsWith(".pdf") ? path : (pair.pdfPath || "");
  const pngPath = String(path || "").toLowerCase().endsWith(".png") ? path : (pair.pngPath || "");
  const pdfReady = Boolean(pdfPath);
  const pngReady = Boolean(pngPath);
  const canPrint = queueItemCanPrint(item, history);
  const flags = queueItemSafetyFlags(item);
  const flagText = flags.length ? flags.map(queueSafetyFlagLabel).join(" · ") : "Güvenlik kontrolü temiz";
  const queueHistory = Array.isArray(item.queue_history) ? item.queue_history.slice(-5).reverse() : [];
  const preflightStatus = String(history?.preflight_status || item?.preflight_status || "").toUpperCase();
  const preflightLabel = preflightStatus
    ? preflightStatus === "OK" || preflightStatus === "PASSED" || preflightStatus === "SUCCESS"
      ? "Hazır"
      : preflightStatus === "ERROR" || preflightStatus === "FAILED"
        ? "Hata"
        : "Kontrol gerekli"
    : "Kayıt yok";
  const detailRow = (label, value, options = {}) => `
    <div class="queue-detail-row${options.multiline ? " multiline" : ""}">
      <span>${esc(label)}</span>
      <b title="${esc(options.title || value || "-")}">${value || "-"}</b>
    </div>
  `;
  if (badge) {
    badge.textContent = queueItemStatusLabel(statusKey, item);
    badge.className = `status-pill ${queueItemStatusClass(statusKey)}`;
  }
  if (railBadge) {
    railBadge.textContent = `${queueItemStatusLabel(statusKey, item)} · ${labelText || modelLabel || "İş"}`;
    railBadge.title = `${queueItemStatusLabel(statusKey, item)} · ${modelLabel} · ${labelText || "-"}`;
  }
  if (preview) {
    preview.className = "queue-detail-preview";
    preview.innerHTML = queueItemPreviewHtml(item, history, modelLabel);
  }
  if (info) {
    info.innerHTML = `
      <section class="queue-detail-section">
        <h4>Üretim Bilgisi</h4>
        ${detailRow("Model", esc(modelLabel))}
        ${detailRow("İsim", esc(labelText || "-"))}
        ${detailRow("Tarih", esc(dateText || "-"))}
        ${detailRow("Not", esc(noteText || "-"), { title: noteText || "-", multiline: true })}
        ${detailRow("Ölçü", esc(sizeText || "-"))}
        ${detailRow("Adet", esc(quantity))}
      </section>
      <section class="queue-detail-section">
        <h4>Kaynak Bilgisi</h4>
        <div class="queue-detail-row"><span>Kaynak</span>${queueItemSourceBadgeHtml(item)}</div>
        ${item.origin_source_label ? detailRow("Origin", esc(item.origin_source_label), { title: item.origin_source_label }) : ""}
        ${detailRow("Sipariş no", esc(item.order_no || "-"))}
        ${detailRow("Müşteri", esc(item.customer_name || "-"))}
        ${detailRow("Dosya", esc(fileName(path) || "-"), { title: path || "-" })}
        ${detailRow("Oluşturulma", esc(createdText))}
        ${detailRow("Güncelleme", esc(item.updated_at || "-"))}
        ${detailRow("Batch", esc(item.batch_id || "-"))}
        ${detailRow("Duplicate key", esc(item.duplicate_key || "-"), { title: item.duplicate_key || "-", multiline: true })}
        ${detailRow("Relative path", esc(normalizeOutputRef(path) || "-"), { title: path || "-", multiline: true })}
      </section>
    `;
  }
  if (statusBox) {
    statusBox.innerHTML = `
      <section class="queue-detail-section">
        <h4>Kalite / Validasyon</h4>
        <div class="selected-output-status-card ${esc(validation)}"><span>Validation</span><b>${esc(outputValidationLabel(validation))}</b></div>
        <div class="selected-output-status-card ${esc(preflightStatus.toLowerCase() || "neutral")}"><span>Preflight</span><b>${esc(preflightLabel)}</b></div>
        <div class="selected-output-status-card ${pdfReady ? "validated" : "missing"}"><span>PDF</span><b>${pdfReady ? "Hazır" : "PDF bulunamadı"}</b></div>
        <div class="selected-output-status-card ${pngReady ? "validated" : "missing"}"><span>PNG</span><b>${pngReady ? "Hazır" : "PNG çıktısı yok"}</b></div>
        <div class="selected-output-status-card ${flags.length ? "warn" : "validated"}"><span>Güvenlik</span><b title="${esc(flagText)}">${esc(flagText)}</b></div>
      </section>
      <section class="queue-detail-section">
        <h4>Queue Durumu</h4>
        <div class="selected-output-status-card ${esc(statusKey)}"><span>Durum</span><b>${esc(queueItemStatusLabel(statusKey, item))}</b></div>
        <div class="selected-output-status-card neutral"><span>Format</span><b>${esc(queueItemOutputFormat(item, path) || "-")}</b></div>
      </section>
      <section class="queue-detail-section">
        <h4>Geçmiş Logları</h4>
        ${queueHistory.length ? queueHistory.map(log => `<div class="queue-history-row"><b>${esc(log.event || "queue_event")}</b><span>${esc(log.created_at || "")}</span><small>${esc(log.message || queueItemStatusLabel(log.status_key || ""))}</small></div>`).join("") : `<div class="queue-history-row muted"><b>Kayıt yok</b><small>Bu eski kayıt için geçmiş logu bulunmuyor.</small></div>`}
      </section>
      <p class="queue-safe-note compact">Yazıcı otomatik çalışmaz. PDF’i kontrol ettikten sonra manuel yazdırın. PDF açıldıktan sonra yazdırmayı siz onaylarsınız.</p>
    `;
  }
  if (actions) {
    actions.innerHTML = `
      <div class="queue-detail-action-group primary">
        <span>Birincil</span>
        ${pdfReady ? `<button class="btn primary" onclick="openPdfPreview('${esc(pdfPath)}')">PDF Aç</button>` : `<button class="btn" disabled title="PDF bulunamadı">PDF Aç</button>`}
        ${canPrint ? `<button class="btn print-primary" onclick="safePrint('${esc(item.id)}')">Güvenli Yazdır</button>` : `<button class="btn print-primary" disabled title="Gerçek PDF ve hazır durum olmadan güvenli yazdırma başlatılmaz">Güvenli Yazdır</button>`}
      </div>
      <div class="queue-detail-action-group secondary">
        <span>İkincil</span>
        ${pngReady ? `<button class="btn" onclick="selectManualPngPreview('${esc(pngPath)}')">PNG Aç</button>` : `<button class="btn" disabled title="PNG çıktısı yok">PNG Aç</button>`}
        <button class="btn" disabled aria-disabled="true" title="Kaynak ekrana dönüş bağlantısı bu kayıt tipi için henüz production backend’e bağlı değil — sonraki fazda etkinleşecek">Kaynağa Dön</button>
        <button class="btn" onclick="openQueueItemInStudio('${esc(item.id)}')">Studio’da Aç</button>
        ${statusKey === "printed" || statusKey === "delivered" ? `<button class="btn" onclick="markQueuePending('${esc(item.id)}')">Beklemeye Al</button>` : `<button class="btn success-soft" onclick="markQueuePrinted('${esc(item.id)}')">Yazıldı İşaretle</button>`}
        ${statusKey === "delivered" ? `<button class="btn" onclick="markQueuePending('${esc(item.id)}')">Teslimi Geri Al</button>` : `<button class="btn success-soft" onclick="markQueueDelivered('${esc(item.id)}')">Teslim Et</button>`}
      </div>
      <div class="queue-detail-action-group danger">
        <span>Tehlikeli</span>
        <button class="btn danger-soft" onclick="removeQueueItem('${esc(item.id)}')">Sıradan Kaldır</button>
      </div>
    `;
  }
}

function defaultPrintQueueDetailCollapsed() {
  return Boolean(window.matchMedia?.("(max-width: 1500px)")?.matches);
}

function ensurePrintQueueDetailPanelState() {
  if (printQueueDetailCollapsed === null) {
    const saved = localStorage.getItem("ceyizhome_print_queue_detail_collapsed");
    printQueueDetailCollapsed = saved === "1" ? true : saved === "0" ? false : defaultPrintQueueDetailCollapsed();
  }
  applyPrintQueueDetailPanelState();
}

function applyPrintQueueDetailPanelState() {
  const collapsed = Boolean(printQueueDetailCollapsed);
  const layout = byId("printQueueLayout");
  const panel = byId("queueDetailPanel");
  const toggle = byId("queueDetailToggle");
  const rail = byId("queueDetailRail");
  if (layout) layout.classList.toggle("detail-collapsed", collapsed);
  if (panel) panel.classList.toggle("collapsed", collapsed);
  if (toggle) {
    toggle.textContent = collapsed ? "›" : "‹";
    toggle.title = collapsed ? "Detayı Göster" : "Paneli Gizle";
    toggle.setAttribute("aria-label", collapsed ? "Detayı Göster" : "Paneli Gizle");
  }
  if (rail) {
    rail.hidden = !collapsed;
    rail.setAttribute("aria-expanded", collapsed ? "false" : "true");
  }
}

function togglePrintQueueDetailPanel(forceOpen) {
  ensurePrintQueueDetailPanelState();
  printQueueDetailCollapsed = typeof forceOpen === "boolean" ? !forceOpen : !printQueueDetailCollapsed;
  localStorage.setItem("ceyizhome_print_queue_detail_collapsed", printQueueDetailCollapsed ? "1" : "0");
  applyPrintQueueDetailPanelState();
}

function updatePrintQueue(rows) {
  const queue = byId("printQueueList");
  const mini = byId("bulkPrintQueueMini");
  const visibleBaseRows = rows.filter(item => printQueueFilterState.includeTestArchive || !isQueueTestArchiveItem(item));
  const hiddenTestArchiveCount = rows.length - visibleBaseRows.length;
  const filtered = filteredPrintQueueRows(rows);
  const metricRows = visibleBaseRows;
  const visibleRankedRows = sortPrintQueueForDefault(metricRows);
  const totalQty = metricRows.reduce((sum, item) => sum + queueItemQuantityNumber(item, queueItemHistory(item)), 0);
  const printed = metricRows.filter(item => ["printed", "delivered"].includes(queueItemStatusKey(item, queueItemHistory(item)))).length;
  const review = metricRows.filter(item => ["review", "missing", "needs_review", "blocked", "failed", "waiting_output"].includes(queueItemStatusKey(item, queueItemHistory(item)))).length;
  const pending = metricRows.filter(item => ["pending", "ready_to_print", "output_ready"].includes(queueItemStatusKey(item, queueItemHistory(item)))).length;
  const firstPending = visibleRankedRows.find(item => ["pending", "ready_to_print", "output_ready"].includes(queueItemStatusKey(item, queueItemHistory(item)))) || null;
  setText("queueNext", firstPending ? queueItemModelLabel(firstPending, queueItemHistory(firstPending)) : "-");
  setText("queueNextMeta", firstPending ? (queueItemLabelText(firstPending, queueItemHistory(firstPending)) || queueItemStatusLabel(queueItemStatusKey(firstPending, queueItemHistory(firstPending)), firstPending)) : (review ? `${review} iş kontrol gerekli` : "Sırada iş yok"));
  setText("queueTotalJobs", metricRows.length);
  setText("queueQty", totalQty);
  setText("queuePending", pending);
  setText("queuePrinted", printed);
  setText("queueReview", review);
  const clearButton = byId("clearQueueButton");
  if (clearButton) clearButton.hidden = !rows.length;
  const hiddenReviewCount = visibleBaseRows.filter(item => ["review", "missing"].includes(queueItemStatusKey(item, queueItemHistory(item)))).length;
  const pageCount = Math.max(1, Math.ceil(filtered.length / PRINT_QUEUE_PAGE_SIZE));
  printQueuePage = Math.max(1, Math.min(printQueuePage, pageCount));
  const pageRows = filtered.slice((printQueuePage - 1) * PRINT_QUEUE_PAGE_SIZE, printQueuePage * PRINT_QUEUE_PAGE_SIZE);
  if (!filtered.some(item => item.id === selectedPrintQueueItemId)) selectedPrintQueueItemId = pageRows[0]?.id || filtered[0]?.id || "";
  selectedPrintQueueIds = new Set(Array.from(selectedPrintQueueIds).filter(id => rows.some(item => item.id === id)));
  const rowsHtml = pageRows.length
    ? pageRows.map((item, pageIndex) => {
      const index = (printQueuePage - 1) * PRINT_QUEUE_PAGE_SIZE + pageIndex;
      const path = queueItemPath(item);
      const history = queueItemHistory(item);
      const pair = outputPairForPath(path, history);
      const statusKey = queueItemStatusKey(item, history);
      const modelLabel = queueItemModelLabel(item, history);
      const labelText = queueItemLabelText(item, history);
      const dateText = queueItemDateText(item, history);
      const noteText = queueItemNoteText(item, history);
      const quantity = queueItemQuantity(item, history);
      const sizeText = queueItemSizeText(item, history);
      const kind = queueItemKind(item);
      const validation = outputValidationState({ ...item, relative_path: path, status: item.validation_status }, history);
      const pdfPath = String(path || "").toLowerCase().endsWith(".pdf") ? path : (pair.pdfPath || "");
      const pngPath = String(path || "").toLowerCase().endsWith(".png") ? path : (pair.pngPath || "");
      const createdText = item.created_at || queueItemCreatedDate(item, history) || "-";
      const flags = queueItemSafetyFlags(item);
      const canPrint = queueItemCanPrint(item, history);
      const flagText = flags.length ? flags.map(queueSafetyFlagLabel).join(" · ") : "";
      const originLabel = item.origin_source_label ? `Origin: ${item.origin_source_label}` : "";
      const batchLabel = item.batch_id ? `Batch: ${item.batch_id}` : "";
      const selected = item.id === selectedPrintQueueItemId ? " selected" : "";
      const checked = selectedPrintQueueIds.has(item.id) ? " checked" : "";
      return `
      <article class="queue-row queue-card queue-job-card${selected}" data-queue-id="${esc(item.id)}" onclick="selectPrintQueueItem('${esc(item.id)}')">
        <label class="queue-select" onclick="event.stopPropagation()"><input type="checkbox"${checked} onchange="togglePrintQueueSelection('${esc(item.id)}', this.checked)" /></label>
        <b class="queue-index">${index + 1}</b>
        <div class="queue-preview-stack">
          ${queueItemPreviewHtml(item, history, modelLabel)}
          <span class="output-type-badge ${esc(kind)}">${esc(outputKindLabel(kind))}</span>
        </div>
        <div class="queue-main">
          <span class="queue-model-kicker" title="${esc(modelLabel)}">${esc(modelLabel)}</span>
          <b class="queue-label-title" title="${esc(labelText || "İsim yok")}">${esc(labelText || "İsim yok")}</b>
          <div class="queue-meta compact">
            ${dateText ? `<span>Tarih: ${esc(dateText)}</span>` : ""}
            ${noteText ? `<span title="${esc(noteText)}">Not: ${esc(noteText)}</span>` : ""}
            ${sizeText ? `<span>Ölçü: ${esc(sizeText)}</span>` : ""}
            <span>Adet: ${esc(quantity)}</span>
            ${queueItemSourceBadgeHtml(item)}
            ${originLabel ? `<span class="queue-origin-pill" title="${esc(originLabel)}">${esc(originLabel)}</span>` : ""}
          </div>
        </div>
        <div class="queue-file">
          <b title="${esc(path)}">${esc(fileName(path) || "PDF dosyası")}</b>
          <span>Oluşturulma: ${esc(createdText)}</span>
          ${batchLabel ? `<span title="${esc(batchLabel)}">${esc(batchLabel)}</span>` : ""}
          <small>${esc(path || "Dosya yolu yok")}</small>
        </div>
        <div class="queue-quality">
          <span class="pill ${queueItemStatusClass(statusKey)}">${esc(queueItemStatusLabel(statusKey, item))}</span>
          <span class="output-validation-badge ${esc(validation)}">${esc(outputValidationLabel(validation))}</span>
          <small title="${esc(flagText || "Güvenlik kontrolü temiz")}">${flagText || (validation === "validated" ? "Doğrulandı" : validation === "missing" ? "Dosya kontrolü gerekli" : "Kontrol gerekli")}</small>
        </div>
        <div class="toolbar queue-actions" onclick="event.stopPropagation()">
          <div class="queue-action-set files">
            ${pdfPath ? `<button class="btn small primary" title="PDF’i Aç" onclick="openPdfPreview('${esc(pdfPath)}')">PDF</button>` : `<button class="btn small" title="PDF bulunamadı" onclick="alert('Bu iş için PDF dosyası bulunamadı.')">PDF</button>`}
            ${pngPath ? `<button class="btn small" title="PNG Önizle" onclick="selectManualPngPreview('${esc(pngPath)}')">PNG</button>` : `<button class="btn small" title="PNG önizleme bulunamadı" onclick="alert('Bu iş için PNG önizleme bulunamadı.')">PNG</button>`}
          </div>
          <div class="queue-action-set print">
            ${canPrint ? `<button class="btn small print-primary" title="Güvenli yazdırma akışı; yazıcı otomatik başlamaz." onclick="safePrint('${esc(item.id)}')">Yazdır</button>` : `<button class="btn small print-primary" title="Çıktı dosyası bulunmadan veya kontrol tamamlanmadan güvenli yazdırma başlatılmaz" onclick="alert('Çıktı dosyası bulunamadı veya kayıt yazdırmaya hazır değil.')">Yazdır</button>`}
          </div>
          <div class="queue-action-set status">
            ${statusKey === "printed" || statusKey === "delivered" ? `<button class="btn small" title="Beklemeye Al" onclick="markQueuePending('${esc(item.id)}')">Bekle</button>` : `<button class="btn small success-soft" title="Yazdırıldı İşaretle" onclick="markQueuePrinted('${esc(item.id)}')">Yazıldı</button>`}
            ${statusKey !== "delivered" ? `<button class="btn small success-soft" onclick="markQueueDelivered('${esc(item.id)}')">Teslim</button>` : ""}
          </div>
          <div class="queue-action-set danger">
            <button class="btn small danger-soft" title="Sıradan Kaldır" onclick="removeQueueItem('${esc(item.id)}')">Kaldır</button>
          </div>
        </div>
      </article>
    `}).join("")
    : rows.length
      ? `<div class="empty-state"><b>${hiddenReviewCount && printQueueFilterState.status === "all" && !printQueueFilterState.includeTestArchive ? "Yazdırmaya hazır müşteri işi yok." : hiddenTestArchiveCount && !printQueueFilterState.includeTestArchive ? "Müşteri kuyruğu temiz." : "Bu filtrelere uygun iş bulunamadı."}</b><p>${hiddenReviewCount && printQueueFilterState.status === "all" && !printQueueFilterState.includeTestArchive ? `${hiddenReviewCount} iş kontrol gerekli durumunda. Doğrulanmadan yazdırma akışına alınmaz.` : hiddenTestArchiveCount && !printQueueFilterState.includeTestArchive ? `${hiddenTestArchiveCount} kalite/test işi Test/QA Arşivi filtresinde saklandı.` : "Arama veya filtreleri temizleyerek tüm kuyruk işlerini görebilirsiniz."}</p><div class="toolbar"><button class="btn primary" onclick="clearPrintQueueFilters()">Filtreleri Temizle</button>${hiddenReviewCount && printQueueFilterState.status === "all" && !printQueueFilterState.includeTestArchive ? `<button class="btn gold" onclick="setPrintQueueStatusFilter('review')">Kontrol Gerekenleri Göster</button>` : ""}${hiddenTestArchiveCount && !printQueueFilterState.includeTestArchive ? `<button class="btn gold" onclick="showPrintQueueTestArchive()">Test/QA Arşivini Göster</button>` : ""}</div></div>`
      : `<div class="empty-state"><b>Yazdırma sırasında bekleyen iş yok.</b><p>Etiket Studio veya Toplu Etiket’ten çıktı oluşturup Yazdırma Sırasına Ekle diyebilirsiniz.</p><div class="toolbar"><button class="btn primary" onclick="showSection('label')">Etiket Studio’ya Git</button><button class="btn" onclick="showSection('bulkLabel')">Toplu Etiket’e Git</button></div></div>`;
  const footer = filtered.length > PRINT_QUEUE_PAGE_SIZE
    ? `<div class="queue-pagination"><span>Toplam ${filtered.length} iş · Sayfa ${printQueuePage} / ${pageCount}</span><div class="toolbar"><button class="btn small" ${printQueuePage <= 1 ? "disabled" : ""} onclick="changePrintQueuePage(-1)">Önceki</button><button class="btn small" ${printQueuePage >= pageCount ? "disabled" : ""} onclick="changePrintQueuePage(1)">Sonraki</button></div></div>`
    : "";
  if (queue) queue.innerHTML = rowsHtml + footer;
  renderQueueDetail(filtered.find(item => item.id === selectedPrintQueueItemId) || null);
  updatePrintQueueSelectionCount();
  hydrateQueuePdfThumbnails();
  if (mini) mini.innerHTML = visibleBaseRows.length ? visibleBaseRows.slice(0, 3).map(item => `<div class="list-row"><b>${esc(queueItemModelLabel(item, queueItemHistory(item)))}</b><br><small>${esc(queueItemSourceLabel(item))} · ${esc(queueItemQuantity(item, queueItemHistory(item)))} adet</small></div>`).join("") : "Yazdırma sırasında müşteri işi yok.";
}

function refreshPrintQueueFilters() {
  printQueuePage = 1;
  printQueueFilterState = {
    query: byId("queueSearch")?.value || "",
    status: byId("queuePendingOnlyToggle")?.checked || byId("queueHidePrintedToggle")?.checked ? "pending" : (byId("queueStatusFilter")?.value || "all"),
    type: byId("queueTypeFilter")?.value || "all",
    date: byId("queueDateFilter")?.value || "all",
    sort: byId("queueSortFilter")?.value || "created",
    includeTestArchive: Boolean(byId("queueTestArchiveToggle")?.checked)
  };
  if (byId("queuePendingOnlyToggle")?.checked || byId("queueHidePrintedToggle")?.checked) {
    const statusFilter = byId("queueStatusFilter");
    if (statusFilter) statusFilter.value = "pending";
  }
  updatePrintQueue(currentState.printQueue || []);
}

function clearPrintQueueFilters() {
  printQueuePage = 1;
  printQueueFilterState = { query: "", status: "all", type: "all", date: "all", sort: "created", includeTestArchive: false };
  ["queueSearch", "queueStatusFilter", "queueTypeFilter", "queueDateFilter", "queueSortFilter"].forEach(id => {
    const node = byId(id);
    if (!node) return;
    node.value = id === "queueSortFilter" ? "created" : "all";
    if (id === "queueSearch") node.value = "";
  });
  const pendingToggle = byId("queuePendingOnlyToggle");
  const hidePrintedToggle = byId("queueHidePrintedToggle");
  if (pendingToggle) pendingToggle.checked = false;
  if (hidePrintedToggle) hidePrintedToggle.checked = false;
  const testArchiveToggle = byId("queueTestArchiveToggle");
  if (testArchiveToggle) testArchiveToggle.checked = false;
  updatePrintQueue(currentState.printQueue || []);
}

function showPrintQueueTestArchive() {
  const toggle = byId("queueTestArchiveToggle");
  if (toggle) toggle.checked = true;
  printQueueFilterState.includeTestArchive = true;
  updatePrintQueue(currentState.printQueue || []);
}

function setPrintQueueStatusFilter(value) {
  printQueuePage = 1;
  printQueueFilterState.status = value || "all";
  const filter = byId("queueStatusFilter");
  if (filter) filter.value = printQueueFilterState.status;
  const pendingToggle = byId("queuePendingOnlyToggle");
  const hidePrintedToggle = byId("queueHidePrintedToggle");
  if (pendingToggle) pendingToggle.checked = false;
  if (hidePrintedToggle) hidePrintedToggle.checked = false;
  updatePrintQueue(currentState.printQueue || []);
}

function selectReadyPrintQueueItems() {
  selectedPrintQueueIds.clear();
  filteredPrintQueueRows(currentState.printQueue || []).forEach(item => {
    const key = queueItemStatusKey(item, queueItemHistory(item));
    if (["ready_to_print", "output_ready", "pending"].includes(key) && queueItemCanPrint(item, queueItemHistory(item))) {
      selectedPrintQueueIds.add(item.id);
    }
  });
  updatePrintQueue(currentState.printQueue || []);
  const message = selectedPrintQueueIds.size
    ? `${selectedPrintQueueIds.size} yazdırmaya hazır iş seçildi. Yazıcı otomatik başlamaz.`
    : "Yazdırmaya hazır gerçek PDF çıktısı bulunan iş yok.";
  if (typeof showToast === "function") showToast(message, selectedPrintQueueIds.size ? "success" : "warning");
  else alert(message);
}

function showPrintQueueReviewItems() {
  setPrintQueueStatusFilter("review");
}

function showPrintQueueBlockedItems() {
  setPrintQueueStatusFilter("blocked");
}

function showPrintQueueBatchFilterNotice() {
  const batch = prompt("Batch ID veya dosya parçası yazın. Bu işlem sadece arama filtresini uygular; yazıcı çalışmaz.");
  if (!batch) return;
  const search = byId("queueSearch");
  if (search) search.value = batch;
  refreshPrintQueueFilters();
}

function changePrintQueuePage(delta) {
  printQueuePage = Math.max(1, printQueuePage + Number(delta || 0));
  updatePrintQueue(currentState.printQueue || []);
}

function selectPrintQueueItem(id) {
  selectedPrintQueueItemId = id || "";
  document.querySelectorAll("#printQueueList .queue-job-card").forEach(card => {
    card.classList.toggle("selected", card.dataset.queueId === selectedPrintQueueItemId);
  });
  const item = (currentState.printQueue || []).find(row => row.id === selectedPrintQueueItemId);
  renderQueueDetail(item || null);
}

function togglePrintQueueSelection(id, checked) {
  if (checked) selectedPrintQueueIds.add(id);
  else selectedPrintQueueIds.delete(id);
  updatePrintQueueSelectionCount();
}

function toggleAllPrintQueueSelection(checked) {
  const rows = filteredPrintQueueRows(currentState.printQueue || []);
  rows.forEach(item => {
    if (checked) selectedPrintQueueIds.add(item.id);
    else selectedPrintQueueIds.delete(item.id);
  });
  updatePrintQueue(currentState.printQueue || []);
}

function updatePrintQueueSelectionCount() {
  const count = selectedPrintQueueIds.size;
  setText("queueSelectedCount", `${count} seçili`);
  // Buton metinlerini seçili sayıya göre güncelle
  const openBtn = byId("queueBulkOpenPdfs");
  const printBtn = byId("queueBulkPrint");
  if (openBtn) openBtn.textContent = count > 0 ? `PDF'leri Aç (${count})` : "PDF'leri Aç";
  if (printBtn) printBtn.textContent = count > 0 ? `Yazdır (${count})` : "Yazdır";
  const rows = selectedQueueRows();
  const pending = rows.filter(item => queueItemStatusKey(item, queueItemHistory(item)) === "pending").length;
  const printed = rows.filter(item => queueItemStatusKey(item, queueItemHistory(item)) === "printed").length;
  const delivered = rows.filter(item => queueItemStatusKey(item, queueItemHistory(item)) === "delivered").length;
  const review = rows.filter(item => {
    const key = queueItemStatusKey(item, queueItemHistory(item));
    return key === "review" || key === "missing";
  }).length;
  const summaryParts = [];
  if (pending) summaryParts.push(`${pending} bekleyen`);
  if (printed) summaryParts.push(`${printed} yazdırıldı`);
  if (delivered) summaryParts.push(`${delivered} teslim`);
  if (review) summaryParts.push(`${review} kontrol gerekli`);
  setText("queueSelectedSummary", count ? summaryParts.join(" · ") || "Seçili işler hazır" : "Önce en az bir iş seçin.");
  ["queueBulkOpenPdfs", "queueBulkPrint", "queueBulkPrinted", "queueBulkDelivered", "queueBulkRemove"].forEach(id => {
    setQueueBulkButtonEnabled(id, count > 0);
  });
  const bar = document.querySelector("#printQueue .queue-bulk-actions");
  if (bar) bar.classList.toggle("is-empty", count === 0);
  const all = byId("queueSelectAll");
  if (all) {
    const filtered = filteredPrintQueueRows(currentState.printQueue || []);
    all.checked = !!filtered.length && filtered.every(item => selectedPrintQueueIds.has(item.id));
  }
}

function selectedQueueRows() {
  return (currentState.printQueue || []).filter(item => selectedPrintQueueIds.has(item.id));
}

function setQueueBulkButtonEnabled(id, enabled) {
  const button = byId(id);
  if (!button) return;
  button.classList.toggle("bulk-disabled", !enabled);
  button.setAttribute("aria-disabled", enabled ? "false" : "true");
}

function showPrintQueueSelectionRequired() {
  const message = "Önce en az bir iş seçin.";
  if (typeof showToast === "function") showToast(message, "warning");
  else alert(message);
}

function queueBatchResultSummary(total, failed, successLabel) {
  const success = Math.max(0, Number(total || 0) - Number(failed || 0));
  if (failed) return `${total} işten ${success}’i ${successLabel}, ${failed} işte hata var.`;
  return `${total} iş ${successLabel}.`;
}

function showQueueBatchResult(total, failed, successLabel) {
  const message = queueBatchResultSummary(total, failed, successLabel);
  if (typeof showToast === "function") showToast(message, failed ? "warning" : "success");
  else alert(message);
}

// ── Yarı-otomatik toplu yazdırma/PDF akışı ──────────────────────────────────

var _bulkWorkflow = null;

function _ensureBulkWorkflowModal() {
  if (byId("bulkQueueWorkflowModal")) return;
  var el = document.createElement("div");
  el.id = "bulkQueueWorkflowModal";
  el.setAttribute("hidden", "");
  el.style.cssText = "position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:9999;display:flex;align-items:center;justify-content:center;";
  el.innerHTML = [
    '<div style="background:var(--surface,#fff);border-radius:var(--radius-lg,12px);',
    "padding:24px 28px;min-width:340px;max-width:480px;box-shadow:0 8px 32px rgba(0,0,0,.18)\">",
    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">',
    '<strong id="bwTitle" style="font-size:1.05rem"></strong>',
    '<button onclick="cancelBulkQueueWorkflow()" style="background:none;border:none;cursor:pointer;font-size:1.2rem;padding:2px 6px" title="İptal">✕</button>',
    "</div>",
    '<div id="bwProgress" style="color:var(--text-muted,#777);font-size:.875rem;margin-bottom:8px"></div>',
    '<div id="bwItem" style="font-size:.88rem;font-family:monospace;word-break:break-all;',
    "background:var(--surface-2,#f5f5f5);padding:8px 10px;border-radius:6px;margin-bottom:12px;min-height:34px\"></div>",
    '<div id="bwStatus" style="font-size:.85rem;color:var(--text-muted,#777);margin-bottom:16px;min-height:18px"></div>',
    '<div style="display:flex;gap:8px;justify-content:flex-end">',
    '<button onclick="cancelBulkQueueWorkflow()" class="btn small">İptal</button>',
    '<button onclick="bulkWorkflowSkip()" class="btn small">Atla →</button>',
    '<button id="bwActionBtn" onclick="bulkWorkflowDoAction()" class="btn small gold"></button>',
    "</div></div>"
  ].join("");
  document.body.appendChild(el);
}

function startBulkQueueWorkflow(rows, mode) {
  _ensureBulkWorkflowModal();
  _bulkWorkflow = { rows: rows, index: 0, mode: mode, done: 0, skipped: 0 };
  _renderBulkWorkflowStep();
  var modal = byId("bulkQueueWorkflowModal");
  if (modal) modal.removeAttribute("hidden");
}

function _renderBulkWorkflowStep() {
  if (!_bulkWorkflow) return;
  var w = _bulkWorkflow;
  var item = w.rows[w.index];
  var total = w.rows.length;
  var isPdf = w.mode === "pdf";
  var title = byId("bwTitle");
  var progress = byId("bwProgress");
  var itemEl = byId("bwItem");
  var status = byId("bwStatus");
  var actionBtn = byId("bwActionBtn");
  if (title) title.textContent = isPdf ? "Sıralı PDF Açma" : "Sıralı Yazdırma";
  if (progress) progress.textContent = (w.index + 1) + " / " + total + "  —  ✅ " + w.done + " tamamlandı  ↷ " + w.skipped + " atlandı";
  if (itemEl) {
    var name = item.label_text || item.source_label || (queueItemPath(item).split(/[\\/]/).pop()) || item.id || "—";
    itemEl.textContent = name;
  }
  if (status) status.textContent = "";
  if (actionBtn) actionBtn.textContent = isPdf ? "PDF Aç" : "Yazdır";
}

function bulkWorkflowDoAction() {
  if (!_bulkWorkflow) return;
  var w = _bulkWorkflow;
  var item = w.rows[w.index];
  var status = byId("bwStatus");
  if (w.mode === "pdf") {
    var path = queueItemPath(item);
    if (!path) {
      if (status) status.textContent = "⚠️ Dosya yolu yok — atlanıyor";
      setTimeout(bulkWorkflowSkip, 700);
      return;
    }
    openPdfPreview(path);
    w.done++;
    if (status) status.textContent = "✅ PDF açıldı";
  } else {
    safePrint(item.id);
    w.done++;
    if (status) status.textContent = "✅ Yazdırma başlatıldı";
  }
  setTimeout(_bulkWorkflowAdvance, 700);
}

function bulkWorkflowSkip() {
  if (!_bulkWorkflow) return;
  _bulkWorkflow.skipped++;
  _bulkWorkflowAdvance();
}

function _bulkWorkflowAdvance() {
  if (!_bulkWorkflow) return;
  _bulkWorkflow.index++;
  if (_bulkWorkflow.index >= _bulkWorkflow.rows.length) {
    _bulkWorkflowFinish();
  } else {
    _renderBulkWorkflowStep();
  }
}

function _bulkWorkflowFinish() {
  var w = _bulkWorkflow;
  _bulkWorkflow = null;
  var modal = byId("bulkQueueWorkflowModal");
  if (modal) modal.setAttribute("hidden", "");
  var msg = "Toplu işlem tamamlandı: " + (w ? w.done : 0) + "/" + (w ? w.rows.length : 0) + " başarılı" + (w && w.skipped ? ", " + w.skipped + " atlandı" : "") + ".";
  if (typeof showToast === "function") showToast(msg, "success"); else alert(msg);
}

function cancelBulkQueueWorkflow() {
  var w = _bulkWorkflow;
  _bulkWorkflow = null;
  var modal = byId("bulkQueueWorkflowModal");
  if (modal) modal.setAttribute("hidden", "");
  if (w && (w.done || w.skipped)) {
    var msg = "İşlem iptal edildi: " + w.done + " tamamlandı, " + w.skipped + " atlandı.";
    if (typeof showToast === "function") showToast(msg, "warning"); else alert(msg);
  }
}

function printSelectedQueueItems() {
  const rows = selectedQueueRows();
  if (!rows.length) { showPrintQueueSelectionRequired(); return; }
  if (rows.length === 1) { safePrint(rows[0].id); return; }
  startBulkQueueWorkflow(rows, "print");
}

function openSelectedQueuePdfs() {
  const rows = selectedQueueRows();
  if (!rows.length) { showPrintQueueSelectionRequired(); return; }
  if (rows.length === 1) { openPdfPreview(queueItemPath(rows[0])); return; }
  startBulkQueueWorkflow(rows, "pdf");
}

function removeSelectedQueueItems() {
  const rows = selectedQueueRows();
  if (!rows.length) {
    showPrintQueueSelectionRequired();
    return;
  }
  if (!confirm(`Seçili ${rows.length} iş yazdırma sırasından kaldırılacak. Bu işlem yazıcıyı çalıştırmaz ancak kuyruktan kaldırır. Devam edilsin mi?`)) return;
  removeQueueItems(rows.map(item => item.id), { summary: true });
}

function markSelectedQueuePrinted() {
  const rows = selectedQueueRows();
  if (!rows.length) {
    showPrintQueueSelectionRequired();
    return;
  }
  if (!confirm(`Seçili ${rows.length} iş yazdırıldı olarak işaretlenecek. Devam edilsin mi?`)) return;
  markQueueItems(rows.map(item => item.id), "printed", { summary: true });
}

function markSelectedQueueDelivered() {
  const rows = selectedQueueRows();
  if (!rows.length) {
    showPrintQueueSelectionRequired();
    return;
  }
  if (!confirm(`Seçili ${rows.length} iş teslim edildi olarak işaretlenecek. Devam edilsin mi?`)) return;
  markQueueItems(rows.map(item => item.id), "delivered", { summary: true });
}

function removeQueueItem(id) {
  if (!confirm("Bu iş yazdırma sırasından kaldırılacak. Bu işlem yazıcıyı çalıştırmaz ancak kuyruktan kaldırır. Devam edilsin mi?")) return;
  removeQueueItems([id]);
}

function removeQueueItems(ids, options = {}) {
  const unique = Array.from(new Set(ids.filter(Boolean)));
  if (!unique.length) return;
  let remaining = unique.length;
  let failed = 0;
  unique.forEach(id => {
    selectedPrintQueueIds.delete(id);
    bridge.remove_from_print_queue(id, raw => {
      const result = parseBridgeResult(raw);
      if (String(result.status || "").toUpperCase() === "ERROR") failed += 1;
      remaining -= 1;
      if (remaining <= 0) {
        if (options.summary) showQueueBatchResult(unique.length, failed, "sıradan kaldırıldı");
        refreshState();
      }
    });
  });
}

function markQueuePrinted(id) {
  markQueueItems([id], "printed");
}

function markQueuePending(id) {
  markQueueItems([id], "pending");
}

function markQueueDelivered(id) {
  markQueueItems([id], "delivered");
}

function markQueueItems(ids, status, options = {}) {
  const unique = Array.from(new Set(ids.filter(Boolean)));
  if (!unique.length) return;
  const fn = status === "delivered" && bridge.mark_queue_item_delivered
    ? "mark_queue_item_delivered"
    : status === "pending" && bridge.mark_queue_item_pending
      ? "mark_queue_item_pending"
      : "mark_queue_item_printed";
  let remaining = unique.length;
  let failed = 0;
  unique.forEach(id => {
    bridge[fn](id, raw => {
      const result = parseBridgeResult(raw);
      if (String(result.status || "").toUpperCase() === "ERROR") failed += 1;
      remaining -= 1;
      if (remaining <= 0) {
        if (options.summary) {
          const label = status === "delivered" ? "teslim edildi olarak işaretlendi" : "yazdırıldı olarak işaretlendi";
          showQueueBatchResult(unique.length, failed, label);
        }
        refreshState();
      }
    });
  });
}

function confirmClearPrintQueue() {
  const rows = currentState.printQueue || [];
  if (!rows.length) return;
  const modal = byId("queueClearModal");
  const summary = byId("queueClearSummary");
  const pending = rows.filter(item => queueItemStatusKey(item, queueItemHistory(item)) !== "printed").length;
  const printed = rows.length - pending;
  if (summary) {
    summary.innerHTML = `
      <div><span>Bekleyen</span><b>${pending}</b></div>
      <div><span>Yazdırıldı</span><b>${printed}</b></div>
      <div><span>Toplam</span><b>${rows.length}</b></div>
    `;
  }
  if (modal) modal.hidden = false;
}

function closeQueueClearModal() {
  const modal = byId("queueClearModal");
  if (modal) modal.hidden = true;
}

function clearPrintQueueConfirmed(includePrinted = false) {
  closeQueueClearModal();
  if (includePrinted) {
    selectedPrintQueueIds.clear();
    bridge.clear_print_queue(refreshAfterResult);
    return;
  }
  const pendingIds = (currentState.printQueue || [])
    .filter(item => queueItemStatusKey(item, queueItemHistory(item)) !== "printed")
    .map(item => item.id);
  removeQueueItems(pendingIds);
}

function openQueueItemInStudio(id) {
  const item = (currentState.printQueue || []).find(row => row.id === id);
  if (!item) {
    alert("Bu iş yazdırma sırasında bulunamadı.");
    return;
  }
  const history = queueItemHistory(item);
  if (history?.model_path || history?.model_key) {
    const model = currentLabelModels.find(candidate =>
      normalizeOutputRef(candidate.path || candidate.model_path || candidate.key || "") === normalizeOutputRef(history.model_path || history.model_key || "") ||
      String(candidate.name || candidate.display_name || "").toLowerCase() === String(history.model_name || "").toLowerCase()
    );
    if (model) {
      selectLabelModel(model.path);
    }
  }
  showSection("label");
}

function hydrateQueuePdfThumbnails() {
  const thumbs = Array.from(document.querySelectorAll("[data-pdf-thumb-path]"));
  if (!thumbs.length || !bridge?.get_pdf_preview_payload) return;
  thumbs.forEach(thumb => {
    const path = thumb.getAttribute("data-pdf-thumb-path") || "";
    if (!path) return;
    const cached = queuePdfThumbCache.get(path);
    if (cached) {
      thumb.innerHTML = `<img src="${esc(cached)}" alt="PDF önizleme" />`;
      return;
    }
    bridge.get_pdf_preview_payload(path, raw => {
      const payload = parseBridgeResult(raw);
      const firstPage = Array.isArray(payload.preview_pages) ? payload.preview_pages[0] : null;
      const url = firstPage?.preview_url || "";
      if (payload.status === "OK" && url) {
        queuePdfThumbCache.set(path, url);
        const currentThumb = Array.from(document.querySelectorAll("[data-pdf-thumb-path]"))
          .find(node => node.getAttribute("data-pdf-thumb-path") === path);
        if (currentThumb) currentThumb.innerHTML = `<img src="${esc(url)}" alt="PDF önizleme" />`;
      }
    });
  });
}

function safePrint(id) {
  pendingSafePrintId = id;
  const modal = byId("safePrintModal");
  if (!modal) return;
  const item = (currentState.printQueue || []).find(row => row.id === id);
  if (!item) {
    const status = byId("safePrintStatus");
    if (status) {
      status.className = "safe-print-status warn";
      status.textContent = "Bu iş yazdırma sırasında bulunamadı. Listeyi yenileyin.";
    }
    modal.hidden = false;
    return;
  }
  const path = item.relative_path || item.path || "";
  const history = historyForOutputPath(path);
  bridge.print_queue_item_safe(id, raw => {
    const result = parseBridgeResult(raw);
    if (result.status !== "MANUAL_PRINT_REQUIRED" && result.status !== "OK") {
      alert(result.message || "Çıktı güvenli değil. Lütfen kontrol edin.");
      return;
    }
    requestPdfPrint(result.relative_path || path, {
      modelName: queueItemModelLabel(item, history),
      labelText: queueItemLabelText(item, history),
      dateText: queueItemDateText(item, history),
      noteText: queueItemNoteText(item, history),
      sizeText: queueItemSizeText(item, history),
      quantity: queueItemQuantity(item, history),
      fileName: fileName(result.relative_path || path),
      sourceLabel: queueItemSourceLabel(item),
      outputFormat: queueItemOutputFormat(item, result.relative_path || path),
      printerName: "Manuel PDF kontrolü",
      queueItemId: id
    });
  });
}

function confirmSafePrintOpen() {
  if (!pendingPrintCandidate?.relativePath) {
    alert("Yazdırılacak PDF bulunamadı.");
    return;
  }
  const profileId = byId("safePrintProfileSelect")?.value || "";
  const approved = Boolean(byId("safePrintOperatorApproval")?.checked);
  if (!profileId) {
    alert("Manuel print hazırlığı için yazıcı profili seçin.");
    return;
  }
  if (!approved) {
    alert("Manuel kontrol onayı olmadan print hazırlığı tamamlanmaz.");
    return;
  }
  const status = byId("safePrintStatus");
  if (pendingPrintCandidate.queueItemId && bridge?.prepare_manual_print) {
    bridge.prepare_manual_print(pendingPrintCandidate.queueItemId, profileId, raw => {
      const result = parseBridgeResult(raw);
      if (result.status !== "OK") {
        if (status) {
          status.className = "safe-print-status warn";
          status.textContent = result.message || "Manuel print hazırlığı tamamlanmadı.";
        }
        alert(result.message || "Manuel print hazırlığı tamamlanmadı.");
        return;
      }
      if (status) {
        status.className = "safe-print-status ok";
        status.textContent = "Manuel print hazırlığı tamamlandı. PDF kontrol için açılıyor; yazdırmayı kullanıcı onaylar.";
      }
      bridge.open_project_file(pendingPrintCandidate.relativePath);
      refreshState();
    });
    return;
  }
  if (status) {
    status.className = "safe-print-status ok";
    status.textContent = "PDF varsayılan görüntüleyicide açılıyor. Yazdırmayı kullanıcı onaylar.";
  }
  bridge.open_project_file(pendingPrintCandidate.relativePath);
}

function closeSafePrintModal() {
  pendingSafePrintId = null;
  pendingPrintCandidate = null;
  const modal = byId("safePrintModal");
  if (modal) modal.hidden = true;
}

function openPdfPreview(relativePath) {
  if (!relativePath) {
    alert("PDF dosyası bulunamadı.");
    return;
  }
  if (!bridge || typeof bridge.get_pdf_preview_payload !== "function") {
    alert("PDF önizleme bu oturumda hazır değil.");
    return;
  }
  bridge.get_pdf_preview_payload(relativePath, raw => {
    const payload = JSON.parse(raw || "{}");
    if (payload.status !== "OK") {
      alert(payload.message || "PDF program içinde görüntülenemedi.");
      return;
    }
    pdfPreviewState = { pages: payload.preview_pages || [], index: 0, zoom: 1, payload };
    renderPdfPreviewModal();
    const modal = byId("pdfPreviewModal");
    if (modal) modal.hidden = false;
  });
}

function addPdfToQueue(relativePath) {
  if (!relativePath) {
    showLabelOutputStatus("Yazdırma sırasına eklenecek PDF bulunamadı.", "warn");
    alert("Yazdırma sırasına eklenecek PDF bulunamadı.");
    return;
  }
  if (!String(relativePath || "").toLowerCase().endsWith(".pdf")) {
    showLabelOutputStatus("Yazdırma sırasına sadece doğrulanmış PDF dosyaları eklenir.", "warn");
    return;
  }
  if (bridge.add_pdf_output_to_print_queue) {
    bridge.add_pdf_output_to_print_queue(relativePath, handleQueueAddedResult);
  } else {
    bridge.add_label_outputs_to_print_queue(handleQueueAddedResult);
  }
}

function parseBridgeResult(raw) {
  if (!raw) return {};
  if (typeof raw === "string") {
    try { return JSON.parse(raw); } catch (_) { return { status: "ERROR", message: raw }; }
  }
  return raw || {};
}

function handleQueueAddedResult(raw) {
  const result = parseBridgeResult(raw);
  refreshState();
  const status = String(result.status || result.queue_result?.status || "").toUpperCase();
  if (status === "OK" || status === "ADDED" || status === "DUPLICATE") {
    showQueueAddedModal(result);
    return;
  }
  alert(result.message || "Yazdırma sırasına eklenemedi.");
}

function showQueueAddedModal(result = {}) {
  const currentSignature = manualOutputSignature();
  if (result.batch_pdf_path || result.pdf_path || result.png_path) {
    lastManualOutput = { ...(lastManualOutput || {}), ...(result || {}), _manual_signature: currentSignature };
    lastManualRenderAt = lastManualRenderAt || new Date().toLocaleTimeString("tr-TR", { hour: "2-digit", minute: "2-digit" });
  }
  if (result.preflight) lastManualPreflightResult = result.preflight;
  lastManualQueueResult = { ...(result || {}), _manual_signature: manualOutputSignature() };
  updateManualOutputControlPanel();
  const modal = byId("queueAddedModal");
  if (!modal) return;
  const queue = result.queue_result || {};
  const file = result.batch_pdf_path || result.relative_path || result.pdf_path || queue.relative_path || "";
  rememberQueueSourceForPath(file);
  setText("queueAddedText", queue.status === "DUPLICATE"
    ? "Bu çıktı zaten yazdırma sırasında. Yazıcı otomatik çalışmaz; PDF’i kontrol ettikten sonra manuel yazdırabilirsiniz."
    : "Etiket işi güvenli şekilde yazdırma sırasına alındı. Yazıcı otomatik çalışmaz; PDF’i kontrol ettikten sonra manuel yazdırabilirsiniz.");
  setText("queueAddedFile", file ? `Dosya: ${fileName(file)}` : "");
  modal.hidden = false;
}

function closeQueueAddedModal() {
  const modal = byId("queueAddedModal");
  if (modal) modal.hidden = true;
}

function goToPrintQueueFromModal() {
  closeQueueAddedModal();
  showSection("printQueue");
}

function renderPdfPreviewModal() {
  const payload = pdfPreviewState.payload || {};
  setText("pdfPreviewTitle", payload.display_name || "PDF Önizleme");
  setText("pdfPreviewMeta", `${payload.file_type || "PDF"} · ${payload.page_count || 1} sayfa · ${payload.size_kb || "-"} KB · ${payload.created_at || "-"}`);
  const currentPage = pdfPreviewState.pages[pdfPreviewState.index];
  const counter = byId("pdfPreviewCounter");
  if (counter) counter.textContent = `${Math.min(pdfPreviewState.index + 1, payload.page_count || 1)} / ${payload.page_count || 1}`;
  const stage = byId("pdfPreviewStage");
  if (!stage) return;
  if (currentPage.preview_url) {
    stage.innerHTML = `<img class="pdf-page-image" style="width:${Math.round(pdfPreviewState.zoom * 100)}%" src="${esc(currentPage.preview_url)}" alt="PDF sayfa ${esc(currentPage.page || pdfPreviewState.index + 1)}" />`;
  } else if (payload.file_url) {
    stage.innerHTML = `<iframe class="pdf-frame" src="${esc(payload.file_url)}"></iframe>`;
  } else {
    stage.innerHTML = `<div class="empty-state"><b>PDF program içinde görüntülenemedi.</b><p>Harici Aç ile kontrol edebilirsiniz.</p></div>`;
  }
  const warnings = byId("pdfPreviewWarnings");
  if (warnings) {
    warnings.innerHTML = (payload.warnings || []).length
      ? (payload.warnings || []).map(item => `<div class="safe-note">${esc(item)}</div>`).join("")
      : "";
  }
}

function nextPdfPage() {
  if (!pdfPreviewState.pages.length) return;
  pdfPreviewState.index = Math.min(pdfPreviewState.pages.length - 1, pdfPreviewState.index + 1);
  renderPdfPreviewModal();
}

function prevPdfPage() {
  if (!pdfPreviewState.pages.length) return;
  pdfPreviewState.index = Math.max(0, pdfPreviewState.index - 1);
  renderPdfPreviewModal();
}

function zoomPdf(delta) {
  pdfPreviewState.zoom = Math.max(0.5, Math.min(2.5, pdfPreviewState.zoom + delta));
  renderPdfPreviewModal();
}

function resetPdfZoom() {
  pdfPreviewState.zoom = 1;
  renderPdfPreviewModal();
}

function closePdfPreviewModal() {
  const modal = byId("pdfPreviewModal");
  if (modal) modal.hidden = true;
}

function openCurrentPdfExternal() {
  const relativePath = pdfPreviewState.payload?.relative_path;
  if (relativePath) bridge.open_project_file(relativePath);
}

function addCurrentPdfToQueue() {
  addPdfToQueue(pdfPreviewState.payload?.relative_path || "");
}

function refreshAfterResult(raw) {
  if (raw) {
    try {
      const result = JSON.parse(raw);
      if (result.message) alert(result.message);
    } catch (_) {}
  }
  refreshState();
}

function updateReports() {
  renderReportSummaryCards();
  if (!byId("reportBox").dataset.selected) selectReport("summary");
}

function readinessText(value) {
  return value === "BLOKE" ? "Bloke" : value === "KONTROL_GEREKLI" ? "Kontrol gerekli" : value === "HAZIR" ? "Hazır" : "Bekliyor";
}

function selectReport(name) {
  const box = byId("reportBox");
  if (!box) return;
  box.dataset.selected = name;
  const reports = currentState.reports || {};
  const s = currentState.summary || {};
  if (name === "summary") {
    box.innerHTML = `
      <div class="report-panel-head">
        <div><b>Üretim Özeti</b><p>Son kontrol raporuna göre üretim durumu.</p></div>
        <span class="pill ${currentState.readiness === "HAZIR" ? "ok" : currentState.readiness === "BLOKE" ? "bad" : "warn"}">${esc(readinessText(currentState.readiness || "NO_CHECK"))}</span>
      </div>
      <div class="report-card-grid">
        ${reportMetric("Toplam sipariş", s.total || s.valid || 0, "muted")}
        ${reportMetric("Geçerli sipariş", s.valid || 0, "ok")}
        ${reportMetric("Kritik hata", s.errors || 0, Number(s.errors || 0) ? "bad" : "ok")}
        ${reportMetric("Kontrol gerekli", s.review || 0, Number(s.review || 0) ? "warn" : "ok")}
        ${reportMetric("Etiket işleri", s.label || 0, "muted")}
      </div>
      <div class="report-safe-note">Güvenlik: CorelDRAW, yazıcı, RDWorks ve lazer otomatik çalışmaz.</div>
    `;
  } else if (name === "errors") {
    const rows = reports.errors || [];
    box.innerHTML = rows.length
      ? rows.map(row => `<article class="report-row-card bad"><b>${esc(row.title || "Kritik hata")}</b><p>${esc(row.desc || "Detay yok.")}</p>${row.row ? `<small>${esc(row.row)}</small>` : ""}</article>`).join("")
      : `<div class="empty-state compact"><b>Kritik hata yok.</b><p>Üretimi bloke eden rapor kaydı görünmüyor.</p></div>`;
  } else if (name === "review") {
    box.innerHTML = formatRowsAsCards(reports.reviewRows || [], "Kontrol gerektiren satır yok.", "Kontrol gerekli");
  } else if (name === "labels") {
    box.innerHTML = formatRowsAsCards(reports.labelRows || [], "Henüz etiket çıktısı yok.", "Etiket çıktısı");
  } else if (name === "release") {
    const models = currentLabelModels || [];
    const readyModels = models.filter(model => modelHealthDetails(model).label === "Hazır").length;
    const missingPreview = models.filter(model => modelHealthDetails(model).label === "Görsel eksik").length;
    const queue = currentState.printQueue || [];
    const outputs = (currentState.labelOutputs || []).filter(isCustomerOutput);
    const history = currentState.productionHistory || [];
    const validated = history.filter(item => productionHistoryValidationState(item) === "passed").length;
    const q = currentState.qualityGateEvidence || {};
    const qStatus = String(q.status || "MISSING").toUpperCase();
    const acceptanceStatus = String(q.acceptance_status || q.acceptanceStatus || "MISSING").toUpperCase();
    const qPdf = q.pdf_relative_path || q.pdf_path || "";
    const qPng = q.png_relative_path || q.png_path || "";
    box.innerHTML = `
      <div class="report-panel-head">
        <div><b>Release Dashboard</b><p>Canlı veriden güvenli üretim ve UX kontrol özeti.</p></div>
        <span class="pill ${Number(s.errors || 0) || qStatus === "ERROR" ? "bad" : qStatus === "PASSED" || qStatus === "OK" ? "ok" : "warn"}">${Number(s.errors || 0) ? "P0/P1 kontrol gerekli" : "P0/P1 görünmüyor"}</span>
      </div>
      <div class="report-card-grid">
        ${reportMetric("Hazır model", readyModels, readyModels ? "ok" : "warn")}
        ${reportMetric("Görsel eksik", missingPreview, missingPreview ? "warn" : "ok")}
        ${reportMetric("Queue işi", queue.length, queue.length ? "ok" : "muted")}
        ${reportMetric("Müşteri çıktısı", outputs.length, outputs.length ? "ok" : "muted")}
        ${reportMetric("Doğrulanan üretim", validated, validated ? "ok" : "warn")}
        ${reportMetric("Kalite kapısı", qStatus === "MISSING" ? "Yok" : qStatus, qStatus === "PASSED" || qStatus === "OK" ? "ok" : qStatus === "ERROR" ? "bad" : "warn")}
        ${reportMetric("Kabul senaryosu", acceptanceStatus === "MISSING" ? "Yok" : acceptanceStatus, acceptanceStatus === "PASSED" || acceptanceStatus === "OK" ? "ok" : "warn")}
      </div>
      <div class="release-check-grid">
        <div class="settings-check ok"><b>Direct print</b><span>Kapalı kalır</span></div>
        <div class="settings-check ok"><b>Fiziksel cihaz</b><span>Otomatik tetiklenmez</span></div>
        <div class="settings-check ok"><b>Kaynak AI/CDR</b><span>Değiştirilmez</span></div>
        <div class="settings-check ${Number(s.errors || 0) ? "bad" : "ok"}"><b>Rapor hataları</b><span>${esc(s.errors || 0)} kritik kayıt</span></div>
        <div class="settings-check ${qStatus === "PASSED" || qStatus === "OK" ? "ok" : "warn"}"><b>Son kalite kanıtı</b><span>${esc(q.quality_gate_dir || "Kanıt yok")}</span></div>
        <div class="settings-check ${q.queue_relative_path ? "ok" : "warn"}"><b>Queue kanıtı</b><span>${esc(q.queue_relative_path || "Son doğrulanmış queue yolu yok")}</span></div>
      </div>
      <div class="release-evidence-grid">
        <div class="release-evidence-card ${qStatus === "PASSED" || qStatus === "OK" ? "ok" : "warn"}">
          <b>Canvas → PDF/PNG</b>
          <span>${esc(qStatus === "MISSING" ? "Kalite kanıtı yok" : qStatus)}</span>
          <small>${esc(q.quality_gate_dir || "Screenshot/çıktı kanıtı bekleniyor")}</small>
        </div>
        <div class="release-evidence-card ${qPdf ? "ok" : "warn"}">
          <b>Son PDF</b>
          <span>${esc(qPdf || "PDF yolu yok")}</span>
          ${qPdf ? `<button class="btn small" onclick="openPdfPreview(${jsArg(qPdf)})">PDF’i Gör</button>` : ""}
        </div>
        <div class="release-evidence-card ${qPng ? "ok" : "warn"}">
          <b>Son PNG</b>
          <span>${esc(qPng || "PNG yolu yok")}</span>
          ${qPng ? `<button class="btn small" onclick="selectManualPngPreview(${jsArg(qPng)})">PNG Önizle</button>` : ""}
        </div>
        <div class="release-evidence-card ${acceptanceStatus === "PASSED" || acceptanceStatus === "OK" ? "ok" : "warn"}">
          <b>Gerçek kullanıcı kabulü</b>
          <span>${esc(acceptanceStatus === "MISSING" ? "Kanıt yok" : acceptanceStatus)}</span>
          <small>Buton, drag/resize, output ve queue kapıları birlikte değerlendirilir.</small>
        </div>
      </div>
      <div class="report-safe-note">Kalite komutları bu panelden çalıştırılmaz; son karar için test/quality gate komut çıktıları kullanılır.</div>
    `;
  } else {
    box.innerHTML = currentState.log
      ? `<pre class="report-log">${esc(currentState.log)}</pre>`
      : `<div class="empty-state compact"><b>Henüz günlük kaydı yok.</b><p>Çalışma günlüğü oluştuğunda burada görünür.</p></div>`;
  }
}

function renderReportSummaryCards() {
  const box = byId("reportSummaryCards");
  if (!box) return;
  const s = currentState.summary || {};
  const readiness = readinessText(currentState.readiness || "NO_CHECK");
  box.innerHTML = `
    ${reportMetric("Durum", readiness, currentState.readiness === "HAZIR" ? "ok" : currentState.readiness === "BLOKE" ? "bad" : "warn")}
    ${reportMetric("Kritik hata", s.errors || 0, Number(s.errors || 0) ? "bad" : "ok")}
    ${reportMetric("Kontrol gereken", s.review || 0, Number(s.review || 0) ? "warn" : "ok")}
    ${reportMetric("Etiket işi", s.label || 0, "muted")}
  `;
}

function reportMetric(label, value, tone = "muted") {
  return `<div class="report-metric ${esc(tone)}"><small>${esc(label)}</small><b>${esc(value)}</b></div>`;
}

function formatRowsAsCards(rows, empty, title) {
  if (!rows.length) return `<div class="empty-state compact"><b>${esc(empty)}</b><p>Bu bölümde işlem gerektiren kayıt görünmüyor.</p></div>`;
  return rows.map((row, index) => {
    const entries = Object.entries(row).filter(([, value]) => String(value || "").trim());
    return `
      <article class="report-row-card">
        <b>${esc(row.name || row.file || row.model_name || `${title} ${index + 1}`)}</b>
        <dl>${entries.slice(0, 8).map(([key, value]) => `<div><dt>${esc(key)}</dt><dd>${esc(value)}</dd></div>`).join("")}</dl>
      </article>
    `;
  }).join("");
}

function setSettingsInput(id, value) {
  const input = byId(id);
  if (input) input.value = value ?? "";
}

function readSettingsNumber(id, label, { positive = false, nonNegative = false, integer = false } = {}) {
  const input = byId(id);
  const raw = String(input?.value || "").trim().replace(",", ".");
  const value = Number(raw);
  if (!Number.isFinite(value)) {
    throw new Error(`${label} sayısal olmalı.`);
  }
  if (positive && value <= 0) {
    throw new Error(`${label} 0'dan büyük olmalı.`);
  }
  if (nonNegative && value < 0) {
    throw new Error(`${label} negatif olamaz.`);
  }
  return integer ? Math.max(1, Math.round(value)) : value;
}

function resetSettingsFormToState() {
  const defaults = currentState.labelDefaults || {};
  setSettingsInput("settingsWidthMm", defaults.label_width_mm || 50);
  setSettingsInput("settingsHeightMm", defaults.label_height_mm || 30);
  setSettingsInput("settingsDefaultCopies", defaults.default_copies || 1);
  setSettingsInput("settingsPrinterDpi", defaults.printer_dpi || 300);
  setSettingsInput("settingsSafeMarginMm", defaults.safe_margin_mm || 1.5);
  setSettingsInput("settingsScalePercent", defaults.scale_percent || 100);
  setSettingsInput("settingsRollWidthMm", defaults.roll_width_mm || defaults.label_width_mm || 50);
  setSettingsInput("settingsRollGapMm", defaults.roll_gap_mm || 3);
}

function readSettingsCenterPayload() {
  return {
    media_type: "ROLL",
    label_width_mm: readSettingsNumber("settingsWidthMm", "Genişlik", { positive: true }),
    label_height_mm: readSettingsNumber("settingsHeightMm", "Yükseklik", { positive: true }),
    default_copies: readSettingsNumber("settingsDefaultCopies", "Varsayılan adet", { positive: true, integer: true }),
    printer_dpi: readSettingsNumber("settingsPrinterDpi", "DPI", { positive: true, integer: true }),
    safe_margin_mm: readSettingsNumber("settingsSafeMarginMm", "Güvenli alan", { nonNegative: true }),
    scale_percent: readSettingsNumber("settingsScalePercent", "Ölçek", { positive: true }),
    roll_width_mm: readSettingsNumber("settingsRollWidthMm", "Rulo genişliği", { positive: true }),
    roll_gap_mm: readSettingsNumber("settingsRollGapMm", "Etiket aralığı", { nonNegative: true }),
    background_enabled: true,
    show_cut_boundary: false,
    show_order_number_on_label: false
  };
}

function showSettingsSaveStatus(message, tone = "ok") {
  const box = byId("settingsSaveStatus");
  if (!box) return;
  box.className = `settings-save-status ${tone}`;
  box.textContent = message || "";
}

function saveSettingsFromCenter() {
  try {
    const payload = readSettingsCenterPayload();
    if (!bridge?.save_label_defaults_json) {
      showSettingsSaveStatus("Bu oturumda güvenli ayar kaydı hazır değil.", "warn");
      return;
    }
    bridge.save_label_defaults_json(JSON.stringify(payload), raw => {
      const result = parseBridgeResult(raw, "Ayarlar kaydedilemedi.");
      if (result.status !== "OK") {
        showSettingsSaveStatus(result.message || "Ayarlar kaydedilemedi.", "warn");
        return;
      }
      currentState.labelDefaults = result.label_defaults || payload;
      currentState.settingsBackups = result.backups || currentState.settingsBackups || [];
      updateSettings(currentState);
      showSettingsSaveStatus(result.message || "Ayarlar kaydedildi. Direct print kapalı kaldı.", "ok");
    });
  } catch (error) {
    showSettingsSaveStatus(String(error?.message || error), "warn");
  }
}

function updateSettings(state) {
  const defaults = state.labelDefaults || {};
  const printMode = state.printMode || "label_designer";
  const width = Number(defaults.label_width_mm || 0);
  const height = Number(defaults.label_height_mm || 0);
  const gap = Number(defaults.roll_gap_mm || 0);
  const dpi = Number(defaults.printer_dpi || 0);
  const copies = Number(defaults.default_copies || 1);
  resetSettingsFormToState();
  setText("labelDefaultsText", `Etiket tipi: ${defaults.media_type || "ROLL"} · Ölçü: ${width || "-"} x ${height || "-"} mm · DPI: ${dpi || "-"}`);
  const cards = byId("labelDefaultsCards");
  if (cards) {
    cards.innerHTML = `
      ${settingsMetric("Genişlik", width ? `${width} mm` : "-", "ok")}
      ${settingsMetric("Yükseklik", height ? `${height} mm` : "-", "ok")}
      ${settingsMetric("Aralık", `${gap || 0} mm`, "muted")}
      ${settingsMetric("DPI", dpi || "-", "muted")}
      ${settingsMetric("Varsayılan adet", copies || 1, "muted")}
      ${settingsMetric("Baskı modu", printMode === "label_designer" ? "Etiket tasarım" : "Veri modu", "ok")}
    `;
  }
  const strip = byId("settingsSafetyStrip");
  if (strip) {
    strip.innerHTML = `
      <span class="pill ok">Güvenli Mod: Aktif</span>
      <span class="pill ok">Direct Print: Kapalı</span>
      <span class="pill ok">Yazıcı otomatik çalışmaz</span>
      <span class="pill ok">Yazdır: kullanıcı onaylı PDF açar</span>
      <span class="pill ok">Lazer otomatik başlamaz</span>
    `;
  }
  const security = byId("settingsSecurityList");
  if (security) {
    security.innerHTML = [
      ["Direct print", "Kapalı", "ok"],
      ["Yazdırma güvenliği", "Yazdır butonu PDF’i kullanıcı onayına sunar; sessiz otomatik yazdırma kapalıdır.", "ok"],
      ["Yazdırma onayı", "Gerekli", "ok"],
      ["Corel/Illustrator", "Otomatik açılmaz", "ok"],
      ["RDWorks/Lazer", "Otomatik başlamaz", "ok"],
      ["Kaynak AI/CDR", "Değiştirilmez", "ok"]
    ].map(([label, value, tone]) => `<div class="settings-check ${tone}"><b>${esc(label)}</b><span>${esc(value)}</span></div>`).join("");
  }
  const roll = byId("settingsRollSummary");
  if (roll) {
    const rollWidth = Number(defaults.roll_width_mm || width || 0);
    const perRow = width ? Math.max(1, Math.floor((rollWidth + gap) / Math.max(width + gap, 1))) : "-";
    const safeMargin = Number(defaults.safe_margin_mm || 0);
    roll.innerHTML = `
      <div class="settings-roll-line"><b>Rulo genişliği</b><span>${rollWidth || "-"} mm</span></div>
      <div class="settings-roll-line"><b>Satır başına yaklaşık</b><span>${perRow} etiket</span></div>
      <div class="settings-roll-line"><b>Güvenli alan</b><span>${safeMargin || 0} mm</span></div>
      <div class="settings-roll-note">Etiket Studio’da yapılan ölçü değişikliği sadece o iş için geçicidir; global ayarı otomatik değiştirmez.</div>
    `;
  }
  const backupInfo = byId("settingsBackupInfo");
  if (backupInfo) {
    const backups = state.settingsBackups || [];
    backupInfo.innerHTML = `
      <div class="settings-backup-step ok"><b>Model ayarı değişirse</b><span>Önce güvenli backup alınır.</span></div>
      <div class="settings-backup-step ok"><b>Tasarım görseli bağlanırsa</b><span>Kopya proje içindeki güvenli klasöre alınır.</span></div>
      <div class="settings-backup-step ok"><b>Kaynak dosyalar</b><span>AI/CDR overwrite edilmez.</span></div>
      <div class="settings-roll-note">Geri alma gereken durumlarda en son backup dosyası raporlarda ve işlem sonucunda belirtilir.</div>
      <div class="settings-backup-log">
        <b>Son ayar backup geçmişi</b>
        ${backups.length
          ? backups.map(item => `<span>${esc(item.created_at || "")} · ${esc(item.file_name || "")} · ${esc(item.size_kb || "-")} KB</span>`).join("")
          : `<span>Henüz settings backup kaydı yok.</span>`}
      </div>
    `;
  }
  const fontColor = byId("settingsFontColorInfo");
  if (fontColor) {
    fontColor.innerHTML = [
      ["Varsayılan font", "Etiket Studio içinden seçilir; teknik font yolu normal kullanıcıya gösterilmez.", "ok"],
      ["Marka renkleri", "CeyizHome Gold, Cream, Brown, Burgundy ve Soft Pink paletleri Studio’da kullanılır.", "ok"],
      ["Kontrast kontrolü", "Zayıf okunurlukta kullanıcıya baskı uyarısı gösterilir.", "warn"]
    ].map(([label, value, tone]) => `<div class="settings-check ${tone}"><b>${esc(label)}</b><span>${esc(value)}</span></div>`).join("");
  }
  const folders = byId("settingsOutputFolders");
  if (folders) {
    folders.innerHTML = [
      ["Çıktı klasörü", state.outputDir || "output", "ok"],
      ["PDF/PNG müşteri çıktıları", "output/YYYY-MM-DD/print ve preview klasörleri", "ok"],
      ["Backup klasörü", "config/backups ve model backups klasörleri", "ok"],
      ["Kaynak dosyalar", "AI/CDR kaynakları overwrite edilmez", "ok"]
    ].map(([label, value, tone]) => `<div class="settings-check ${tone}"><b>${esc(label)}</b><span>${esc(value)}</span></div>`).join("");
  }
  renderLiveIntegrationSecurity(state.liveIntegrationSecurity || {}, state.liveIntegrationRegistry || {});
  renderPrinterProfiles(state.printerProfiles || []);
  renderDataBackups(state.systemBackups || []);
}

function settingsMetric(label, value, tone = "muted") {
  return `<div class="settings-kpi ${esc(tone)}"><small>${esc(label)}</small><b>${esc(value)}</b></div>`;
}

function integrationActionLabel(actionKey = "") {
  const registry = currentState.liveIntegrationRegistry || {};
  return registry[actionKey]?.label || {
    trendyol_status_update: "Trendyol statü güncelleme",
    trendyol_shipping_label: "Trendyol kargo etiketi",
    trendyol_invoice: "Trendyol fatura",
    direct_print: "Direct print",
    laser_send: "Lazer otomatik gönderim",
    rdworks_open_or_send: "RDWorks aç/gönder"
  }[actionKey] || actionKey || "Riskli aksiyon";
}

function renderLiveIntegrationSecurity(settings = {}, registry = {}) {
  const status = byId("liveIntegrationSecurityStatus");
  const grid = byId("liveIntegrationSecurityGrid");
  const list = byId("liveIntegrationRiskRegistry");
  if (status) {
    status.hidden = false;
    status.className = "status-line warn";
    status.textContent = "Canlı entegrasyon bağlı değil. Sistem dry-run modunda; Trendyol, yazıcı, lazer ve RDWorks gerçek çağrısı yapılmaz.";
  }
  if (grid) {
    const rows = [
      ["Canlı Trendyol işlemleri", settings.live_trendyol_actions_enabled ? "Açık" : "Kapalı", "warn"],
      ["Direct print", settings.direct_print_enabled ? "Açık" : "Kapalı", "warn"],
      ["Lazer/RDWorks otomatik gönderim", settings.laser_rdworks_auto_send_enabled ? "Açık" : "Kapalı", "warn"],
      ["Sadece dry-run", settings.dry_run_only === false ? "Kapalı" : "Açık", "ok"],
      ["Yönetici onayı gerekli", settings.admin_approval_required === false ? "Hayır" : "Evet", "ok"]
    ];
    grid.innerHTML = rows.map(([label, value, tone]) => `<div class="settings-check ${tone}"><b>${esc(label)}</b><span>${esc(value)}</span></div>`).join("");
  }
  if (list) {
    const actions = Object.entries(registry || {});
    list.innerHTML = actions.length
      ? actions.map(([key, action]) => `
          <div class="integration-risk-row">
            <div>
              <b>${esc(action.label || key)}</b>
              <span>${esc(action.category || "Canlı entegrasyon")} · ${action.dry_run_only ? "Dry-run modunda" : "Canlı mod kapalı"}</span>
              <small>${esc(action.would_do || "Bu işlem gerçek sistemde değişiklik yapabilir; bu fazda kapalı.")}</small>
            </div>
            <div class="integration-risk-badges">
              <span class="source-badge source-badge--legacy">Canlı entegrasyon bağlı değil</span>
              ${action.requires_admin ? `<span class="source-badge source-badge--laser">Yönetici onayı gerekli</span>` : ""}
              <button class="btn tiny" onclick="openIntegrationDryRunModal(${jsArg(key)}, { source: 'settings', title: ${jsArg(action.label || key)} })">Dry-run</button>
            </div>
          </div>
        `).join("")
      : `<div class="empty-state compact"><b>Riskli aksiyon registry yüklenmedi.</b><p>Bridge hazır değilse canlı aksiyonlar kapalı kabul edilir.</p></div>`;
  }
}

function saveLiveIntegrationSecuritySettings() {
  if (!bridge?.save_live_integration_security_settings) {
    setIntegrationGuardStatus("Entegrasyon güvenliği bridge bağlantısı hazır değil.", "warn");
    return;
  }
  bridge.save_live_integration_security_settings(JSON.stringify({ dry_run_only: true }), raw => {
    const result = parseBridgeResult(raw);
    currentState.liveIntegrationSecurity = result.settings || currentState.liveIntegrationSecurity || {};
    updateSettings(currentState);
    setIntegrationGuardStatus(result.message || "Canlı aksiyonlar kapalı, dry-run modu açık kaldı.", result.status === "OK" ? "ok" : "warn");
    refreshState();
  });
}

function setIntegrationGuardStatus(message, tone = "info") {
  const box = byId("liveIntegrationSecurityStatus");
  if (!box) return;
  box.hidden = false;
  box.className = `status-line ${tone === "ok" ? "ok" : tone === "bad" || tone === "error" ? "bad" : "warn"}`;
  box.textContent = message || "";
}

function openIntegrationDryRunModal(actionKey = "", payload = {}) {
  pendingIntegrationDryRunAction = actionKey || "";
  pendingIntegrationDryRunPayload = payload || {};
  const modal = byId("integrationDryRunModal");
  const body = byId("integrationDryRunBody");
  if (!modal || !body) {
    setIntegrationGuardStatus("Dry-run modalı bu ekranda hazır değil. Canlı işlem yapılmadı.", "warn");
    return;
  }
  const registry = currentState.liveIntegrationRegistry || {};
  const action = registry[actionKey] || {};
  body.innerHTML = `
    <div class="integration-dryrun-summary">
      <span class="source-badge source-badge--legacy">Canlı entegrasyon bağlı değil</span>
      <span class="source-badge source-badge--trendyol">Dry-run modunda</span>
      <span class="source-badge source-badge--laser">Yönetici onayı gerekli</span>
    </div>
    <div class="integration-dryrun-grid">
      <div><small>Aksiyon</small><b>${esc(action.label || integrationActionLabel(actionKey))}</b></div>
      <div><small>Kayıt</small><b>${esc(payload.record_id || payload.source_item_id || "-")}</b></div>
      <div><small>Sipariş</small><b>${esc(payload.order_no || "-")}</b></div>
      <div><small>Dosya</small><b>${esc(payload.file_path || payload.output_path || "-")}</b></div>
      <div><small>Yazıcı/Lazer</small><b>${esc(payload.printer_name || payload.laser_name || "-")}</b></div>
      <div><small>Canlı işlem</small><b>Yapılmadı</b></div>
    </div>
    <p class="safe-note">${esc(action.would_do || "Bu işlem gerçek sistemde değişiklik yapabilir; bu fazda kapalı.")}</p>
    <p class="safe-note">Dry-run yalnızca izin, ayar ve audit kontrolü yapar. Trendyol statü/kargo/fatura, yazıcı, lazer ve RDWorks tetiklenmez.</p>
    <div id="integrationDryRunResult" class="integration-guard-result">Onay kutularını işaretleyip dry-run kontrolünü çalıştırın.</div>
  `;
  const op = byId("integrationDryRunOperatorApproval");
  const admin = byId("integrationDryRunAdminApproval");
  if (op) op.checked = false;
  if (admin) admin.checked = false;
  modal.hidden = false;
}

function closeIntegrationDryRunModal() {
  const modal = byId("integrationDryRunModal");
  if (modal) modal.hidden = true;
  pendingIntegrationDryRunAction = "";
  pendingIntegrationDryRunPayload = {};
}

function integrationGuardResultTone(status = "") {
  if (status === "DRY_RUN") return "ok";
  if (status === "PERMISSION_REQUIRED") return "warn";
  if (status === "NOT_CONFIGURED") return "warn";
  return "bad";
}

function completeIntegrationDryRun() {
  if (!pendingIntegrationDryRunAction) {
    setIntegrationGuardStatus("Dry-run için aksiyon seçilmedi. Canlı işlem yapılmadı.", "warn");
    return;
  }
  if (!bridge?.guard_live_integration_action) {
    setIntegrationGuardStatus("Entegrasyon guard bridge bağlantısı hazır değil. Canlı işlem yapılmadı.", "warn");
    return;
  }
  const operatorConfirmed = Boolean(byId("integrationDryRunOperatorApproval")?.checked);
  const adminConfirmed = Boolean(byId("integrationDryRunAdminApproval")?.checked);
  bridge.guard_live_integration_action(
    pendingIntegrationDryRunAction,
    JSON.stringify(pendingIntegrationDryRunPayload || {}),
    adminConfirmed,
    operatorConfirmed,
    true,
    raw => {
      const result = parseBridgeResult(raw);
      const tone = integrationGuardResultTone(result.status);
      const box = byId("integrationDryRunResult");
      if (box) {
        box.className = `integration-guard-result ${tone}`;
        box.innerHTML = `
          <b>${esc(result.status || "GUARD")}</b>
          <span>${esc(result.message || "Guard sonucu alındı.")}</span>
          <small>Canlı Trendyol: ${result.live_trendyol_changed ? "tetiklendi" : "tetiklenmedi"} · Yazıcı: ${result.auto_print_started ? "başladı" : "başlamadı"} · Lazer/RDWorks: ${(result.laser_started || result.rdworks_started) ? "başladı" : "başlamadı"}</small>
        `;
      }
      setIntegrationGuardStatus(result.message || "Dry-run kontrolü tamamlandı.", tone);
      showTrendyolStatus(result.message || "Canlı işlem yapılmadı.", tone === "ok" ? "ok" : "warn");
      refreshState();
    }
  );
}

function renderPrinterProfiles(profiles = []) {
  const list = byId("printerProfileList");
  if (!list) return;
  list.innerHTML = profiles.length
    ? profiles.map(profile => `
        <div class="printer-profile-row ${profile.is_default ? "default" : ""}">
          <div>
            <b>${esc(profile.profile_name || "Yazıcı profili")}</b>
            <span>${esc(profile.printer_name || "Manuel PDF kontrolü")} · ${esc(profile.paper_size || "-")} · ${esc(profile.label_size || "-")}</span>
            <small>${profile.is_default ? "Varsayılan · " : ""}${esc(profile.orientation || "portrait")} · ${esc(profile.margin || "0 mm")} · ${esc((profile.output_format_allowed || []).join(", ") || "PDF")}</small>
          </div>
          <div class="toolbar compact">
            <button class="btn small" onclick="editPrinterProfile('${esc(profile.printer_profile_id)}')">Düzenle</button>
            <button class="btn small" onclick="setDefaultPrinterProfile('${esc(profile.printer_profile_id)}')">Varsayılan</button>
            <button class="btn small" onclick="deletePrinterProfile('${esc(profile.printer_profile_id)}')">Sil</button>
          </div>
        </div>
      `).join("")
    : `<div class="empty-state compact"><b>Yazıcı profili yok.</b><p>Manuel print hazırlığı için önce profil oluşturun. Yazıcı otomatik çalışmaz.</p></div>`;
}

function setDataMaintenanceStatus(message, tone = "info") {
  const box = byId("dataMaintenanceStatus");
  if (!box) return;
  box.hidden = !message;
  box.className = `status-line ${tone === "ok" ? "ok" : tone === "bad" || tone === "error" ? "bad" : tone === "warn" ? "warn" : ""}`;
  box.textContent = message || "";
}

function renderDataBackups(backups = []) {
  const list = byId("dataBackupList");
  if (!list) return;
  const rows = Array.isArray(backups) ? backups : [];
  if (!selectedDataBackupPath && rows[0]) selectedDataBackupPath = rows[0].backup_path || "";
  list.innerHTML = rows.length
    ? rows.map(item => {
        const path = item.backup_path || "";
        const selected = path === selectedDataBackupPath ? " selected" : "";
        return `
          <div class="data-backup-row${selected}">
            <div>
              <b>${esc(item.backup_id || "CeyizHome Lab yedeği")}</b>
              <span>${esc(item.created_at || "-")} · ${esc(item.file_count || 0)} dosya · ${esc(item.size_kb || "-")} KB</span>
              <small>${esc(path)}${item.reason ? ` · ${esc(item.reason)}` : ""}</small>
            </div>
            <div class="toolbar compact">
              <button class="btn small" onclick="selectDataBackup(${jsArg(path)})">Seç</button>
              <button class="btn small" onclick="validateSelectedDataBackup(${jsArg(path)})">Doğrula</button>
              <button class="btn small" onclick="previewSelectedDataRestore(${jsArg(path)})">Dry-run</button>
            </div>
          </div>`;
      }).join("")
    : `<div class="empty-state compact"><b>Henüz yedek yok.</b><p>JSON persistence dosyalarını yedeklemek için Yedek Oluştur’a basın.</p></div>`;
}

function selectDataBackup(path) {
  selectedDataBackupPath = path || "";
  renderDataBackups(currentState.systemBackups || []);
  setDataMaintenanceStatus(selectedDataBackupPath ? "Yedek seçildi. Önce doğrulama veya dry-run yapabilirsiniz." : "Yedek seçilemedi.", selectedDataBackupPath ? "ok" : "warn");
}

// --- DXF Library UI ---------------------------------------------------------

let dxfLibraryState = { entries: [], summary: null, watcherRunning: false, lastError: "" };

function setDxfLibraryStatus(message, tone = "ok") {
  const box = byId("dxfLibraryStatus");
  if (!box) return;
  box.className = `status-line ${tone}`;
  box.hidden = !message;
  box.textContent = message || "";
}

function refreshDxfLibrary() {
  if (!bridge?.dxfLibraryRefresh) {
    setDxfLibraryStatus("DXF kütüphane bridge bağlantısı hazır değil.", "warn");
    return;
  }
  setDxfLibraryStatus("Kütüphane taranıyor…", "ok");
  bridge.dxfLibraryRefresh(raw => {
    const result = parseBridgeResult(raw);
    if (result.status !== "OK") {
      setDxfLibraryStatus(result.message || "Tarama başarısız.", "bad");
      return;
    }
    const warnCount = (result.warnings || []).length;
    const summaryText = `Tarama tamam: ${result.scanned} kayıt (yeni ${result.added}, güncellenen ${result.updated}, silinen ${result.removed})` + (warnCount ? ` — ${warnCount} uyarı` : "");
    setDxfLibraryStatus(summaryText, warnCount ? "warn" : "ok");
    loadDxfLibraryList();
  });
}

function loadDxfLibraryList() {
  if (!bridge?.dxfLibraryList) return;
  bridge.dxfLibraryList(raw => {
    const result = parseBridgeResult(raw);
    dxfLibraryState.entries = result.entries || [];
    dxfLibraryState.summary = result.summary || null;
    renderDxfLibraryList();
  });
}

function renderDxfLibraryList() {
  const summaryBox = byId("dxfLibrarySummary");
  const listBox = byId("dxfLibraryList");
  if (!summaryBox || !listBox) return;
  const s = dxfLibraryState.summary || {};
  const searchTerm = (byId("dxfLibrarySearchInput")?.value || "").trim().toLowerCase();
  summaryBox.innerHTML = `
    <div class="dxf-library-stat"><b>Toplam</b><span>${esc(s.total ?? 0)}</span></div>
    <div class="dxf-library-stat"><b>70x40</b><span>${esc(s.per_size_group?.["70x40"] ?? 0)}</span></div>
    <div class="dxf-library-stat"><b>80x40</b><span>${esc(s.per_size_group?.["80x40"] ?? 0)}</span></div>
    <div class="dxf-library-stat"><b>100x40</b><span>${esc(s.per_size_group?.["100x40"] ?? 0)}</span></div>
    <div class="dxf-library-stat ${s.unreadable ? 'bad' : ''}"><b>Okunamayan</b><span>${esc(s.unreadable ?? 0)}</span></div>
    <div class="dxf-library-stat ${s.with_warnings ? 'warn' : ''}"><b>Uyarılı</b><span>${esc(s.with_warnings ?? 0)}</span></div>
    <div class="dxf-library-stat"><b>ezdxf</b><span>${s.ezdxf_available ? '✓ yüklü' : '✗ yok'}</span></div>
  `;
  const filtered = (dxfLibraryState.entries || []).filter(entry => {
    if (!searchTerm) return true;
    const name = (entry.name || "").toLowerCase();
    const ascii = (entry.ascii_name || "").toLowerCase();
    return name.includes(searchTerm) || ascii.includes(searchTerm);
  });
  if (!filtered.length) {
    listBox.innerHTML = `<div class="dxf-library-empty">${searchTerm ? "Aramayla eşleşen DXF yok." : "Kütüphane boş. Leyla'nın çizdiği DXF'leri assets/dxf_library/&lt;boyut&gt;/ altına atın ve 'Kütüphaneyi Tara' deyin."}</div>`;
    return;
  }
  listBox.innerHTML = filtered.map(entry => {
    const warn = entry.bbox_warning || "";
    const unreadable = !entry.readable;
    const tone = unreadable ? "bad" : (warn ? "warn" : "ok");
    return `
      <div class="dxf-library-row ${tone}">
        <div class="dxf-library-row-head">
          <b>${esc(entry.name || entry.ascii_name)}</b>
          <span class="dxf-library-group">${esc(entry.size_group || "?")}</span>
        </div>
        <small>${esc(entry.ascii_name)}.dxf · bbox ${entry.bbox_mm?.[0]?.toFixed?.(1) ?? '?'}×${entry.bbox_mm?.[1]?.toFixed?.(1) ?? '?'} mm · ${esc((entry.entity_types || []).join(", ") || "—")}${entry.is_compound ? ' · birleşik isim' : ''}</small>
        ${warn ? `<small class="dxf-library-warn">${esc(warn)}</small>` : ""}
        ${unreadable ? `<small class="dxf-library-warn">DXF okunamıyor: ${esc(entry.read_error || "?")}</small>` : ""}
      </div>
    `;
  }).join("");
}

function toggleDxfLibraryWatcher() {
  if (!bridge?.dxfLibraryStartWatcher || !bridge?.dxfLibraryStopWatcher) {
    setDxfLibraryStatus("Watcher bridge bağlantısı hazır değil.", "warn");
    return;
  }
  const btn = byId("dxfLibraryWatcherBtn");
  if (dxfLibraryState.watcherRunning) {
    bridge.dxfLibraryStopWatcher(raw => {
      const result = parseBridgeResult(raw);
      dxfLibraryState.watcherRunning = result.status === "OK" ? false : dxfLibraryState.watcherRunning;
      if (btn) btn.textContent = "Otomatik İzlemeyi Başlat";
      setDxfLibraryStatus(result.message || "Watcher durduruldu.", result.status === "OK" ? "ok" : "warn");
    });
  } else {
    bridge.dxfLibraryStartWatcher(raw => {
      const result = parseBridgeResult(raw);
      if (result.status === "UNAVAILABLE") {
        setDxfLibraryStatus(result.message, "warn");
        return;
      }
      dxfLibraryState.watcherRunning = result.status === "OK" || result.status === "ALREADY_RUNNING";
      if (btn) btn.textContent = dxfLibraryState.watcherRunning ? "Otomatik İzlemeyi Durdur" : "Otomatik İzlemeyi Başlat";
      setDxfLibraryStatus(result.message || "Watcher başlatıldı.", dxfLibraryState.watcherRunning ? "ok" : "warn");
      if (dxfLibraryState.watcherRunning) loadDxfLibraryList();
    });
  }
}

function refreshDataBackups() {
  if (!bridge?.list_backups) {
    setDataMaintenanceStatus("Yedek listesi bridge bağlantısı hazır değil.", "warn");
    return;
  }
  bridge.list_backups(raw => {
    const rows = parseBridgeResult(raw);
    currentState.systemBackups = Array.isArray(rows) ? rows : [];
    if (!currentState.systemBackups.some(item => item.backup_path === selectedDataBackupPath)) {
      selectedDataBackupPath = currentState.systemBackups[0]?.backup_path || "";
    }
    renderDataBackups(currentState.systemBackups);
    setDataMaintenanceStatus(`${currentState.systemBackups.length} yedek listelendi. Canlı üretim işlemi tetiklenmedi.`, "ok");
  });
}

function createDataBackup() {
  if (!bridge?.create_backup) {
    setDataMaintenanceStatus("Yedek oluşturma bridge bağlantısı hazır değil.", "warn");
    return;
  }
  setDataMaintenanceStatus("Yedek oluşturuluyor...", "info");
  bridge.create_backup(raw => {
    const result = parseBridgeResult(raw);
    if (result.status !== "OK") {
      setDataMaintenanceStatus(result.message || "Yedek oluşturulamadı.", "bad");
      return;
    }
    selectedDataBackupPath = result.backup_path || selectedDataBackupPath;
    refreshDataBackups();
    setDataMaintenanceStatus(`${result.message || "Yedek oluşturuldu."} Yazıcı, lazer, RDWorks ve Trendyol tetiklenmedi.`, "ok");
  });
}

function selectedBackupPath(overridePath = "") {
  const path = overridePath || selectedDataBackupPath || currentState.systemBackups?.[0]?.backup_path || "";
  if (!path) setDataMaintenanceStatus("Önce bir yedek seçin.", "warn");
  return path;
}

function validateSelectedDataBackup(overridePath = "") {
  const path = selectedBackupPath(overridePath);
  if (!path) return;
  selectedDataBackupPath = path;
  if (!bridge?.validate_backup) {
    setDataMaintenanceStatus("Yedek doğrulama bridge bağlantısı hazır değil.", "warn");
    return;
  }
  bridge.validate_backup(path, raw => {
    const result = parseBridgeResult(raw);
    renderDataRestorePreview(result);
    setDataMaintenanceStatus(result.message || "Yedek doğrulandı.", result.status === "OK" ? "ok" : "bad");
    renderDataBackups(currentState.systemBackups || []);
  });
}

function previewSelectedDataRestore(overridePath = "") {
  const path = selectedBackupPath(overridePath);
  if (!path) return;
  selectedDataBackupPath = path;
  if (!bridge?.restore_backup) {
    setDataMaintenanceStatus("Restore dry-run bridge bağlantısı hazır değil.", "warn");
    return;
  }
  bridge.restore_backup(path, true, raw => {
    const result = parseBridgeResult(raw);
    renderDataRestorePreview(result);
    setDataMaintenanceStatus(result.message || "Geri yükleme önizlendi.", result.status === "DRY_RUN" ? "ok" : "bad");
    renderDataBackups(currentState.systemBackups || []);
  });
}

function restoreSelectedDataBackup() {
  const path = selectedBackupPath();
  if (!path) return;
  if (!bridge?.restore_backup) {
    setDataMaintenanceStatus("Restore bridge bağlantısı hazır değil.", "warn");
    return;
  }
  const ok = confirm("Seçili yedek geri yüklenecek. Önce otomatik snapshot alınır; yazıcı, lazer, RDWorks ve Trendyol tetiklenmez. Devam edilsin mi?");
  if (!ok) {
    setDataMaintenanceStatus("Geri yükleme iptal edildi.", "warn");
    return;
  }
  bridge.restore_backup(path, false, raw => {
    const result = parseBridgeResult(raw);
    renderDataRestorePreview(result);
    if (result.status === "OK") {
      currentState.systemBackups = bridge?.list_backups ? currentState.systemBackups : currentState.systemBackups;
      refreshDataBackups();
    }
    setDataMaintenanceStatus(result.message || "Geri yükleme kontrol edildi.", result.status === "OK" ? "ok" : "bad");
  });
}

function renderDataRestorePreview(result = {}) {
  const box = byId("dataRestorePreview");
  if (!box) return;
  if (!result || !Object.keys(result).length) {
    box.innerHTML = "";
    return;
  }
  const changes = Array.isArray(result.changes) ? result.changes : [];
  const errors = Array.isArray(result.errors) ? result.errors : [];
  const warnings = Array.isArray(result.warnings) ? result.warnings : [];
  const changedCount = changes.filter(item => item.will_change).length;
  box.innerHTML = `
    <div class="data-restore-head ${result.status === "OK" || result.status === "DRY_RUN" ? "ok" : "bad"}">
      <b>${esc(result.status || "Kontrol")}</b>
      <span>${esc(result.message || "")}</span>
    </div>
    ${changes.length ? `<div class="data-restore-summary">${esc(changedCount)} / ${esc(changes.length)} dosya değişecek.</div>` : ""}
    ${changes.slice(0, 8).map(item => `
      <div class="data-restore-change ${item.will_change ? "will-change" : ""}">
        <b>${esc(item.relative_path || "")}</b>
        <span>${item.target_exists ? "Mevcut" : "Yeni"} · ${item.will_change ? "değişecek" : "aynı"}</span>
      </div>`).join("")}
    ${errors.map(error => `<div class="data-restore-warning bad">${esc(error)}</div>`).join("")}
    ${warnings.map(warning => `<div class="data-restore-warning warn">${esc(warning)}</div>`).join("")}
    ${result.snapshot?.backup_path ? `<div class="data-restore-warning ok">Restore öncesi snapshot: ${esc(result.snapshot.backup_path)}</div>` : ""}
  `;
}

function currentPrinterProfileFormPayload() {
  return {
    printer_profile_id: selectedPrinterProfileEditId || "",
    profile_name: byId("printerProfileName")?.value || "",
    printer_name: byId("printerProfilePrinterName")?.value || "Manuel PDF kontrolü",
    paper_size: byId("printerProfilePaperSize")?.value || "A4",
    label_size: byId("printerProfileLabelSize")?.value || "50 x 30 mm",
    orientation: byId("printerProfileOrientation")?.value || "portrait",
    margin: byId("printerProfileMargin")?.value || "0 mm",
    copies_default: byId("printerProfileCopies")?.value || 1,
    output_format_allowed: (byId("printerProfileFormats")?.value || "PDF").split(",").map(item => item.trim()).filter(Boolean),
    is_default: Boolean(byId("printerProfileDefault")?.checked)
  };
}

function setPrinterProfileStatus(message, tone = "info") {
  const box = byId("printerProfileStatus");
  if (!box) return;
  box.className = `tiny-status ${tone}`;
  box.textContent = message || "";
}

function savePrinterProfileFromSettings() {
  const payload = currentPrinterProfileFormPayload();
  if (!String(payload.profile_name || "").trim()) {
    setPrinterProfileStatus("Profil adı zorunlu.", "warn");
    return;
  }
  if (!bridge?.save_printer_profile) {
    setPrinterProfileStatus("Yazıcı profili bridge bağlantısı hazır değil.", "warn");
    return;
  }
  bridge.save_printer_profile(JSON.stringify(payload), raw => {
    const result = parseBridgeResult(raw);
    currentState.printerProfiles = result.profiles || currentState.printerProfiles || [];
    renderPrinterProfiles(currentState.printerProfiles);
    resetPrinterProfileForm();
    setPrinterProfileStatus(result.message || "Profil kaydedildi. Yazıcı otomatik çalışmaz.", result.status === "OK" ? "ok" : "warn");
  });
}

function editPrinterProfile(profileId) {
  const profile = (currentState.printerProfiles || []).find(item => item.printer_profile_id === profileId);
  if (!profile) {
    setPrinterProfileStatus("Düzenlenecek profil bulunamadı.", "warn");
    return;
  }
  selectedPrinterProfileEditId = profile.printer_profile_id || "";
  if (byId("printerProfileName")) byId("printerProfileName").value = profile.profile_name || "";
  if (byId("printerProfilePrinterName")) byId("printerProfilePrinterName").value = profile.printer_name || "";
  if (byId("printerProfilePaperSize")) byId("printerProfilePaperSize").value = profile.paper_size || "";
  if (byId("printerProfileLabelSize")) byId("printerProfileLabelSize").value = profile.label_size || "";
  if (byId("printerProfileOrientation")) byId("printerProfileOrientation").value = profile.orientation || "portrait";
  if (byId("printerProfileMargin")) byId("printerProfileMargin").value = profile.margin || "";
  if (byId("printerProfileCopies")) byId("printerProfileCopies").value = profile.copies_default || 1;
  if (byId("printerProfileFormats")) byId("printerProfileFormats").value = (profile.output_format_allowed || ["PDF"]).join(",");
  if (byId("printerProfileDefault")) byId("printerProfileDefault").checked = Boolean(profile.is_default);
  setPrinterProfileStatus("Profil düzenleme modunda. Kaydetmeden cihaz tetiklenmez.", "info");
}

function resetPrinterProfileForm() {
  selectedPrinterProfileEditId = "";
  ["printerProfileName", "printerProfilePrinterName", "printerProfilePaperSize", "printerProfileLabelSize", "printerProfileMargin"].forEach(id => {
    const input = byId(id);
    if (input) input.value = "";
  });
  if (byId("printerProfileOrientation")) byId("printerProfileOrientation").value = "portrait";
  if (byId("printerProfileCopies")) byId("printerProfileCopies").value = "1";
  if (byId("printerProfileFormats")) byId("printerProfileFormats").value = "PDF";
  if (byId("printerProfileDefault")) byId("printerProfileDefault").checked = false;
}

function setDefaultPrinterProfile(profileId) {
  if (!bridge?.set_default_printer_profile) return setPrinterProfileStatus("Varsayılan profil bridge bağlantısı hazır değil.", "warn");
  bridge.set_default_printer_profile(profileId, raw => {
    const result = parseBridgeResult(raw);
    currentState.printerProfiles = result.profiles || currentState.printerProfiles || [];
    renderPrinterProfiles(currentState.printerProfiles);
    setPrinterProfileStatus(result.message || "Varsayılan profil güncellendi.", result.status === "OK" ? "ok" : "warn");
  });
}

function deletePrinterProfile(profileId) {
  if (!confirm("Yazıcı profili silinecek. Yazıcı otomatik çalışmaz. Devam edilsin mi?")) return;
  if (!bridge?.delete_printer_profile) return setPrinterProfileStatus("Silme bridge bağlantısı hazır değil.", "warn");
  bridge.delete_printer_profile(profileId, raw => {
    const result = parseBridgeResult(raw);
    currentState.printerProfiles = result.profiles || currentState.printerProfiles || [];
    renderPrinterProfiles(currentState.printerProfiles);
    setPrinterProfileStatus(result.message || "Profil silindi.", result.status === "OK" ? "ok" : "warn");
  });
}

function testSelectedPrinterProfile() {
  const profileId = selectedPrinterProfileEditId || defaultPrinterProfile()?.printer_profile_id || "";
  if (!profileId) return setPrinterProfileStatus("Test için önce profil seçin veya oluşturun.", "warn");
  if (!bridge?.test_printer_profile) return setPrinterProfileStatus("Test bridge bağlantısı hazır değil.", "warn");
  bridge.test_printer_profile(profileId, raw => {
    const result = parseBridgeResult(raw);
    let tone;
    if (result.status === "OK") {
      tone = "ok";
    } else if (result.status === "UNSUPPORTED") {
      tone = "warn";
    } else {
      tone = "bad";
    }
    setPrinterProfileStatus(result.message || (result.status === "OK" ? "Test başarılı." : "Test başarısız."), tone);
  });
}

function updateLaserOutputs(rows) {
  const list = byId("svgList");
  if (!list) return;
  list.innerHTML = rows.length
    ? rows.map(item => `<div class="list-row"><b>${esc(item.name || "SVG")}</b><br><small>${esc(item.relative_path || "")}</small></div>`).join("")
    : "Henüz lazer SVG çıktısı yok.";
}

